window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-044.json"] = [{"name":"红翅椋鸟","english_name":"Red-winged Starling","scientific_name":"Onychognathus morio","overview":"红翅椋鸟（英文名：Red-winged Starling，学名：Onychognathus morio），是雀形目椋鸟科栗翅椋鸟属的鸟类。大型的、光泽黑亮的椋鸟。其最显著的特征是翅膀上醒目的砖红色斑块，雄鸟全身漆黑，雌鸟头部呈现灰暗色。广泛分布于非洲东部、东南部至南部，包括埃塞俄比亚至南非开普省。适应性强，常见于城市环境。","appearance":"成年红翅椋鸟长约30厘米，重115至155克。雄鸟的羽毛呈金属蓝黑色光泽，雌鸟的冠、颈、头侧面、下巴、喉咙和上胸为灰白色，带有深色条纹。幼鸟外观与成年雄鸟相似，但光泽较弱，眼睛呈深棕色，喙为棕色。红翅椋鸟的尾巴较长而尖，飞行时可见其翼下独特的红褐色斑块。","call":"发出一系列清脆的哨音和颤鸣，最典型的是一声两音节的‘cher-leeeoo’联系叫声，以及其它悦耳的口哨声和颤音。","habits":"栖息于岩石峭壁、峡谷和山地，现已适应城市环境中的建筑物。偏好海拔较高的地区，但在肯尼亚的盐矿附近也能发现它们。以果实为主食，但也吃昆虫、小型脊椎动物和腐肉，具有杂食性和机会主义特性。在树木、灌木丛和地面上觅食，甚至在潮间带活动。","breeding":"繁殖季节在埃塞俄比亚为4月和10月，在东非全年均可繁殖，高峰期在11月至12月和3月。巢由两性共同筑造，通常位于岩石或悬崖的突出处，现在多见于建筑上。每窝产2至4枚蛋，孵化期为13至14天，幼鸟的喂养期为22至28天。双亲共同育雏。","identification":"与淡栗翅椋鸟的区别在于，红翅椋鸟的初级飞羽为红褐色，而淡栗翅椋鸟的为白色边缘橙色。此外，红翅椋鸟的眼睛颜色较深，接近黑色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部、东南部至南部，从埃塞俄比亚到南非开普省，包括肯尼亚、乌干达、南非等地。在南非克鲁格国家公园的数量估计超过4000只。","other":"在某些南非地区不受保护，因为它会损害水果作物。"},{"name":"细嘴栗翅椋鸟","english_name":"Slender-billed Starling","scientific_name":"Onychognathus tenuirostris","overview":"细嘴栗翅椋鸟（英文名：Slender-billed Starling，学名：Onychognathus tenuirostris），是雀形目椋鸟科栗翅椋鸟属的鸟类。大型椋鸟，该鸟以细长的喙和尾羽著称，雄鸟呈现蓝黑色，雌鸟为深灰色。其翼部带有醒目的红色斑块，飞行时尤为显眼。广泛分布于非洲东部，包括埃塞俄比亚南部、乌干达西南部、卢旺达、布隆迪、刚果民主共和国东部、肯尼亚西部和中部、坦桑尼亚东北部、中部和南部（东弧山脉）、赞比亚东北部和马拉维北部（尼基亚高原）。","appearance":"细嘴栗翅椋鸟体型较大，拥有长而尖的尾巴和细长的喙。雄鸟的基础颜色为蓝黑色，而雌鸟则呈深灰色。翅膀上有一大块红色斑块，飞行时非常醒目。这种鸟通常形成大群。","call":"发出一系列叫声，包括清晰的“cheed-lit”声、刺耳的嘶哑声和长时间的对话式鸣叫。","habits":"栖息于中高海拔的各种生境，包括森林、荒野、悬崖，有时也会出现在人类建筑附近。经常组成大型群体。","breeding":"关于细嘴栗翅椋鸟的繁殖行为具体细节尚未详细记载。","identification":"与红翼椋鸟相似，但细嘴栗翅椋鸟具有更长、更尖的尾羽和更为纤细的喙。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部，具体包括：厄立特里亚南部至埃塞俄比亚中部和南部；刚果民主共和国东部、乌干达西南部、卢旺达和布隆迪；埃尔贡山（乌干达-肯尼亚边境）、肯尼亚西部和中部；坦桑尼亚东北部、中部和南部（东弧山脉）；赞比亚东北部和马拉维北部（尼基亚高原）。"},{"name":"栗翅椋鸟","english_name":"Chestnut-winged Starling","scientific_name":"Onychognathus fulgidus","overview":"栗翅椋鸟（英文名：Chestnut-winged Starling，学名：Onychognathus fulgidus），是雀形目椋鸟科栗翅椋鸟属的鸟类。广泛分布于非洲热带雨林，常见于低地森林，以光泽黑体和长尾为显著特征。","appearance":"成年栗翅椋鸟体长28至35厘米，体重103至140克，体色深暗，雄鸟头部呈蓝黑色光泽，颈背、耳羽、头侧、颏喉为黑色带绿光泽，翼与尾部黑色具绿光泽，初级飞羽红棕色带宽黑边；雌鸟头部灰色，带暗绿色条纹，幼鸟较暗淡，虹膜棕色。","call":"发出混合的嘶哑音与尖叫声，以及‘churng-chuzick’声；飞行时会发出哨音‘ti-ew’，也有其他双音节变体，停栖时很少鸣叫。","habits":"栖息于低地原始森林和旧次生林，有时在开阔地带和树木花园，海拔一般低于1000米，但在繁殖季节外高度移动，可能进行局部季节性迁移。主要以果实为主食，也吃Bombax的花蜜和昆虫，如白蚁、甲虫和蚂蚁。","breeding":"繁殖季在不同地区有所不同，如利比里亚的10月至3月，科特迪瓦的9月至12月等。筑巢于棕榈叶基部、密集的附生植物中或树洞，高15至35米，有时使用赤颈鵟或棕榈鹫的旧巢，巢址可能连续多年使用。","identification":"大型暗色椋鸟，具长尾和重型喙。雄鸟指名亚种头部有光泽蓝黑色，雌鸟头部灰色，有暗绿色重条纹。hartlaubii亚种体型更小，喙明显较小，雄鸟头部和颈部有绿色光泽。","protection":"IUCN：LC（无危）；在西非相当常见，局部地区数量较多。","distribution":"广泛分布于非洲西部和中部，包括科特迪瓦、利比里亚、加纳、尼日利亚、喀麦隆、圣多美和普林西比、刚果民主共和国北部和东部、乌干达以及安哥拉北部。","other":"具有高流动性，非繁殖季节中在一个地点停留时间通常不超过几天。"},{"name":"高山栗翅椋鸟","english_name":"Waller's Starling","scientific_name":"Onychognathus walleri","overview":"高山栗翅椋鸟（英文名：Waller's Starling，学名：Onychognathus walleri），是雀形目椋鸟科栗翅椋鸟属的鸟类。分布于非洲中西部、中部及东部地区，常见于蒙特森林的树冠层，常以小群体形式活动。其命名纪念了英国自然学家Gerald Waller。","appearance":"该鸟体型中等，尾部较短，呈方形。雄鸟的头部至背部呈现蓝黑色，翅膀与尾羽色泽暗淡，翼上有醒目的红褐色斑块。雌鸟头部及胸部为灰白色，喉部至腹部颜色较深，有金属绿光泽。幼鸟外观与成年雄鸟相似，但缺乏光泽，虹膜呈深棕色。","call":"鸣唱由一系列清晰的哨音组成，有时伴有碎裂声和粗糙的音节。群唱前会分离出领地。飞行意向鸣叫为双音哨声；联络鸣叫为单一响亮的哨声；警戒鸣叫则为刺耳的摩擦声。","habits":"栖息于海拔1000-3000米的蒙特森林，主要食物为果实和小型动物，如变色龙、蜘蛛及昆虫。觅食活动主要在森林树冠进行，善于攀爬细枝，捕捉飞行中的昆虫，也会从树皮和树叶上搜寻食物。","breeding":"繁殖季节在不同地区有所不同，如喀麦隆为11月至12月，刚果民主共和国可能为3月至4月。一夫一妻制，巢穴建于4-20米高的树洞中，由苔藓、树皮和枯叶制成，内部铺有细枝和藤蔓纤维。孵化期约13-16天，雏鸟喂养期约为23-30天。繁殖成功率较低，巢穴失败多因掠食者。","identification":"与肯氏狭尾椋鸟相似，但体型更大，更粗壮，眼睛红色，尾部较短。与其它红翼椋鸟相比，尾部亦更短。","protection":"IUCN：LC（无危）","distribution":"分布于布隆迪、喀麦隆、刚果民主共和国、赤道几内亚、肯尼亚、马拉维、尼日利亚、卢旺达、南苏丹、坦桑尼亚、乌干达和赞比亚。"},{"name":"索马里栗翅椋鸟","english_name":"Somali Starling","scientific_name":"Onychognathus blythii","overview":"索马里栗翅椋鸟（英文名：Somali Starling，学名：Onychognathus blythii），是雀形目椋鸟科栗翅椋鸟属的鸟类。大型、光泽黑色的椋鸟，显著特征包括强大的喙和非常长而尖锐的尾巴，以及在飞行中显眼的红色翼板。雄鸟头部深色，雌鸟头部呈淡灰，易于区分。广泛分布在干旱地区的悬崖和岩石地带，主要见于厄立特里亚、埃塞俄比亚、吉布提、索马里以及索科特拉岛。","appearance":"体型较大，全长约28厘米，体重约100克。全身羽毛大部分呈现均匀的紫黑色，带有金属光泽；初级飞羽为红棕色，末端有一条狭窄的黑色带。雄鸟的头部、颈部、侧面、下巴、喉咙和胸部均为纯灰白色。雌鸟的上述部位颜色较浅，为灰白色。幼鸟羽毛暗淡，呈烟灰色，虹膜为棕色。","call":"发出尖锐的音乐般的‘tleep’声作为飞行叫声，同时有粗糙的‘scraich’报警声，以及被描述为典型叫声的悦耳哨音。成对时，成员间会发出双音节的‘di-heed’接触叫声。","habits":"主要栖息于高海拔的干旱山区，繁殖季节多在1000米以上，最高可达3800米（埃塞俄比亚巴勒山脉）。非繁殖季节会下降至海平面高度。以果实和昆虫为主食，如无花果、杜松、橄榄树和索科特拉龙血树的果实，以及甲虫、蜜蜂和蚱蜢等昆虫。偶尔取食花蜜和可能的花粉。通常形成小群，最多约20只，夜间会在深谷中形成大群休息。","breeding":"繁殖季节在埃里特里亚为4月，在埃塞俄比亚为4月至5月和9月，在索马里为5月，在索科特拉岛基于幼鸟的存在推测为11月至4月。一夫一妻制。巢穴由草和羽毛构成，不使用泥土，建于悬崖洞穴、道路堤岸或建筑物上，甚至在有人居住的帐篷的屋脊上。每窝产4-5枚蛋，蛋壳呈绿蓝色，带有红色斑点。","identification":"与细嘴栗翅椋鸟相似，但在更干燥的环境中发现，喙更厚实，尾巴更尖锐。还与索科特拉和红翅椋鸟类似，但尾巴更长、更尖。通过这些特征可以将其与其他椋鸟区分开来。","protection":"IUCN：LC（无危）。数量常见至局部丰盛。索科特拉岛上估计有33,000只个体。主要生活在干旱的山地，面临较少的直接威胁。在多个保护区中出现，例如Awash国家公园和Bale山脉国家公园。","distribution":"繁殖区域：埃里特里亚、埃塞俄比亚北部、吉布提、索马里北部。非繁殖区域：沿海地区。在非洲，具体分布于厄立特里亚、埃塞俄比亚、吉布提、索马里和索科特拉岛。","other":"在索科特拉岛上，经常栖息在牛背上，从中受益，因为牛群会惊扰到猎物，椋鸟也会从牛身上移除蜱虫。"},{"name":"索岛栗翅椋鸟","english_name":"Socotra Starling","scientific_name":"Onychognathus frater","overview":"索岛栗翅椋鸟（英文名：Socotra Starling，学名：Onychognathus frater），是雀形目椋鸟科栗翅椋鸟属的鸟类。大型、全身光泽黑亮的椋鸟，拥有强劲的喙。该物种仅分布于非洲的索科特拉岛，以独特的红棕色翼斑和黑色光泽羽毛著称。","appearance":"成鸟体型较大，约25厘米长，重100克，拥有适度长度、略呈梯级状的尾巴。羽毛均匀呈现光泽黑色，翼部有显著的红棕色主羽，翼尖为深褐色。虹膜、喙和腿分别为深褐色、深棕色和黑色。雌雄外观相似，幼鸟则呈烟灰色，主羽色泽较暗淡，尾部更短，喙呈灰色。","call":"发出清脆、传远的哨声，‘pee-hoo’；警报声为刺耳的‘scraich’；伴侣间的联系叫声则是一种轻柔的单音节‘huid’。","habits":"索岛栗翅椋鸟常出现在悬崖和岩石地带，此处也是它们的筑巢地。觅食偏好干燥林地，也光顾城镇花园。主要食物包括果实和昆虫，已记录的果实来源有无花果、枣树和索科特拉龙血树的果实，以及豆科种子。昆虫如蚂蚁和蚱蜢，以及被椋鸟在‘砧石’上敲碎的蜗牛。椋鸟在植被中像鸫鸟一样觅食，不与牲畜共处，也会进入人类聚居区觅食废弃的食物残渣。","breeding":"繁殖行为在11月观察到，雏鸟出现的时间指示繁殖可能持续至12月至次年3月。巢穴由草和枝条堆砌，置于石灰岩洞穴的屋顶或墙上的自然凹槽中。通常每对亲鸟只抚养一只雏鸟。","identification":"与索马里栗翅椋鸟雄鸟相似，但后者尾巴明显更短且尖锐。与灰帽索马里栗翅椋鸟雌鸟的区别更为明显。","protection":"IUCN：LC（无危）。该物种全球数量稳定，无直接威胁。2003年估计种群数量为12,000只，曾被评为易危，但目前状态稳定。","distribution":"仅分布于非洲的索科特拉岛，位于也门东南沿海。","other":"该鸟种利用索科特拉岛特有的龙血树的空心树枝筑巢，除了食用蚱蜢和无花果外，还吃龙血树的浆果，有助于种子的散布。"},{"name":"红海栗翅椋鸟","english_name":"Tristram's Starling","scientific_name":"Onychognathus tristramii","overview":"红海栗翅椋鸟（英文名：Tristram's Starling，学名：Onychognathus tristramii），是雀形目椋鸟科栗翅椋鸟属的鸟类。中等体型的椋鸟，体长25厘米，体重115至131克，主要分布于中东地区的沙漠地带。该属中唯一主要分布于非洲以外的物种。红海栗翅椋鸟以其适应极端干燥环境的能力而闻名。","appearance":"雄性红海栗翅椋鸟全身呈现光泽的黑色，翅膀上具有醒目的橙色斑块，尤其在飞行中更为显眼；雌鸟颜色较暗，头部略呈灰色，缺乏雄鸟的光泽。幼鸟与成年雌鸟相似，但光泽度较低。它们的喙和腿均为黑色。","call":"红海栗翅椋鸟的鸣叫声独特，是一种类似口哨的音乐性叫声，例如“wuuwííwuu”，同时也会发出尖锐的警报声“veeech”。","habits":"红海栗翅椋鸟栖息在荒凉的岩石地带，适应了沙漠条件，也能在人类居住区找到。它们以水果、昆虫为主要食物，偶尔食用小型软体动物，也会在城镇中寻找残羹剩饭。在非繁殖季节，它们会组成小到中等规模的群落。","breeding":"繁殖期在以色列为3月至6月，通常会养育第二窝。它们是单配偶制，雄鸟在求偶时会向雌鸟喂食昆虫并提供小枝条。巢穴由草或城市环境中绿柽柳枝条构成，位于悬崖或建筑的洞穴中，离地面6至21米。雌鸟独自孵化2至4枚蓝色带棕色斑点的蛋，孵化期15至17天。双亲共同喂养雏鸟，离巢期28至31天，之后继续喂养约10天。","identification":"红海栗翅椋鸟通过其橙色的翼斑和独特的口哨声与其它椋鸟区分。雌雄间的主要区别在于雌鸟头部的灰色调和光泽度的差异。","protection":"IUCN：LC（无危）","distribution":"分布于以色列东部与南部、巴勒斯坦、约旦西部、埃及东北部（西奈半岛）、阿拉伯半岛西部（南至也门，东至阿曼西南部）。近年来，红海栗翅椋鸟在人类活动影响的环境下数量增加，尤其是在城镇中。","other":"红海栗翅椋鸟展现出与人类共生的趋势，利用人类环境中的资源，这促进了其分布范围的北扩。"},{"name":"淡栗翅椋鸟","english_name":"Pale-winged Starling","scientific_name":"Onychognathus nabouroup","overview":"淡栗翅椋鸟（英文名：Pale-winged Starling，学名：Onychognathus nabouroup），是雀形目椋鸟科栗翅椋鸟属的鸟类。主要分布在非洲西南部至南非南部和中部，包括安哥拉、博茨瓦纳、纳米比亚和南非等地的干旱及半干旱地区。","appearance":"体长约27厘米，体重介于94至122克。全身羽毛呈现均匀的光泽黑色，仅在收拢的翅膀上可见窄窄的浅红褐色条纹，中央初级飞羽常显露出一些白色；所有初级飞羽宽幅黑色尖端，内侧五枚飞羽其余部分为奶油白色，外侧四枚飞羽内侧边缘为奶油白色，外侧边缘为红褐色。飞行时，白色斑块位于翼中央位置；虹膜橙黄色；喙和腿黑色。雄鸟和雌鸟外观相似，但在质量、尾巴长度、跗跖长度和翼长上统计学上雄鸟较大。幼鸟光泽度不及成鸟，虹膜呈棕色。","call":"具有响亮悦耳的‘preeeeooo’飞行叫声和多变的鸣唱声。","habits":"成对或小群体居住在半沙漠和沙漠地带，偏好岩石区和悬崖，同时也出现在城镇和灌木丛中寻找果实和无脊椎动物。它们是杂食性的，以各种水果和昆虫为食。","breeding":"繁殖季节为11月至次年4月在纳米比亚，10月至次年3月在南非，可能有两次繁殖。一夫一妻制，伴侣似乎会连续几个季节在一起。半群居，多个配对在同一悬崖上筑巢。巢由两性共同建造，用干树枝嵌入岩石裂缝中，碗状巢底由干草、动物毛发组成，偶尔用Parkinsonia africana树针叶状叶子，置于岩石裂缝中；偶尔也会利用建筑物类似位置筑巢。每次产卵通常为3枚，蛋壳呈淡绿色，带有红褐色斑点和污迹；孵化由雌鸟负责，雄鸟在附近守候并经常长时间鸣唱，孵化期为13至14天；雏鸟由雄鸟和雌鸟共同喂养，巢中成长期约25天。巢穴常被大斑凤头鹃寄生，会对靠近巢穴的啄木鸟发动攻击。","identification":"与相似的红翅椋鸟的区别在于飞行时显示的是白色（而非砖红色）的翼斑，尾羽形状为方形（而非渐变），眼睛颜色为橙色（而非深红色）。","protection":"IUCN：LC（无危）。在人口稀少的广泛区域内，数量普遍较多。","distribution":"主要分布于非洲西南部至南非南部和中部，具体包括安哥拉西南部、纳米比亚（除东部）、南非西部内陆至自由州南部和东开普省西部。"},{"name":"须冠栗翅椋鸟","english_name":"Bristle-crowned Starling","scientific_name":"Onychognathus salvadorii","overview":"须冠栗翅椋鸟（英文名：Bristle-crowned Starling，学名：Onychognathus salvadorii），是雀形目椋鸟科栗翅椋鸟属的鸟类。主要分布在非洲的埃塞俄比亚中部至乌干达东北部，肯尼亚中部和索马里中部。","appearance":"这种椋鸟体型较大，头部前额有一个模糊的隆起。飞行时，其非常长而尖锐的尾巴和大红色翼斑格外显眼。羽毛呈蓝黑色，具有独特的额头突起，尾部更尖长。","call":"发出一系列简单的叫声，其中最常见的是两部分组成的“chu-pit”声。","habits":"栖息于干燥的草原和荆棘灌木丛中的悬崖和其他岩石地带，有时会坐在家畜上。","identification":"与其它红翼椋鸟相似，但须冠栗翅椋鸟体型更大，尾部更加尖锐，前额有明显的突起。","distribution":"分布于非洲中部埃塞俄比亚至东北部乌干达，肯尼亚中部以及索马里中部。"},{"name":"白嘴栗翅椋鸟","english_name":"White-billed Starling","scientific_name":"Onychognathus albirostris","overview":"白嘴栗翅椋鸟（英文名：White-billed Starling，学名：Onychognathus albirostris），是雀形目椋鸟科栗翅椋鸟属的鸟类。拥有象牙色的喙、深红色的眼睛以及翅膀上显眼的红色斑块。雄鸟具有深色头部，而雌鸟的头部呈淡灰色。其尾巴相对较短且末端平截。该鸟种分布于非洲厄立特里亚山区至埃塞俄比亚的高地。","appearance":"白嘴栗翅椋鸟体羽深色，最显著的特征是其象牙色的喙和深红的眼珠，翅膀上有大型红色斑块。雄鸟头部颜色较深，而雌鸟头部为淡灰色。尾巴较短且末端平截，给人一种紧凑的感觉。","call":"其鸣叫为安静而絮叨的哨音。","habits":"它们栖息于岩石山脉地带，包括林地、干燥森林和灌木丛，通常以数十只的大群出现。在Degua Tembien区，人们曾在陡峭的悬崖上发现它们的身影。","identification":"与其它红翼椋鸟相似，但通过其象牙色的喙和更短的尾巴很容易区分。","distribution":"白嘴栗翅椋鸟主要分布在非洲的厄立特里亚和埃塞俄比亚的高山区，具体而言，其分布范围从厄立特里亚南部一直延伸到埃塞俄比亚中部。"},{"name":"诺氏栗翅椋鸟","english_name":"Neumann's Starling","scientific_name":"Onychognathus neumanni","overview":"诺氏栗翅椋鸟（英文名：Neumann's Starling，学名：Onychognathus neumanni），是雀形目椋鸟科栗翅椋鸟属的鸟类。大型、光泽黑亮的椋鸟，原生于非洲。以岩石悬崖、出露岩层和峡谷为栖息地，主要分布在萨赫勒地带，自毛里塔尼亚至赤道几内亚直至苏丹西部。该鸟种的命名是为了纪念德国鸟类学家奥斯卡·鲁道夫·诺伊曼。","appearance":"成年诺氏栗翅椋鸟长约25厘米，具有楔形尾部，飞行时翅膀上的砖红色斑块尤为显眼。雄鸟全身呈光泽黑色，雌鸟头部为灰白色，带有深色条纹。幼鸟外观类似雄鸟，但光泽度较弱，眼睛颜色为棕色而非暗红色。","call":"其鸣叫声为特有的响亮流利的莺鸣般的接触叫声，伴有其他旋律性的口哨声和颤音。","habits":"诺氏栗翅椋鸟偏好栖息于岩石地貌，如悬崖峭壁和峡谷之中，主要活动于萨瓦纳地带。它们具有领域性，繁殖期间表现出攻击性，甚至会驱赶其他鸟类，包括猛禽。杂食性，食物来源广泛，包括果实（如无花果）和部分无脊椎动物。","breeding":"繁殖季节在马里的3月至9月，在象牙海岸和布基纳法索的6月至7月，在尼日利亚的4月至5月，在喀麦隆的2月至3月，在苏丹的7月至8月。巢穴通常为简单的草杯状，建于洞穴中的岩石壁架上，由双亲共同喂养雏鸟。","identification":"与栗翅椋鸟相似，但体型更壮实，喙部更厚重，尾巴更宽大。分布区域不同，有助于区分类别。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲中部和西部，具体包括毛里塔尼亚、赤道几内亚至苏丹西部的萨赫勒地带。","other":"在城市环境中筑巢的记录显示，诺氏栗翅椋鸟可能适应人类居住区。"},{"name":"斯氏狭尾椋鸟","english_name":"Stuhlmann's Starling","scientific_name":"Poeoptera stuhlmanni","overview":"斯氏狭尾椋鸟（英文名：Stuhlmann's Starling，学名：Poeoptera stuhlmanni），是雀形目椋鸟科狭尾椋鸟属的鸟类。通常长约19厘米，主要以种子、谷物、节肢动物和幼虫为食。分布于非洲中部，包括埃塞俄比亚西南部、南苏丹南部（伊马通山脉）、刚果民主共和国东部、乌干达西南部、卢旺达、布隆迪、肯尼亚西部以及坦桑尼亚西部。","appearance":"斯氏狭尾椋鸟体型较小，体态苗条，全身暗色。眼睛呈棕色，雌鸟在飞行时翅膀上显现出大块的栗色斑块。它们的羽毛颜色和图案有助于在森林环境中伪装。","call":"其鸣叫包括简单的哨音和尖锐、略带抱怨声的音符。","habits":"斯氏狭尾椋鸟常见于山地森林树冠层，通常以小群出现。它们经常在枯木和其他开放的栖息点上显眼地栖息。这种椋鸟的活动范围广泛，既能在树冠活动，也能在地面觅食。","breeding":"关于斯氏狭尾椋鸟的繁殖习性的具体信息较少，但一般而言，椋鸟会在繁殖季节筑巢，进行求偶、交配、产卵和孵化等行为。","identification":"与高山栗翅椋鸟相比，斯氏狭尾椋鸟体型更小，身姿更为修长，眼睛为棕色而非红色，且仅雌鸟具有红褐色的翼斑。","protection":"IUCN：LC（无危）","distribution":"斯氏狭尾椋鸟的分布区域包括埃塞俄比亚中部、肯尼亚西部、南苏丹南部、刚果民主共和国东北部、乌干达至坦桑尼亚西部。具体而言，分布于埃塞俄比亚西南部、南苏丹的伊马通山脉、刚果民主共和国东部、乌干达西南部、卢旺达、布隆迪、肯尼亚西部以及坦桑尼亚西部。"},{"name":"肯氏狭尾椋鸟","english_name":"Kenrick's Starling","scientific_name":"Poeoptera kenricki","overview":"肯氏狭尾椋鸟（英文名：Kenrick's Starling，学名：Poeoptera kenricki），是雀形目椋鸟科狭尾椋鸟属的鸟类。中等体型的椋鸟，以英国军官雷金纳德·沃特金·爱德华-肯里克的名字命名，由乔治·埃内斯特·谢利于1894年首次描述。肯氏狭尾椋鸟在非洲的肯尼亚和坦桑尼亚的山区被发现。","appearance":"肯氏狭尾椋鸟是一种中等体型的鸟，雄鸟体重约为50克，雌鸟体重约38克。雄鸟呈现出光泽的黑色，而雌鸟则是灰烬色，其最显著的特征是雌鸟在飞行时可见的栗色初级飞羽。两性之间存在明显的颜色差异。","call":"肯氏狭尾椋鸟最常见的叫声是一个简单的‘tweep’声，同时也会发出低沉的嘁嘁喳喳声。","habits":"这种鸟生活在山地森林的树冠层，通常在中等海拔，倾向于小群活动，常见于果实丰富的树木周围。它们明显地栖息在枯木桩和其他开阔的栖息处。它们是洞穴筑巢者，已知会在啄木鸟和拟啄木鸟留下的旧洞中筑巢。","breeding":"关于肯氏狭尾椋鸟的繁殖行为了解不多，仅知双亲共同喂养雏鸟。它们偏好在枯树或枯枝中的洞穴中筑巢。","identification":"与斯氏狭尾椋鸟相比，肯氏狭尾椋鸟较小，身形更纤细，眼睛呈褐色而非红色，且只有雌鸟具有红色翼斑。此外，它们通过分布范围进行区分。","protection":"IUCN：LC（无危）","distribution":"肯氏狭尾椋鸟分布在肯尼亚和坦桑尼亚的山区，具体包括肯尼亚的Mount Kenya周边，坦桑尼亚的Usambara和Uluguru山脉，以及Mount Kilimanjaro和Mount Meru。最近也有记录显示在马拉维有超过150只的群体。","other":"历史上，一些权威曾认为肯氏狭尾椋鸟与斯氏狭尾椋鸟是同一种，或者将其视为单一亚种。目前承认两种亚种：P. k. bensoni和P. k. kenricki，前者体型较大，喙部较重，胸部颜色变化更为明显。"},{"name":"狭尾椋鸟","english_name":"Narrow-tailed Starling","scientific_name":"Poeoptera lugubris","overview":"狭尾椋鸟（英文名：Narrow-tailed Starling，学名：Poeoptera lugubris），是雀形目椋鸟科狭尾椋鸟属的鸟类。最显著的特征为锐利的目光和狭长的尾巴。分布于西非至中非的低地森林，包括塞拉利昂至刚果民主共和国东部和安哥拉北部。","appearance":"雄鸟全身呈深蓝色光泽，而雌鸟则为较暗淡的灰色，两性均具有鲜明的黄色眼睛。雄鸟的尾巴细长且尖锐，雌鸟的尾巴相对较短。飞行时可见翅膀上的栗色斑块。","call":"叫声包括短暂的‘tuwee！’和上升的‘dree！’，当由一群鸟发出时，可形成悦耳的旋律。","habits":"栖息于低地森林的树冠层，也会利用次生林和林间空地。它们以水果为主食，偶尔食用昆虫或种子。","breeding":"通常以10到30只以上的群体活动，有时会与其他食果鸟类混群。筑巢于高大的枯木洞穴中，这些洞穴最初由群居的凿木鸟挖掘，有时与凿木鸟的巢穴相邻近。卵呈淡蓝灰色，带有褐色斑点。","identification":"雄鸟与雌鸟在颜色上有所区别，雄鸟全身光泽紫黑色，雌鸟全身灰黑色，两者均具有明亮的黄色眼睛。雄鸟的尾巴长而尖，雌鸟的尾巴较短。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的西至中非，从塞拉利昂和利比里亚东部至乌干达西部，刚果民主共和国东部，中部和安哥拉北部。"},{"name":"黄腹紫椋鸟","english_name":"Sharpe's Starling","scientific_name":"Pholia sharpii","overview":"黄腹紫椋鸟（英文名：Sharpe's Starling，学名：Pholia sharpii），是雀形目椋鸟科 Pholia 属的唯一物种。小型椋鸟，以英国动物学家Richard Bowdler Sharpe的名字命名，以纪念他对鸟类学的贡献。黄腹紫椋鸟以其独特的外观和分布区域著称，主要分布在非洲的埃塞俄比亚、刚果民主共和国东部至坦桑尼亚一带。","appearance":"黄腹紫椋鸟是一种小型椋鸟，身长约18厘米，体重介于40至56克之间。其背部呈蓝黑色，光泽感强；喉部白色，腹部呈现温暖的淡黄色。头部、颈部和上体包括翅膀和尾巴均为亮丽的蓝黑色，胸部奶油色并带有淡黄色调，翼弯处有两块小的蓝黑色斑点，似部分胸带。下腹部、两侧和大腿及尾下覆羽为淡黄色。虹膜黄色，喙和腿黑色。雌雄同色，幼鸟的上体为哑光灰色，翅膀和尾巴有光泽，下体奶油色，大腿和尾下覆羽有淡黄色晕染，虹膜深棕色，喙基部淡黄色。","call":"黄腹紫椋鸟的叫声是一声尖锐的'sveet'，其歌声为一系列高音清脆的哨声，音调高低起伏，混合刮擦和喋喋不休的音符，容易被忽视，与灰背织雀的歌声相似。联系叫声为柔和的哨声，飞行叫声为高音的'chink'或'spink'。","habits":"黄腹紫椋鸟主要生活在山地森林中，常见于树冠层，通常成对或小群体活动，喜欢在枯木桩和其他开放的栖息处显眼地停留。它们主要以果实为食，偶尔也会捕食昆虫。已知食用的果实包括Sapium、Olea、Bridelia、Eugenia capensis、Ocotea usambarensis、Urea hypselodendron、Rapanea pulchra、Ilex mitis、Macaranga neomildbreadiana和Polyscias fulva等。它们在觅食时会与Poeoptera femoralis、、和以及bulbuls（Pycnonotidae科）共同活动。","breeding":"黄腹紫椋鸟的繁殖季节在苏丹和埃塞俄比亚为2月至4月，在肯尼亚西部为4月至6月，在坦桑尼亚为10月至12月。在刚果民主共和国，基于标本的繁殖状态，繁殖可能发生在3月至4月。巢穴位于树洞中，高度可达15米，已知的一个巢中有3枚卵。关于繁殖的其他信息尚不清楚。","identification":"黄腹紫椋鸟与类似椋鸟的区别在于其白色的喉部和淡黄色的腹部。在光线良好的条件下，其蓝黑色的背部更为明显，但在一般光照下看起来通常是黑色。它的眼睛颜色较浅，总是很突出。","protection":"IUCN：LC（无危）","distribution":"黄腹紫椋鸟的分布区域包括非洲东南部的南苏丹东南部、埃塞俄比亚中南部及西南部、刚果民主共和国东部、乌干达西部、卢旺达和布隆迪的部分地区、埃尔贡山（乌干达-肯尼亚边境）、肯尼亚北部、中部和南部，以及坦桑尼亚的北部、西部和西南部。"},{"name":"艾氏紫椋鸟","english_name":"Abbott's Starling","scientific_name":"Arizelopsar femoralis","overview":"艾氏紫椋鸟（英文名：Abbott's Starling，学名：Arizelopsar femoralis），是雀形目椋鸟科 Arizelopsar 属的鸟类。小型而独特的椋鸟，拥有一个狭窄的分布范围，仅见于肯尼亚和坦桑尼亚的高海拔森林。雄鸟背部和胸部呈蓝黑色，腹部白色；雌鸟背部和胸部棕色，腹部有棕色条纹。两性均具有黄色的眼睛。","appearance":"成年艾氏紫椋鸟长约17厘米，头部、整个上体、下喉至胸部为蓝黑色，略带光泽；翅膀和尾巴呈现深蓝色；腹部、两侧和下尾覆羽为奶油白色；虹膜接近白色；喙和腿为黑色。雌雄相似，文献中基于亚成年雌鸟的错误描述需注意。幼鸟上方暗灰色，喉部和胸部带有黄色洗色，喉咙、胸部和腹部有深色的羽轴斑纹，虹膜深褐色。","call":"叫声包括尖锐的“sveet”声，其鸣唱是一串快速、高音的叮咚声。","habits":"栖息于蒙特内森林，偏好树冠层较高的森林，高度在1800至2600米之间，有时可达2800米。常以小群或成对出现，喜在枯木和其他开阔处显眼地停歇。它们是居民鸟，但在特定树木结果时会局部移动，导致数量波动和周期性从某些区域消失。主要以水果和昆虫为食，记录中包括Cornus volkensii的果实。","breeding":"繁殖记录显示在肯尼亚的10月和11月，以及坦桑尼亚的2月、3月和10月。巢筑于树洞中，包括旧啄木鸟的洞穴；已记录到两窝每窝两个幼鸟的情况；幼鸟由双亲喂食昆虫。无其他繁殖信息。","identification":"与黄腹紫椋鸟相似，但后者胸部较暗。通过蓝黑色的上体和白色的腹部以及黄色的眼睛可以区分艾氏紫椋鸟。","protection":"IUCN：EN（濒危）。在小范围内罕见，有证据显示在曾经常见的地点数量下降。持续的森林损失和退化是主要威胁。","distribution":"分布于肯尼亚（裂谷以东的南部）和坦桑尼亚东北部的高地森林。","other":"纪念威廉·路易斯·艾伯特（William Louis Abbott，1860-1936），一位研究了印澳地区野生动物的美国自然学家和采集者。"},{"name":"白领椋鸟","english_name":"White-collared Starling","scientific_name":"Grafisia torquata","overview":"白领椋鸟（英文名：White-collared Starling，学名：Grafisia torquata），是雀形目椋鸟科白领椋鸟属的鸟类。独特而美丽的椋鸟。本属唯一鸟种。分布于非洲的喀麦隆、中非共和国北部和刚果民主共和国北部。","appearance":"成年雄鸟全身呈现蓝黑色光泽，胸部有一显著的白色环状斑块，眼睛橙黄色，喙和腿黑色。雌鸟灰暗，翅膀和尾巴黑灰色，头部至臀部的羽毛尖端呈蓝黑色，眼虹膜及裸露部位颜色与雄鸟相似。幼鸟外观似雌鸟，但腹部羽毛偏棕色，虹膜深褐色。","call":"发出连续的啾啾声和三个短促的哨音。","habits":"常见于非洲的开阔林地，偏好高树顶栖息，但也有记录显示其出现在喀麦隆的山地草原。以昆虫、浆果、野无花果及musanga和macaranga assass树的果实为食。通常成对或小群活动，偶尔记录到百鸟以上的大群。","breeding":"繁殖活动在3月被观察到，雄鸟此时有大睾丸，结合5月至7月间出现的幼鸟，表明繁殖期可能在上半年。雄鸟会从显眼的栖木上做短距离圆周飞行，可能作为求偶展示。","identification":"雄鸟的白颈环和橙黄色眼睛是其最明显的特征，雌鸟可通过灰暗的羽毛、无光泽感、短尾和橙黄色眼睛辨别。","protection":"IUCN：LC（无危）","distribution":"分布于喀麦隆、中非共和国北部和刚果民主共和国北部。","other":"由Anton Reichenow首次描述并命名为Spreo torquatus，后由James Chapin独立发现并命名为Stilbopsar leucothorax，最终由George Latimer Bates归入现属Grafisia。"},{"name":"鹊椋鸟","english_name":"Magpie Starling","scientific_name":"Speculipastor bicolor","overview":"鹊椋鸟（英文名：Magpie Starling，学名：Speculipastor bicolor），是雀形目椋鸟科鹊椋鸟属的鸟类。广泛分布于东非的干燥地带，包括埃塞俄比亚东北部和索马里北部至乌干达北部，肯尼亚和坦桑尼亚东北部。以其鲜明的黑白配色和独特的鸣声而闻名。","appearance":"鹊椋鸟长约16-19厘米，体重约66-69克。雄鸟上半身、头部和上胸部呈蓝黑色光泽，腹部、两翼下方、大腿及尾羽下方白色；翅膀蓝黑，一级飞羽的白色基部在收拢时形成明显的白条纹，飞行时更为突出。雌鸟的羽毛模式与雄鸟相似，但色调较暗淡，头部、喉咙和上胸部灰色，蓝黑色羽毛仅限于胸前的一条狭窄带状。幼鸟缺乏成鸟的蓝黑色，上半身、下巴、喉咙和胸部灰色，翅膀和尾巴灰棕色，眼睛和喙腿棕色，随年龄增长眼睛变为橙红色。","call":"鸣唱柔和，夹杂着较为尖锐的音符；被囚禁的雄鸟能持续长时间歌唱。飞行时发出尖锐的哨声，警报声为尖厉的‘ti-chuk chuk-chuk’。","habits":"鹊椋鸟栖息于东非的干燥灌木丛和荆棘灌木丛，常以群体形式游荡。它们是群居性鸟类，活动范围不定，喜好在北部和东部肯尼亚的干燥地带活动，同时也出现在埃塞俄比亚、索马里、南苏丹、坦桑尼亚和乌干达。","breeding":"关于鹊椋鸟的繁殖习性，现有资料较少。通常它们会在适宜的季节进行繁殖，营巢、产卵、孵化和育雏等行为在星椋鸟科中相对典型。","identification":"与其他星椋鸟科物种相比，鹊椋鸟的黑白相间的羽毛和橙红色的眼睛是其显著的辨识特征。雌雄之间可通过羽毛色泽的差异来区分。","protection":"IUCN状态未知。","distribution":"鹊椋鸟分布于非洲东北部，具体包括埃塞俄比亚东北部和索马里北部至乌干达北部，以及肯尼亚和坦桑尼亚东北部。"},{"name":"白翅噪椋鸟","english_name":"Babbling Starling","scientific_name":"Neocichla gutturalis","overview":"白翅噪椋鸟（英文名：Babbling Starling，学名：Neocichla gutturalis），是雀形目椋鸟科白翅噪椋鸟属的鸟类。独特的椋鸟科鸟类，属于白翅噪椋鸟属，仅分布于非洲中部的安哥拉、马拉维、坦桑尼亚和赞比亚等国的特定区域。这种鸟以其灰色头部、淡色眼睛、黑色胸饰和翼部的白色斑块而著称。","appearance":"体长约17厘米，体重介于64至72克之间。成鸟的头部，包括下巴和喉咙，呈灰色，眼上区颜色较深；肩部和背部为棕色，边缘有浅黄色羽缘，臀部灰褐色；翅膀棕色，主飞羽有光泽，次级飞羽的白色边缘形成折叠翼时显眼的条带（飞行时为清晰的翼斑）；尾巴深棕色，带有光泽，最外侧两对尾羽尖端白色；胸部中央有一小块黑色楔形标记；其余腹部部分为浅黄色，向腹部中心渐变为白色；虹膜黄色；喙黑色；腿黄色至黄褐色。雄雌外观相似。幼鸟的冠羽和肩部为深棕色，喉咙和下体有暗棕色泪滴状斑点在浅色背景上，虹膜灰色，喙黄色，顶端深色，腿淡棕色。亚种emangusta/em与指名亚种的主要区别在于外侧尾羽的白色边缘更窄，上体颜色更浅。","call":"常见鸣声为一系列粗糙的责骂叫声。","habits":"白翅噪椋鸟通常生活在开放的miombo阔叶林地带，较为罕见。它们常以小群体的形式出现。","identification":"与褶领椋鸟最为相似，但通过淡色的眼睛和翼部的白色斑块可以轻松区分。","protection":"IUCN：LC（无危）","distribution":"非洲中部，具体包括安哥拉、马拉维、坦桑尼亚和赞比亚。"},{"name":"纹胁旋椋鸟","english_name":"Stripe-headed Rhabdornis","scientific_name":"Rhabdornis mystacalis","overview":"纹胁旋椋鸟（英文名：Stripe-headed Rhabdornis，学名：Rhabdornis mystacalis），是雀形目椋鸟科纹旋木雀属的特有种鸟类，分布于菲律宾（除巴拉望岛群、民都洛和苏禄群岛）。具有白色的喉部和腹部，棕色的翅膀和尾巴，黑色的面罩，深色的冠羽上细密地带有白色条纹，侧面则有宽阔的白色条纹。","appearance":"纹胁旋椋鸟体长15.1至17.5厘米，体重22.4至31.5克。雄鸟指名亚种的冠羽和颈背为深褐色至黑色，羽心白色形成鲜明的白色条纹；背部暗褐色，向臀部渐变为红色，肩羽有明显的白色轴纹，从颈后的条纹延续至背部下方逐渐不明显；上翼和尾巴为暗褐色；面部面具从眼窝延伸至颈背，颜色为暗褐至黑色，被一条狭窄的白色眉线包围；喉咙和胸部中心及腹部纯白色，侧胸、侧腹和下尾覆羽有大胆的白色中心，边缘为深褐色和黑色，形成宽大的条纹；虹膜深褐色；喙黑色或暗角质色；腿为暗角质色。雌鸟与雄鸟的区别在于冠羽和面部面具颜色较浅。幼鸟与成鸟相似，但上方更偏棕色，包括面具，头部和肩羽的条纹不那么明显，下体为淡黄白色，侧腹的条纹对比度较低。","call":"觅食和栖息时发出一系列'zeet'音符的叫声。还记录到一种刺耳的高音调'tsee tsee wick-tsee'声，起始音几乎听不见，随后是最后一个短语中的爆炸性'wick'音节。","habits":"栖息于原始森林至森林边缘和空地，海拔从海平面至1000米，偶尔更高。饮食多样，包括昆虫（如毛虫）、果实和种子。以多达20只或更多的群体觅食，快速穿过树冠和中层林，从树皮下和树叶下搜寻昆虫。也加入混合物种的觅食群体，尤其与丽色山雀一同出现。通过短暂悬停在树枝下摘取外枝的种子和果实。","identification":"与同属的其他物种类似，但在海拔较低处发现，具有深色并带有白色条纹的冠羽，而非灰色的冠羽。","distribution":"分布于菲律宾，除巴拉望岛群、民都洛和苏禄群岛之外。"},{"name":"纹胸旋椋鸟","english_name":"Stripe-breasted Rhabdornis","scientific_name":"Rhabdornis inornatus","overview":"纹胸旋椋鸟（英文名：Stripe-breasted Rhabdornis，学名：Rhabdornis inornatus），是雀形目椋鸟科纹旋木雀属的菲律宾南部和中部特有种。曾与米岛旋木雀和Luzon岛的长嘴旋椋鸟被视为同一物种的不同亚种，现普遍认为它们是独立的物种。","appearance":"中等体型，喉部及腹部白色，上体棕色，翼及尾色更深，具黑色面罩，灰冠，侧身宽白条纹。雄鸟头顶褐色带微暗边缘，颈背棕色带显著白边，形成装饰性项圈；雌鸟较雄鸟色浅，包括面罩。幼鸟上体比成鸟更棕，下体重条纹，泛黄。不同亚种间差异主要在于项圈的存在与否及小翼羽上的白点。","call":"发出尖锐的‘tzit’声，常连续快速重复。","habits":"栖息于山脚和低海拔山林，善于在死枝上停歇。以昆虫、种子、果实为主食，偶尔食用小型蛙类。通常在森林中层至顶层活动，很少接近地面。成小群活动，有时加入混种鸟群，食物集中时会聚集上百只。通过跳跃和跳跃于枝叶间觅食昆虫。","breeding":"筑巢于树洞中，观察到的巢位于离地约15米的半枯树洞中，由成鸟携带小枝、树叶和碎皮入巢。繁殖季节为4月初至6月，具体繁殖细节尚缺乏资料。","identification":"与纹胁旋椋鸟相似，但常见于更高海拔，喙较短厚，冠灰色而非白条纹。项圈和小翼羽上的白点是亚种间辨识要点。","protection":"IUCN：LC（无危）。受地域限制，分布于Mindanao和Eastern Visayas。相对罕见，全球数量不明但呈下降趋势，因栖息地丧失和碎片化。需定期监测其种群。","distribution":"分布于菲律宾中东部的东Visayas群岛和南部的Mindanao岛。"},{"name":"长嘴旋椋鸟","english_name":"Grand Rhabdornis","scientific_name":"Rhabdornis grandis","overview":"长嘴旋椋鸟（英文名：Grand Rhabdornis，学名：Rhabdornis grandis），是雀形目椋鸟科纹旋木雀属的鸟类。亦被称为长嘴旋木雀或长嘴旋椋，原生于菲律宾吕宋岛的山林中。以独特的长喙和鲜明的羽色而著称，主要栖息在中高海拔的森林地带。","appearance":"长嘴旋椋鸟体长介于16.3至18厘米，体重约45至46克。雄鸟头部顶部呈深灰，羽毛尖端为深灰至黑色，颈后灰色逐渐过渡至背部的棕色，背部可见极淡的条纹。翼上覆羽有显著的白色条纹或斑点，边缘环绕着深棕色；主翼羽深棕色，次级飞羽红棕色；尾巴深棕色。面颊至颈背黑色，上方有一条白色眉线，下方隐约可见白色颌纹；颈部侧面有黑色斑点；喉咙浅灰色；上胸部位灰白相间，颈部两侧的黑色斑点延伸至胸侧；侧身和胁部羽毛灰白，边缘红棕色形成条纹，渐隐入胸侧；腹部污白色，尾下覆羽同侧身颜色。眼睛褐色，喙黑色或暗角质色，腿脚棕灰色。雌鸟羽毛与雄鸟相似，但体型略小。幼鸟羽毛描述未知，推测与成鸟类似。","call":"其鸣声包括尖锐的‘tsip！’叫声。","habits":"长嘴旋椋鸟栖息于中高海拔的原始和次生森林，包括被砍伐过的森林，但未见于高海拔的松树林（Pinus）。它们以昆虫、种子和果实为食，绿色种子和肉质果实是其胃中常见食物。通常单独或小群体活动，也会加入混合物种的鸟群。","breeding":"关于长嘴旋椋鸟的繁殖信息尚未详细记录。","identification":"与纹胁旋椋鸟相似，但长嘴旋椋鸟通常栖息在更高海拔，且头部顶部为灰色而非白色条纹。此外，通过其特有的长喙和特定的叫声进行辨识。","protection":"IUCN：LC（无危）；尽管如此，其种群数量仍因栖息地丧失和碎片化而下降。","distribution":"长嘴旋椋鸟分布于菲律宾北部吕宋岛的Cordillera山脉和Sierra Madre山脉。","other":"目前将其视为独立物种，但过去有时被当作纹胸旋椋鸟的亚种处理。"},{"name":"米岛旋木雀","english_name":"Visayan Rhabdornis","scientific_name":"Rhabdornis rabori","overview":"米岛旋木雀（英文名：Visayan Rhabdornis，学名：Rhabdornis rabori），是雀形目椋鸟科纹旋木雀属的鸟类。特有于菲律宾中部的班乃岛和内格罗斯岛，栖息于热带湿润山地森林，面临栖息地丧失的威胁。","appearance":"该鸟体长17至18.8厘米，雄鸟额头、冠部至颈背呈淡灰色，下颈有黑色斑点和模糊的白色羽轴条纹，具棕色面罩，从眼眶延伸至颈部两侧。背部温暖棕色，臀部偏赤褐色，翅膀和尾羽深棕色，翼尖小覆羽带白色条纹或斑点，尾羽更暗。下颚有白色颊纹，喉部淡棕色，腹部白色，从喉侧到尾下覆羽的羽毛边缘为红棕色，形成条纹外观。雌鸟与雄鸟相似，但整体颜色较浅。幼鸟比成鸟更偏棕色，下部有明显的条纹。","call":"其叫声被描述为高音的‘tzit’声，经常重复，有时快速连串发出。","habits":"米岛旋木雀栖息于海拔800至1700米的山地原始和次生林、林缘，偶尔出现在林间空地。它们常在森林树冠层的上层活动。","breeding":"关于繁殖的信息有限，繁殖季节可能在3月至6月之间。巢由树枝构成，安置于树洞中。具体细节可能与纹胸旋椋鸟相似。","identification":"与纹胁旋椋鸟相似，但通常栖息于更高海拔，喙较短且厚实，冠部灰色而非带有白色条纹的暗色。","protection":"IUCN：LC（无危）。该物种仅限于内格罗斯和班乃生态区，全球数量估计在2500至9999只成熟个体之间，因栖息地损失而持续下降。目前在内格罗斯岛的几个残存森林区域发现，如Canlaon山、Balinsasayao湖周围和Cuernos de Negros。","distribution":"分布于菲律宾中西部的班乃岛和内格罗斯岛的山地。","other":"曾被认为是纹胸旋椋鸟的一个亚种。"},{"name":"黄嘴牛椋鸟","english_name":"Yellow-billed Oxpecker","scientific_name":"Buphagus africanus","overview":"黄嘴牛椋鸟（英文名：Yellow-billed Oxpecker，学名：Buphagus africanus），是雀形目牛椋鸟科牛椋鸟属的雀形目鸟类。其显著特征为黄色基部带红色尖端的喙，以及淡色臀部。原生于撒哈拉以南非洲的草原，从塞内加尔东至苏丹。与红嘴牛椋鸟相比，虽分布区重叠，但通常占据主导地位。","appearance":"体长约20厘米，体重57至71克，头部至喉咙呈暗褐色到橄榄灰色，背部、翅膀和尾巴颜色相似，与淡色臀部形成鲜明对比。胸部至尾下覆羽呈浅棕色，眼睛红色，眼周有黄色环。喙侧扁，基部宽大，近尖端膨大，黄色，远端红色。腿色深棕至黑。雌雄同色。幼鸟初期具黄色喙和眼环，数周内转为深棕色，一年内达到成鸟色彩。","call":"飞行时发出独特的嘶嘶声裂响叫声。","habits":"栖息于草原和农田，依赖大型野生哺乳动物和家畜为食源，灵活地在宿主身上觅食，主要摄食蜱、螨和其他外寄生虫，偶尔吸食宿主血液。飞行能力强，直接而有力。","breeding":"繁殖期从6月至9月，一夫一妻制，每窝产卵2至3枚，白色至乳白色，有时带有红褐色斑点。孵化期至少13天，由父母双方和1至6个成年助手共同喂养幼鸟，巢期约25天。","identification":"与红嘴牛椋鸟的区别在于后者喙全红，眼周黄色，臀部与上体颜色相同。","protection":"IUCN：LC（无危）","distribution":"分布于非洲，广泛存在于从塞内加尔至苏丹的撒哈拉以南草原，以及东非、南部非洲等地。","other":"过去因猎杀野生动物和有毒化学物质控制家畜蜱虫而数量减少，但在多个保护区已显著恢复。"},{"name":"红嘴牛椋鸟","english_name":"Red-billed Oxpecker","scientific_name":"Buphagus erythrorynchus","overview":"红嘴牛椋鸟（英文名：Red-billed Oxpecker，学名：Buphagus erythrorynchus），是雀形目牛椋鸟科牛椋鸟属的鸟类，广泛分布于东非至南部非洲的广阔区域，以独特的红嘴和红眼为其显著特征。该物种在非洲大草原上与大型食草哺乳动物共生，以其清创护理工作和警报功能而闻名。","appearance":"红嘴牛椋鸟体型类似乌鸫，橄榄褐色，具有醒目的全红色喙和环绕红眼的黄色裸露皮肤。幼鸟的喙色暗淡，无鲜艳的嘴和眼色彩。成鸟两性相似，头部至喉部暗橄榄褐色，背部颜色较浅，翅膀和尾部深橄榄灰色，胸部至尾下覆羽呈较浅的棕色，大腿部深棕色。虹膜颜色从黄色到红色，眼周裸露皮肤黄色，喙侧扁而近中部略膨大，鲜红色，腿灰棕色至黑色。","call":"红嘴牛椋鸟在飞离大型哺乳动物时，会发出特有的“tsik-tsik”叫声。","habits":"栖息于大草原林地和农田，海拔高度可达3000米，依赖于大型野兽或家畜存在，几乎全天候附着在其身上。它们在这些宿主身上寻找并清除蜱虫、螨虫、虱子、蚂蟥和咬人蝇等外寄生虫，偶尔吸食宿主血液。红嘴牛椋鸟需树木栖息和繁殖，通常在树洞中筑巢。","breeding":"红嘴牛椋鸟随雨季繁殖，筑巢于树洞中，由毛发、干粪、草和根须构成，巢高1至15米。每窝产2至5枚蛋，平均3枚，蛋壳白色至乳白色，常有红褐色和紫灰色斑点。双亲共同孵化，孵化期12至13天，雏鸟喂养期27至30天，幼鸟21天后能自食，40天后成鸟不再喂养，但在某些情况下，助手鸟可能持续喂养至90天。","identification":"红嘴牛椋鸟与黄嘴牛椋鸟的区别在于后者有黄色的喙基和淡色臀部，且缺乏眼周裸露皮肤。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部至南部，从厄立特里亚、埃塞俄比亚和索马里南至纳米比亚东北部、博茨瓦纳和南非东北部，包括东非大裂谷的国家和地区。","other":"红嘴牛椋鸟对控制大型哺乳动物的外寄生虫有积极作用，但对家畜直接吸血的行为可能造成伤害。"},{"name":"红尾蚁鸫","english_name":"Red-tailed Ant Thrush","scientific_name":"Neocossyphus rufus","overview":"红尾蚁鸫（英文名：Red-tailed Ant Thrush，学名：Neocossyphus rufus），是雀形目鸫科红尾蚁鸫属的鸟类。特征为长尾、栗褐色体羽，尾部中央深色而两侧淡红。活跃于中南部非洲的湿润森林地带，常在地面附近行动，性格羞涩。会跟随蚂蚁群落移动。","appearance":"红尾蚁鸫体长约22至25厘米，体重介于53至80克之间。成鸟上体呈暗淡的栗褐，头部颜色较浅，尾部除中央一对羽毛较深外，其余鲜亮栗红。下体为肉桂色，喉部带灰绿橄榄色调。喙为棕黑色，腿脚颜色由肉色至淡棕色或紫灰色不等。雌雄外观相似，幼鸟色泽更暗且偏棕色。Gabunensis亚种比标准种更深，喉部和胸部带有明显灰调。","call":"其鸣唱多变且有时绵长，包含下降的单一哨音、两声哨音或一系列哨音和颤音的组合。叫声为短促的颤音‘brttt’。","habits":"偏好湿润森林环境，常见于地面或近地面，行为隐秘。会追随蚂蚁群落，利用蚂蚁驱赶的昆虫作为食物源。","identification":"与白尾蚁鸫相比，红尾蚁鸫尾部为红而非黑白相间。与栗色鵙鸫相比，姿态更水平，且活动于地面而非林中层。叫声和鸣唱具有显著差异。","protection":"IUCN状态未提及，需查阅最新资料。","distribution":"分布于非洲中部和东部，具体包括喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬、肯尼亚、索马里、坦桑尼亚和乌干达。其自然栖息地为亚热带或热带湿润低地森林。","other":"系统学历史与声音行为方面，红尾蚁鸫的鸣叫复杂多样，包括多种类型的哨音和颤音，且在不同亚种间存在差异。"},{"name":"白尾蚁鸫","english_name":"White-tailed Ant Thrush","scientific_name":"Neocossyphus poensis","overview":"白尾蚁鸫（英文名：White-tailed Ant Thrush，学名：Neocossyphus poensis），是雀形目鸫科红尾蚁鸫属的鸟类。广泛分布于非洲西部和中部的热带雨林地带。这暗色、单一色调、长尾的鸫类，以跟随蚂蚁群而闻名。","appearance":"白尾蚁鸫体长20至22厘米，体重43至60克。上身呈深褐色石板灰，尾羽外侧三根具有明显的白色尖端，翼部显露出橙红色斑块，尤其在飞行时更为明显。喉咙颜色较浅，略带灰色，下体为橙红色。喙呈黑色，腿脚为淡肉色。两性相似，幼鸟特征未详细描述。","call":"常见鸣声包括一段长而高亢的哨音和短促的‘brttt’颤音。其歌声有时在树上约10至15米的高度发出，丰富而类似Turdus属鸟类的声音，但较为低调，通常在蚂蚁群附近听到。","habits":"栖息于湿润森林地面或近地面的植被中，常随军蚁群活动，依赖蚂蚁群为其提供丰富的昆虫食物。食物主要包括小昆虫及其幼虫，如蚂蚁、白蚁、甲虫、蟑螂和蚱蜢，偶尔也会吃小青蛙和浆果。","identification":"与Finsch's Flycatcher-Thrush相比，白尾蚁鸫的上体颜色更深，臀部为暗色，翼斑更为突出，喙较大，腿较长，且在地面上活动时会摆动尾巴。与红尾蚁鸫的区别在于尾部为黑白相间而非红棕色。","protection":"IUCN：LC（无危）。在西非和东非普遍到局部常见，但在某些地区可能被低估。在加蓬、喀麦隆等地密度较高。","distribution":"分布于安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、加纳、几内亚、肯尼亚、利比里亚、尼日利亚、塞拉利昂、坦桑尼亚、多哥和乌干达。主要栖息于亚热带或热带湿润低地森林。"},{"name":"弗氏蚁鸫","english_name":"Fraser's Rufous Thrush","scientific_name":"Stizorhina fraseri","overview":"弗氏蚁鸫（英文名：Fraser's Rufous Thrush，学名：Stizorhina fraseri），是雀形目鸫科棕蚁鸫属的鸟类。亦被称为红褐色飞鸫，是蚁鸫中的一个独特物种。以霸鹟式的猎食方式和站立时明显的直立姿态而著称。分布于非洲东部和中部的湿润森林地带，包括尼日利亚、安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬、南苏丹、乌干达和赞比亚。","appearance":"体型中等，长约18至20厘米，体重27至44克。头部灰褐色，背部及肩部呈红褐色至下背部，臀部鲜亮的栗色。翅膀橄榄棕色，上部有红土色翼斑，下部有锈色斜杠。尾巴橄榄棕色，外侧尾羽红土色。下体从喉咙到腹部富丽的土黄色。喙黑色，基部下颚淡色；腿浅棕色。两性相似，幼鸟颜色较暗淡。亚种rubicunda比指名亚种略淡；vulpina的尾巴比其他亚种更浅。","call":"领土歌曲是一系列4至5个高音上升的哨声，'wiii-wiii-wiii-wiii'，在反唱时更快、更短的'wiit-wiit-wiit-wiit'，在直接冲突时更粗糙的颤音'swit-swit-swit-swit-swit'；求偶时低沉的短语，通常以响亮的颤音开始。叫声包括缓慢的3至4个轻微上升的哨声，'weeeee-ee-eee-eeeee'，作为伴侣间的联系，最多30秒内可达7至8个系列；起飞时短促的'siit'；还有在焦虑时虚弱的上升颤音'sweet'，更响亮的'weez weez weez'作为警报，以及当群起攻击时嘶哑的责骂'tswit-tswit-tswit'。","habits":"主要以大约1厘米长的昆虫为食，尤其是蚂蚁、白蚁、甲虫和苍蝇，偶尔也会吃小型蜗牛和千足虫。从栖木处进行空中狩猎，从树干、树叶、空中，偶尔从地面捕获猎物。常加入混合鸟群，特别是在旱季；会参加军蚁群，但并非一贯如此。","identification":"与红尾蚁鸫相似，但体型较小，站立更为直立，通常不在地面活动。可以通过其特有的飞行和站立姿势以及鸣叫来识别。","protection":"IUCN：LC（无危）","distribution":"分布在非洲东部最东端（尼日利亚）和广泛分布于非洲中部（安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬）以及非洲东部（南苏丹、乌干达、赞比亚）。自然栖息地为亚热带或热带湿润的低地森林。"},{"name":"芬氏蚁鸫","english_name":"Finsch's Rufous Thrush","scientific_name":"Stizorhina finschi","overview":"芬氏蚁鸫（英文名：Finsch's Rufous Thrush，学名：Stizorhina finschi），是雀形目鸫科棕蚁鸫属的鸟类。亦被称为芬氏飞鸫或芬氏锈色飞鸫，西非森林特有的、外观类似鵙的鸫科鸟类。其体色为暗褐色，尾部较长，尾端黑白相间。栖息于森林底层，偏好湿润环境，如溪流旁或沼泽地带，分布范围从塞拉利昂至尼日利亚南部。","appearance":"体长约18厘米，体重介于33至44克之间。头部呈灰褐色，上体为暗锈色，臀部颜色较亮。翅膀为褐色，翼上有不明显的红棕色条纹。尾羽深灰色，外侧有显著白色尖端。下体颜色较淡，喉部略带灰色。喙黑色，基部下方较浅；腿呈淡褐色。站立姿态挺立，尾巴常做剪刀状摆动。与非常相似的弗氏蚁鸫相比，芬氏蚁鸫颜色较为暗淡，翅膀图案不明显，尾巴更灰且外侧有白色尖端。雌雄相似，幼鸟特征未详述。","call":"鸣声为缓慢上升的一系列哀婉哨音，叫声为连续的‘kweee’音符组成的训斥般系列。","habits":"栖息于低海拔森林的密集区域，高度从海平面到约1500米。以昆虫为食，包括蚂蚁、白蚁、甲虫、蚱蜢、苍蝇、蝽象和蛾子。通过空中出击的方式从栖木捕食，偶尔从地面捕食。加入混合物种群，跟随行军蚁群。通常独居或成对出现，繁殖季节高度领地性，非繁殖季节可能加入混合物种群。","breeding":"繁殖信息有限，观察到在3月收集筑巢材料，在6月至12月处于繁殖状态，9月见到独立的幼鸟。","identification":"与弗氏蚁鸫的区别在于颜色较为暗淡，翅膀图案不明显，尾巴更灰且外侧有白色尖端。","protection":"IUCN：LC（无危）","distribution":"分布于西非，自塞拉利昂向东至尼日利亚西南部。在某些地区罕见，但在部分地区常见。","other":"有时被认为是弗雷泽氏锈色鸫的亚种，但在此被视为独立物种。"},{"name":"青背地鸫","english_name":"Slaty-backed Thrush","scientific_name":"Geokichla schistacea","overview":"青背地鸫（英文名：Slaty-backed Thrush，学名：Geokichla schistacea），是雀形目鸫科少斑地鸫属的独特鸟类。以黑色、白色和灰色的独特组合而引人注目，仅限于印度尼西亚摩鹿加群岛南部的塔宁巴尔群岛，具体在Larat和Yamdena两个岛屿上。","appearance":"青背地鸫拥有灰色的上部羽毛和黑色的头部，头部显眼地装饰着大胆的白色颊斑和长长的白色眉纹。它的喉咙和胸部呈黑色，腹部则是干净的白色，上腹部点缀着黑色的斑点。这种鸟的外观令人难忘，是其栖息地中的独特存在。","call":"青背地鸫的复杂歌声是一系列旋律优美的哨音乐章，大多在开始时上扬，其间穿插着快速的“chew-chew-chew”短语。","habits":"青背地鸫生活在森林环境中，在地面觅食，但常栖息于树冠下层的树枝上，尤其是在歌唱时。它在特定的地理区域内活动，体现了其生态位的特异性。","identification":"青背地鸫的黑白灰三色组合以及独特的鸣叫声使其在同类中易于辨识。","protection":"IUCN：NT（近危）","distribution":"青背地鸫的分布局限于华莱士区内的塔宁巴尔群岛，具体在印尼摩鹿加群岛南部的Larat和Yamdena两个岛屿上。"},{"name":"摩鹿加地鸫","english_name":"Buru Thrush","scientific_name":"Geokichla dumasi","appearance":"成年布鲁地鸫长约17厘米，上体呈丰富的赤褐色，眼圈不完整，颊部白色，翼黑带两段白色斑点，飞羽边缘锈褐色，尾羽深色带赤褐色边缘；面部至腹部中间黑色，向下渐变为黑色斑点覆盖于白色底色之上，下腹至尾下覆羽白色，略带赭黄色调；喙黑色，腿色介于灰肉色到黄褐色。性别间相似，幼鸟则具淡色羽轴纹，上部赤褐色带斑点，下体淡黄色，包括模糊的须纹和喉部，胸侧及胁部有不规则的黑色、淡色和赤褐色斑驳。","call":"其鸣唱未有详细记录，但属于典型的鸫类悦耳歌曲，包含短哨音和沙哑音符。发出尖锐延长的“seeeeeeeet”叫声。","habits":"栖息于海拔700至1500米的原生山地雨林，常单独或成对在地面觅食，偶尔在低矮的灌木层停留。在布鲁岛为留鸟。","breeding":"繁殖记录显示，二月初开始产卵，四月和五月见到幼鸟。另有十一月观察到成鸟坐巢的记录。卵呈极淡的蓝色，带有小红褐色斑点。","identification":"布鲁地鸫在其分布区内无相似物种，其独特的外观和叫声使其易于识别。","protection":"IUCN：NT（近危）","distribution":"分布局限于印尼布鲁岛的山区，位于摩鹿加群岛西中部。","other":"传统上，将塞拉姆地鸫视为其亚种，此时的通用名是布鲁地鸫。"},{"name":"斯岛地鸫","english_name":"Seram Thrush","scientific_name":"Geokichla joiceyi","appearance":"这种鸟长约17厘米，头顶呈红褐色，逐渐变为淡橄榄棕色至背部，再到灰橄榄棕色直至尾巴。翅膀较暗，带有断续的白色翼纹，有时仅剩单个白点；眼周、眼圈和耳羽黑色；腹部黑色，上腹有白色鳞状斑点，向下渐变为灰白色下腹和尾下覆羽，两胁灰黑色；喙黑色，腿色介于灰肉色到黄棕色之间。","call":"其鸣叫包括高音的‘tew-teweeeeeee’，首音短促，第二音迅速上升；同时发出短而尖锐的下降‘tsew’声。另有非常细弱的‘tseep’声，能在50米外听到；被惊飞时的叫声为高音的‘tsree-tsree’。","habits":"生活在斯兰岛的低山区域，栖息于海拔800至1280米的山地雨林，常见于森林地面。通常单独或成对出现于丘陵和平地森林地带。为留鸟，不迁徙。","breeding":"关于繁殖行为的信息尚缺。","identification":"塞兰地鸫在斯兰岛上无类似物种，其独特的红褐色冠羽、黑色腹部和白色腹侧斑点使其易于识别。","protection":"IUCN：NT（近危）","distribution":"分布于斯兰岛（印尼摩鹿加群岛中东部）的山区，记录显示其出现在Manusela国家公园的较高海拔。","other":"在1996年8月的五天内记录了七只不同个体，表明在较低的山地森林中可能有一个相对健康的种群。"},{"name":"栗顶地鸫","english_name":"Chestnut-capped Thrush","scientific_name":"Geokichla interpres","overview":"栗顶地鸫（英文名：Chestnut-capped Thrush，学名：Geokichla interpres），是雀形目鸫科少斑地鸫属的鸟类。黑色的背部与白色腹部形成鲜明对比。分布于东南亚的森林与林地，包括泰国南部、苏禄群岛、婆罗洲、爪哇岛以及小巽他群岛的部分岛屿。","appearance":"体长16-18厘米，头部呈深栗色，逐渐过渡到蓝黑色的背部，两翼上有宽阔的白色翼带。眼周有一圈不完整的白环，脸颊处有明显的白色斑点，腹部白色并带有黑色斑点。喙部黑色，腿脚颜色从黄色至粉黄色不等。雌雄外观相似，幼鸟头顶的栗色延伸至背部，胸部锈褐色，腹部可见不规则的大黑斑。","call":"鸣唱由一系列间隔开的清脆哨音、口哨声和颤音组成，富有旋律感，但音量不大。叫声包括尖锐的‘tac’声、细高下降的‘tsi-i-i-i’声以及响亮的‘turrrr-turrrr’声。","habits":"栖息于森林地带，既在地面觅食，也会上树。主要以无脊椎动物为食，包括蚯蚓、昆虫和蜗牛，偶尔食用果实。有时会与其他鸟类一起在结果的树木上觅食。","breeding":"具体繁殖细节尚不清楚，但观察到雄鸟会向潜在配偶传递蚯蚓。幼鸟吐出过一厘米长的黑色种子。","identification":"与胸背地鸫相比，体型较小，胸背地鸫具有黑色的头顶和红褐色的背部。Enggano地鸫背部橄榄赭色，眼周和耳羽上的白色较少。","protection":"IUCN：EN（濒危）。在泰国和菲律宾罕见，马来西亚半岛稀少且分布局限。苏门答腊仅有两次记录。在小巽他群岛，曾因非法贸易导致数量急剧下降。","distribution":"分布于泰国南部至苏禄群岛（菲律宾南部）、婆罗洲、爪哇岛以及小巽他群岛的西部至中部，包括龙目岛、松巴哇岛和弗洛勒斯岛。","other":"在动物园中极为罕见，仅在欧洲私人鸟舍中有少量个体。"},{"name":"恩岛地鸫","english_name":"Enggano Thrush","scientific_name":"Geokichla leucolaema","overview":"恩岛地鸫（英文名：Enggano Thrush，学名：Geokichla leucolaema），是雀形目鸫科少斑地鸫属的鸟类。小型而精致的鸟类，仅见于印度尼西亚苏门答腊岛西南部外海的恩加诺岛。其栖息于本地森林及林缘地带，偏好有良好遮荫的地面环境。","appearance":"该物种具有暗橙色的冠羽和颈背，黑色胸部，翅膀上带有斑点，腹部为白色。成鸟与幼鸟在羽毛色彩上有细微差异，但具体细节需进一步观察确认。","call":"恩岛地鸫的鸣唱包含一系列高音哨声、颤音及嘁嘁喳喳的音符，其叫声独特，类似于许多其他Geokichla属鸫的高而细的‘tseee’叫声。","habits":"恩岛地鸫主要在有浓密树荫的地面上觅食，其栖息地为雨林中的原生森林和林缘地带。关于其具体的迁徙、飞行特点、活动范围和食物来源的信息尚待研究。","breeding":"关于恩岛地鸫的繁殖习性的详细信息目前尚未明确，包括繁殖期、求偶、筑巢、孵化和育雏的过程。","identification":"恩岛地鸫曾被认为是栗顶地鸫的一个亚种，但现已确认为独立物种。其与栗顶地鸫的区别在于分布区域和一些形态特征。","protection":"IUCN：NT（近危）","distribution":"恩岛地鸫的分布局限于印尼恩加诺岛，位于苏门答腊岛西南部外海。","other":"恩岛地鸫的生态行为及生物学特性尚有许多未知领域，亟待进一步的研究探索。"},{"name":"红背地鸫","english_name":"Red-backed Thrush","scientific_name":"Geokichla erythronota","overview":"红背地鸫（英文名：Red-backed Thrush，学名：Geokichla erythronota），是雀形目鸫科少斑地鸫属的鸟类。具有醒目的栗色背部和白色面部斑块，黑色翅膀带有白色条纹，下部有大胆的黑白相间标记。分布于印尼苏拉威西岛及附近的Buton和Kabaena岛，因森林破坏而变得罕见。","appearance":"红背地鸫长约20厘米，体重52-61克。成鸟头部至臀部为锈红色或锈栗色，翅膀黑色，有两条宽阔的白色翼带，飞行羽边缘白色，尾巴黑色，外侧羽毛尖端白色；眼上纹黑色；面颊和眉纹白色，眼周黑色，延伸至下巴至中胸处形成黑色条纹；胸部有宽白带，腹部白色至两胁，带有宽黑半斑点，看起来像条状；尾下覆羽白色；喙淡蓝绿色；腿肉色。雌雄相似。幼鸟肩羽有淡褐色条纹，脸部和喉咙更黄褐色，下体有锈黄褐色晕染。","call":"哀怨的鸣声为一系列高音哨音，如'deee-der-doo'或'deee-der'。叫声包括'chak'音符和高音'peep'声。","habits":"栖息于热带低地和中海拔常绿阔叶林的深荫处，主要为原始森林，海拔低于1000米。在Kabaena岛上，栖息于未受干扰的闭冠次生林、沿溪流高度受扰的次生林、峡谷中的次生植被、腰果种植园、竹林和广阔灌木丛，海拔380-600米。主要以昆虫为食，包括膜翅目（主要是蚂蚁）、异翅目、鞘翅目和鳞翅目昆虫。高度陆栖，通常在地面0.5米以下活动，觅食时快速移动。在Kabaena岛，曾观察到跟随苏拉威西噪鹛群。","identification":"在有限的分布范围内，其独特的外观使它易于识别。幼鸟与成鸟相比，肩部有淡黄色条纹，脸部和喉咙颜色较淡，下体有锈黄色晕染。Kabaena岛的亚种在头顶至背部上部为黑色，这一特征至少在一次观察中出现在指名亚种中。","protection":"IUCN：NT（近危）","distribution":"分布于华莱士区以东、巴布亚新几内亚以西的区域，具体包括印尼的苏拉威西岛及附近岛屿Buton和Kabaena。"},{"name":"红黑地鸫","english_name":"Red-and-black Thrush","scientific_name":"Geokichla mendeni","overview":"红黑地鸫（英文名：Red-and-black Thrush，学名：Geokichla mendeni），是雀形目鸫科少斑地鸫属的鸟类。特有于印尼珀伦岛（Peleng）和塔利阿布岛（Taliabu）森林中的鸟类，因栖息地丧失而受到威胁。","appearance":"该鸟长约20厘米，上体自额至背部呈赤褐色，尾下覆羽亦为赤褐色（至少在塔利阿布岛的个体）。其余部位为黑色，仅耳羽处有一显著白色椭圆斑点。喙呈板岩色，腿为淡肉粉色。性别差异不明显，幼鸟特征尚未描述。","call":"发出典型的复杂鸣唱，具笛音和哨声，结合粗糙的短语，规律重复。叫声微弱，几乎听不见，为高音薄细的“seeep”声。","habits":"红黑地鸫在低地森林中单独或成对活动，常于地面觅食。其活动范围受限于珀伦岛和塔利阿布岛。","breeding":"关于繁殖信息，目前资料匮乏。","identification":"在珀伦岛和塔利阿布岛上，红黑地鸫的外观独特，易于识别。与其他地鸫相比，其独特的红黑配色和白耳斑是明显的辨识特征。","protection":"IUCN：NT（近危）。由于分布范围极小且数量稀少，应考虑将其至少列为Vulnerable（易危）。","distribution":"分布于印尼的珀伦岛（Peleng，位于邦盖群岛）和塔利阿布岛（Taliabu，位于苏拉群岛）。","other":"历史上，红黑地鸫曾被认为是红背地鸫的亚种。"},{"name":"栗背地鸫","english_name":"Chestnut-backed Thrush","scientific_name":"Geokichla dohertyi","overview":"栗背地鸫（英文名：Chestnut-backed Thrush，学名：Geokichla dohertyi），是雀形目鸫科少斑地鸫属的鸟类。一种引人注目的地鸫，具有黑白色头部图案，栗色背部，醒目的白色翼纹，黑色胸部，侧腹有大型黑色斑点，腹部白色。幼鸟上部有栗色斑点，下部为带有黑色斑点的淡黄色，翼上有淡黄色条纹。该物种分布于印度尼西亚的低地和山麓森林，包括龙目岛至帝汶岛的小巽他群岛，属于华莱士区的特有种。","appearance":"成鸟长16至18厘米，头呈黑白色，背部栗色，翼上有显著的白色标记，胸部黑色，侧腹有大块黑色斑点，腹部白色。幼鸟头部和背部有栗色条纹，面部和喉咙淡黄色，胸部有黑色斑点在锈色背景上，下体淡白色。两性相似。","call":"鸣唱由一系列富于节奏感的音节组成，间隔约1秒，每个音节包含3至7个清澈悦耳的哨声，伴有更复杂的交织旋律。叫声包括粗糙的音符、单一的平缓哨声和非常高的尖锐哨声。","habits":"栖息于封闭冠层的半常绿低山和高山森林，偶尔出现在退化生境，如村庄灌木丛。关键生境因素包括高树密度、高树、密集的冠层覆盖和高海拔，偏好高海拔原始森林。在地面觅食，也可见于树木中，最常见于中间层次。偶尔成群活动，最多五只，在结果的树上觅食，有时与栗顶地鸫一起。","identification":"与红背地鸫相似，但头顶全黑色，脸部更多白色；下体不同，胸部黑色斑点宽泛且不规则地涂抹在白色腹部中央，沿胸部侧面和侧腹有暗锈色；喙黑色；腿白色或肉粉色。幼鸟头顶和背部有栗色条纹，面部和喉咙淡黄白色，胸部黑色斑点在锈色背景下，下体淡白色。","protection":"IUCN：NT（近危）","distribution":"分布于龙目岛至帝汶岛（西部至小巽他群岛东部）。具体地点包括Lombok、Sumbawa、Flores、Sumba、Alor和Timor。","other":"自2011年10月以来，包括柏林动物园、Birdworld、Bristol Zoo在内的多个欧洲机构成功繁殖了这一物种，目前有91只栗背地鸫在这些机构中。"},{"name":"杂色地鸫","english_name":"Pied Thrush","scientific_name":"Geokichla wardii","overview":"杂色地鸫（英文名：Pied Thrush，学名：Geokichla wardii），是雀形目鸫科少斑地鸫属的鸟类。纤细的地栖鸫，雄鸟身着引人注目的黑白相间羽毛，雌鸟则以灰橄榄棕色为主，带有白色眉毛、有鳞状斑纹的下体及长而黄的喙。繁殖于喜马拉雅山脉的湿润、遮荫良好的山麓森林，冬季则迁徙至斯里兰卡的密集森林、森林边缘及过度生长的种植园。","appearance":"体长约18至20厘米，体重52至72克。雄鸟上半身及中胸为黑色，自中胸至尾羽下覆羽为白色，侧翼有黑色V字形斑纹；具白色眉纹延伸至眼上，小翼羽、中翼羽、翼带及飞羽尖端和臀部为白色；喙与腿呈黄色。雌鸟上半身及面部为灰橄榄棕色，眉纹至眼上为淡褐色，两道斑点翼带，胸部为淡褐色带有少许鳞状斑纹，逐渐过渡至白色，下腹部有褐色斑点和鳞状纹，胸羽染有橄榄棕色，尾羽下覆羽为白色；喙与腿为暗黄色。幼鸟似雌鸟但颜色更深，雄鸟幼鸟类似成年雄鸟，但喉部与胸部有白色斑点。","call":"鸣唱为一连串不甚悦耳的间隔哨音，每组由2至4个短促、甜美的高音符组成，结尾常为沙哑的‘tsrrrii’或‘tzit’声。警戒叫声为连续的‘ptz-ptz-ptz-ptz’声。","habits":"栖息于森林地面的落叶层中觅食，会翻动树叶；亦见于较高的浆果树木中。冬季访问粪堆。食物包括甲虫、苍蝇、蜈蚣，偏好桑葚，也食用其他水果，如番石榴和野生无花果。","breeding":"繁殖季节为5月至7月。筑深杯状巢，内部铺以草料并以泥土加固，置于低矮树叉中。每窝产3至4枚白色或蓝白色的蛋。繁殖于海拔1500至2500米的喜马拉雅山厚林中。","identification":"雄鸟的黑白对比羽毛及雌鸟的橄榄棕色和白色眉纹，以及长而黄的喙，使它们在同属中易于识别。与长嘴地鸫和大长嘴地鸫相比，其喙不那么弯曲，与相似的雌性白眉地鸫不同，雌鸟脸颊处无明显浅色斑点。","protection":"IUCN：LC（无危）","distribution":"夏季繁殖于印度北部喜马拉雅山脉（西起喜马偕尔邦西部、北阿坎德邦）至尼泊尔中部；冬季主要迁徙至斯里兰卡，少量个体出现在南印度山区。","other":"曾被归入Zoothera属，后分子系统发育研究于2008年确认其分类地位，恢复到Geokichla属。"},{"name":"灰地鸫","english_name":"Ashy Thrush","scientific_name":"Geokichla cinerea","overview":"灰地鸫（英文名：Ashy Thrush，学名：Geokichla cinerea），是雀形目鸫科少斑地鸫属的鸟类。其分布局限于菲律宾的吕宋岛和民都洛岛北部。灰地鸫以地面觅食为生，主要栖息于低地和山麓森林。","appearance":"灰地鸫是一种中等体型的鸟类，全长约18至20厘米。上体呈现暗淡的钢灰色，翼上有两道白色翼条，翼覆羽基部黑色，形成鲜明对比。眼上方有黑色宽条纹，向下延伸为次级黑色条纹，颊部和耳羽白色。下体白色，胸部密集分布黑色斑点，腹部斑点稀疏，尾下覆羽全白。喙色较暗，腿呈淡黄色。雌雄外观相似。幼鸟描述未详。","call":"灰地鸫的鸣唱是一系列旋转上升后下降的口哨式旋律，声音略带嘶哑。还发出刺耳的摩擦声。","habits":"灰地鸫在森林地面觅食，尤其偏好开阔地带，以昆虫和无花果为食。它们主要栖息于热带湿润的低地和山地森林。","breeding":"繁殖记录显示，灰地鸫在吕宋岛的Quezon市三月、五月末至六月初筑巢。二月观察到处于繁殖状态的个体，五月发现两只幼鸟，十月见到完全成长的幼鸟，十二月有未成年雌鸟的记录，繁殖季节大约从二月至八月。","identification":"灰地鸫与虎斑地鸫和巽他地鸫相似，但体型更小，下体具斑点而非鳞片状，眼部有明显的垂直黑纹。","protection":"IUCN：VU（易危）。灰地鸫受到栖息地丧失的严重威胁，主要原因是大规模森林砍伐，预计未来会因伐木和道路建设而继续失去栖息地。非法狩猎和宠物捕捉可能也对其种群产生负面影响。尽管被列为不常见物种，但在Dalton Pass的迁徙瓶颈处，七年间的环志记录显示的数量比预期高，这可能意味着实际数量更多。近来的保护措施已正式保护了Sierra Madre山脉中大片森林，其中包括北方Sierra Madre自然公园，这里是灰地鸫的栖息地。它还在Quezon国家公园中出现，尽管该公园遭受非法伐木，同时在Mount Makiling国家公园中季节性出现。","distribution":"灰地鸫分布于菲律宾的吕宋岛群和民都洛岛北部。"},{"name":"橙斑地鸫","english_name":"Orange-sided Thrush","scientific_name":"Geokichla peronii","overview":"橙斑地鸫（英文名：Orange-sided Thrush，学名：Geokichla peronii），是雀形目鸫科少斑地鸫属的鸟类。独特的鸫科少斑地鸫属鸟类。拥有‘虎纹’般的脸部条纹，白色喉咙，宽阔的橙色胸带，橙色侧翼，白色腹部以及显著的白色翼纹。幼鸟展现出锈色的翼斑、淡色条纹，黑色和淡褐色的胸带，以及黑色侧翼斑点。分布于印度尼西亚和东帝汶的小巽他群岛东部。","appearance":"成年橙斑地鸫长约19.5至21.5厘米，上部深橙棕色，连接到下方橙栗色的胸部和侧翼，脸部至上胸白色，腹部至臀下覆羽白色；宽阔的黑色眼后纹和向下延伸的眶下纹，模糊的橙棕色髭纹，白色的较小和中等翼覆羽及大覆羽尖端，黑色飞羽带有白色主羽边缘；喙呈棕黑色，腿色从淡紫色至浅棕色。性别相似。幼鸟有淡色轴向条纹和锈边翼斑，胸带由黑色和淡色斑点组成，锈色侧翼有黑色斑点。","call":"全年大部分时间，橙斑地鸫会发出一系列短语，每组短语包含三个响亮、清脆、上扬的哨音，随后是一系列较短的断续或叽叽喳喳的音符。","habits":"橙斑地鸫单独或成对在地面和树上觅食，栖息于低地和丘陵的森林和林地斑块。它们偏好在有封闭树冠的森林中活动。","breeding":"具体繁殖细节未提及。","identification":"与其他少斑地鸫属鸟类相比，橙斑地鸫的‘虎纹’脸部图案、橙色胸带和侧翼以及白色腹部是其显著特征。","protection":"IUCN：NT（近危）；虽然普遍常见，但其栖息地内的封闭树冠森林正在不断减少。此外，担心随着其他小巽他群塔岛鸫类因猎人而濒临灭绝或接近灭绝，对该物种的贸易将增加。","distribution":"分布于澳大利亚新几内亚地区的小巽他群岛东部，具体包括蒂莫尔岛和南部马鲁古群岛。","other":"无"},{"name":"橙头地鸫","english_name":"Orange-headed Thrush","scientific_name":"Geokichla citrina","overview":"橙头地鸫（英文名：Orange-headed Thrush，学名：Geokichla citrina），是雀形目鸫科少斑地鸫属的鸟类。羽色鲜艳的地栖性鸟类。头部、胸部和腹部亮橙色，极具辨识度。常见于印度次大陆及东南亚的多荫森林地带，偏好湿润环境，如水沟和峡谷林地。在一些亚种中，脸颊两侧可见两条宽黑纹。其鸣唱优美，各段落间隔清晰，由颤音和哨声组成。","appearance":"体型介于20至23厘米，体重47至67克。雄鸟指名亚种的上半身呈暗淡灰褐色，有光泽和无光泽部分交替，翅膀和尾巴上有白色中翼覆羽和白色下腹至尾下覆羽。喙黑色，基部较浅，腿肉色。雌鸟相似，但上半身和背部为暗淡的绿褐色，翅膀和尾巴也是棕色。幼鸟从头部到背部呈暗橙棕色，带有模糊的斑点，脸部有深色条纹，翅膀上有双翼条纹，下部暗棕色带淡黄色斑点，尤其是胸部最为明显，下巴和喉咙为纯色；下部很快变成成年橙色，胸部颜色更深，喉咙颜色更黄。不同亚种间存在颜色和大小差异。","call":"鸣唱响亮、丰富、旋律优美，由一系列短小连贯的乐句组成，涉及滑音和丰富的颤音，有时模仿多种鸟类的声音，包括普通鹰鹃。叫声包括尖锐的‘tzzeet’、低沉的‘tjuck’以及在警戒时发出的尖锐尖叫‘kreeee’或‘teer-teer-teerrr’。","habits":"偏好湿润的落叶林和常绿森林，以及混交的次生林和竹林，经常在靠近流水和低海拔峡谷的地区活动。在泰国，活动高度可达1500米。在中国的种群大多会迁徙，但具体模式尚不清楚。以昆虫（包括白蚁）、蚯蚓、蛞蝓、蜗牛、浆果、果实和草籽为主食，尤其在马来西亚半岛冬季偏好无花果。在浓密植被下的落叶层中安静地寻找食物，主要从地面拾取，积极翻动叶子；也会在土壤和石缝间的苔藓中探查。偶尔从高树上摘取果实。","breeding":"繁殖期在印度喜马拉雅山脉为4月至6月，其他地方可能延续至9月。筑巢于灌木、竹子或树木边缘1至5米高的位置，巢为浅而厚的杯状，由茎、软皮、根和绿色苔藓混合泥巴构成，内衬苔藓、蕨类根和纤维。每窝产卵3至4枚，极少数2或5枚，卵壳呈蓝白色、绿白色或奶油色，带淡红色斑点。孵化期13至14天，雏鸟期12天。偶尔受到斑翅凤头鹃的寄生。","identification":"与同属其他物种相比，橙头地鸫的头部和下体橙色鲜明，上体灰色或橄榄色，具有独特的色彩组合。不同亚种在颜色和面部条纹上有所不同，例如cyanota亚种脸部有宽阔的橄榄棕色垂直眼线下条纹和并行的宽阔耳后条纹，窄橙色颊纹，白色下巴至上胸部。","protection":"IUCN：LC（无危）","distribution":"广泛分布于东洋界，包括印度次大陆（如孟加拉国、印度、斯里兰卡）、东南亚至爪哇和中国南部。在喜马拉雅山脉，活动高度可达2300米。在中国，包括海南岛，种群稀少。在泰国和马来西亚半岛，既是居民鸟也是冬候鸟。在北婆罗洲，数量稀少。在爪哇，由于笼鸟贸易的捕获，数量大幅下降。","other":"橙头地鸫在印尼西部的鸟类歌唱比赛中价格高昂，市场需求自1990年代以来导致大量幼鸟被捕获，特别是在巴厘岛，2008至2009年繁殖季节期间，约有16万只幼鸟被捕获。"},{"name":"白眉地鸫","english_name":"Siberian Thrush","scientific_name":"Geokichla sibirica","overview":"白眉地鸫（英文名：Siberian Thrush，学名：Geokichla sibirica），是雀形目鸫科少斑地鸫属的鸟类。俗名: 白眉麦鸡、西伯利亚地鸫、地穿草鸫、阿南鸡，成年雄鸟整体呈深石板灰色，脸部和肩部颜色更深，拥有醒目的白色眉纹。雌鸟为深褐色，脸部和腹部带有鳞状斑纹。性情较为害羞，偏好生活在中海拔森林的湿润阴凉地带。","appearance":"雄鸟成鸟为深石板灰色，雌鸟为橄榄色至深褐色，两者均具有白色眉纹。雄鸟腹部白色，雌鸟腹部具斑点。幼鸟与雌鸟相似，但更灰暗，脸部带白色斑点。喙黑色，腿黄色。体长20.5至23厘米，体重60至72克。","call":"雄鸟会从高处的栖木上发出一系列嘶哑的双音节哨声。","habits":"栖息于中海拔森林的阴湿区域，冬季迁徙至东南亚的山林。主要以昆虫、蠕虫和果实为食，常在地面觅食，有时也会造访结果的树木。","breeding":"繁殖期在中国和日本为5月至7月，在西伯利亚中部为6月至7月。筑杯状巢于树上或灌木丛中，离地1米以上，巢由小枝条、苔藓和树叶构成，每窝产卵4至5枚，孵化期约11天。","identification":"飞行时，两性均具有黑带的白色下翼，这是识别的重要特征，与鳞鸫共享此特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯东西伯利亚的针叶林，迁徙至东南亚过冬，罕见于欧洲西部。","other":"20世纪前半叶，由于在日本的捕捉，数量曾严重减少。"},{"name":"阿比西尼亚地鸫","english_name":"Abyssinian Ground Thrush","scientific_name":"Geokichla piaggiae","overview":"阿比西尼亚地鸫（英文名：Abyssinian Ground Thrush，学名：Geokichla piaggiae），是雀形目鸫科少斑地鸫属的鸟类。分布于非洲东北部的高海拔山地森林。此物种以19世纪意大利探险家Carlo Piaggia的名字命名。","appearance":"阿比西尼亚地鸫是一种具有深红橙色头部和脸部的大体型鸫鸟，其上体橄榄棕色，下体颜色逐渐变为较淡的红橙色，两侧呈橙色。最显著的特征是其独特的白色眼环和翼折处两道显眼的白色翼条。成鸟长约19至20厘米，体重在43至65克之间。幼鸟相较于成鸟颜色更浅，更为暗淡。","call":"其接触叫声为高音的“tseep”，鸣唱则是一系列典型的鸫鸟般悦耳的口哨声，包含旋律性的呼啸和啾啾声。","habits":"这种鸫鸟主要栖息于年降雨量丰富的常绿山地森林的下层植被中，海拔高度通常在1,800至3,300米之间，尤其常见于2,500米以上的地区。它也可能出现在竹林或埃塞俄比亚的异域松树林中。阿比西尼亚地鸫是害羞且独居的鸟种，偏好在地面活动，跳跃、奔跑或行走于树下或茂密的植被中。它的食物主要是蚯蚓、千足虫、蜗牛和昆虫，偶尔也会食用果实如无花果、浆果和一些种子。","breeding":"繁殖季节随其分布范围而变化，通常在雨季进行。鸟巢是由苔藓或其他植物材料制成的杯状结构，内衬植物纤维，一般位于离地面不超过5米的树枝或小树苗的分叉处，隐蔽性良好。每巢产两枚蛋，由双亲共同喂养幼鸟，幼鸟离巢后仍与父母共同生活长达三个月。","identification":"与橙色地鸫相似，但头部图案不同：橙色的冠羽，素面，以及完整的白色眼环，是区分两者的要点。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲中部和东部的山地森林中，具体包括埃塞俄比亚、肯尼亚、坦桑尼亚等地。","other":"目前共有六个公认的亚种。"},{"name":"科氏地鸫","english_name":"Crossley's Ground Thrush","scientific_name":"Geokichla crossleyi","overview":"科氏地鸫（英文名：Crossley's Ground Thrush，学名：Geokichla crossleyi），是雀形目鸫科少斑地鸫属的鸟类。中大型的鸫科少斑地鸫属鸟类，以橙红褐色下体和橄榄棕色上体为主要特征，拥有双白色翼带和独特的黑色面具，分布于非洲中部的喀麦隆山脉和伊通贝高原的山地森林中。","appearance":"成年科氏地鸫长约21.5厘米，体重63至82克。头顶、颈背和上体呈淡橄榄棕色，上眼圈和臀部颜色更亮，翼覆羽较暗，有两道白色斑点的翼带，外侧尾羽带有淡黄色尖端。脸部有模糊的黑色面具，被半环状白眼圈隔断，下巴有黑色点斑；下体呈暗红褐色，腹部至尾下覆羽渐变为白色。喙黑色，腿肉色至粉红色。雌雄相似。幼鸟上部有淡黄色的轴纹，下体红黄褐色，喉部黑色，胸部和侧腹有深色标记。","call":"其鸣唱由一系列7至10个富有韵味的哨音组成，音调逐渐上升，每组音节类似但略有变化，如‘hor-her-hiiwo-chichiwo-tsitsi’。报警叫声为尖细的‘siiip’。","habits":"科氏地鸫偏好湿润的山地森林环境，包括沟壑和峡谷地带，常在地面觅食，但在树冠层歌唱。其活动海拔范围在800至2300米之间。","breeding":"关于科氏地鸫的繁殖生态学细节尚缺乏详细记录。","identification":"科氏地鸫最显著的特点是其独特的黑色面部面具，这一特征在其他地鸫中未曾见到。","protection":"IUCN：LC（无危）","distribution":"科氏地鸫分布于非洲中部的喀麦隆、刚果共和国、刚果民主共和国和尼日利亚的山地森林中。","other":"由于栖息地丧失，科氏地鸫的数量正在减少，成为罕见物种。"},{"name":"橙色地鸫","english_name":"Orange Ground Thrush","scientific_name":"Geokichla gurneyi","overview":"橙色地鸫（英文名：Orange Ground Thrush，学名：Geokichla gurneyi），是雀形目鸫科少斑地鸫属的鸟类。以英国银行家、政治家兼鸟类学家约翰·亨利·格尼命名，其分布于非洲东部和南部的山地森林中。","appearance":"橙色地鸫是一种大型鸟类，身长21至23厘米，体重44.5至76克。上体呈橄榄棕色，部分区域略带灰色，翅膀上有两道明显的白色翼纹。喉咙、胸部及两侧为橙色，腹部白色。具有不完整的白色眼环，喙部深色，腿部粉红色。雌鸟颜色较雄鸟暗淡，幼鸟则有斑驳的下体羽毛。","call":"鸣叫声为清脆的\"tsip\"和\"cureek\"，歌曲由一系列柔和悦耳的音符组成。","habits":"橙色地鸫为晨昏活动型鸟类，一般保持定居状态，但在某些地区会进行海拔迁移。它们主要在地面觅食，以蚯蚓、昆虫、软体动物和果实为食。","breeding":"繁殖季节在肯尼亚为1月至5月，在坦桑尼亚为8月至12月，在马拉维为10月至次年1月，在莫桑比克、南非和津巴布韦为9月至12月。雌鸟通常比雄鸟重。巢为深杯状，由苔藓、树枝、树叶、根和蕨类植物构成，每窝产2到3枚青蓝绿色的蛋，孵化期约为15天，幼鸟离巢时间为18至20天。","identification":"与阿比西尼亚地鸫相似，但头部图案不同：橄榄色顶冠，眼睛下方有黑色条纹，眼环断续。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部和南部的山地森林，具体包括肯尼亚、坦桑尼亚、安哥拉西部、刚果民主共和国东南部、马拉维北部、南非东部以及莫桑比克、南非和津巴布韦的部分地区。"},{"name":"澳氏地鸫","english_name":"Oberländer's Ground Thrush","scientific_name":"Geokichla oberlaenderi","overview":"澳氏地鸫（英文名：Oberländer's Ground Thrush，学名：Geokichla oberlaenderi），是雀形目鸫科少斑地鸫属的鸟类。分布于刚果民主共和国东部和乌干达西部的低地和过渡森林中。","appearance":"体长约19至20厘米，体重41至48克。头部呈赤褐色，有断裂的白色眼环和黑色亚眶纹；上体暗橄榄赤褐色，翼羽较深，具两道白色点状翼带；下体淡赤褐色，腹部至尾下覆羽渐变为白色；喙黑色，腿肉白色至白色。雄雌相似。幼鸟冠部颜色更深，面部有暗色斑块，喙角褐色，胸腹部分布有重黑色斑点。","call":"鸣唱为一系列变化无穷的甜美、笛音般的、柔和的哨声，音调和品质类似欧乌鸫和阿比西尼亚地鸫的tanganjicae亚种。","habits":"栖息于原始低地和过渡森林，海拔700至1850米。偏好靠近河流的茂密森林类型，特别是在布温迪森林。","breeding":"繁殖期在雨季和旱季末期。巢由干草、植被条和植物纤维构成，位于地面或树上。2007年在乌干达发现的一个巢穴，位于Carapa gradiflora树上，高约5米，主要由苔藓和少量蕨茎组成，内有3只刚孵化的小鸟。","identification":"与其他地鸫种类的区别在于其独特的颜色模式和鸣唱。","protection":"IUCN：NT（近危）","distribution":"主要分布在刚果民主共和国东部（伊图里森林、塞姆利基山谷和伊通贝山脉）和乌干达西部（塞姆利基/布万巴森林和布温迪/难以穿越森林）。","other":"该物种对森林退化和丧失极为敏感，其栖息地正遭受严重威胁，主要用于农田和木材采伐，尤其是在伊通贝和布万巴地区。"},{"name":"黑耳地鸫","english_name":"Black-eared Ground Thrush","scientific_name":"Geokichla camaronensis","overview":"黑耳地鸫（英文名：Black-eared Ground Thrush，学名：Geokichla camaronensis），是雀形目鸫科少斑地鸫属的鸟类。锈棕色背部，双白色翼带，以及脸部独特的垂直条纹。西部种群色彩更丰富，东部种群则较为暗淡。在刚果盆地的低地和山地森林中以成对形式罕见出现。","appearance":"体长约16.5至18厘米，体重42至57克。雄鸟上部呈暗淡的栗褐色，臀部颜色更亮；喙色深，腿呈肉白色。雌鸟整体较淡且颜色暗淡。幼鸟背部有浅色条纹，下体有黑色斑点。亚种graueri更灰，下体颜色更暗淡，有时胸部有模糊的暗色条纹；kibalensis体型略大，上部更偏赤褐色，下体颜色更鲜艳。","call":"其歌曲未被描述；报警声为典型的高音‘ssreee’。还有‘tssrr’的叫声。","habits":"栖息于低地原始森林和过渡森林，最高可达1370米。在刚果民主共和国的伊图里森林中，其生境下层非常开阔，有短约40厘米的马兰科和姜科植物组成的草本层；在乌干达的布东戈森林中，主要出现在由铁木（Cynometra alexandri）主导的高大森林中，林下层相对清晰。以昆虫和小蜗牛等无脊椎动物为食，常在地面翻动枯叶觅食。","breeding":"繁殖期记录显示，筑巢时间为9月至10月，在乌干达观察到处于繁殖状态的个体和幼鸟。巢为松散搭建的开放杯状，由死叶、一些枝条和干皮构成，通常位于Rinoria或Acalypha灌木或小树的清晰分叉处，高度在1.2至3.5米之间，靠近研究路径。已知的四窝蛋都被捕食。","identification":"与其它地鸫的不同在于脸部的双垂直条纹，除了体型更大的灰地鸫，后者面部和胸部颜色更淡。亚种间辨识要点在于kibalensis体型更大，颜色更鲜艳。","protection":"IUCN：LC（无危）。Kibalensis亚种自1966年以来仅发现两份标本，显然极为罕见。其他亚种分布范围有限，可能确实稀少，但目前面临的压力不大。在喀麦隆的科鲁普国家公园有指名亚种的记录。在乌干达，几乎只存在于布东戈森林的原始铁木森林中。","distribution":"分布于非洲中部，包括喀麦隆、刚果民主共和国、赤道几内亚、加蓬和乌干达。","other":"Kibalensis亚种有时被视为独立物种，即基巴莱地鸫。"},{"name":"灰色地鸫","english_name":"Grey Ground Thrush","scientific_name":"Geokichla princei","overview":"灰色地鸫（英文名：Grey Ground Thrush，学名：Geokichla princei），是雀形目鸫科少斑地鸫属的鸟类。这种神秘的鸫类栖息于低地的原始和次生森林中，常见于靠近水源、植被茂盛的地带。","appearance":"全身灰褐色，具有独特的双白色翼带和耳羽上的双黑色横纹。与同样鲜为人知的黑耳地鸫相似，但灰色地鸫的外观更单一灰褐，且翼带颜色更为明亮。","call":"其歌声尚未被记录，但据报告会发出尖锐、嘶嘶声的叫声。","habits":"栖息在非洲的低地湿润热带森林，具体分布于喀麦隆、刚果民主共和国、加蓬、加纳、象牙海岸、利比里亚、塞拉利昂和乌干达。","breeding":"关于其繁殖行为的信息目前尚不清楚。","identification":"与黑耳地鸫相比，灰色地鸫的羽毛色彩更加单一，翼带更为显眼。","protection":"IUCN状态未知。","distribution":"主要分布在非洲中南部地区的西部和中部。"},{"name":"斑地鸫","english_name":"Spotted Ground Thrush","scientific_name":"Geokichla guttata","overview":"斑地鸫（英文名：Spotted Ground Thrush，学名：Geokichla guttata），是雀形目鸫科少斑地鸫属的鸟类。背部呈暖褐色，下体具显著斑点，翼上有白色斑纹。分布于非洲东部及东南部，包括刚果民主共和国、肯尼亚、马拉维、南非、苏丹、坦桑尼亚等地，可能也存在于莫桑比克。此物种因森林栖息地的丧失而面临威胁。","appearance":"斑地鸫体长19至23厘米，体重45至78克。成鸟头部至尾部上方为暖褐色，两翼有白色斑点，面部和下体为灰白色，具黑色条纹和斑点，翼下覆羽橙色至淡黄色。喙部深色，下颚基部黄色；腿为暗肉色。幼鸟较成鸟颜色更深，头部具淡色斑点，下体更黄。种族间差异微小。","call":"斑地鸫的歌声是一系列甜美旋律的3至6个音符，有时以柔和的高音颤音结尾。叫声为细长的高音\"pssssss\"或\"sriiiii\"，持续约半秒。","habits":"斑地鸫栖息于多种森林环境，包括海岸低地湿润常绿森林、珊瑚礁森林、干Cynometra灌木丛等。迁徙时偏好有深荫、稀疏灌木和厚落叶层的森林。它们夜间迁徙，以蚯蚓、软体动物、小型千足虫、昆虫及其幼虫为主食，也会吃种子和果实。","breeding":"繁殖季节为11月至次年2月。巢由树枝、叶子、藤蔓等构成，通常置于离地面1.5至2.5米高的树木中。每窝产卵1至3枚，卵为蓝绿色至白色，带有红棕色和绿色斑点。孵化期和育雏期均为14至16天。南非洲的繁殖成功率约为10至20%，巢穴易受蛇、猛禽和家猫的捕食。","identification":"与非洲地鸫相比，斑地鸫生活在森林环境中，具有更平直的体态和白色翼斑，易于区分。","protection":"IUCN：VU（易危）。全球估计数量不足2500只。面临的主要威胁是栖息地缩减。","distribution":"繁殖于马拉维、南非洲部分地区；非繁殖季分布扩展至东非沿海地区，如肯尼亚、坦桑尼亚北部。在南非洲，冬季栖息于沿海森林，夏季迁至内陆森林。","other":"斑地鸫的某些种群在冬季和夏季有不同的活动范围，如南非夸祖鲁-纳塔尔省的种群。"},{"name":"斑翅地鸫","english_name":"Spot-winged Thrush","scientific_name":"Geokichla spiloptera","overview":"斑翅地鸫（英文名：Spot-winged Thrush，学名：Geokichla spiloptera），是雀形目鸫科少斑地鸫属的鸟类。体型中等，主要分布于斯里兰卡的雨林和部分干燥林区，海拔介于500至2000米之间，以独特的翼部白点和下部显著的黑斑闻名。","appearance":"斑翅地鸫全长约21至27厘米，重约70克，上部淡褐色，具双排白色翼斑，面部浅色带两道深色条纹，下体白色伴以密集黑斑，喙黑色，腿呈黄肉色；幼鸟上部具锈色条纹，面及下体浅棕色，条纹明显。","call":"其鸣唱丰富多变，清晨或黄昏时发出悠扬、略带哀伤的哨音，包括‘piii, piii-puu, piii, pip-piii, piii, piii-puu’等旋律，另有警戒时的尖锐‘tzsee’声和接触时的轻柔‘chik-chik’。","habits":"主要栖息于地面，偏好湿润叶堆环境，以翻找土壤中的蚯蚓、啄食地表昆虫和捕捉叶间虫子为主，偶尔也会捕食空中飞虫，饮食上杂食但偏爱昆虫，也食用小蛙和果实。","breeding":"筑巢于树杈，巢由植被构成，每次产2-3枚淡黄色或蓝绿色卵，每年繁殖两次，幼鸟具明显羽纹差异。","identification":"斑翅地鸫翼上的白色斑点和下体的黑斑是其显著特征，与斑地鸫相比，上体更偏褐色，面部标记更浓重，胸部侧边有灰色调，下体斑点更小、更椭圆且密集。","protection":"IUCN：NT（近危）；受限于斯里兰卡，面临森林退化、碎片化和干扰的威胁，封闭林面积自1956年的29,000平方公里减少至1983年的12,260平方公里。","distribution":"主要分布在斯里兰卡的雨林和干燥林区，繁殖区域与非繁殖区域相似，海拔750至1500米，尤其在原生林中数量较多。","other":"在斯里兰卡，当地语言称为Pulli Wal Awichchiya，属于当地文化的一部分。"},{"name":"苏拉山鸫","english_name":"Geomalia","scientific_name":"Zoothera heinrichi","appearance":"苏拉威西山鸫拥有约28至30厘米的体长，尾部渐长且略呈弧形，翼展较短且圆润，喙粗壮，腿弱。成年鸟上身颜色为深棕色至板岩灰色，翅膀上有锈色斑点；下体为红褐色，喉部有暗灰色斑纹。幼鸟下体羽毛呈锈色，颈部、喉部及胸部有广泛的暗灰色斑点，腹部和侧腹处斑点较少。雌雄外观相似，但幼鸟喙较短，尾羽初期比成鸟短。","call":"苏拉威西山鸫发出高音调的哨声，持续约1秒，间隔0.5秒重复，叫声持久但间歇性。","habits":"苏拉威西山鸫栖息于海拔1700至3500米的原始山地常绿森林中，偏好密集的林下植被、苔藓森林和矮树丛。它们是留鸟，以大型甲虫、幼虫和小型蜗牛为食，在地面觅食，通过敏捷的跳跃和短暂的停留寻找食物，行为类似鵙鵙和鸫。","breeding":"关于繁殖行为的信息目前未知。","identification":"与塔岛鸫和苏拉威西鸫相比，苏拉威西山鸫具有明显更长的尾羽，缺乏黑色眉纹，且喉咙没有暗色。不同亚种间存在细微差异，如matingensis亚种体型略小，下体和头部颜色较深。","protection":"IUCN：LC（无危）","distribution":"苏拉威西山鸫的分布限于苏拉威西岛的山脉，具体位于印尼华莱士区的苏拉威西岛上。","other":"苏拉威西山鸫面临来自非法伐木和其他导致苏拉威西高地退化活动的威胁，包括在洛雷林杜国家公园等受法律保护地区的破坏。"},{"name":"埃氏地鸫","english_name":"Everett's Thrush","scientific_name":"Zoothera everetti","overview":"埃氏地鸫（英文名：Everett's Thrush，学名：Zoothera everetti），是雀形目鸫科地鸫属的鸟类。独特的鸫科地鸫属鸟类，以英国殖民管理员兼动物学家Alfred Hart Everett的名字命名。仅分布于婆罗洲北部高山地区，属于罕见而令人向往的物种，因其羞涩而难得一见。","appearance":"成鸟体长19至20厘米，上部深橄榄棕色，颈部侧面和臀部略带橄榄色。眼周淡黄色，下颌至喉部淡黄白色，颊部深棕色，耳羽饰有淡黄色斑点；腹部橙栗色，向下渐变为白色，腹下部和尾下覆羽呈浅橙色。喙黑色，腿肉色至棕色。雌雄相似，幼鸟翼羽覆羽尖端橙黄色，橙色下部有棕色斑点。","call":"叫声包括尖锐的‘deeer’声和急促粗糙的警报音，其鸣叫特征尚待深入了解。","habits":"栖息于海拔1200至2140米的苔藓山地森林，偏好密集的下层植被环境，常见于藤蔓密布的丛林或矮树丛中。单独或小群体在湿润的地面或低矮植被中觅食，主要食物为小型昆虫如甲虫幼虫和白蚁，也会食用蠕虫和蚂蟥。","identification":"通过橙色下部、石板灰色背部和带有杂乱面纹的棕色头部与其它地鸫种类相区别。","protection":"IUCN：NT（近危）。","distribution":"仅限于婆罗洲山脉，具体在马来西亚东部沙巴州和北砂拉越地区的高山地带。"},{"name":"巽他地鸫","english_name":"Sunda Thrush","scientific_name":"Zoothera andromedae","overview":"巽他地鸫（英文名：Sunda Thrush，学名：Zoothera andromedae），是雀形目鸫科地鸫属的鸟类。其特征为蓝灰色的羽毛，侧面呈现美丽的黑白相间的斑纹，脸部图案微妙而独特。这种鸟十分羞涩，常隐匿于山地和丘陵森林的茂密灌木丛中，很少出现在开阔地带。在整个分布区内数量稀少，发出高音调下降的“tsewwww”叫声。","appearance":"成年鸟体长约23.5至25厘米，体重在81至108克之间。头部呈黑褐色，具白色眼圈，脸颊、耳羽及下髭纹有黑色斑点，衬以白色。冠部渐变为暗灰色，背部和肩羽亦为暗灰色，带黑色鳞状斑纹，翅膀和尾巴为棕灰色。胸部至腹部中间为浅灰色，向下渐变为白色，腹部至尾下覆羽处有明显的黑色鳞状斑纹，侧翼上带有白色箭头。喙长而黑色，腿为灰褐色。雌雄相似。幼鸟上方稍显棕色，头顶和颈背有淡色斑点，背部和肩羽有淡色条纹，两翼有淡色斑点，下体为淡白色，遍布黑色鳞状斑纹。","call":"发出非常尖锐的下降式‘tsewwww’叫声。","habits":"生活在遮蔽良好的森林地面，通常在密集的草本层中觅食昆虫。偏好于亚热带或热带湿润的低地和山地森林。","identification":"与同属物种相比，巽他地鸫的头部特征和独特的脸纹使其易于辨认，同时，其特定的叫声也是识别的重要依据。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏门答腊岛（含恩加诺岛）、爪哇岛、巴厘岛、菲律宾（除巴拉望群岛和苏禄群岛）以及龙目岛至Romang（小巽他群岛东部）。"},{"name":"淡背地鸫","english_name":"Alpine Thrush","scientific_name":"Zoothera mollissima","overview":"淡背地鸫（英文名：Alpine Thrush，学名：Zoothera mollissima），是雀形目鸫科地鸫属的鸟类。曾被统称为光背地鸫，现分为阿尔卑斯地鸫、四川淡背地鸫与新发现的喜山淡背地鸫三个独立物种。具有巧克力棕色外表，下体密布细小白色鳞状斑纹，主要分布于喜马拉雅山脉西北部至中国南部的高海拔地区。","appearance":"成年淡背地鸫体长25至27厘米，体重80至112克。头部至尾部上方呈均匀温暖的橄榄棕色，眼圈白色，脸部呈淡褐色，下眼睑、耳后覆羽及颊部有深色标记，下体白色，布满密集的黑色新月形斑点，尾巴下方覆羽有明显的棕色和白色图案。虹膜深棕色，喙部暗色，下颚较浅，跗跖呈粉红色。两性相似，幼鸟较暗淡，颈背至肩部有淡褐色轴纹，胸部和颈部颜色更淡。","call":"其歌声简单但并不完全缺乏音乐感，由流畅的颤音和尖锐的摩擦音组成。","habits":"淡背地鸫繁殖于海拔3000至4500米的开阔多岩高山草甸，春季会暂时使用云杉、冷杉和松树林等森林环境。非繁殖季节，它们会下降到更低海拔的开阔灌木地带，农田，山谷和森林，最低至300米。","breeding":"繁殖期从4月至7月，主要在6月至7月间。巢建于地面或岩石边，由植被构成，内衬精细纤维，通常产三至四枚蛋，蛋壳呈淡白色，带有大量深红和棕红色斑点。","identification":"与长尾地鸫相比，淡背地鸫尾部较短，胸部具鳞状斑纹而非黑色横纹，翅膀上的条纹较窄且颜色较深。与四川淡背地鸫和喜山淡背地鸫相比，淡背地鸫的喙部较短，前额颜色较深。","protection":"IUCN：LC（无危）。全球范围内普遍数量不多。在巴基斯坦非常罕见且分布局部，在印度和尼泊尔较为常见，在中国分布稀少。","distribution":"繁殖区域从喜马拉雅山脉西北部延伸至中国南部，包括印度、巴基斯坦、尼泊尔、不丹、孟加拉、缅甸、越南以及中国的西藏、四川、云南等地。非繁殖季节分布下降至较低海拔。","other":"近年来的研究揭示了淡背地鸫复杂的分类学历史，包括隐秘物种的发现和系统学地位的调整。"},{"name":"四川淡背地鸫","english_name":"Sichuan Thrush","scientific_name":"Zoothera griseiceps","overview":"四川淡背地鸫（英文名：Sichuan Thrush，学名：Zoothera griseiceps），是雀形目鸫科地鸫属的鸟类。这里是它的主要繁殖地。这种地鸫在冬季会迁至越南西北部。曾被认为是淡背地鸫和平背地鸫的同种，直到2016年才被确认为独立物种。","appearance":"成鸟头部前至颈背呈暗灰褐色，与温暖的赤褐色上体形成对比，翅膀和尾巴同样为赤褐色。眉线白色，颊纹灰白，喉部至上胸部白色，下喉至腹部为淡黄色，带有密集的黑色新月形斑点。虹膜深棕色，眼圈白色宽大，喙角暗至黑色，基部较浅，腿肉黄色。雌雄相似，幼鸟整体较暗淡，背部至肩部有浅色条纹，下体颜色更偏黄。体长约25-27厘米。","call":"歌唱缓慢而优美，包含拉长的丰富清晰音符和较短的薄音，几乎不含刺耳或粗糙音调，比喜山淡背地鸫的歌声更丰富、更深沉、更具音乐性，音节平均更长，频率带窄，中频低，峰值频率低。","habits":"栖息于中国四川北部和中部的密集丘陵和山地森林，偏好浓密的林下植被和针叶树丛。在地面阴影处觅食，翻转落叶和腐烂植被，探查土壤，主要以各种节肢动物、蜗牛和其他类似无脊椎动物及部分植物物质（如浆果、种子）为食。非繁殖季节的行为尚不明确。","breeding":"繁殖季节可能为4月至7月，具体繁殖细节未知，但预计与淡背地鸫相似。","identification":"与淡背地鸫相比，具有灰色的冠顶和更厚重的喙；与长尾地鸫的区别在于尾部较短，无显著的‘耳罩’。与淡背地鸫幼鸟的区别在于喙更深，冠顶更暗，上体更赤褐色。","protection":"IUCN：LC（无危）。在当地较为常见，目前未识别到对该物种的威胁，因此认为其种群稳定。需要进一步的野外研究。","distribution":"繁殖于中国中南部，尤其是四川北部和中部的密集丘陵和山地森林。冬季迁徙至越南西北部。","other":"2016年前，四川淡背地鸫被归类为平背地鸫的亚种之一，后被确认为独立物种。"},{"name":"喜山淡背地鸫","english_name":"Himalayan Thrush","scientific_name":"Zoothera salimalii","overview":"喜山淡背地鸫（英文名：Himalayan Thrush，学名：Zoothera salimalii），是雀形目鸫科地鸫属的鸟类。神秘而分布受限的鸫科地鸫属鸟类，以其深褐色的外表和黑色鳞片状腹部著称，眼圈白色，整体羽毛均匀。与四川地鸫和阿尔卑斯地鸫极为相似，但平均颜色更深，喙更粗壮，体型更为粗壮。繁殖于喜马拉雅东部森林地带，海拔约3000-4000米，冬季降至约1450米。其鸣声为典型的清脆悦耳的鸫类歌曲。","appearance":"身长25–27厘米，与淡背地鸫，四川淡背地鸫相似，与长尾地鸫比较相似，但相比前者，喜山淡背地鸫拥有明显更长且更深的喙，上颌边缘更弯曲，喙钩更长，下颌边缘更弯。喙通常完全或几乎全黑，而的喙基通常是淡粉色或黄色。头部羽毛更浓密、更蓬松，鼻羽更广泛。翼短，初级飞羽突出短，尾短，跗蹠短，但喙大且相对后爪较长。","call":"其鸣声被认为是更加悦耳和‘鸫类’般的，混合了丰富的、延长的清晰音符和较短、较细的声音，几乎没有粗糙的刮擦音。歌曲节奏较慢，音符间的音高变化更为显著，通常以较细的音符结束，使歌曲似乎在结尾处逐渐消失。","habits":"生活习性尚不清楚，但在非繁殖季节（9月至次年4月），该物种似乎向低纬度和低海拔移动，冬季记录最南可达印度的梅加拉亚邦和曼尼普尔邦，以及泰国（2018年4月）和越南北部（最北至Tonkin）。在非繁殖季节期间，海拔可降至近1400米（夏季记录不低于约3200米）。","breeding":"繁殖详情尚未报告，但基本细节可能与其他复合体成员相似。","identification":"与淡背地鸫相比，羽色更棕色，上体色更均匀；喙更大，形态更拱；喙色更暗，鼻羽更蓬松；体态更紧凑，鸣声更优美。与四川淡背地鸫相比，喙、翼和尾更短，缺乏从前额到颈背的灰色，脸部图案对比更明显，耳羽斑点更多，条纹不均匀，鸣唱更为饱满悠扬。与长尾地鸫相比，喜山淡背地鸫喙更大，尾和跗跖短，体侧斑纹更细，尾下斑块更小。","protection":"IUCN：LC（无危）。在喜马拉雅山脉东部局部常见，甚至在中国云南省独龙江地区丰盛。其栖息地目前未受到直接威胁。","distribution":"分布于印度东北部（西孟加拉邦，东北部）至中国南部（云南）。在繁殖季节，栖息于喜马拉雅山脉东部森林地带，海拔3000-4000米；冬季下降至约1450米。","other":"2016年新描述的物种，从中分离出来。基于遗传学研究，估计至少在300万年前（估计范围为3-6百万年前）从共同祖先分化。"},{"name":"长尾地鸫","english_name":"Long-tailed Thrush","scientific_name":"Zoothera dixoni","overview":"长尾地鸫（英文名：Long-tailed Thrush，学名：Zoothera dixoni），是雀形目鸫科地鸫属的鸟类。分布于尼泊尔、不丹、缅甸、泰国、越南及中国中南部和西南部，包括西藏、青海、甘肃、四川、云南、贵州等地。其自然生境为喜马拉雅山脉中部至东部的高海拔森林，常绿林区。该物种以长尾著称，命名来源于英国鸟类学家Charles Dixon。","appearance":"长尾地鸫体型中等，长度约25至27厘米，体重介于71至125克之间。上体呈暖橄榄褐色，头部至尾部颜色一致，眼圈白色，脸部下方及耳羽后方有暗色标记，翼上有两道斑点构成的翼带，下体淡白色，布满密集的黑色新月形斑纹，尾下覆羽为奶油色，喙部深色，腿部呈粉红色。性别相似，幼鸟从颈背到肩部有明显的淡色条纹。","call":"其鸣唱缓慢而冗长，由一系列吱吱声、笛音般的咯咯声、干燥的颤音和叽叽喳喳组成，听起来不如宝兴歌鸫的鸣声悦耳。叫声记录尚不明确。","habits":"长尾地鸫主要栖息于海拔1200至4000米的山地森林，特别是在有杜鹃花和针叶树的地带，冬季会降至较低海拔。它们通常在地面上觅食，沿叶铺小径或路边活动。非繁殖季节偶尔会形成小型群落，参与混合鸫鸟群。","breeding":"具体繁殖行为信息不详，但已知长尾地鸫在中国的西藏东南部、云南南部及西部和四川省繁殖。迁徙期间，在广西西部有记录。","identification":"与宝兴歌鸫相比，长尾地鸫上体无鳞状斑纹，翼上横纹更为显著，多为橄榄色，尾更长，翼斑为皮黄色而非白色，且下体黑色月牙形纹较少。与宝兴歌鸫及其他Turdus属种类相比，长尾地鸫外侧尾羽端白，下体具鳞状斑纹而非点斑，且翼下有两道白色粗纹。与淡背地鸫的区别在于翼上横纹更明显，多为橄榄色，尾长，翼斑为皮黄色，下体黑色月牙形纹较少。","protection":"IUCN：LC（无危）","distribution":"繁殖于喜马拉雅山脉中部至东部，包括中国中南部和西南部的西藏、青海、甘肃、四川、云南、贵州等地。非繁殖季节分布于东南亚北部。"},{"name":"虎斑地鸫","english_name":"White's Thrush","scientific_name":"Zoothera aurea","overview":"虎斑地鸫（英文名：White's Thrush，学名：Zoothera aurea），是雀形目鸫科地鸫属的鸟类。体长约27至31厘米的大型地鸫，其命名源自英国自然学家Gilbert White。具有独特的黑色鳞状斑纹覆盖在淡黄色或白色的背景上，性成熟个体相似。该物种在东部帕里亚地区繁殖，主要分布于西伯利亚至朝鲜半岛和日本的湿冷针叶林中。","appearance":"虎斑地鸫的显著特征是其体长24至30厘米，体重可达173克，全身覆盖着金色橄榄绿到黄色的羽毛，布满黑色边缘的鳞状斑纹。腹部和臀部为白色，背部和翅膀带有淡黄色色调，初级覆羽尖端呈黑色，中翼和大翼覆羽有黄白相间的尖端形成两条浅色翼带，飞行羽和初级覆羽中部边缘呈黄色。尾巴黑色，中央羽毛较浅灰色，外侧羽毛尖端白色；翼下黑色，腋下白色，有宽大的淡黄色中央带。雌雄相似，幼鸟上体颜色更偏黄褐，下体斑点比成鸟更多。","call":"虎斑地鸫的鸣唱是一连串长达约1.5秒的简单平直哨音，间隔几秒重复。叫声为细弱、哀怨的“srreeeet”，偶尔在觅食时发出短暂的“chick”声。","habits":"虎斑地鸫偏好在中高海拔的森林中繁殖，冬季则迁移到低地的公园和森林。它们主要以昆虫、虫子、小型软体动物和浆果为食，常在地面或低矮植被中觅食，用颤动神经般的步伐行走，经常快速展开和抬高尾巴。黎明和黄昏时分最活跃，此时会利用森林路径和道路。","breeding":"繁殖期在西伯利亚为5月至8月，朝鲜北部为5月至8月，日本为4月至8月。筑巢于树叉、灌木或河岸1至6米高处，巢由苔藓、树枝、草和根构成，有时全由松针制成，以泥土、树枝和苔藓固定，内衬精细的根须、蕨茎和纤维，每窝产卵3至5枚。","identification":"虎斑地鸫与鳞喉鵙相比，其歌声更简单，为单一的长哨音，而鳞喉鵙的歌声复杂，由一系列音符组成。虎斑地鸫的下喙基部肉色，而怀氏虎鸫的下喙基部也为肉色。两者在外观上有细微差异，但在叫声和分布上更为明显。","protection":"IUCN：LC（无危）。全球范围内，虎斑地鸫的数量稳定，但在台湾的居民种群因不确定的分类地位和罕见性，可能被列为当地红皮书物种。该物种全球数量正在缓慢下降，主要由于栖息地丧失和退化。","distribution":"繁殖区主要位于欧亚大陆东部，包括西伯利亚、满洲、韩国和日本的湿冷针叶林。非繁殖期广泛分布于台湾和东南亚地区，北方种族迁徙至东南亚过冬。偶尔有记录显示其漂泊至西欧。","other":"虎斑地鸫曾被认为是鳞喉鵙的一个亚种，但后来成为新种。原虎斑地鸫日本亚种现作为怀氏虎鸫的亚种存在。"},{"name":"琉球地鸫","english_name":"Amami Thrush","scientific_name":"Zoothera major","overview":"琉球地鸫（英文名：Amami Thrush，学名：Zoothera major），是雀形目鸫科地鸫属的鸟类。特有于日本北部南西群岛的阿美美大岛（Amami Ōshima）和加古罗岛（Kakeroma island）。其外观与虎斑地鸫相似，但拥有12根尾羽而非14根，且整体色调较暗淡。","appearance":"琉球地鸫体型较大，长约29至31厘米，体重约172克。羽毛上部呈温暖的橄榄棕至淡黄色，下部为白色并带有黑色鳞状斑点。头部有明显的白色眼圈，耳羽有黑色斑点，喉部和脸颊区域为白色，冠羽和颈后部为黄褐色带黑尖。背部和翅膀颜色较深，尾巴黑色，中央尾羽更偏灰棕色，外侧尾羽有大白色尖端。下腹部淡黄色，翼下有宽阔的白色中央条纹，脚部粉红色。","call":"琉球地鸫的叫声包括薄而扁平的“tsih”声（飞行中发出），低语般的“sih”声，以及高音下降的“tseeooo”。它的歌声丰富，由3至4个旋律性的哨音组成，结尾华丽，类似于白眉地鸫的歌声。","habits":"生活在未受干扰的亚热带常绿阔叶林中，海拔100至400米，偏好湿润山谷环境。食物以昆虫和果实为主，已知会大量捕食蚯蚓。飞行和活动特点独特，奔跑时像矶鹬一样突然停下来听寻猎物。","breeding":"繁殖季节为5月至6月，巢建于藤树（Schefflera octophylla）主枝叉处，距地面11.5米，巢由苔藓、树枝、树叶和细根构成，内径约12.7厘米。每窝产卵3至4枚。","identification":"与虎斑地鸫相比，琉球地鸫的喉咙颜色更淡，头纹更简单，耳羽后面的暗斑减少，下腹部有更广泛的淡黄色，翅膀上的白色较少。体型更大，喙和翅膀更长。","protection":"IUCN：LC（无危）","distribution":"琉球地鸫仅分布于日本北部南西群岛的阿美美大岛（Amami-Oshima）和加古罗岛（Kakeromajima），属于北琉球群岛（n Ryukyu Is.）。","other":"琉球地鸫曾在1990年代因成熟阔叶林的砍伐而数量锐减，但自控制了引入的小爪哇獴（Herpestes javanicus）后，其种群数量显著回升。"},{"name":"小虎斑地鸫","english_name":"Scaly Thrush","scientific_name":"Zoothera dauma","overview":"小虎斑地鸫（英文名：Scaly Thrush，学名：Zoothera dauma），是雀形目鸫科地鸫属的鸟类。俗名: 虎鸫、顿鸫、虎斑山鸫。其最显著的特征是具有黑色边缘的金色鳞片状羽毛。广泛分布于喜马拉雅山脉至东南亚，包括台湾在内的多个地区。相较于虎斑地鸫，本种体型略小，初级飞羽突出较短。","appearance":"成鸟长28-30厘米，体重88-130克，头部较为平滑的白色，具白色眼圈，黑色斑点点缀于颊部和耳羽，黑色的耳侧标记；体羽呈现黑色鳞片状，覆盖在白色底色之上，腹部和臀部白色，背部和翅膀带有淡黄色调，翅膀具有双排浅色翼带，由黄色至白色的中翼覆羽和大翼覆羽形成；尾巴黑色，中央羽毛更显灰白，外侧羽毛尖端白色；下翼黑色，腋下白色，有一宽大的浅色中央带；虹膜棕色；喙较大，黑色，下颌颜色稍浅；腿粉色。雌雄相似，幼鸟上体更偏淡黄色，下体斑点比鳞片更明显。","call":"鸣唱为一系列间断的、响亮的音符，包含急促的简单丰富音节与嘶哑声，如“pur-loo-trii-lay”重复多次，接着是“dur-lii-dur-lii”两次重复，最后是“drr-drr-chew-you-wi-iiii”重复，有时会发出更悠长、连续的音流，如“chirrup chwee chueu weep chirrol chup”。至少有两种不同的歌型，分别代表喜马拉雅和东部地区的种群。","habits":"栖息于成熟阔叶林和针叶林，如橡树林和银杉林，有茂密的灌木层和湿润土壤，海拔2400-3600米；冬季迁徙至低海拔森林边缘、蕨类主导的林下植被、牧场边缘、莎树林、树木溪边、竹林和芒果园，海拔从平原至1800米。以昆虫、蠕虫、蜗牛和浆果为食，常在地面或低矮植被中觅食，以颤动的步态行走，经常快速扇动和抬起尾巴，用喙翻动落叶。","breeding":"繁殖期在4月至6月于喜马拉雅山脉，8月在泰国北部。巢位于1-6米高的树叉、灌木或堤岸，由苔藓、树枝、草和根构成，底部环绕着泥、树枝和苔藓，内部铺有细根、蕨类茎和纤维。每窝通常产三枚以上光滑、明亮的鲑鱼色蛋，带有稍深的斑点，蛋大小约为28.8-36.5毫米×22.1-23.6毫米。","identification":"与光背地鸫和长尾地鸫相比，小虎斑地鸫体型显著较小，上体无暗色斑纹，缺乏金色，野外容易区分。与虎斑地鸫的区别在于体型略小，初级飞羽突出较短。","protection":"IUCN：LC（无危）。全球范围内数量不明，普遍描述为罕见至常见，但可能比记录显示的更为普遍，因其行为隐秘。在巴基斯坦和泰国的数量较少。","distribution":"繁殖于喜马拉雅山脉至印尼苏门答腊岛和爪哇岛。非繁殖季节主要分布在喜马拉雅山麓、印度东北部低地、中国南部和东南亚。","other":"台湾有繁殖种群。"},{"name":"启利氏地鸫","english_name":"Bonin Thrush","scientific_name":"Zoothera terrestris","appearance":"关于小笠原地鸫的外观特征，由于仅有的记录和标本，描述极为有限。其确切的体型、羽毛颜色及性别差异等细节因缺乏足够的观察资料而难以详述。","call":"对于小笠原地鸫的鸣叫特征，目前没有相关记录或描述可供参考。","habits":"小笠原地鸫的习性仅知它们曾在岸边林地被发现，推测可能在地上筑巢。然而，由于物种的灭绝，其详细的生态习性和活动模式无法得到更深入的了解。","breeding":"关于小笠原地鸫的繁殖行为和生长周期，因记录不足，具体信息缺失。","identification":"鉴于小笠原地鸫的稀有性和灭绝状态，与其他地鸫属鸟类的辨识特征无从考证。","protection":"IUCN：EX（已灭绝）","distribution":"小笠原地鸫的分布区域局限于日本东南部的小笠原群岛，具体为父岛，理论上的分布还包括兄岛及弟岛，但未得到证实。","other":"小笠原地鸫的灭绝可能与1830年后引入的哺乳动物捕食和栖息地破坏有关。"},{"name":"尼尔吉里地鸫","english_name":"Nilgiri Thrush","scientific_name":"Zoothera neilgherriensis","overview":"尼尔吉里地鸫（英文名：Nilgiri Thrush，学名：Zoothera neilgherriensis），是雀形目鸫科地鸫属的鸟类。大型的、金橄榄色的鸫科地鸫属鸟类，广泛分布在印度西南部的东洋界。曾被认为是小虎斑地鸫的亚种，现已被认定为独立物种。","appearance":"雄雌相似，体长约27至31厘米，具有黑色鳞状斑纹覆盖于淡白色或黄白色的底色之上。最显著的飞行识别特征是在白色的下翼上有一条黑色带纹，这一特征与西伯利亚地鸫共享。下腹部及臀部亦可见鳞状斑纹。","call":"雄鸟的鸣唱是一连串响亮、机械般的哨声，每次持续约一秒，两句话之间有5至10秒的停顿，形成了独特的twee...tuuu....tuuu....tuuu的节奏。","habits":"栖息于湿润、阴暗的地带，如森林中的沟壑和溪流旁，通常在浓密的常绿森林和雪松林中活动，海拔高度介于600至2100米之间。雨天时偶尔会在道路上出现。以昆虫为食，是机会主义的食虫者。","breeding":"关于其繁殖生态的具体细节尚缺乏详细记录。","identification":"与小虎斑地鸫极为相似，但分布范围并不重叠，通过特定的生境选择和鸣唱模式可以区分。","protection":"IUCN：LC（无危）","distribution":"分布于印度西南部的西方山脊，主要栖息于高海拔的云雾森林中，这些森林被起伏的高山草原隔开。","other":"此物种的分类历史复杂，直到1990年代之前，都被认为是小虎斑地鸫的一部分。"},{"name":"斯里兰卡地鸫","english_name":"Sri Lanka Thrush","scientific_name":"Zoothera imbricata","overview":"斯里兰卡地鸫（英文名：Sri Lanka Thrush，学名：Zoothera imbricata），是雀形目鸫科地鸫属的鸟类。大型、橄榄褐色的地鸫，特征是拥有黑色斑点覆盖全身，尤其是丰富的橙肉桂色下体。在斯里兰卡的低地和山地湿润森林中秘密生活，主要在森林底层活动。","appearance":"体长24厘米，上部橄榄褐色，黑色斑点密集，下部为橙肉桂色，斑纹未延伸至肛区。喉部偏白色，其余下体丰富肉桂色，黑色斑点显著，腹部和肛区带有白色。喙较大，黑色，下颚较淡；腿呈暗粉色。雌雄相似，幼鸟记录不明。","call":"其哀伤而低调的歌声是一系列下滑的哨声，开始音节强调，最后两个音节快速，\"cheeew-chew-lew\"。叫声包括几乎听不见的高音、短促、尖锐的\"tsit\"音。","habits":"居住于低地至山地的湿润森林，海拔600-1800米，偶尔出现在树丛、阴凉咖啡种植园和公园。以昆虫和其他叶床中的无脊椎动物为食，主要在地上觅食，翻动潮湿的落叶。","breeding":"繁殖期为2月至5月，7月至10月。巢为大型苔藓杯状，内部铺有细蕨根，通常位于密林中4-6米高的树苗或树上，有时在靠近森林边缘的茶田遮荫树上。每窝产卵2枚，颜色从蓝白色到浅橄榄绿，带有淡栗色斑点。","identification":"与小虎斑地鸫相比，体型较小，尾巴更短，下体颜色更丰富。与雌鸟Pied和斑翅地鸫的区别在于背部有大量黑色标记和下体的丰富橙肉桂色。","protection":"IUCN：NT（近危）","distribution":"主要分布在斯里兰卡西南部的低地至山地湿润森林。","other":"曾被认为与小虎斑地鸫同种，直到1990年代。分类复杂，有待解决。"},{"name":"黄胸地鸫","english_name":"Fawn-breasted Thrush","scientific_name":"Zoothera machiki","overview":"黄胸地鸫（英文名：Fawn-breasted Thrush，学名：Zoothera machiki），是雀形目鸫科地鸫属的鸟类。显著特征为褐色上部带有丰富的赤褐色背部和尾部，翅膀上的醒目白色斑点，以及淡金色的喉部和胸部。分布局限于印度尼西亚的Tanimbar群岛，包括Larat和Yamdena岛。","appearance":"体长约21至22厘米，上部呈温暖的中褐色，臀部和尾部略带红褐色，身体羽毛上有极轻微的深色鳞状斑纹；翅膀边缘较浅，具有两道明显的浅色翼条；喉部、胸部和腹部中央呈淡金色，轻微的黑色鳞状斑纹，逐渐过渡到白色的下腹和两胁，黑色鳞片更为密集；喙黑色，下颚基部黄色；腿为赭肉色。雌雄相似，幼鸟特征未知。","call":"其鸣唱由一系列笛声和哨音组成，叫声为短促的“tsit”。","habits":"栖息于森林和灌木丛中，常在地面单独觅食。活动范围主要限于Tanimbar群岛。","identification":"在Tanimbar群岛是唯一一种褐色地鸫，易于识别。","protection":"IUCN：NT（近危）。面临栖息地丧失的威胁。","distribution":"仅分布于印度尼西亚的Tanimbar群岛，具体包括Larat和Yamdena岛。","other":"黄胸地鸫是Tanimbar群岛特有的物种，受到自然环境变化的影响。"},{"name":"黄尾地鸫","english_name":"Russet-tailed Thrush","scientific_name":"Zoothera heinei","overview":"黄尾地鸫（英文名：Russet-tailed Thrush，学名：Zoothera heinei），是雀形目鸫科地鸫属的鸟类。栖息于温带森林和热带湿润低地森林。","appearance":"体型较大，成鸟上部呈深橄榄褐色，布满黑色鳞状斑纹，有两个浅棕色的翼带；喉咙白色，脸颊条纹呈淡红褐色；上胸淡红褐色，其余下部白色，均布满黑色鳞状斑纹；喙浅褐色；腿灰色偏粉或灰黄色。与绿尾地鸫相似，但略小，眼看似更大，臀部和上尾温暖的赤褐色，翼尖有更多白色。雌雄相似，幼鸟与成鸟非常相像，但暗色斑点不那么明显。","call":"鸣唱独特而纤细，下降音调的'whee-doo'声，与绿尾地鸫截然不同。","habits":"以蠕虫和软体动物为食，也会吃一些果实。在森林地面觅食，日出前后会到边缘地带和道路上。在新几内亚，Papuensis亚种被报道在觅食时缓慢摇摆。","breeding":"繁殖期为8月至次年1月。巢为大型杯状，由树皮条、干草和树叶制成，覆盖苔藓，内衬细根，置于离地高达15米的树杈或旧树桩上，隐蔽得很好。产卵数2-3枚（在新几内亚为2枚），蛋壳颜色为浅绿蓝至天空蓝，带有稀疏的栗色和陶土色斑点。无更多信息。","identification":"与绿尾地鸫相比，黄尾地鸫具有较小的喙外观，对比度更高的上部标记，飞行时尾端白色可见，而Bassian没有。此外，翼带在成年黄尾地鸫中比Bassian更突出。","protection":"IUCN：LC（无危）","distribution":"分布在新几内亚至St. Matthias（俾斯麦群岛中北部）、舒瓦瑟尔岛（所罗门群岛中北部）和澳大利亚中东部。","other":"存在四个亚种：Papuensis、Eichhorni、Choiseuli和Heinei，各自分布于不同的地理区域。"},{"name":"绿尾地鸫","english_name":"Bassian Thrush","scientific_name":"Zoothera lunulata","overview":"绿尾地鸫（英文名：Bassian Thrush，学名：Zoothera lunulata），是雀形目鸫科地鸫属的鸟类。中等体型、主要以昆虫为食的鸫科鸟类。分布广泛，自澳大利亚东北至东南部，包括塔斯马尼亚岛，以及部分较大岛屿如巴斯海峡和袋鼠岛。平均长度介于27至29厘米，体重约100克。绿尾地鸫栖息于林地、雨林和灌木丛，可能表现出一定程度的季节性游荡习性。","appearance":"绿尾地鸫拥有深橄榄棕色的上体，带有明显的黑色鳞状斑纹；下体较淡，亦具黑色鳞状斑点；喉咙白色，其余下体白色。嘴部中等大小，黑色，下颚较浅色；腿肉色。幼鸟上体暗纹更细，下体斑点多于鳞状。成年绿尾地鸫与小虎斑地鸫相似，但前者上体鳞纹更重，臀部至尾部呈橄榄色无红褐色调，翅膀尖端更白，翼条较长。","call":"绿尾地鸫的鸣唱由一系列三声远传的哨音颤音组成，首尾两声平稳，中间一声上扬，‘wheeer-aoo-whooo’，有时会继续为柔和的颤音亚歌。叫声包括高升的‘seep’作为接触信号，高音断续的蟋蟀般的‘chi-lit’在轻微警戒时发出，拉长的上升‘seeeee’回应‘chi-lit’，喂养幼鸟时发出平坦的‘seeeee’。","habits":"绿尾地鸫栖息于潮湿森林，常在落叶层中觅食，以蚯蚓、昆虫、软体动物和落果为主食。它采用静止-启动的觅食模式，静听并探查地面，成功率约为每4分钟一只蚯蚓，喂养双胞胎时提高至每分钟两只。","breeding":"繁殖期为7月至次年1月。筑巢为圆形杯状，由树皮条、树叶和草构成，外部伪装有绿色苔藓，内部铺垫根须，通常建于离地面高达15米的树桩、树蕨冠顶、高灌木或树木中。每窝产卵2至3枚，颜色从淡石灰色到淡奶油灰色，密布红褐色斑点。孵化期未知；雏鸟期14天。种族halmaturina的世代长度估计为4年。","identification":"绿尾地鸫与黄尾地鸫相比，嘴部显得更大，上体标记更不明显，尾巴角落无白色，而黄尾地鸫在飞行或整理羽毛时可见。欧歌鸫的下体有斑点而非鳞状标记。","protection":"IUCN：LC（无危）","distribution":"绿尾地鸫主要分布在澳大利亚的东北部、东南部、南部以及塔斯马尼亚岛，也在巴斯海峡的一些较大岛屿和袋鼠岛上发现其踪迹。","other":"绿尾地鸫在非繁殖季节可能表现出游荡倾向，但总体而言，它被认为是一个留鸟种。"},{"name":"新不列颠地鸫","english_name":"Black-backed Thrush","scientific_name":"Zoothera talaseae","overview":"新不列颠地鸫（英文名：New Britain Thrush，学名：Zoothera talaseae），是雀形目鸫科地鸫属的鸟类。种特有于巴布亚新几内亚的新不列颠岛、乌姆博伊岛和布干维尔岛。主要栖息在温带、亚热带或热带湿润的低地森林以及亚热带或热带湿润的山地森林。","appearance":"新不列颠地鸫的外观特征显著，背部呈黑色，这是其得名的由来。关于其具体的羽毛颜色、大小和性别差异的详细描述未提供。","habits":"新不列颠地鸫的栖息地选择多样，既可见于低地湿润森林，也能在山地森林中找到它们的身影。关于其迁徙、飞行特点、活动范围和觅食方式的具体信息未提供。","identification":"在某些分类系统中，布干维尔地鸫（Z. t. atrigena）被视作独立的物种，这基于其与新不列颠地鸫的形态和遗传差异。","distribution":"新不列颠地鸫的分布局限于澳新界，具体在新不列颠岛的山区（俾斯麦群岛东南部）和布干维尔岛（所罗门群岛北部）。"},{"name":"圣岛地鸫","english_name":"Makira Thrush","scientific_name":"Zoothera margaretae","appearance":"马基拉地鸫主要生活在地面，体形圆胖，全身呈锈褐色。胸部有复杂的鳞状斑纹，向喉部逐渐变淡且更加密集。翼上有两排白色斑点。它更倾向于行走和跳跃而非飞行。","call":"其常见叫声是一种非常高且尖细的‘tseeeep’声，容易被忽视。","habits":"马基拉地鸫偏好生活在森林浓密的下层植被中，尤其是溪谷地带，海拔高度在400至700米之间，偶尔也会出现在更低的区域。","identification":"与同属其他物种相比，马基拉地鸫的两排白色翼斑和特有的叫声是其辨识要点。","protection":"IUCN：NT（近危）","distribution":"马基拉地鸫仅分布于所罗门群岛东南部的马基拉岛（San Cristobal）。"},{"name":"瓜岛地鸫","english_name":"Guadalcanal Thrush","scientific_name":"Zoothera turipavae","overview":"瓜岛地鸫（英文名：Guadalcanal Thrush，学名：Zoothera turipavae），是雀形目鸫科地鸫属的鸟类。主要栖息于所罗门群岛中的瓜达尔卡纳尔岛（瓜岛）的山区。其特征为深色、灰暗的外表，头部和背部呈深棕色，腹部为乳褐色并带有厚重的斑纹，喉部和脸部的斑纹较细。该物种较为罕见。","appearance":"瓜岛地鸫是一种以地面活动为主的鸟类，拥有非常深沉、灰暗的体羽，头部和上体呈现深棕色，腹部为奶油棕色，带有着明显的鳞片状斑纹，这种斑纹在喉部和面部变得更为细致。它还具有一圈淡黄色的眼环，这一特征有助于识别。","call":"瓜岛地鸫的常见叫声是一串拉长的、尖锐、嘶嘶作响的‘tsss’声，音调高且持续。","habits":"该物种主要栖息于海拔1400米以上的森林地带，偏好湿润的亚热带或热带山地森林环境。尽管其栖息地可能位于瓜达尔卡纳尔岛的伐木活动之上，但已知岛上高海拔区域存在猫和鼠等哺乳类掠食者的威胁。","breeding":"关于瓜岛地鸫的繁殖生态信息尚不明确。","identification":"与形态相似的塔岛鸫相比，瓜岛地鸫具有黑色体羽、黄色腿、喙和眼环的特点，但两者的主要区别在于颜色差异。","protection":"IUCN：NT（近危）。这是一种分布范围受限的物种，仅存在于所罗门群岛群组的极小范围内。估计总成熟个体数量在250至1000之间，仅在1953年、1994年和1997年在其类型定位点被记录过三次。目前，引入的哺乳类掠食者如猫和鼠在岛上高海拔处较为常见，对物种构成了严重威胁。","distribution":"瓜岛地鸫的分布限于澳新界的瓜达尔卡纳尔岛山区，即所罗门群岛东南部。"},{"name":"大长嘴地鸫","english_name":"Long-billed Thrush","scientific_name":"Zoothera monticola","overview":"大长嘴地鸫（英文名：Long-billed Thrush，学名：Zoothera monticola），是雀形目鸫科地鸫属的大型灰褐色鸟类。其最显著特征是拥有异常长的喙。分布于喜马拉雅山脉至缅甸和越南的热带湿润山地森林。","appearance":"体型较大，长约26至28厘米，重115至131克。背部呈蓝灰色，头部深棕色，下体有斑驳的浅色。喙非常长且略带钩状，暗色。两性相似，幼鸟颜色更深，有橙色羽轴纹和斑点翼条。","call":"在黄昏或黎明时发出一系列哀怨的口哨声，通常为2至3个低沉的哨音，如“tsuweet-tsew-tsuw”，最后一个音符较低且最柔和。","habits":"偏好生活在湿润、阴凉的山地森林中，尤其沿溪流地带。以翻找落叶下的无脊椎动物为食，如蚯蚓。活动于多溪流的潮湿林下地表。","breeding":"繁殖期为5月至7月，巢为植被制成的深杯状，位于树叉或树枝上2至7米高处，产卵3至4枚，卵色从淡绿色到灰绿色或淡奶油色至暖色调的黄褐色，带有红棕色斑点。","identification":"与同属物种相比，其长喙是主要识别特征。幼鸟与成鸟的区别在于颜色更深，具有明显的橙色羽轴纹和斑点。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括喜马拉雅山脉，冬季迁移到海拔1000至2500米处；在东南亚的分布高度为900至2135米。在中国大陆，如云南德宏傣族景颇族自治州瑞丽市莫里瀑布附近也有记录。","other":"在尼泊尔仍被视为罕见和局部分布，而在缅甸和越南则较为稀缺。"},{"name":"长嘴地鸫","english_name":"Dark-sided Thrush","scientific_name":"Zoothera marginata","overview":"长嘴地鸫（英文名：Dark-sided Thrush，学名：Zoothera marginata），是雀形目鸫科地鸫属的鸟类。由爱德华·布莱斯于1847年首次描述，基于在缅甸（今缅甸）若开邦采集的标本。其最显著的外部特征是异常长的喙，全身呈深褐色，翼部带有红褐色调。分布于喜马拉雅山脉东部至泰国的高海拔地区。","appearance":"长嘴地鸫体长约24至25厘米，体重约81克。头部深棕色，与红褐色翅膀形成对比，面部有白色眉纹和眼圈，喉部和下巴白色。上体背部和尾羽红褐色，下体胸部密布灰色斑点，腹部斑点较大且稀疏。喙黑色，下颚较浅色，跗跖粉红色。雌雄相似，幼鸟与成鸟相比，上体颜色较浅，有黑色耳后条纹，翼上有橙色条纹和斑点，下体图案较不明显。","call":"发出一系列单调的细长哨音。","habits":"主要以昆虫为食，在湿润地带活动，特别是在溪流附近，会用其长喙在湿土和腐烂植被中挖洞觅食。通常栖息于海拔750至2100米的阔叶林中，偏好潮湿环境和岩石溪流旁，亦见于竹林和芦苇丛。非迁徙性，但在冬季会向下迁移至较低海拔。","breeding":"具体繁殖信息未详述。","identification":"与大长嘴地鸫相比，长嘴地鸫头侧颜色更深，下体有深色点斑而非鳞状斑纹。","protection":"IUCN状态未提及。","distribution":"分布于喜马拉雅山脉东部，间断至泰国。在缅甸北部、泰国北部、老挝、越南及中国极南部有零星分布。中国境内见于云南、西藏等地。","other":"由于其隐秘的习性和伪装的羽毛，可能经常被忽视。"},{"name":"杂色鸫","english_name":"Varied Thrush","scientific_name":"Ixoreus naevius","overview":"杂色鸫（英文名：Varied Thrush，学名：Ixoreus naevius），是雀形目鸫科杂色鸫属的鸟类。以其独特的黑橙蓝三色羽毛和穿透力强的诡异鸣声著称。分布于太平洋西北部的成熟湿润森林，冬季迁徙至太平洋沿岸地区，偶尔在美国西部及加拿大广泛地区可见。其别称源于其羽毛色彩的多样性。","appearance":"杂色鸫成年个体总长19.0-26.5厘米，体重65-100克。雄鸟特征鲜明，拥有蓝色至蓝灰色的背部、头部和颈部，橙色的眼眉和翼纹，以及明显的黑色V形胸带。雌鸟颜色较淡，上体呈棕橄榄色至棕灰色，胸带模糊。幼鸟类似雌鸟，但具淡色眼眉和斑驳的胸部羽毛。雄鸟喙呈深褐色，基部下方为稻草色；雌鸟喙色相似。腿色为中等至浅棕色。","call":"杂色鸫的鸣唱是一系列缓慢、幽灵般的长笛音，具有独特的穿透力和迷人的旋律，尤其在繁殖季节中听得到。","habits":"杂色鸫偏好成熟且湿润的森林，主要栖息在太平洋西北部的针叶林中。冬季，它们会迁移到更低海拔的地带，包括公园、花园和居民区，以果实、浆果和坚果为主食，同时也会摄取昆虫和无脊椎动物。繁殖季节，雄鸟会在领地内鸣叫以标记领地。","breeding":"繁殖期通常在春季至夏季，雌鸟选择巢址，雄鸟负责筑巢。巢一般位于离地4至50米处，杯状，内部衬有优质材料。每窝产2至5枚淡蓝色带褐色斑点的卵，由雌鸟孵化，孵化期约为两周。父母双方共同喂养雏鸟，大约13至14天后雏鸟离巢。","identification":"杂色鸫的黑橙蓝三色羽毛组合在北美独一无二，与旅鸫的雌鸟相比，杂色鸫的橙色眼眉和黑色胸带更为明显。在鸣声上，杂色鸫的长颤音易于识别。","protection":"IUCN：LC（无危）","distribution":"杂色鸫繁殖于从阿拉斯加至北加州的太平洋西北部，冬季南迁至太平洋沿岸，从阿拉斯加至南加州，偶见于美国西部及加拿大内陆。在繁殖季外，分布范围可能更广泛。","other":"杂色鸫在特定年份会发生爆发性迁徙，数量显著增加，这一现象每2-5年达到高峰。"},{"name":"阿兹特克地鸫","english_name":"Aztec Thrush","scientific_name":"Ridgwayia pinicola","overview":"阿兹特克地鸫（英文名：Aztec Thrush，学名：Ridgwayia pinicola），是雀形目鸫科阿芝鸫属的鸟类。偶尔有迷鸟出现在美国西南部。其显著特征为雄鸟具有深褐色头部和上体，翼部和尾部饰有白色斑纹，雌鸟较淡，下体偏灰。","appearance":"体长约21.5至24厘米，体重约67至88克。雄鸟具深棕色头颈及上背部，缀以白色点纹或条纹，翼部与尾部黑色，带有白色边缘与斑块；雌鸟色调较浅，下体偏灰，胸腹部条纹更为明显。幼鸟全身黑褐色，头部和背部饰有金黄色斑纹，下背呈肉桂色或红棕色，尾部黑色，腹部有鳞状斑点。","call":"主要叫声为颤音‘wheeerr’，金属质感的‘whein’，以及警报声‘sweee-uh’或‘tlee-zip’。","habits":"通常栖息于海拔1,800至3,500米的山地森林，偏好松林和松栎混交林中的沟壑地带。多单独或小群活动，偶尔加入混合鸟群觅食。食性包括浆果和昆虫，觅食时会抬头观察。","breeding":"繁殖季节从5月至6月，在南部范围内。筑巢于地面或低枝，巢呈杯状，由草和苔藓构成，产卵颜色为淡蓝色。","identification":"雄鸟与雌鸟的主要区别在于头部和上体的颜色差异，雌鸟更灰白，而雄鸟头部和上体呈深褐色。与同属其他物种相比，阿兹特克地鸫的翼部和尾部具有独特的白色斑纹。","protection":"IUCN：LC（无危）。尽管数量估计不足50,000只，但由于下降速度不足以达到易危标准，且范围和种群规模均超过易危门槛，故评估为无危。","distribution":"主要分布于墨西哥西部至中部的山区，偶尔迷鸟出现在美国西部得克萨斯州至东南亚利桑那州。","other":"曾被归入Turdus和Zoothera属，现独立于Ridgwayia属。"},{"name":"苏拉威西地鸫","english_name":"Sulawesi Thrush","scientific_name":"Turdus turdoides","overview":"苏拉威西地鸫（英文名：Sulawesi Thrush，学名：Turdus turdoides），是雀形目鸫科鸫属的中型。原生于印尼苏拉威西岛的山地森林，分布于海拔1100至2400米之间。其独特的橄榄褐色外观，橙黄色腿脚与喙，黑色眉纹，以及明亮的黄色眼环使其容易辨认。","appearance":"成年苏拉威西地鸫体长约20至25厘米，头冠暗褐色，眉纹宽黑，上身呈暗橄榄色，翅膀与尾巴颜色较深，下体较淡，腹部接近白色。嘴、眼环和腿均为鲜明的橙黄色。雌雄相似，幼鸟下体具斑点。不同亚种在色泽上有所差异。","call":"其鸣唱富于旋律，带有笛音的哀婉曲调，由一系列短而丰富的笛状乐句组成，有时会融入模仿声。还会发出喋喋不休的叫声和尖细的\"tsip\"声。","habits":"苏拉威西地鸫常出现在茂密下层植被的山地常绿森林与苔藓森林中，高度范围在1100至2400米。它既在地上觅食也在林下层活动，以小果实和昆虫为食。偶尔加入混种群，或单个或小群体出现。","breeding":"关于繁殖习性的信息目前尚未记录。","identification":"与苏拉威西山鸫和塔岛鸫相比，苏拉威西地鸫具有黑色眉纹且腹部无红棕色。相对于苏拉威西山鸫，其尾部更短。","protection":"IUCN：LC（无危）","distribution":"苏拉威西地鸫仅限于印尼苏拉威西岛的山地森林，特别是在洛雷林杜国家公园内有记录。","other":"此物种历史上曾被分类在不同的科属中，近期研究确认其为鸫属的一员，属于高度分化的种类。"},{"name":"非洲地鸫","english_name":"Groundscraper Thrush","scientific_name":"Turdus litsitsirupa","overview":"非洲地鸫（英文名：Groundscraper Thrush，学名：Turdus litsitsirupa），是雀形目鸫科鸫属的鸟类。别称源自其独特的地面刮食行为。体长约22-24厘米，具有灰褐色上体，白色且密布黑斑的下体，以及带有明显黑色标记的白色脸部。翼下有黑色和白色的图案，飞行时尤为显眼。该物种广泛分布于东非和南非的高地。","appearance":"非洲地鸫为中等体型，翼宽而尾短，站立时姿态挺拔。冠至尾部呈浅灰褐色，飞行羽深色，内侧有宽阔的橙色斑块，仅在飞行或振翅时可见。脸部及下体呈淡黄色，具粗大的垂直黑色眼纹，耳羽条纹及狭窄的颊纹均为黑色，腹部至下腹处有放射状黑色斑点。喙黑色带橙色下颌，腿黄色。雌雄相似，但雌鸟斑点较淡。幼鸟颜色更深，上体有更多淡色斑点，下体黄色更浓。","call":"鸣唱由响亮、缓慢的短乐句组成，结合尖锐的‘tsik’叫声和高音下滑哨声，偶尔发出沙哑的哨音。报警时发出‘tsi-tsi-tsi-rufa’的叫声，伴有空洞的咔哒声和咯咯声，有时模仿其他物种的叫声。","habits":"栖息于高海拔草地、开阔林地、次生林和耕作或放牧地带，偏好重度放牧和烧荒地区。活动范围包括埃塞俄比亚和厄立特里亚的高地，以及南部非洲的开放或次生森林地带。以昆虫及其幼虫为主食，如苍蝇、白蚁、蚱蜢、甲虫等，也会捕食蜘蛛、等足类、蛞蝓、蚯蚓、石龙子和果实。在开阔地带觅食，常在落叶中刮食。","breeding":"繁殖季节通常在7月至10月间，筑杯状巢，直径约7-9厘米，深度4-7厘米，主要由根、藤蔓、枝条和长茎构成，有时加入羊毛和粪便，内部可能衬以细根和草。巢置于树叉中，距离地面1.5-7米，常见于树干旁或水平叉中，靠近水域或与叉尾卷尾的巢相距不远。每窝产卵1-4枚，通常2-3枚，蛋色从浅奶油蓝到绿蓝色，带有紫罗兰色、灰色和红棕色斑点。孵化期14-15天，双亲共同孵化；雏鸟期16天，父母照顾长达六周，直至独立。","identification":"与同属的其他物种相比，非洲地鸫具有独特的橙色翼斑和脸部标记。此外，其鸣唱和叫声也具有辨识度。","protection":"IUCN：LC（无危）","distribution":"非洲地鸫广泛分布于东非和南非的高地，包括埃塞俄比亚、厄立特里亚、刚果民主共和国、坦桑尼亚、马拉维、安哥拉、莫桑比克、赞比亚、津巴布韦、纳米比亚、博茨瓦纳和南非的部分地区。","other":"非洲地鸫有时会表现出合作繁殖行为，最多有四只成年鸟喂养幼鸟。"},{"name":"黄腿鸫","english_name":"Yellow-legged Thrush","scientific_name":"Turdus flavipes","overview":"黄腿鸫（英文名：Yellow-legged Thrush，学名：Turdus flavipes），是雀形目鸫科鸫属的中型鸣禽。雄鸟具有鲜明的黑头至胸、黑翼和尾巴，背部与下体为暗灰色调，而雌鸟则全身呈暖褐色，腹部略浅且带有橙色调。该物种分布于南美洲北部和东南部，包括哥伦比亚北部、委内瑞拉、巴西东北部、特立尼达和多巴哥、玛格丽塔岛以及巴西东部、巴拉圭东部和阿根廷东北部的部分地区。","appearance":"黄腿鸫体型长约22厘米，体重在55至72克之间。雄鸟的头部、胸部、翅膀和尾巴为黑色，其余部位为灰蓝色，而雌鸟上身呈暖褐色，下体颜色较浅，带有少许橙色。两者均拥有黄色的喙、眼环和腿。幼鸟雄鸟表现为灰褐色，翅膀和尾巴为黑色，雌鸟幼鸟与成年雌鸟相似，但带有更多的橙色斑点。","call":"黄腿鸫的鸣唱高度变化，由一系列可变但重复的短语组成，有时优美悦耳，有时尖锐刺耳，包括模仿其他鸟类的歌声，尽管在巴西东南部和特立尼达的模仿质量较差。其叫声包括典型的‘tsrip’声，以及在警戒时发出的奇特‘seeeet’声。","habits":"黄腿鸫主要以水果为食，如Myrcia、Sloanea和matchwood等植物的果实，偶尔也食用昆虫。它们通常在树冠层活动，偶尔会到地面觅食。常见于海拔500至1500米的森林、林缘和花园中，但也有在更低或更高海拔处发现的记录。","breeding":"繁殖期在哥伦比亚为6月，特立尼达为3月至7月，巴西南部为11月至1月。巢穴通常是一个浅杯状结构，由根茎和泥土构成，外部覆盖苔藓，内部铺细根，位于溪谷的河岸或岩石缝隙中。在巴西东南部，巢穴有时建在附生凤梨的茂密叶片中。每窝产卵2枚，卵色为淡蓝至绿蓝色，带有红棕色斑点。","identification":"与黑冠鸫的雌鸟比较，黄腿鸫的雌鸟具有更黄色的喙和眼环。亚种之间存在差异，如venezuelensis亚种雄鸟的背部和腹部颜色更灰白，chin部白色；polionotus亚种雌鸟头部至尾巴颜色更灰；melanopleura亚种雄鸟腹部黑色更多；xanthoscelus亚种雄鸟全身黑色。","protection":"IUCN：LC（无危）","distribution":"黄腿鸫分布于南美洲北部，包括哥伦比亚北部、委内瑞拉、巴西东北部、特立尼达和多巴哥、玛格丽塔岛；以及东南部的巴西东部、巴拉圭东部和阿根廷东北部。在巴西里约热内卢和埃斯皮里托桑托较为常见，但在南里奥格兰德州则较少见。","other":"黄腿鸫的分类存在争议，部分分类学家将其置于Platycichla属，但多数分类系统如AOU和IOC将其归于Turdus属。"},{"name":"淡眼鸫","english_name":"Pale-eyed Thrush","scientific_name":"Turdus leucops","overview":"淡眼鸫（英文名：Pale-eyed Thrush，学名：Turdus leucops），是雀形目鸫科鸫属的鸟类。分类上存在争议，部分分类学家基于形态学证据将其归入Platycichla属。分布于南美洲的委内瑞拉至玻利维亚一带，偏好生活在海拔1000至2000米的亚热带湿润山地森林。","appearance":"雄性淡眼鸫全身深黑色，拥有醒目的浅色眼睛、橙色喙和腿；雌鸟呈深褐色，喙较暗，腹部带有斑点，眼圈不明显。幼鸟类似雌鸟，但背部带有橙色斑纹，腹部有棕色到黑色的斑驳。","call":"雄鸟在树顶歌唱时发出响亮而复杂的鸫类鸣声，间歇性长停顿，声音多变且复杂，有时模仿其他鸟类的声音。","habits":"主要以果实和浆果为食，在树林中悄悄觅食，偶尔成小群聚集在结果的树木中，也会在林内地面上觅食，常见其跟随行军蚁群。","breeding":"繁殖季节在委内瑞拉为4月至6月，厄瓜多尔为12月至6月。巢通常建在树上，高度1.2至3.2米，由苔藓和植物纤维构成。每窝产卵2枚，极少数1枚，卵橄榄绿至淡蓝色，带有红棕色斑点。雌鸟独自孵化，双亲共同照顾雏鸟，孵化期14天，雏鸟期18天。","identification":"淡眼鸫与其它相似的鸫类的区别在于两性均无眼圈，雄鸟特有的浅色眼睛和橙色喙及腿。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉、哥伦比亚、秘鲁至玻利维亚，以及巴西、圭亚那的部分地区，具体","other":"在哥伦比亚西部（乔科）较为罕见和局部，而在委内瑞拉则稀少至少见，但在厄瓜多尔的波多卡普斯国家公园中数量较为可观。"},{"name":"非洲鸫","english_name":"African Thrush","scientific_name":"Turdus pelios","overview":"非洲鸫（英文名：African Thrush，学名：Turdus pelios），是雀形目鸫科鸫属的鸟类。广泛分布于西非至中非的广阔地带，常见于树木茂密的环境。其上部灰褐色，下部颜色变化多样，包括浅黄色、灰色或红棕色，具有一张醒目的黄色喙。非洲鸫在不同的地理区域展现出了丰富的变异性。","appearance":"非洲鸫身长21-23厘米，体重46-78克，头部至尾部呈暗橄榄灰色，侧面喉部均匀地带有棕色条纹，胸部呈灰褐色，侧腹为淡橙色，这种色彩并不延伸到下胸，腹部和臀部为白色，喙呈黄色至橙色。幼鸟颜色更偏棕色，身上有橙色条纹，下部白色，腹部有斑点，胸部和侧腹有橙色斑块，侧胸为灰色。","call":"鸣唱持续而清晰，由一系列不同的短语组成，重复模式较为随机，此外还发出尖锐的高音尖叫飞行叫声。","habits":"栖息于各种木本生境，包括森林边缘、河岸林地、灌木丛、农田、公园和花园。活动时间集中在清晨和黄昏，以昆虫为主食，也吃果实、种子、小鱼等。偶尔会在石上敲开蜗牛壳。","breeding":"繁殖期横跨全年，但在雨季达到高峰。筑杯状大巢，常用植物纤维和泥巴建造，内衬细草、叶子和根，通常建在离地面不到10米的树枝上或藤蔓间。一窝通常产2-3枚蛋，由雌鸟孵化，双亲共同喂养幼鸟，有时一年会繁殖两次。","identification":"与橄榄鸫相似，但分布于较低海拔地区，一般较淡，喙色较浅。不同亚种在颜色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于西非至中非，包括塞内加尔、冈比亚至南苏丹、埃塞俄比亚和厄立特里亚，南至赞比亚西北部和安哥拉西部。","other":"曾被认为是橄榄鸫的同种，现已明确为独立物种。"},{"name":"非洲裸眼鸫","english_name":"Bare-eyed Thrush","scientific_name":"Turdus tephronotus","overview":"非洲裸眼鸫（英文名：Bare-eyed Thrush，学名：Turdus tephronotus），是雀形目鸫科鸫属的鸟类。其独特的外观由灰色、红褐色和白色构成，具有橙色的喙和环绕眼睛的裸露皮肤。在干燥地带广泛分布，从埃塞俄比亚南部至肯尼亚、索马里中部到坦桑尼亚中部，常见于多种生境中的茂密灌木丛。","appearance":"体长20.5至21.5厘米，体重45至55克。头部至胸部呈中灰色，背部暗灰；喉部白色，饰有黑色条纹；腹部橙色；显著特征为宽大的黄橙色眼圈，喙橙色，基部更黄；腿淡橙色。两性相似。幼鸟与成鸟类似，但颜色较褐，上部具棕褐色斑点和条纹，下部少有灰色，眼圈较为暗淡。","call":"常见的叫声为短暂低沉的颤音，歌声则是一种低沉的组合，包含闲聊般的哨音和颤音，间歇频繁。","habits":"栖息于多种环境，包括干燥荆棘草原、灌木丛和林地，偏好岩石区和水道附近的区域，主要分布在半干旱低地，但也会出现在果园和其他植被茂盛的耕作区，海拔可达1750米。相较于非洲鸫，它生活在更干燥的环境中。","breeding":"繁殖季节与雨季同步，具体繁殖行为资料不足。","identification":"与非洲鸫和橙腹鸫有轻微范围重叠，但在这些区域，非洲裸眼鸫通过其独特的眼周裸皮容易识别。","protection":"IUCN：LC（无危）","distribution":"分布于埃塞俄比亚南部、索马里中部、肯尼亚和坦桑尼亚中部，常见于沿海低地，局部地区数量较多，如肯尼亚的Tsavo东国家公园和坦桑尼亚的Mkomazi野生动物保护区。"},{"name":"橙腹鸫","english_name":"Kurrichane Thrush","scientific_name":"Turdus libonyana","overview":"橙腹鸫（英文名：Kurrichane Thrush，学名：Turdus libonyana），是雀形目鸫科鸫属的鸟类。常见于非洲中南部，主要栖息在干草原、森林边缘和多种林地环境。以灰色头部和上体、白色腹部、橙色胁部及独特的亮橙色喙和眼环为显著特征。","appearance":"体长21至23厘米，体重约46至82克。头、背部及胸部呈灰橄榄色，腹部白色，两侧有黑色条纹，胁部橙红色。喉部白色，基部黄色转淡。两性相似，幼鸟与成鸟有细微差别，头部更偏灰，胁部橙色更深。不同亚种颜色稍有差异。","call":"发出一系列变化多端的笛音和哨声，通常以高音颤音或嘶嘶声结尾。有时模仿其他鸟类叫声。","habits":"偏好米翁博树林、金合欢林地等生境，偶尔出现在公园和花园。主要以昆虫为食，包括甲虫、蚱蜢、毛虫等，也吃蚯蚓、软体动物、蜘蛛等，以及果实和种子。主要在地面觅食，偶尔在空中捕食。","breeding":"筑巢于大树叉间，巢由树枝、草、苔藓等构成，放置高度1至10米。每窝产卵1至4枚，通常3枚，孵化期12至14天，雏鸟期13至16天，出巢后依赖父母至少两个月。赤胸杜鹃有时寄生其巢。","identification":"与非洲鸫类似，但后者喙黄色而非橙色。幼鸟与斑点鸫幼鸟相似，但头部更灰，胁部更橙。","protection":"IUCN：LC（无危）","distribution":"分布于安哥拉、博茨瓦纳、刚果民主共和国、斯威士兰、莱索托、马拉维、莫桑比克、纳米比亚、南非、坦桑尼亚、赞比亚和津巴布韦。","other":"在某些地区，如南非较高海拔处较为罕见，但在过去一个世纪内其分布范围已显著扩大。"},{"name":"圣多美鸫","english_name":"Sao Tome Thrush","scientific_name":"Turdus olivaceofuscus","overview":"圣多美鸫（英文名：Sao Tome Thrush，学名：Turdus olivaceofuscus），是雀形目鸫科鸫属的鸟类。大型的橄榄褐色鸫科鸟类，具有黄色尖端的暗色喙和鳞状下体。仅在非洲圣多美岛上发现，为该岛常见居民，广泛分布于树荫环境。","appearance":"成鸟长约24厘米，重75至95克。头部至尾部呈暗淡橄榄褐色，头略深色。下巴到喉咙为灰褐色，带有白色条纹，胸部具灰褐色鳞片，逐渐过渡到白色下体上的灰褐色斑点。橙黄色的翼下覆羽与乳白色次级飞羽形成对比。眼睛棕色至红色，喙大而暗，尖端较淡黄色，腿为深棕灰色。雄雌相似。幼鸟上部轻微斑驳，下部重重斑点。","call":"鸣唱为悦耳、丰富、变化多端的哨声混合，‘wee-eet wheeeoo, cheee chirrit’，音调起伏，通常在黎明和黄昏时分发出。","habits":"以甲虫、臭虫、毛虫、蚯蚓和蜗牛为食，包括长达8厘米的特有种Columna columna蜗牛。也大量食用果实，如果园中的番石榴和鳄梨，以及次生环境中Spondias cytherae和Cecropia的果实。在森林中，尤其是无花果，包括Ficus sur, F. kamerunensis和F. fernandesiana。在地面落叶层中觅食，从椰子串中觅食，可能部分夜行。常在‘砧石’上砸碎蜗牛壳。","breeding":"繁殖季节为7月末至1月，高峰期为10月至12月。巢为一个由干植物物质和泥巴制成的大杯状巢（130至170毫米×60至80毫米），外部覆盖枯叶、苔藓和交错的枝条，内部铺有叶片骨架和草茎，通常放置在离地面0.5至4米的浓密植被中。每窝产卵两枚，蓝绿色，带有深红和紫褐色斑点，大小为27至33.1毫米×20至23.1毫米。许多巢被棕色鼠（Rattus rattus）破坏。","identification":"唯一在圣多美岛上的鸫类，通过其橄榄褐色外观、黄色尖端喙和鳞状下体辨识。与普林西比岛上的普林西比鸫非常相似，有时被认为是同一物种的不同岛屿变种。","protection":"IUCN：LC（无危）。之前被认为接近受威胁。全球数量不大，但在适宜的栖息地中广泛且常见。圣多美岛的云雾林高海拔地区密度较低，暗示全球数量较小。可可种植园的遮阴树木移除是局部威胁；土地私有化和东西海岸的道路开发对岛上的原始森林安全构成一些担忧。","distribution":"仅分布于圣多美岛（几内亚湾群岛南部）。"},{"name":"普林西比鸫","english_name":"Principe Thrush","scientific_name":"Turdus xanthorhynchus","overview":"普林西比鸫（英文名：Principe Thrush，学名：Turdus xanthorhynchus），是雀形目鸫科鸫属的鸟类。为普林西比岛特有种，曾被认为是绿棕鸫的亚种。其特征包括大体型、棕色羽衣、蓝灰色眼睛、鲜黄喙及鳞状腹部。分布于低地至中海拔森林，高度介于100至800米之间。","appearance":"该物种体长约24厘米，头部至尾部呈暗橄榄褐色，头部颜色较深。下巴与喉部为淡褐色带白色条纹，胸腹部具不规则的暗褐色斑点。成鸟较绿棕鸫小，下部斑点更粗且不均匀，喉咙更白，无连续的胸带，翼下覆羽呈淡赭色，次级飞羽对比明显，虹膜蓝白色，眼环黄色，喙与腿为醒目的黄色。雌雄相似，幼鸟特征未详尽描述。","call":"其歌声为多变的哨音组合，通常在黎明和黄昏时分发出，报警叫声为典型的‘dzzrt’声。","habits":"栖息于低地和中海拔原始森林的下层与中层，偏好山谷底部和山脊地带，海拔100至约800米间，密度最高处位于400至600米之上。在次生林和种植园中似乎不存在。","breeding":"相关繁殖信息缺失。","identification":"与圣多美鸫相比，普林西比鸫较小，下体斑点更暗、更粗且分布不均，喉咙更白，无连续胸带，翼下覆羽颜色对比明显。叫声与绿棕鸫有区别。","protection":"IUCN：CR（极危）","distribution":"仅限于几内亚湾的普林西比岛。","other":"自1997年重新发现以来，仅在岛上的少数剩余原始森林（约45平方公里）中被记录，受Parque Natural d’Obaô do Príncipe保护区庇护。2007年的调查显示，成熟个体数量少于250只，面临栖息地丧失和猎捕威胁。"},{"name":"橄榄鸫","english_name":"Olive Thrush","scientific_name":"Turdus olivaceus","overview":"橄榄鸫（英文名：Olive Thrush，学名：Turdus olivaceus），是雀形目鸫科鸫属的鸟类。在非洲东南部广泛分布的鸫科鸫属鸟类。其分布区内最为常见的鸫科成员之一，自南部马拉维和莫桑比克向南延伸至好望角。这种鸟主要栖息于森林和林地环境，但在一些郊区公园和大型花园中也能适应生存。","appearance":"成年橄榄鸫体长可达20-24厘米，体重介于60-101.5克之间，具体因亚种而异。上身呈暗橄榄色，下身则为赤褐色。喉部白色，带有深棕色条纹，胸部有橄榄灰色带，腹部橙色至肛门处，尾下覆羽白色带暗尖。喙颜色为黄色至黄橙色，腿脚呈黄褐色。雌雄外观相似。幼鸟外观与成鸟类似，但背部有斑点，翅膀覆羽上有浅色斑点，下身更淡且有重斑点。不同亚种在色彩上有细微差异。","call":"橄榄鸫的鸣唱包含笛声、哨音和颤音的混合，具有地域性变化，偶尔模仿其他鸟类的声音。叫声包括尖锐的'chink'，柔和的'chk-chk-chk'，粗犷的'gew'或'gew-gew'以及责备般的'tsrk tsrk'。","habits":"橄榄鸫主要栖息于各种类型的高地森林，也会出现在低地林地、灌木丛、异域种植园（如松树）、密集未烧的fynbos、花园（尤其是在干旱地区的旱季）、公园和卡拉哈里半沙漠水道旁的金合欢灌木丛中。它广泛分布在海拔1400-2200米的马拉维，1600-1900米的莫桑比克，以及900-2200米的津巴布韦。","breeding":"繁殖季节在津巴布韦为9月至次年1月，在南非的东北部高峰为9月至11月，在西部开普省全年皆可繁殖，高峰期为8月至11月和2月至4月。巢由小枝、根须、树皮、草、苔藓、地衣、树叶和蕨类构成，通常位于树、灌木或藤蔓上的叉枝间，高2-5米。每窝产卵1-4枚（通常2-3枚），孵化期为14天，由雌鸟单独孵化，雏鸟孵化后16天离巢，几天后就能飞行。","identification":"橄榄鸫与相似的非洲鸫相比，颜色更深，下方橙色更为广泛和深沉，喙基部通常更橙色。与南非鸫的区别在于后者侧翼为灰色而非赤褐色，眼环为黄色而非棕色，喙上颌基部为黄色而非深棕色，喉咙条纹较少。","protection":"IUCN：LC（无危）","distribution":"橄榄鸫广泛分布于非洲东南部，从南部马拉维和莫桑比克到南非的好望角。在南非，它在上世纪30年代至80年代期间大大扩展了其分布范围，有时在郊区地区以高密度繁殖，例如在开普敦的一个3.5公顷的公园中就有36对。"},{"name":"乌山鸫","english_name":"Usambara Thrush","scientific_name":"Turdus roehli","overview":"乌山鸫（英文名：Usambara Thrush，学名：Turdus roehli），是雀形目鸫科鸫属的鸟类。生活在东非的鸫科鸟类。过去曾被视为橄榄鸫的一个亚种，现已确认为独立物种，且已知与橄榄鸫存在杂交现象。","appearance":"这是一种中等体型的鸟，身长可达24厘米，翼展介于117至133毫米之间，喙长20至24毫米，跗跖长度在30至34.5毫米范围内，体重至少可达86克。成年乌山鸫头部深灰，背部呈暗棕色，喉咙为灰色并带有细淡色条纹，上胸逐渐变为更灰而少棕色，下胸和腹部白色，两胁淡橙色，大腿部分灰色或沙色，尾下覆羽白而尖端暗。喙黄色至橙红色，腿脚黄褐色。雌雄相似，幼鸟上部斑驳淡橙色，肩羽和翼覆羽有淡色斑点，下体较淡，胸部有重黑色斑点。","call":"其叫声特征尚未明确与近似种橄榄鸫的区别，但有报道指出两者间可能存在明显的差异。具体细节目前尚未公开。","habits":"乌山鸫栖息于坦桑尼亚东北部的帕雷山脉和乌桑巴拉山脉的原生和次生森林中，偏好未受干扰的地带，海拔范围约900至2300米，偏好林下层开阔但树冠封闭的环境。在森林边缘也能找到它们的身影，但不会出现在紧邻的小农耕作区。在森林之外，它们的位置被另一种鸫鸟Turdus libonyanus所替代。","identification":"乌山鸫与东非鸫外观相似，但二者分布范围不重叠。辨识时需留意其独特的暗脸、黄色喙和条纹喉部。","protection":"IUCN：NT（近危）","distribution":"乌山鸫的分布局限于非洲坦桑尼亚东北部的帕雷山脉和乌桑巴拉山脉，属于狭域物种，分布于坦桑尼亚-马拉维山区生态区。在东乌桑巴拉山脉的阿马尼自然保护区有其栖息地。"},{"name":"东非鸫","english_name":"Abyssinian Thrush","scientific_name":"Turdus abyssinicus","overview":"东非鸫（英文名：Abyssinian Thrush，学名：Turdus abyssinicus），是雀形目鸫科鸫属的鸟类。分布于非洲东部高海拔地区的鸫科鸫属鸟类。其分布范围自埃塞俄比亚南部至坦桑尼亚北部，包括索马里北部和非洲大湖区域到赞比亚东北部及马拉维。该鸟种具有显著的地域变异。","appearance":"东非鸫长约22厘米，上体呈深褐色至橄榄灰色，前额、头顶、眉纹和耳羽颜色较深，下体自喉部至腹部呈现不同程度的橙红色，腹下部白色。喙和眼环橙色，腿脚赭黄色。性别相似，幼鸟具条纹，翼覆羽具淡色斑点，下体有重斑点。不同亚种在颜色上有细微差异。","call":"其鸣唱为一系列悦耳、变化丰富的哨音和颤音，间歇频繁。","habits":"栖息于多种高海拔山区环境，如森林、花园和灌木丛。通常在地面或附近活动，以跳跃方式觅食。食谱广泛，包括昆虫、蠕虫、软体动物、蜘蛛、小鱼和各种果实。偶尔在枝头捕食昆虫，果实主要在树冠层取食。","breeding":"具体繁殖习性研究较少，因其曾被认为是橄榄鸫的亚种。","identification":"与非洲鸫相比，东非鸫整体更暗，喙为橙色而非黄色，无颊纹。随海拔升高，颜色渐深。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部，自索马里北部至坦桑尼亚北部，向南可达莫桑比克北部。","other":"曾与橄榄鸫视为同一物种，后因遗传差异而独立分类。"},{"name":"南非鸫","english_name":"Karoo Thrush","scientific_name":"Turdus smithi","overview":"南非鸫（英文名：Karoo Thrush，学名：Turdus smithi），是雀形目鸫科鸫属的鸟类。传统上，被视作橄榄鸫的一个亚种，但现今越来越被认定为独立物种。物种名称以苏格兰军事外科医生兼自然学家Sir Andrew Smith命名。","appearance":"该中型鸟类长约24厘米，翼展介于117至131毫米之间，喙长20至24毫米，跗跖长度为30.0至34.5毫米，体重至少可达86克。其显著特征为橄榄褐色的上体，腹部中央呈赤褐色，侧面和两胁为灰褐色，下腹部橙色较暗淡且局限。成年个体上体颜色比橄榄鸫更偏褐色，前喉部为暗褐色而非白色，喉部条纹更细且颜色更浅，下体颜色更灰且橙色区域更小，尾下覆羽呈淡黄色。喙全黄，不同于橄榄鸫的黑色喙尖。两性相似，幼鸟具斑点，羽色更淡。","call":"鸣唱多样，典型thrush的‘chk-chk’或细薄的‘tseeep’叫声。然而，关于其具体声学细节的研究尚未详细展开。","habits":"栖息于干旱草原、沙漠、半沙漠及卡鲁地区的浓密灌木丛和乔木林，常见于南非高原的河流边、异域种植园、花园、公园和果园。适应力强，尤其在分布区东部的都市环境中。在分布区西南部，偏好沿河和溪流的更干燥地带，而橄榄鸫则偏好树木茂密的环境、密集的河岸植被和花园。两者生态位有所重叠。","breeding":"相关信息未详述。","identification":"与橄榄鸫的区别在于：侧腹非赤褐色而是橄榄色，眼圈为橙色而非棕色，上喙基部颜色为黄色而非深棕色，且喉部条纹更明显。在分布区内，可通过上述特征与橄榄鸫进行区分。","protection":"IUCN：LC（无危）。在博茨瓦纳和南非普遍较为常见，但在纳米比亚罕见，可能接近其耐受干旱条件的边缘。自20世纪30年代至80年代，在南非范围内显著扩展了栖息地，特别是在郊区，能以高密度繁殖。","distribution":"分布于纳米比亚南部、博茨瓦纳东南部和南非北部，包括Little Namaqualand、Karoo、北方省、自由州、豪登省、林波波省、姆普马兰加省及西北省部分地区。","other":"曾与橄榄鸫杂交，现被视为独立物种。"},{"name":"索马里鸫","english_name":"Somali Thrush","scientific_name":"Turdus ludoviciae","overview":"索马里鸫（英文名：Somali Thrush，学名：Turdus ludoviciae），是雀形目鸫科鸫属的典型鸫类，体型和颜色均具特色。全身大部分呈深黑色，腹部略显灰色，拥有醒目的黄色喙、眼圈和腿脚。分布于索马里北部山区特有的杜松和哈格尼亚树林。","appearance":"雄鸟成鸟呈蓝灰色，头部、面部和喉部颜色更深，腹部逐渐变浅至灰色；尾下覆羽边缘泛白，翼下覆羽带橙色。雌鸟头部略显棕色，下巴和喉咙带有黑色条纹，胸部渐变为浅灰色。幼鸟色泽更淡，背部斑点和条纹灰褐色，腹部杂以灰褐色斑点，喙色较暗。","call":"其鸣叫特征记录不多，已知会发出典型的鸫类歌曲般的鸣唱，以及尖锐的“chk-chk”叫声。","habits":"栖息于海拔1,300至2,000米的山地杜松林地带，偏好开放区域。关于迁徙习性和具体活动范围的信息尚不充分。","identification":"与其他鸫类相比，索马里鸫的显著特点是全身深黑的羽毛和黄色的喙、眼圈及腿脚。雌雄之间在色泽上有细微差异。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲索马里北部山区，特别是在蒙塔涅地区。","other":"近年来，索马里鸫的栖息地破坏程度低于最初预测，得益于当地保护努力，其保护等级已从极度濒危下调至易危。"},{"name":"肯尼亚鸫","english_name":"Taita Thrush","scientific_name":"Turdus helleri","overview":"肯尼亚鸫（英文名：Taita Thrush，学名：Turdus helleri），是雀形目鸫科鸫属的鸟类。极度濒危的鸟类，原产自肯尼亚东南部的泰塔山，仅限于该地区的潮湿森林，体长介于20至22厘米，头、胸和上半身呈深色，腹部白色，两翼带红褐色，喙、眼圈和腿为橙黄色。1985年起被视为独立物种。","appearance":"体长约20至22厘米，体重53至89克。头部和喉部黑色，上半身黑灰色；胸部暗灰，腹部中央白色，两侧暗红褐色；喙、眼圈和腿橙黄色。与 roehli相似，但颜色更深。雌雄外观相似，幼鸟颜色较淡。","call":"其鸣唱类似于，但在每句结尾有更丰富和缓慢的音调，常在隐蔽处或黄昏时歌唱，飞翔中亦会鸣唱。接触叫声为尖锐高音的‘tseee’，警戒声为柔和的‘chook’。","habits":"栖息于泰塔山残留的山地森林底层，以多种无脊椎动物为食，也吃季节性水果，如Canthium oligocarpum、Rapanea melanophloeos和Xymalos monospora的果实，偏好在落叶层觅食，通常活动高度低于2米。在Mbololo和Ngangao，黄昏时会聚集在有水源的地方。","breeding":"具体繁殖信息未详述。","identification":"与 roehli相比，头部、喉部、胸部和上半身颜色更深。在泰塔山的小范围内，是独特的物种。","protection":"IUCN：EN（濒危）。全球估计数量约1350只，仅存于泰塔山三块小森林碎片，面临严重威胁。","distribution":"仅分布于非洲东南部的肯尼亚泰塔山，包括Mbololo、Chawia、Yale和Ngangao四片森林。","other":"肯尼亚森林部门正努力保护剩余的森林碎片，避免农业、薪柴采集和非本地树种种植造成的破坏。"},{"name":"也门鸫","english_name":"Yemen Thrush","scientific_name":"Turdus menachensis","overview":"也门鸫（英文名：Yemen Thrush，学名：Turdus menachensis），是雀形目鸫科鸫属的鸟类。但色彩相对暗淡，主要呈棕色，喉部与胸部带有深色条纹，喙黄色，雌鸟比雄鸟略显苍白。分布于欧亚大陆及非洲北部的特定山区，特别是在沙特阿拉伯西南部和也门西部的萨拉瓦特山脉。","appearance":"也门鸫体型中等，长约23厘米，体重介于72至79克。雄鸟上半身橄榄褐色，下半身较浅且带灰，有细密的深褐色条纹均匀排列在灰白的下巴、喉咙及胸腹部。雌鸟颜色稍淡，下方更偏黄褐色，有时可见腹侧及胁部的暗色羽轴纹。喙和眼圈均为黄色，腿色较为暗淡。幼鸟特征未详，但幼鸟时期的喙为深色。","call":"其鸣唱结合了哨音和颤音，整体听起来比一般鸫类的歌声更为干涩和缺乏音乐感。此外，也会发出典型的鸫类‘chk-chk’和尖锐的‘tseeep’叫声。","habits":"栖息于中高海拔地带，偏好密集的原生树林和灌木丛环境，包括金合欢、杜松林、橄榄树和野玫瑰，也出现在果园、大花园和耕作的河谷中。活动于1200米至3100米之间，最低可在沿水道的茂密植被中发现。以地面的昆虫、蜗牛等无脊椎动物和多种果实为食，如蔷薇、杜松、橄榄和无花果。","breeding":"具体繁殖细节未详细记载，但通常在适宜的栖息地中筑巢繁殖。","identification":"与欧亚黑鸫雌鸟相似，但可以通过范围、整体颜色较浅和黄色的喙来区分。","protection":"IUCN：NT（近危）","distribution":"主要分布在沙特阿拉伯山区西南部和也门西南部，即阿拉伯半岛西南部的萨拉瓦特山脉。","other":"尽管在沙特阿拉伯部分地区常见且广泛分布，但在也门却相当罕见且分布局限。目前种群数量估计约为1万对，且可能正在下降。"},{"name":"科摩罗鸫","english_name":"Comoro Thrush","scientific_name":"Turdus bewsheri","overview":"科摩罗鸫（英文名：Comoro Thrush，学名：Turdus bewsheri），是雀形目鸫科鸫属的鸟类。体型与普通鸫相似，但羽毛呈独特的棕色。分布于印度洋西南部的科摩罗群岛，包括Grand Comoro、Mohéli和Anjouan三个岛屿。","appearance":"成年雄鸟标本种（指名亚种）上体橄榄褐色，下巴和喉咙白色，脸颊下方有淡色斑点，胸部灰褐色带微暗棕色尖端，腹部中央至臀部有不规则软边斑点。雌鸟略显棕色，胸侧和侧翼斑点更宽或更均匀。幼鸟类似成鸟，但更为红褐色，背部有淡黄色条纹，胸部有淡黄色斑点。不同亚种间存在显著差异。","call":"歌声丰富多样，包含不同的旋律，如“chri-chri-chri”、“richi-richi-richi”等。警戒叫声为尖锐的“twit”，每秒重复一次。","habits":"栖息于湿润森林、次生林和种植园，海拔多在较高处，但在某些地方低至海平面。主要在树冠下层或地面觅食，食物包括蜘蛛、蚱蜢、昆虫、软体动物及果实种子。","breeding":"繁殖季节为8月中旬至10月，会用植物纤维和根部筑杯状巢，覆盖苔藓并以细草衬里，置于离地约3米的树桩、附生植物中或水平树枝上，通常产卵2枚。","identification":"不同岛屿上的种群在羽毛颜色和斑点上有明显区别，尤其是Anjouan岛的种群。识别时需注意其独特的棕色羽毛和腹部的斑点模式。","protection":"IUCN：NT（近危）","distribution":"分布于科摩罗群岛的Grand Comoro、Mohéli和Anjouan三个岛屿。","other":"容忍因香蕉种植园建立而退化的森林环境。"},{"name":"灰背鸫","english_name":"Grey-backed Thrush","scientific_name":"Turdus hortulorum","overview":"灰背鸫（英文名：Grey-backed Thrush，学名：Turdus hortulorum），是雀形目鸫科鸫属的鸟类。以其鲜明的羽色和悦耳的鸣声著称。成年雄鸟背部呈纯灰色，腹部橙色亮丽，而雌鸟及亚成雄鸟背部为褐色，喉部和胸部带有深色斑纹。广泛分布于山林深处、城市公园及庭院等各类栖息地中，繁殖于中国东北和俄罗斯远东地区，冬季迁徙至中国南部和越南北部。","appearance":"灰背鸫体长20-23厘米，体重61-69克。雄鸟上体为明亮的灰色，过渡至中胸的淡灰色，下胸和两胁为鲜亮的橙红褐色，腹部白色至臀部。雌鸟上体橄榄灰褐色，下体白色至橙色，喉部和胸部有暗色斑点。幼鸟类似雌鸟，但上体有橙褐色斑点和条纹，下体斑点更明显，橙色部分减少。","call":"灰背鸫的鸣声优美，通常从树顶发出一系列短促（3-4秒）的响亮变化音节，每个音节通常分为两部分，先是快速重复的哨音，随后是高音颤音。叫声包括柔和的低沉咕哝声、刺耳的‘chack-chack’声，以及警报时尖锐的‘tsee’或‘chee’声。","habits":"灰背鸫栖息于温带森林，常在落叶层中单独或成对活动，以昆虫、蜗牛和水果为食。它们在春季迁徙至繁殖地，秋季返回越冬地。活动范围包括林缘、荒地、草坡和农田，偏好低山丘陵地带的茂密森林。","breeding":"繁殖期为5月至8月中旬，营巢于树木幼枝上的叉点，巢由草和泥土构成，内部铺有干茎。一窝产卵3-5枚，卵色为淡绿色，带红褐色和紫罗兰色斑点。孵化期约为14天，由雌鸟承担。雏鸟孵化后11天左右即可离巢。","identification":"灰背鸫雌鸟与乌灰鸫雌鸟的主要区别在于上体颜色更偏灰色，嘴为黄色，点斑仅限于胸部。与黑胸鸫雌鸟的区别在于胸部底色更白。灰背鸫在迁徙季节可能与其他鸫类混群。","protection":"IUCN：LC（无危）。灰背鸫在中国东北和邻近的俄罗斯远东地区繁殖，种群数量相对丰富。","distribution":"繁殖区位于欧亚大陆的俄罗斯东南部和中国东北部，非繁殖区分布于东南亚，包括中国南部和越南北部。迁徙路线经过中国东部大部分地区。","other":"灰背鸫在迁徙和繁殖季节的鸣叫频率很高，尤其在清晨和傍晚。它们对人类保持警惕，鸣叫时通常站在树下的小树枝上，发现人后会迅速飞落地面，通过跳跃前进。"},{"name":"蒂氏鸫","english_name":"Tickell's Thrush","scientific_name":"Turdus unicolor","overview":"蒂氏鸫（英文名：Tickell's Thrush，学名：Turdus unicolor），是雀形目鸫科鸫属的鸟类，也被称为梯氏鸫。主要分布在喜马拉雅山脉西部至中部，常见于开放森林环境，是喜玛拉雅山区林地的夏候鸟，冬季则向南迁移至印度南部和偶尔至孟加拉国。2007年6月，中国西藏中尼边境樟木镇首次正式记录到蒂氏鸫的存在。","appearance":"蒂氏鸫的雄鸟个体呈均匀的蓝灰色，腹部略淡，具有微弱的黑色眼纹和喉部的白色细纹，中腹部至尾羽覆羽为白色；喙、眼环和腿均为黄色。雌鸟个体上体为淡橄榄棕色，具灰白色髭纹和颏部，由深棕色狭窄的颊纹分隔，形成窄项链状斑点在浅黄色胸部；两胁为浅黄色，中腹部至腹下部为白色；喙和腿为黄褐色。幼鸟上体棕色，冠至肩部有模糊的浅黄色眉纹和条纹，双翼有橙色斑点，两颊图案类似雌鸟，但斑点更密集，延伸至胸侧，两胁有橙色色调，渐变为腹下部的浅黄色至白色。","call":"蒂氏鸫的鸣唱由雄鸟在繁殖季节从高处发出，包含一系列短小的乐句，带有滑音和断奏音符，较弱且不如的歌曲那样悦耳，但地区间存在变异，某些地区的歌曲更为悦耳且不那么单调。重复的二音节或三音节乐句。叫声包括响亮的“juk-juk”，减速的喋喋不休声“juh'juk-juk, juk”和短暂的高音嗡嗡声。","habits":"蒂氏鸫主要以蚯蚓、昆虫和水果为食，包括果园中的落果。它会在裸露的地面上觅食，如松叶堆中，但也会在短草地上活动，如草坪；采用典型的鸫类觅食技巧，短距离跳跃和停顿。冬季有时会形成松散的小群体。","breeding":"蒂氏鸫在4月至6月期间筑巢，使用多种材料，但主要成分是干草。它们不会形成大群，通常为2至5只的松散群体。","identification":"与南亚乌鸫相比，蒂氏鸫的黄色眼环更薄且更淡，且体型较小。在冬季迁徙范围内，可能与南亚乌鸫混淆，但两者在颜色和体型上有明显差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于喜马拉雅山脉西部至中部；非繁殖区域包括印度北部、巴基斯坦，偶尔至孟加拉国。冬季迁徙至印度南部和偶尔至孟加拉国。","other":"蒂氏鸫因在果园中觅食的习惯，有时会造成成熟杏子（Prunus armeniaca）和苹果（Malus）的损害。"},{"name":"黑胸鸫","english_name":"Black-breasted Thrush","scientific_name":"Turdus dissimilis","overview":"黑胸鸫（英文名：Black-breasted Thrush，学名：Turdus dissimilis），是雀形目鸫科鸫属的小型鸟类。以其雄鸟全黑的头部和胸部而闻名。广泛分布于北起印度东北部，南至越南北部，包括中国西南地区的贵州、云南和广西等地。栖息于海拔1200-2500米的森林中。","appearance":"雄鸟头部至背部黑色，其余上体部分为石板灰色，腹部橙色；雌鸟上体灰褐色，下体橙色，喉部具密集的黑色条纹。喙、眼环和腿橙黄色。幼鸟似雌鸟，但头部至肩部有细小斑点，翼上有双橙斑，下体有扩展至更浅橙色的侧腹斑点。","call":"鸣唱为一系列悠扬的旋律短语，包含3-8个响亮多变的音符，可能涉及模仿。叫声为丰富的断奏‘tuc-tuc-tuc’或‘chup-chup-chup...’以及尖细的‘seee’。","habits":"栖息于海拔1200-2500米的橡树和松树林、常绿阔叶林及次生林中。冬季下降至海拔约400米的灌木丛林和红树林中。留鸟，有季节性的垂直移动，偶尔进行长距离迁徙。主要以昆虫、软体动物和浆果为食，常单独或成对活动，多在林下觅食。","breeding":"繁殖期在印度为4-7月，缅甸和中国为4-6月。筑巢于小树或灌木叉上1-6米高的稳固杯状巢，由绿色苔藓和纤维构成。每窝产3-4枚蛋，颜色为奶油色、淡黄、浅绿或蓝绿色，布满棕色、紫罗兰色和/或红棕色或紫色斑点。","identification":"雌鸟与灰背鸫雌鸟相似，但后者胸部为灰色，仅两侧橙色；而黑胸鸫雌鸟上下胸均为橄榄褐色，下胸和两侧全为橙棕色。与白眉鸫的区别在于白眉鸫有白色眉纹，头、颈、胸不为黑色。","protection":"IUCN：LC（无危）。虽然数量减少，但下降速度不足以达到易危标准。在中国部分地区稀缺至相当普遍。","distribution":"分布于印度东北部至越南北部，包括中国西南地区的贵州、云南和广西等地。繁殖区主要位于海拔1200-2500米的森林，冬季下降至海拔约400米的地区。","other":"曾被认为与灰背鸫同种，现确认为独立物种。"},{"name":"乌灰鸫","english_name":"Japanese Thrush","scientific_name":"Turdus cardis","overview":"乌灰鸫（英文名：Japanese Thrush，学名：Turdus cardis），是雀形目鸫科鸫属的鸟类。俗名: 日本灰鸫，行踪隐秘的鸟类，雄鸟头及上胸呈黑色，腹部雪白点缀以深色斑点。分布于日本、前苏联、朝鲜、越南、老挝以及中国多个省份，如河南、湖北、安徽、贵州等。偏好在落叶林和混交林中活动，尤其是阴暗湿润的山谷和溪边。","appearance":"乌灰鸫体型中等，约21-22厘米长。雄鸟成鸟头部至颈背及胸部黑色，其余上体呈石板黑色，腹部白色并有黑色倒心形斑点。雌鸟背部灰褐色，腹部白色，带深色斑点和橙色晕染。亚成鸟背部橄榄棕色至棕色，上体有淡黄褐色条纹和深色羽尖，下体淡黄褐色，腹部更白，带有棕色斑点。","call":"乌灰鸫的鸣唱丰富而悠长，音质优美，音调起伏，节奏类似欧歌鸫，音色接近欧乌鸫。","habits":"乌灰鸫栖息于落叶林和混交林，偏好阴暗湿润的环境，如山谷和溪边。冬季会迁移到东南亚和中国东南部。它们在地面觅食，主要以昆虫、蚯蚓和落果为食。","breeding":"繁殖期在中国为五月，在日本为四月至八月。雄鸟可能实行一夫多妻制。巢由树枝、草和藤蔓构成，外覆苔藓，内部铺以毛发、根须和松针，筑于树叉间。每窝产2-5枚蛋，通常4枚，蛋壳呈浅蓝绿色，有红棕色和淡紫色斑点，孵化期12-13天，雏鸟成长期在圈养条件下为14天。","identification":"乌灰鸫雌鸟与斑鸫的区别在于乌灰鸫腰部呈灰色，黑色点斑延伸至腹部。与其他鸫属鸟类相比，乌灰鸫的黑色斑点在腹部更为明显。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括中国中部和北海道至九州（北部至日本南部）。非繁殖区域涵盖亚洲东南部和中国东南部，包括沿海地带。","other":"乌灰鸫是迁徙性鸟类，冬季迁往东南亚和中国东南部，偶尔会在台湾作为过境迁徙的个体出现。"},{"name":"白颈鸫","english_name":"White-collared Blackbird","scientific_name":"Turdus albocinctus","overview":"白颈鸫（英文名：White-collared Blackbird，学名：Turdus albocinctus），是雀形目鸫科鸫属的鸟类。亦被称为白颈黑鸫，最显著的特点是拥有明亮的白色颈环，环绕至中胸部位。分布于喜马拉雅山脉至中国中南部，包括印度、尼泊尔、不丹、缅甸及中国的西藏、四川等地。栖息于海拔2300-3800米的云杉林、灌木丛或河湖边的灌木丛间。","appearance":"成年雄鸟全身黑色，具有宽阔的白色颈环，延伸至下巴至中胸，环绕颈部和肩部；尾羽下方有细薄的白色条纹和斑点；黄色的眼环、喙和略带黄褐色的腿。雌鸟与雄鸟图案相似，但上半身呈深棕色，头部颜色更深，下半身颜色稍浅，颈环为灰白色或淡黄色。幼鸟为深棕色，背部有广泛的红褐色斑点和条纹，腹部红褐色，带有深棕色斑驳和条纹。","call":"黄昏和黎明时，从树梢发出一系列长音节的歌曲，每分钟重复5-7次，由简单而突然的悲伤、柔和、下降的哨声组成，如‘tiu-i tiu-u tiu-o’等，有时会变化为‘tiu-iio’，偶尔夹杂嘶嘶声和吱吱声，与欧歌鸫的歌声相似。叫声包括沙哑的‘tuck-tuck-tuck…’或‘chack-chack’。","habits":"以昆虫、蚯蚓和其他无脊椎动物为主食，冬季依赖更多植物性食物，如浆果、果实和核果（山楂、山苹果、栒子、冬青、矮槲寄生等）。在地面和树上觅食，冬季也会靠近村庄和花园草地，有时与其它鸫类形成大群。","breeding":"在藏高原，白颈鸫一年可繁殖两次。第一次尝试产下的小窝雏鸟体型较大，第二次则产出更多的雏鸟，但体型较小。这种差异被认为是由父母喂养行为和季节性食物供应的变化驱动的。研究显示，雌鸟在巢穴防御行为上表现出不同的个性，胆大的雌鸟比害羞的雌鸟有更高的筑巢成功率。","identification":"白颈鸫以其独特的白色颈环易于识别，与同属其他物种区别明显。此外，其鸣叫声和活动习性也可用于辨别。","protection":"IUCN：LC（无危）","distribution":"繁殖于喜马拉雅山脉至中国中南部，包括印度、尼泊尔、不丹、缅甸以及中国的西藏、四川等地。在非繁殖季节，分布可能扩展至东南亚地区。","other":"白颈鸫的雏鸟主要被喂食植物材料，尤其是浆果，以及无脊椎动物如节肢动物和环节动物。"},{"name":"环颈鸫","english_name":"Ring Ouzel","scientific_name":"Turdus torquatus","overview":"环颈鸫（英文名：Ring Ouzel，学名：Turdus torquatus），是雀形目鸫科鸫属的鸟类。身长23-24厘米，体重90-138克。雄鸟以黑色为主，胸前有醒目的白色新月形斑纹，雌鸟颜色较淡，幼鸟可能缺乏明显的胸带。主要分布于从爱尔兰至伊朗的山地，高海拔物种，迁徙至南欧、北非和土耳其过冬。","appearance":"雄性环颈鸫通体黑色，具明亮的白色胸部新月形斑纹，翼缘苍白。雌鸟色调较暗，头部至肩部呈棕色，喉部至腹部有较窄且模糊的白色胸带。幼鸟类似雌鸟，但上部有灰褐色条纹，下部色浅，无明显胸带或仅有微弱的痕迹。喙呈黄色，腿为灰褐色。","call":"鸣唱由2-4个略带变化的简单、忧郁的笛音组成，如“pi-ríí, pi-ríí, pi-ríí”和“trruu-trruu-trruu tjii-tjii-tjii”。叫声包括温和的‘tjuck-tjuck-tjuck’和在飞行中的‘dcherrr’或‘tschwierrr’。","habits":"栖息于高山草甸、山毛榉林、松树林、石楠丛生的荒地和多岩石的山坡。偏好潮湿的云杉林和云杉冷杉混交林，以及杜鹃灌木丛和石楠丛。在英国，偏好石楠草地和纳尔杜斯-莫利尼亚草地，小巢穴附近常有岩石、沟壑、碎石和石块。在阿尔卑斯山脉，偏好中上部的森林地带。冬季在北非的杜松森林中较为常见。","breeding":"繁殖期为4月中旬至7月中旬，筑巢于地面或1-16米高的灌木或小树上，巢由干燥的草、茎、苔藓和树叶混合泥浆制成，内衬干草。每窝产3-6枚蛋，通常4-5枚，蛋壳颜色为淡蓝到蓝绿色，带有淡红色斑点。孵化期13-14天，雏鸟孵化后14-16天离巢，之后依赖父母约12天。","identification":"与欧乌鸫、槲鸫、田鸫等大型鸫科鸟类相比，环颈鸫具有独特的白色胸部新月形斑纹，这是最明显的识别特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于西欧至西北俄罗斯的山区，从爱尔兰东至土库曼斯坦。迁徙至南欧、北非和土耳其过冬。在北非，主要集中在杜松森林。","other":"在迁徙季节，常结成大群在林间活动，尤其喜欢在草丛中寻找害虫。成群的鸫类对消灭农田害虫有重要作用。"},{"name":"灰翅鸫","english_name":"Grey-winged Blackbird","scientific_name":"Turdus boulboul","overview":"灰翅鸫（英文名：Grey-winged Blackbird，学名：Turdus boulboul），是雀形目鸫科鸫属的鸟类。俗名: 灰膀鸫，大型森林鸫科鸟类，以雄鸟的黑色身躯和闪亮的银色翅膀为显著特征。雌鸟呈褐色，翅膀亦带银色。该物种广泛分布于喜马拉雅山脉至越南北部，主要栖息于海拔1200-3000米的湿润而稠密的橡树和杜鹃等阔叶林。模式产地位于印度Darjeeling。","appearance":"雄鸟体长27-29厘米，体重85-105克，通体黑色，具有宽大的粉灰色翼片和白色翼尖覆羽，下体有模糊的灰色鳞状纹；雌鸟淡橄榄棕色，翅膀覆羽暖棕色带宽幅粉红褐色端斑。幼鸟上体深褐色，布满浅色斑点和条纹，下体棕黄色，带有狭窄的暗色横杠，翅膀色泽随性别不同而异。","call":"甜美的鸣声由一系列轻松的颤音组成，每段旋律常常以颤音结束，类似欧乌鸫但更加断续，例如“twii-tuuu twii-tuuu chuiyui-twit wiiar-twit wiiar-trtrtrt-wi-wi-wich wiiyar-wiiyar...”。此外，还有低沉的“chuk-chuk”叫声（受惊时更强）、接触时的“churi”声、近巢时愤怒的“churr”声，以及归巢时哀伤的向下弯曲的‘pie-oooh tie-ooh’哨音。","habits":"常于地面觅食，安静地在树叶间寻找无脊椎动物、蠕虫，冬季也食用果实及浆果，如蔷薇科的Cotoneaster和Berberis。有时在树上觅食，于枝条上的苔藓中搜寻无脊椎动物，同时也会以典型的鸫科方式在地面快速跳跃和暂停。冬季常见于小群中活动。","identification":"雄鸟的黑色身体与闪亮的银色翅膀是与同类中其他物种区分的关键特征。雌鸟的淡橄榄棕色和翅膀覆羽的暖棕色端斑也有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉（从巴基斯坦东北部起），中国南部（云南、贵州南部、广西、湖南东南部），以及印度支那北部；非繁殖季节还见于印度东北部（阿萨姆邦南部山区）、缅甸西部和泰国西北部。"},{"name":"欧乌鸫","english_name":"Common Blackbird","scientific_name":"Turdus merula","overview":"欧乌鸫（英文名：Common Blackbird，学名：Turdus merula），是雀形目鸫科鸫属的鸟类。俗名: 百舌、反舌、黑鸫、黑鸟、黑山雀、牛屎、八日雀、中国黑鸫、乌(春鸟)，又称: \"百舌\"，中型鸟类，全身黑色，具黄色的喙和眼圏，鸣声嘹亮，春季尤其善于变化多端的鸣唱，因此有“百舌”之称。常见于欧洲、亚洲西部、北非等地，以及澳大利亚和新西兰的引入区。","appearance":"成年雄鸟体长约23.5至29厘米，体重80至125克，全身黑色，带有光泽，喙橙黄色或黄色，腿黑褐色。雌鸟及幼鸟呈暗褐色，雌鸟喉部较淡，有隐约的斑点和条纹，喙为黄褐色基部带暗色。幼鸟背部有淡色斑点，翅膀上有双色斑点，腹部暗色斑点和条纹明显，第一年雄鸟与成年雄鸟相似，但喙暗色，眼圏不明显，翼部棕色。","call":"雄鸟的鸣唱为低沉的、旋律丰富的哨音，通常从树梢或屋顶等高处发出，春季至夏季最为频繁，有时延续到7月初。有多种叫声，包括攻击性的‘see’声，对陆地捕食者的‘pook-pook-pook’警报声，以及各种‘chink’和‘chook’的叫声。","habits":"栖息于森林、公园、花园、农田和果园，偏好有茂密灌木的开阔林地。活动范围广泛，从海拔较低的地区到高达2700米的山区。部分种群为留鸟，部分季节性迁移，主要依赖于纬度。主要食物为昆虫、蠕虫、水果和种子，偶尔捕食小型脊椎动物。在地面上觅食，通过翻动落叶和挖掘寻找食物。","breeding":"繁殖期从3月至9月，雄鸟通过展示和鸣唱吸引雌鸟。巢由雌鸟独力建造，位于树丛或灌木中，用草、叶和其他植被结合泥土制成杯状。每窝产卵2至6枚，通常3至4枚，淡蓝绿色底有红棕色斑点。孵化期10至19天，雏鸟喂养期约13至14天。每年可育成1至3窝。","identification":"乌鸫与乌鸦的区别在于体型较小，喙为黄色，眼圏明亮，而乌鸦喙为黑色，体型更为粗壮。相较于红嘴山鸦和黄嘴山鸦，乌鸫喙色和腿色不同，山鸦腿红色，无黄色眼圏。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括欧洲、西亚、北非、南亚、澳大利亚和新西兰。非繁殖区域扩展至北非、热带亚洲。在中国大陆，常见于长江流域、华南和西南地区。","other":"曾作为宠物鸟被笼养，现已恢复自然状态。在瑞典被视为国鸟。"},{"name":"乌鸫","english_name":"Chinese Blackbird","scientific_name":"Turdus mandarinus","overview":"乌鸫（英文名：Chinese Blackbird，学名：Turdus mandarinus），是雀形目鸫科鸫属的鸟类。俗名: 百舌、反舌、黑鸫、黑鸟、黑山雀、牛屎、八日雀、中国黑鸫、乌(春鸟)，又称: \"百舌\"，大型黑色鸫类，分布于中国中东部及周边地区，为城市常见鸟类。其最显著特征为全身黑色，喙橙黄至鲜黄，雄鸟全身漆黑，雌鸟深褐。乌鸫鸣声清脆悦耳，变化多端，被誉为‘百舌’。","appearance":"乌鸫体长约28-29厘米，雄鸟全身黑色，雌鸟略带褐色，两者均具橙黄色至黄色的喙，黑色或深褐色的眼环。幼鸟为深褐色，带有淡色斑点和条纹。雌雄两性相似，但雌鸟下体略显褐色，有较宽的暗色条纹，喙色偏棕，基部有淡黄色（主要在下喙）。","call":"乌鸫的鸣唱是一系列响亮而旋律优美的笛音，如‘piew-piew’和‘tiew-quoit’，每个乐句保持单一音调，不同于欧乌鸫的高音结尾。报警时发出尖锐的尖叫或一连串‘wuk’声。","habits":"乌鸫栖息于开阔的森林、花园和农田，常见于草坪和田野觅食，以无脊椎动物、蠕虫为主食，冬季则转向果实和浆果。它们在地面翻找食物，也会在树上寻找浆果。","breeding":"繁殖季节为3月至7月，每年可育2-3窝。巢由干草、树枝和泥土构成，置于离地至少半米的灌木或树上。每窝产卵2-6枚，卵呈浅绿蓝底色，有淡红棕色斑点。","identification":"乌鸫与乌鸦区别明显，体型较小，喙色黄而非黑，且更秀气。与红嘴山鸦和黄嘴山鸦相比，乌鸫体型更小，具有黄色的眼环，腿色不同。","protection":"IUCN：LC（无危）。在中国广泛分布且数量稳定。","distribution":"乌鸫分布于中国中东部，北至黄河以南，南至海南岛，东至台湾海峡，西至四川盆地。在非繁殖季节，部分群体南迁至越南北部、老挝北部等地。","other":"乌鸫曾被作为宠物鸟饲养，现已受到保护。其鸣声变化多端，被称为‘鸣禽之王’，在中国文学中有诸多描绘。"},{"name":"藏乌鸫","english_name":"Tibetan Blackbird","scientific_name":"Turdus maximus","overview":"藏乌鸫（英文名：Tibetan Blackbird，学名：Turdus maximus），是雀形目鸫科鸫属的鸟类。从巴基斯坦北部延伸至西藏东南部。体型较大，总长23-28厘米。雄鸟全身黑褐色，头部、胸部、翅膀和尾巴颜色更深，喙呈暗橙黄色；雌鸟上体黑褐色，下体偏棕色，喉部有微弱的条纹，喙色暗黄。与欧乌鸫相比，藏乌鸫无眼圈，鸣声更为简单。","appearance":"藏乌鸫雄鸟呈现黑褐色，头部、胸部、翅膀和尾部的颜色较深，喙色为暗淡的橙黄色，腿色较暗。雌鸟上体为黑褐色，下体颜色偏棕色，喉部有模糊的条纹，喙色为暗淡的黄褐色。幼鸟类似雌鸟，但背部到翼覆羽有斑驳的灰褐色，喉咙上有灰褐色的条纹，腹部到臀部有灰褐色的横纹。成鸟可能有轻微的兜帽外观。","call":"藏乌鸫的鸣唱是一系列快速金属音符组成的重复曲调，包含不悦耳的尖叫、类似杜鹃鸟的呼啸声和粗哑的嘎嘎声，偶尔穿插纯净的哨音，如悲伤的‘piew-piew’声，非常重复，缺乏欧乌鸫鸣声中的颤音。","habits":"藏乌鸫栖息于陡峭的草地、岩石斜坡和高山草甸，海拔高度通常在3200-4800米之间，冬季会下降到较低海拔，但很少低于3000米。它以蚯蚓、软体动物、昆虫、小蜥蜴、果实、浆果和种子为食。夏季末期，藏乌鸫会在小群体中觅食，数量可达十只。","breeding":"藏乌鸫的繁殖季节从5月持续至7月，筑巢高峰期在6月至7月初。巢由泥土、动物毛发和细草制成，通常建在树根、巨石脚边、低矮灌木、悬崖面或岩石壁旁。在中国，它们偏好在Cotoneaster microphyllus灌木中筑巢。一窝产3-4枚蛋，孵化期大约12-13天，幼鸟离巢时间约为16-18天。","identification":"与欧乌鸫相比，藏乌鸫完全缺乏眼圈，鸣声更简化，体型更大，颜色更均匀深暗。雌雄两性的头部可能显得略微兜帽状。","protection":"IUCN：LC（无危）","distribution":"藏乌鸫分布于喜马拉雅山脉，从巴基斯坦北部至西藏东南部。繁殖季节栖息于海拔3200-4800米的高山区，冬季会迁至较低海拔，但极少低于3000米。","other":"藏乌鸫曾被当作欧乌鸫的亚种，直到2008年基于系统发育证据，被确认为独立物种。"},{"name":"南亚乌鸫","english_name":"Indian Blackbird","scientific_name":"Turdus simillimus","overview":"南亚乌鸫（英文名：Indian Blackbird，学名：Turdus simillimus），是雀形目鸫科鸫属的鸟类。曾被误认为是欧乌鸫的亚种。仅见于印度和斯里兰卡。拥有深灰褐色的羽毛，头部颜色最深，带有明显的橙黄色喙、眼圈和腿，体型较小，长度约19至20厘米。","appearance":"雄性南亚乌鸫上部呈深灰褐色，头部颜色最深，给人以帽状外观，下部略淡，喉部和腹部中部最浅。雌鸟整体较淡，喉部有轻微的条纹。幼鸟像雌鸟，但翼覆羽有橙色边缘，下方橙色带暗棕色斑点和斑驳。不同亚种在颜色和大小上有细微差别。","call":"其歌声为一系列快速、丰富、多变、短促且通常成对的滑音。在斯里兰卡（亚种kinnisii），叫声较为简单，包括急促的硬颤音、低强度版本，以及缓慢的一系列打击乐般的音符；在斯里兰卡还有一种短而高升的颤音。","habits":"栖息于湿润的落叶和常绿阔叶林、灌木丛林、密集的灌木丛边缘、树丛、遮荫咖啡种植园等环境，繁殖季节位于海拔700米以上的印度山区，900米以上的斯里兰卡。冬季会迁移到较低海拔，包括平原地带的类似栖息地，以及树木花园和种植园。","breeding":"繁殖期在印度为2月至11月，在斯里兰卡为3月至4月和8月至9月。巢为深杯状，由草、苔藓和根构成，加固以少量树枝和泥层，内部衬有细根，通常建于树叉、树桩或灌木中。每窝产卵4枚，蛋壳颜色为蓝到淡绿色，表面非常光滑，布有大胆的红棕色和浅红褐色斑点。","identification":"与欧乌鸫相比，南亚乌鸫羽毛颜色较浅，体型更小，具有明显的眼环。不同亚种之间在色彩和比例上有差异。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度和斯里兰卡，遍布于东洋界区域。"},{"name":"岛鸫","english_name":"Island Thrush","scientific_name":"Turdus poliocephalus","overview":"塔岛鸫（英文名：Tasman Sea Island Thrush，学名：Turdus poliocephalus），是雀形目鸫科鸫属的鸟类。曾分布于塔斯曼海中诺福克岛与豪勋爵岛的已灭绝鸫类，旧称“岛鸫”复合体成员。体长约20.5–25厘米，雄鸟通体近黑色具浅褐头罩，雌鸟色暗且腹侧带暖棕，眼环、嘴与足橙黄。因黑家鼠入侵及植被破坏，诺福克亚种灭绝于1975年，豪勋爵亚种灭绝于1920年代。","appearance":"塔岛鸫体长20.5–25厘米，雌雄异形。指名亚种（诺福克岛）雄鸟全身黑褐色，头颈为淡黄褐色头罩，尾下覆羽具白纹；雌鸟似雄鸟但头顶及胸部褐色更深，腹及两胁带暖棕色；嘴、眼环及腿亮橙黄色。幼鸟全身褐色，上体具淡色纵纹，下体具深褐、淡黄及锈色杂斑。豪勋爵亚种雄鸟头灰褐，上体橄榄褐，喉及颈浅褐，胸腹及两胁肉桂褐；雌鸟色泽更淡。","call":"岛鸫复合体成员通常在清晨或傍晚发出一系列响亮、清晰且富有旋律的乐句；警戒时发出金属质感的断续“chik-chik-chik…”或“chak-chak”声，初快后慢；另有短促刺耳摩擦音、微弱高而略下滑的“tss”及飞行时的高音“seeee”。塔岛鸫具体鸣声资料缺乏。","habits":"塔岛鸫曾栖息于诺福克岛及豪勋爵岛的森林及邻近花园，或雨林—松树林混合带。岛鸫复合体普遍选择具成熟树木及较开阔下层的林地和森林，山岛个体多局限于山地森林，可自海平面分布至山顶。为留鸟，不迁徙；觅食方式类似乌鸫，在落叶层及低矮植被间跳跃，亦在林冠取食。食物包括陆生无脊椎动物（蜗牛、蛞蝓、蠕虫、昆虫、多足类、螨、蜘蛛）及小型果实、浆果和种子。塔岛鸫的详细食谱记录稀少。","breeding":"岛鸫复合体通常在森林再生处低处（1.5–2米，偶至5米）或树杈、灌木分叉处筑敞口杯状巢，巢材为草茎、细根、棕榈纤维、叶脉、卷须、嫩枝、叶片及碎树皮，外覆苔藓地衣，内衬软草。每窝1–3枚卵，常2枚，卵绿或蓝绿具密集红褐小斑，孵化期约18天，育雏期17–19天。塔岛鸫在诺福克岛记录繁殖期为8–12月及3–5月，在豪勋爵岛为9–1月。豪勋爵岛巢为大型松散浅杯，以棕榈叶、纤维及枯叶构成，内衬草，置于地面或近地的棕榈基部、树桩、藤蔓或灌木枝上；卵两枚，淡绿或淡灰具红褐斑。诺福克岛巢卵类似，但巢通常位于灌木及树杈，高1.8–6.1米。","identification":"塔岛鸫已与同属其他成员及亚种因灭绝而无野外重叠。指名亚种（诺福克岛）通体黑褐而头颈淡黄褐，尾下覆羽白纹显著；豪勋爵亚种头灰褐、上体橄榄褐、胸腹肉桂褐，整体较淡。与同复合体的萨摩亚岛鸫、斐济岛鸫及新喀岛鸫在羽色及地理分布上差异明显；与白头鸫相比，后者具白色头枕及不同体色模式，且地理上远离。","protection":"IUCN: NE（未评估）（作为“岛鸫”复合体整体被视为无危，但该复合体中多岛系分类群已灭绝或受严重威胁）。诺福克亚种1975年后灭绝；豪勋爵亚种1920年代后灭绝。灭绝主要原因：原生植被清除、与引入乌鸫的竞争及杂交，以及1940年代黑家鼠（Rattus rattus）入侵导致的雏鸟捕食。","distribution":"繁殖区域：曾分布于澳大利亚外海的诺福克岛与豪勋爵岛。非繁殖区域：无，该种为留鸟。","other":"塔岛鸫原为“岛鸫”塔岛鸫复合体的一员，该复合体含50余个岛屿分类群，已于2024年被划分为17个独立物种。塔岛鸫与萨摩亚岛鸫、斐济岛鸫及新喀岛鸫构成一支系，与东亚的伊豆鸫、赤胸鸫、白腹鸫、褐头鸫及白眉鸫亲缘较近。"},{"name":"灰头鸫","english_name":"Chestnut Thrush","scientific_name":"Turdus rubrocanus","overview":"灰头鸫（英文名：Chestnut Thrush，学名：Turdus rubrocanus），是雀形目鸫科鸫属的鸟类。冬季则迁往喜马拉雅东部和东南亚北部。","appearance":"灰头鸫成年雄鸟拥有橙栗色身体，搭配黑色翅膀和尾巴，头部为灰，颈部侧面可见白色调渐变为灰，尾部边缘白色，眼圈黄色，喙和腿均为黄色。雌鸟相似但色泽稍暗淡，头部略深，翅膀和尾巴呈棕色。幼鸟头部颜色更深，背部呈暗淡的锈红色，肩羽有橙色斑点，翅膀和尾巴深色，喉部白色，下体布满暗色斑点。","call":"灰头鸫的鸣唱由雄鸟在高处显眼的枝头发出，主要在晨昏时分，是一系列悠扬、响亮且富有音乐性的短语，重复3至8个音符，充满模仿，如“yii-bre yii-bre yii-bre… diddyit diddyit… yip-bru yip-bru yip-bru…”。报警声包括干燥的断奏颤音、粗哑的‘chuck-chuck-chuck’声和急促的‘kwik-kwik, kwik-kwik’。","habits":"灰头鸫偏好湿润的山地松林和混合森林，尤其喜欢植被密集、阴凉的地方。它们在繁殖季节高度依赖浆果，但也会食用昆虫、蠕虫、千足虫、蛞蝓、蜗牛和浆果。冬季它们可能更依赖浆果。夏季，它们主要在地面觅食，但在冬季常与其他鸫类形成小群。","breeding":"繁殖期为4月至7月，雄鸟在4月初开始占据领地并鸣叫。巢筑于林下小树的枝杈上，离地约2至4米，或是在悬崖、洞穴中。巢由细枝、苔藓、树根、枯草茎、叶构成，内衬细草茎和毛发。每窝产卵3至4枚，偶有5枚，卵为绿色带淡红褐色斑点，卵形卵圆形，大小约为30.6mm×21.6mm，雌鸟负责孵化，雏鸟为晚成性，由双亲共同抚养。","identification":"灰头鸫与其他大型森林鸫的区别在于其独特的灰头、黑翅和橙背腹组合，这种特征在它的分布范围内是独一无二的。","protection":"IUCN：LC（无危）","distribution":"繁殖于海拔1500至3300米的喜马拉雅山脉，冬季下降至450米，栖息于开阔的林地和果园。在中国东南部，分布于900至2500米，偶尔降至200米。在中国大部分地区为留鸟，部分地区为夏候鸟。","other":"灰头鸫在巴基斯坦被认为是灰翅鸫在较高海拔的替代种。"},{"name":"棕背黑头鸫","english_name":"White-backed Thrush","scientific_name":"Turdus kessleri","overview":"棕背黑头鸫（英文名：White-backed Thrush，学名：Turdus kessleri），是雀形目鸫科鸫属的鸟类。又名: 黑头棕背鸫，砖橙色腹部与漆黑的翅膀和头部，雌鸟整体呈暗褐色，翼部较深，背部略显苍白。分布于中国中部高海拔的开阔草地、草原和花园。这留鸟，但在极端寒冷天气下会迁移到较低海拔地区。","appearance":"雄性棕背黑头鸫的头部、颈部至中胸为黑色，上背部为粉红偏白色，下背部至背部为清晰的粉红带栗色，翅膀和尾巴为黑色；胸部有一条粉红偏白色的带状斑纹，其余下体部分为粉红带栗色，腹侧颜色更深，尾部尖端为粉色；眼环黄色，喙黄色，腿呈棕色。雌鸟外观相似但色彩较淡，头部呈棕色，背部和肩羽较灰，喉部有暗色条纹，下体颜色更浅，喙色较暗。幼鸟像雌鸟，但标记更弱，头部和肩羽有淡褐色条纹。","call":"其歌声为一系列悠闲的短促喵叫和尖叫，类似的叫声。叫声包括短而急促的鼻音颤音，如同羊的咩叫，还有柔和的‘dug dug’声和响亮的粗哑笑声。","habits":"栖息于高山上超过林线的岩石灌木丛和矮小灌木，如杜鹃花和雪松，海拔高度在3600至4500米之间，冬季会下降到2100米左右的田地。夏季中午和夜晚也会下降到松树或雪松的树冠中休息或过夜。在喜马拉雅山脉的非繁殖季节，它们会占据开放的灌木植被，包括雪松灌木、Berberis、果园和土豆田。","breeding":"繁殖期从5月初持续到8月初，似乎为单窝繁殖。筑巢时表现社会性，雄鸟形成觅食群，而雌鸟则在孵卵。巢为草茎制成的杯状，内衬毛发和羽毛，通常位于干燥的灌木、矮小杜鹃或靠近溪流的突出岩石下的低处。每窝产卵3至4枚。关于繁殖行为的其他信息尚不详。","identification":"棕背黑头鸫与灰头鸫的区别在于，前者头部、颈部及喉部为黑色而非灰色。此外，与栗色鸫相比，棕背黑头鸫偏好更为开阔的生境，且身体上缺乏淡色斑块。","protection":"IUCN：LC（无危）","distribution":"主要分布于中国西部至西藏东南部，包括青藏高原的东部和东北部（青海东部、甘肃南部至西藏东北部和云南西北部）。在非繁殖季节，也出现在西藏东南部和可能的印度东北部。","other":"在喜马拉雅山脉，从尼泊尔中部至不丹有迷鸟记录。"},{"name":"褐头鸫","english_name":"Grey-sided Thrush","scientific_name":"Turdus feae","overview":"褐头鸫（英文名：Grey-sided Thrush，学名：Turdus feae），是雀形目鸫科鸫属的鸟类。俗名: 费氏穿草鸫，直译: 灰胁鸫，中等体型的温褐色鸫科鸟类，具白色眉纹和眼下的白斑。胸及两胁呈灰色，分布于中国东北部的山区，迁徙至印度、东南亚的热带或亚热带湿润山地森林。在中国数量稀少，属易危物种。","appearance":"褐头鸫为中等体型的鸫，体长22-23.5厘米，上体橄榄棕色，下体灰色渐淡至腹部。雄鸟具白色眉线、眼圈、喉部，喙暗色，下颌黄色；雌鸟脸有斑点，喉部及胸部中央白色，胸侧带棕色边缘。幼鸟描述不详，但第一年冬季的个体类似雌鸟，头部有淡色条纹，翼覆羽尖端淡色，胸部有棕色带。","call":"鸣唱为一系列短语，包含非常短的颤音和丰富悦耳的模糊音符。叫声包括细长的‘zeeee’或‘sieee’声，比白眉鸫的叫声更薄，还有清脆的噼啪声。","habits":"栖息于中到高海拔的北方森林，主要以昆虫和果实为食，也会取食花蜜。在地面或树上觅食，冬季常与白眉鸫混群。长距离迁徙，冬季分布于南亚和东南亚。","breeding":"繁殖期为5月至9月，巢建于华北落叶松上，平均高度约5.3米，巢址周围环境隐蔽。繁殖期活动范围平均1.93公顷。","identification":"与白眉鸫相似，但褐头鸫胸及两胁灰色，而非黄褐色。此外，褐头鸫的叫声更薄，鸣唱不如白眉鸫丰富。","protection":"IUCN：VU（易危），国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）。","distribution":"繁殖于中国东北部（北京、河北、山西），非繁殖期分布于印度东北部、缅甸、泰国西北部。在中国大陆的分布包括北京、河北等地。","other":"可能受到野鸟贸易的威胁，冬季栖息地因木料采集、烧荒和农业而消失。"},{"name":"白眉鸫","english_name":"Eyebrowed Thrush","scientific_name":"Turdus obscurus","overview":"白眉鸫（英文名：Eyebrowed Thrush，学名：Turdus obscurus），是雀形目鸫科鸫属的鸟类。中等体型的鸫科鸟类。其最显著的特征是一条长而微弯的白色眉纹，赋予了它优雅的外观。白眉鸫分布广泛，繁殖于东起西伯利亚至蒙古、日本的密集森林中，冬季迁徙至中国南部及东南亚地区。","appearance":"成年白眉鸫体长21-23厘米，体重61-117克。雄鸟头部灰色，背部褐色，腹部橙色，拥有白色的眉毛、眼线下方的线条、短的胡须纹和下巴，黑色偏褐色的眼前区，以及带有锈色的橄榄褐色上体其余部分。雌鸟整体呈褐色，腹部橙色较淡。幼鸟背部棕色，腹部浅橙色，头部有模糊的暗色和亮色标记。","call":"白眉鸫的鸣唱由一系列短促、断断续续且多变的短语组成，包括简单而丰富但有时略显粗糙或芦苇般的音符，通常以非常短的高音颤音、嗡嗡声或几个清脆的音符结束。群鸟在春季迁徙前会发出咕噜的亚歌曲。","habits":"白眉鸫栖息于低矮树丛和林间，性情活泼喧闹，温顺且好奇。主要食物为鞘翅目、鳞翅目昆虫及其幼虫，也食用小型无脊椎动物和植物果实与种子。迁徙季节可见成群活动，通常独行或成对。","breeding":"繁殖期在5月至7月，白眉鸫在林下的小树或高灌木上筑巢，巢呈杯状，主要由细枝、干草、根和泥土构成。每年繁殖一窝，产卵4-6枚，平均孵化期约14天。在中国北方为夏候鸟，南方为旅鸟或冬候鸟。","identification":"白眉鸫与白腹鸫的区别在于后者无白色眉纹，胸和两胁不为橙黄色；与赤胸鸫的区别在于后者无眉纹；与褐头鸫的区别在于后者胸和两胁为灰色，而白眉鸫两胁为红褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于欧亚大陆中部至俄罗斯东南部；非繁殖区遍布亚洲东南部，包括菲律宾、大巽他群岛、印尼苏拉威西岛北部和弗洛勒斯岛（小巽他群岛中部）。在中国，白眉鸫遍及全境，除青藏高原外。","other":"白眉鸫的化石记录显示，该物种至少自晚更新世就在印度尼西亚存在。"},{"name":"白腹鸫","english_name":"Pale Thrush","scientific_name":"Turdus pallidus","overview":"白腹鸫（英文名：Pale Thrush，学名：Turdus pallidus），是雀形目鸫科鸫属的鸟类。广泛分布于东亚和北亚的鸟类。虽名为‘白腹’，其实全身以褐色为主，但在分布区域内算是羽色较为单一的鸫类。喜欢在低地森林、次生植被、公园及花园中活动，常单独或成对出现，迁徙季节会形成大群，尤其是在有浆果的地方。性情羞怯，善于隐蔽。","appearance":"成鸟长约23厘米，体重介于64到90克之间。雄鸟头部呈蓝灰色，上身淡棕色，下身颜色较浅，胸和两侧偏深，腹部和下体白色至淡黄色。雌鸟外观类似但色调更为暗淡，喉部污白色。幼鸟背部呈棕色，下体橙色，斑点和条纹明显。飞行时，尾羽的白色尖端尤为显眼。","call":"发出响亮的‘chuck-chuck’声和‘see-ip’叫声，以及冒泡般的警报声。春季迁徙前，有时会唱出一系列欢快但单调的歌声，持续约2秒，间隔5秒。","habits":"栖息于多种环境，包括森林、灌木丛、花园和公园。迁徙性较强，夏季在俄罗斯东南部、中国东北部和朝鲜半岛繁殖，冬季南迁至日本、中国南部、韩国南部等地。偏好有水的森林地带，也出现在果园和农田。以昆虫、蜘蛛、浆果和种子为食。","breeding":"繁殖期为5月至7月，主要在海拔1200米以上的针阔叶混交林中筑巢，巢呈杯状，由细枝、干草、根须和泥土构成。一窝产卵4至6枚，孵化期13至14天，雏鸟离巢期13至15天。","identification":"与白眉鸫和灰背鸫相近，但白腹鸫胸部和两侧为褐灰色而非黄褐色，尾羽端部白色较宽。与赤胸鸫的区别在于胸及两侧的颜色差异。无明显的眉纹，这有助于与褐头鸫区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于欧亚大陆的俄罗斯东南部、中国东北部和朝鲜半岛。非繁殖区覆盖日本、台湾岛、中国大陆东南部，偶尔到达云南和菲律宾。","other":"白腹鸫是国家三有保护鸟类，即有益的或者有重要经济、科学研究价值的陆生野生动物。"},{"name":"赤胸鸫","english_name":"Brown-headed Thrush","scientific_name":"Turdus chrysolaus","overview":"赤胸鸫（英文名：Brown-headed Thrush，学名：Turdus chrysolaus），是雀形目鸫科鸫属的鸟类。俗名: 赤腹鸫、日本褐色鸫，直译:褐头鸫鸫，迁徙性的鸫科鸟类。繁殖于库页岛、千岛群岛和日本北部，冬季南迁至日本南部、台湾岛、中国大陆东南部和菲律宾北部。整体羽色为饱满的土褐色，雄鸟成鸟头部深褐色，雌鸟和幼鸟喉部有条纹。主要栖息于温带森林。","appearance":"体长23-24厘米，体重64-90克。雄鸟具有烟灰色脸部和喉咙，逐渐变为棕色至背部和颈部的铁锈色。雌鸟和幼鸟头部颜色与背部一致，喉部有白色条纹，脸颊暗色。腹部两侧橙色，中央白色，腿棕色。喙暗黄色，上颚部分常呈灰暗色。","call":"春季迁徙前的歌曲由一系列3-4个音符组成，如“krurr kruur krr-zeee”或“kiron kiron tsee”，持续约2秒，间隔5秒。叫声包括尖锐的“chuck-chuck”声，当受惊或飞行时发出细长的“zeeee”声。","habits":"夏季主要以昆虫为食，包括蝉、叩头虫、象鼻虫等，同时摄取蜘蛛和软体动物。秋季和早春主要食用果实，如山楂、醋栗、越橘等。栖息于各种森林环境，从低地到海拔2400米的山地。","breeding":"在温带森林中繁殖，具体繁殖行为细节未详述。","identification":"与其他鸫类相比，赤胸鸫具有明显的橙色腹部两侧和中央白色的腹部，雄鸟头部深褐色，而雌鸟和幼鸟的头部颜色与背部一致，喉部有白色条纹。","protection":"IUCN：LC（无危）。在日本常见，但在朝鲜半岛可能非常罕见。","distribution":"繁殖于库页岛、千岛群岛和日本；越冬于中国东南部、台湾、海南和菲律宾北部。在中国大陆，主要见于东部沿海省份。"},{"name":"伊岛鸫","english_name":"Izu Thrush","scientific_name":"Turdus celaenops","appearance":"雄性伊豆鸫长23厘米，上部黑褐色，翅膀和尾巴深色，胸腹部橙红色，腹部中间白色至尾部有暗色条纹，喙黄绿色，眼环窄黄，腿褐色。雌鸟头部深棕色，喉部白色，有深棕色脸颊和喉部条纹。幼鸟上部棕色，具浅色条纹，下部淡色，有斑点。","call":"鸣声为一连串3-5个嗡嗡颤音，音调变化，中间部分尖锐，有时以\"tsizi\"结尾，有时穿插突然的\"chik!\"音符。","habits":"栖息于常绿森林，夏季主要以昆虫为食，尤其集中在树冠层捕食毛虫，冬季则食用果实、种子和无脊椎动物。在树冠和地面枯叶间觅食，有时也在开阔地带。","breeding":"繁殖期为3月至6月，筑巢于低枝或地面，由草和树叶构成，外部覆盖苔藓，每窝产卵2-5枚，通常3-4枚，蛋壳白底带红棕色或紫色斑点。繁殖成功率受外来物种威胁影响。","identification":"雄鸟具有明显的黑色兜帽至下胸，雌鸟与幼鸟上部具淡色条纹，下部具斑点，与褐头鸫雌鸟和幼鸟相似，但有更广泛的黑色斑点。","protection":"IUCN：VU（易危）","distribution":"分布于伊豆群岛（从Toshima至Aogashima）和北琉球群岛（Yakushima、Tokara Islands），冬季部分个体迁至九州南部岛屿、Oshima及本州南部。","other":"面临引入物种的威胁，如西伯利亚鼬鼠、大嘴乌鸦和家猫，对其巢穴和幼鸟造成严重伤害。"},{"name":"黑喉鸫","english_name":"Black-throated Thrush","scientific_name":"Turdus atrogularis","overview":"黑喉鸫（英文名：Black-throated Thrush，学名：Turdus atrogularis），是雀形目鸫科鸫属的鸟类。曾被认为是赤颈鸫的亚种，现已确认为独立物种。其雄鸟具有显著的黑色喉部和胸部，与赤颈鸫形成鲜明对比。分布于欧亚大陆的中西部至西伯利亚中北部和蒙古西北部。","appearance":"体长约24至27厘米，重54至110克。雄鸟面部、喉部及胸部漆黑，背部暗灰，尾羽黑色；下体白色，具宽而不明显的条纹；喙深色，下颚黄色；腿红棕色。雌鸟较暗淡，喉部和胸部有白色羽尖，两胁有细薄的黑纹。幼鸟呈棕灰，上体具淡褐色条纹和斑点，下体浅色，喉部和腹部更淡，面颊深色，胸部密集黑斑，两胁斑点较少。","call":"鸣唱由一系列缓慢的、悠扬的乐句组成，包括‘chip-chip-chip…chi-chi-chi-chi…cherr-vóó, cherr-véé, chet-chet-chet…’等，含有丰富的低沉双音节音符。叫声包括尖锐的‘seet’，高频的‘qui-kwea’用于联系，以及警报时的喉咙发出的‘which-which-which’。","habits":"繁殖于多种生境，包括纯针叶林、干燥稀树地带、落叶松丛、柳树灌丛、杨树林、白桦林、荆棘丛和沼泽地带，海拔高度可达2200米。冬季栖息于草地灌木坡地、森林边缘、柳树林、田野、花园、果园、牧场和耕作地，海拔范围从低地到4200米。迁徙时会穿过伊朗、阿富汗和蒙古。","breeding":"繁殖期为5月至7月，一窝产卵4至7枚，蓝绿色蛋壳上有浅褐色斑点和雀斑。孵化期11至12天，雏鸟期11至13天。","identification":"与赤颈鸫的区别在于，黑喉鸫雄鸟的喉部和胸部为黑色，而非红色。雌鸟与赤颈鸫雌鸟相比，喉部和尾羽两侧无橙色。","protection":"IUCN：LC（无危）","distribution":"繁殖区：欧亚：俄罗斯中西部至西伯利亚中北部和蒙古西北部；非繁殖区：亚洲西南部和南部，包括中东、喜马拉雅山脉、中国南部和缅甸北部。","other":"迁徙模式部分或完全迁徙，冬季分布受天气条件影响。"},{"name":"赤颈鸫","english_name":"Red-throated Thrush","scientific_name":"Turdus ruficollis","overview":"赤颈鸫（英文名：Red-throated Thrush，学名：Turdus ruficollis），是雀形目鸫科鸫属的鸟类。直译: 红喉鸫，栖息于山区的大型鸫科鸟类。其雄鸟颈部及胸部呈赤红色，故得名。分布于欧亚大陆的中南部，自东西伯利亚至中国西北部，冬季南迁至印度北部至越南北部。","appearance":"雄鸟背部灰暗，腹部白色，喉部及胸部为砖红色，眼眉纹亦为砖红色。雌鸟颜色较淡，喉部有黑色斑纹，脸部带淡红色。幼鸟土褐色，具条纹，难以与黑喉鸫区分，但其外侧尾羽为栗红色，喉部有橙色调。体型介于24至27厘米，体重63至103克。","call":"鸣唱为一系列间隔开的简短笛音短语，缺乏黑喉鸫歌曲中的流连、叽叽喳喳的特质。叫声包括粗哑的高音“kwee-kweek”和更对话式的“skrie-kri-kriek”。","habits":"栖息于稀疏的山地森林，常在云杉林的上限、苔藓树线灌木丛、高原针叶林和河谷山地的底部森林。冬季栖息于开放的杜松林、灌木丛和果园，海拔可达3900米。以昆虫为主食，秋季和冬季则摄取浆果和种子。","breeding":"繁殖期为5月至7月，筑杯状巢于树木低处，常用材料为树枝、苔藓和茎，衬以细枝。每窝产卵4至5枚，卵色淡蓝带许多肉桂色斑点，孵化期10至12天，雏鸟期11至13天。","identification":"与黑喉鸫区别在于雄鸟的红色喉部，雌鸟喉部具黑色斑纹，幼鸟尾羽外侧为栗红色。在重叠区域需小心辨别可能的杂交个体，其特征介于两物种之间。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯中南部、蒙古北部和中国西北部；非繁殖期分布于印度北部至越南北部。"},{"name":"红尾斑鸫","english_name":"Naumann's Thrush","scientific_name":"Turdus naumanni","overview":"红尾斑鸫（英文名：Naumann's Thrush，学名：Turdus naumanni），是雀形目鸫科鸫属的鸟类。体背主色调为棕褐色，下体白色，胸部有一圈红棕色斑纹，两胁具红棕色点斑，眼上具清晰的白色眉纹。红尾斑鸫繁殖于欧亚大陆中部的俄罗斯，越冬于东亚，包括中国东部。此物种与斑鸫关系密切，曾一度被视为同一物种。","appearance":"成年红尾斑鸫长约23-25厘米，体重63-81克。雄鸟上体淡橄榄灰色，有淡红褐色眉纹，淡红褐色肩羽尖端和中上翼覆羽，淡红褐色尾羽；下体橙红褐色，具狭窄的暗色斑点组成的颊纹，下胸至腹部有白色的鳞状斑。雌鸟类似雄鸟，但翅膀无红褐色，尾羽更偏褐色，喉部有更强的斑纹。幼鸟类似成鸟，但背部和肩羽有更重的淡褐色条纹，下体黑斑更多。","call":"红尾斑鸫的鸣唱由短暂的乐句组成，每间隔几秒开始，先以细弱的哨声渐强至粗糙的颤音，类似于白眉歌鸫的歌声。叫声记录不详，可能与斑鸫相似，包括报警时的急促“swer-swer-swer”声，起飞时的薄而嘶哑的“zeep”声，以及交流时的“que-que-que”声。","habits":"繁殖于西伯利亚的低地苔原边缘，栖息于稀疏的北方针叶林和灌木丛，迁徙期间出现在低地泛洪平原的栖息地，包括橡树林和麦茬地。在冬季，红尾斑鸫主要在中国、朝鲜半岛和邻近国家越冬，偶尔在日本和台湾出现。食性广泛，包括昆虫、昆虫幼虫和浆果。","breeding":"红尾斑鸫在5月至6月间繁殖，筑巢于树木中，巢呈碗状，内部整洁，外层粗糙。每窝产卵3-5枚，卵呈淡蓝色，表面散有红褐色细斑，平均大小为27.8×20.6毫米。春季返回繁殖地的时间从4月延续到6月初。","identification":"红尾斑鸫与斑鸫的主要区别在于，红尾斑鸫的背部和头部为灰褐色，带锈色，下体白色，脸部、胸部、腰部红棕色，两胁和臀部具红棕色点斑。而斑鸫的背部和臀部颜色更深，脸部、胸部和两胁具黑色点斑。此外，红尾斑鸫的鸣唱可能与斑鸫的简单笛音或哨音有所不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于中西伯利亚至北满洲、阿穆尔河地区和萨哈林岛。非繁殖区域覆盖了俄罗斯东南部和中国东部，主要越冬于中国长江流域以北的华北地区，以及朝鲜半岛和日本。","other":"红尾斑鸫与斑鸫的混种在北京地区较为常见。"},{"name":"斑鸫","english_name":"Dusky Thrush","scientific_name":"Turdus eunomus","overview":"斑鸫（英文名：Dusky Thrush，学名：Turdus eunomus），是雀形目鸫科鸫属的鸟类。又名: 穿草鸡、窜儿鸡、红麦鴓、斑点鸫、傻画眉，以其显著的黑白斑纹著称。广泛分布于中北部至俄罗斯东北部，冬季南迁至印度至日本。斑鸫在西伯利亚的泰加林、桦树林等地繁殖，迁徙期间和非繁殖季节则出现在农田、林缘和村庄附近的灌丛中。","appearance":"斑鸫体长约23-25厘米，体重55-106克。雄鸟头部黑白分明，脸颊黑色，脸部白色，背部为橄榄褐色，具黑色点斑，双翼棕色。雌鸟与雄鸟类似，但颜色稍暗淡，背部和头部为褐色。幼鸟具有较弱的斑纹，胸腹处的黑斑不如成鸟明显。斑鸫与近缘种红尾斑鸫相比，背部和头部颜色更深，下体白色带黑色点斑。","call":"斑鸫的鸣唱由一系列短促、响亮、富有旋律的3-5个音符组成，包括丰富的哀怨笛声、下滑哨音和干燥的颤音，有时持续而丰富，让人联想到新疆歌鸲、欧乌鸫或欧歌鸫的歌声。此外，它在轻微警报时还会发出抑制的断音‘chuck’，或发出尖锐节奏的‘chek-chek-chek-chek’声，特别是在入睡前。","habits":"斑鸫栖息于开放的林地，不同于红尾斑鸫，斑鸫更能适应山区和苔原边缘的环境。它们是强迁徙性鸟类，冬季南迁至东南亚，主要在中国及邻国越冬。迁徙时和越冬期间，它们常结成小群。斑鸫的食谱广泛，包括各种昆虫、蚯蚓、蜘蛛和浆果，尤其是蚊子和甲壳虫。","breeding":"斑鸫在西伯利亚东部繁殖，筑巢于低矮的小树上，高度不超过60厘米。巢呈杯状，由细树枝、枯草茎、草叶和苔藓构成，内壁有泥土粘合。繁殖期为5月至8月，每窝产卵4-7枚，多为5-6枚，卵呈淡蓝绿色，布有褐色斑点。","identification":"斑鸫与红尾斑鸫的区别在于背部和头部的颜色：红尾斑鸫背部和头部为灰褐色，带锈色，而斑鸫为橄榄褐色，具黑色点斑。红尾斑鸫胸、腰为红棕色，两胁和臀部有红棕色点斑，而斑鸫下体白色带黑色点斑。两者在北京地区常见混种现象。","protection":"IUCN：LC（无危）","distribution":"斑鸫繁殖于中北部至俄罗斯东北部，冬季南迁至印度至日本。在中国，它们常见于福建冬季，上海地区也有分布。在日本的南部库页岛、北海道、本州、佐渡岛、四国、九州及较小的岛屿上，斑鸫数量较多。","other":"斑鸫曾遭受过度猎杀，尤其是在1947年之前，每年多达500万只被捕获用于烧烤交易，这大大减少了越冬数量。在中国农村，斑鸫仍被猎杀作为食物。"},{"name":"田鸫","english_name":"Fieldfare","scientific_name":"Turdus pilaris","overview":"田鸫（英文名：Fieldfare，学名：Turdus pilaris），是雀形目鸫科鸫属的鸟类。其头部、颈部和腰部呈灰蓝色，背部深栗褐色，下体白色，胸部与两胁布满黑色条纹，下腹部白色。在欧亚大陆北部的森林与灌木丛中繁殖，广泛分布于北欧至西伯利亚东部。迁徙性强，冬季可见于南欧、北非和中东地区。","appearance":"田鸫身长25厘米左右，翼展39至42厘米，体重介于80至140克之间。头部、颈部和腰部为独特的灰蓝色，背部暗栗色，尾部黑色，下体白色，胸部和两侧有黑色斑点。飞行时，白色的翼下覆羽和腋羽十分醒目。雄鸟和雌鸟相似，但雌鸟上部颜色更偏棕色，喉部和胸部的标记较少且较淡。幼鸟色彩较为暗淡，具有淡色条纹和深色斑点。","call":"田鸫发出的叫声是刺耳的'chak chak chuk'，飞行时尤为明显。此外，它们还发出柔和的'chak chak'声用于同伴间的交流，愤怒或警戒时会发出类似槲鸫的警告声。雄鸟的歌声在繁殖季节演唱，由几种短语、口哨、嘶哑声和叫声混合而成。","habits":"田鸫栖息于混合林地，偏好靠近湿地、荒地或开阔地带的森林。夏季，它们在松树、桦树等混交林中活动；冬季，则迁徙至开阔的田野、果园和公园等地。它们以群居方式生活，尤其在冬季与红翅鸫和其他鸫科鸟类共同觅食。食物多样，包括昆虫、蜗牛、蚯蚓和各种果实。","breeding":"繁殖季节自五月开始，通常在波兰，但在斯堪的纳维亚半岛可能延至七月初。雌鸟在树上建造杯状巢，巢由干草、杂草、树枝和苔藓构成，内衬泥和细草。每窝产蛋5到6枚，蛋壳呈淡蓝色并带有棕色斑点。孵化期为13至14天，主要由雌鸟负责。雏鸟在14至16天后离巢，父母双方共同喂养。","identification":"田鸫与欧乌鸫的区别在于前者头部、腰部的灰蓝色，背部的深栗色以及胸部和两胁的黑色斑纹。幼鸟的特征也有助于与成鸟区分。","protection":"IUCN：LC（无危）。田鸫在全球范围内数量众多，估计有4400万至9600万只，分布在约1000万平方公里的范围内，种群稳定。","distribution":"繁殖区位于欧洲北部至俄罗斯东部，非繁殖区扩展至非洲北部和冰岛。在英国，尽管是罕见的繁殖者，但冬季有大量个体迁徙至此。","other":"田鸫在近百年内数量显著增加，特别是在欧洲，但全球范围内没有已知的相应下降。"},{"name":"白眉歌鸫","english_name":"Redwing","scientific_name":"Turdus iliacus","overview":"白眉歌鸫（英文名：Redwing，学名：Turdus iliacus），是雀形目鸫科鸫属的鸟类。原生于欧洲及亚洲，略小于其近亲欧歌鸫。其最显著特征为两侧及翼底的红色，以及眼上部的奶油白色条纹，因此得名'白眉'。广泛分布于欧亚大陆，冬季迁徙至非洲北部。","appearance":"体长20-24厘米，翼展33-34.5厘米，体重50-75克。背部为单一的棕色，下体白色，布满深褐色斑点。最具识别性的特征是红色的侧腹和翼底，以及眼上方的奶油白色条纹。成鸟在6月至9月期间换羽，部分个体在育雏同时开始更换飞羽。","call":"雄鸟发出多样化的短歌，伴有哨音般的飞行叫声。红翅鸫的歌声包含一系列频率下降或上升的前奏元素，随后是一连串快速而复杂的旋律模式。","habits":"栖息于北方的欧洲和帕拉尔地区的森林、冻土带的针叶林和桦木森林。冬季迁徙至西、中、南欧，北非，西南亚洲至伊朗北部。通常形成松散的群体，有时与田鸫、黑鸫和椋鸟混群。在秋冬季夜迁徙时发出清晰的‘Tseep’联系叫声。","breeding":"繁殖季节为4月初至7月末，筑巢于灌木丛或地面，每窝产卵4-6枚，蛋壳重量约占总重的5%，孵化期为12-13天。雏鸟12-15天后离巢，但需额外14天依赖父母喂养。","identification":"与欧歌鸫相比，白眉歌鸫体型较小，拥有独特的红色侧腹和翼底，以及眼上的奶油白色条纹。","protection":"IUCN：NT（近危）","distribution":"繁殖区域包括欧亚大陆中部和西部，非繁殖季节分布至非洲北部。在欧洲，大量分布于芬兰、俄罗斯、挪威等地。","other":"白眉歌鸫的全球繁殖范围仅40%位于欧洲，但欧洲人口估计已减少25-30%，目前处于近危状态。"},{"name":"欧歌鸫","english_name":"Song Thrush","scientific_name":"Turdus philomelos","overview":"欧歌鸫（英文名：Song Thrush，学名：Turdus philomelos），是雀形目鸫科鸫属的中型鸟类。长约22厘米，背部橄榄褐色，下体白色带黑色点斑，胸部点斑沾皮黄色，腹部及两胁黑色点斑较多。其名称来源于希腊神话中的公主菲洛墨拉，她虽被割舌却变成了歌唱的鸟。欧歌鸫分布广泛，部分为候鸟，迁徙至南欧、北非及中东过冬，也曾被引入新西兰及澳大利亚。","appearance":"欧歌鸫体长20至23.5厘米，体重50至107克，背部呈棕色，腹部为奶油色或黄褐色，带有黑色斑点，腹部颜色渐淡。翅膀下部温暖的黄色，喙黄色，腿和脚粉红色。幼鸟背部和翼盖有橙色或棕色条纹。","call":"欧歌鸫发出短促尖锐的'tsip'叫声，在迁徙时变为细高的'seep'声，类似白眉歌鸫的叫声但更短。报警叫声是'chook-chook'，随着危险增加变得越来越短和尖锐。雄鸟的歌声响亮清晰，由重复的音乐短语组成。","habits":"欧歌鸫栖息于各种森林、花园和公园，偏好有树木和灌木的环境，包括公园、花园、针叶林和落叶林以及树篱。它们在开阔的草地和草坪上觅食，但通常靠近遮蔽处。饮食以无脊椎动物为主，尤其是蚯蚓和蜗牛，也吃软果和浆果。它们会用石头砸开蜗牛壳。","breeding":"繁殖期一般在4月至7月，筑巢于树干附近的地面1至5米高处，巢由草、树枝和苔藓构成，内部衬以泥土、粪便或腐木。每窝产卵4至6枚，孵化期11至12天。一年繁殖1至2窝。","identification":"欧歌鸫体型较槲鸫小，在新疆分布不如槲鸫普遍。与白眉歌鸫相比，白眉歌鸫有明显的白色眉纹，红色侧腹，飞行时可见红色翼下。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲中部和西部，以及乌克兰和俄罗斯近至贝加尔湖。冬季迁徙至地中海、北非和中东。在中国极西北部繁殖，主要在森林和林缘地带，高度约100米左右。","other":"欧歌鸫的歌声被多位诗人提及，如罗伯特·布朗宁、托马斯·哈代和泰德·休斯。"},{"name":"宝兴歌鸫","english_name":"Chinese Thrush","scientific_name":"Turdus mupinensis","overview":"宝兴歌鸫（英文名：Chinese Thrush，学名：Turdus mupinensis），是雀形目鸫科鸫属的鸟类。俗名: 花穿草鸡、歌鸫，为中国特有种，分布于中国部分山区，包括内蒙古、北京、河北、甘肃、贵州、四川、云南、山东、浙江等地，偶有迷鸟至台湾。该物种体长约23厘米，具褐色冠羽和上体，下体密布圆形黑色斑点，耳羽附近有黑色新月形斑纹，头型浑圆，眼圈明显。宝兴歌鸫栖息于海拔1200-3500米的山地针阔叶混交林和针叶林中。","appearance":"中等体型，长约23厘米，上体呈灰褐至褐色，头部有黑色垂直条纹延伸至眼下方和耳羽后方，形成显著的黑色新月形斑。上翼覆羽有明显的大型淡色尖端，下体白色带微黄晕染，胸部至腹部及两胁有厚重的黑色斑点。喙部暗色，基部略浅，腿脚粉红色。雌雄相似，幼鸟头部更偏黄色，颈背至肩部有黄色条纹。","call":"鸣唱声多变而通常柔和，带有许多上扬的音节，歌曲由一系列悦耳的、间隔均匀的短语组成，每组短语包含3-5个音调相当均匀的音符，如“drrip-dii-du dudu-du-twi dju-wi-wi chu-wii-wr’up chu-wi’i-wu-wrrh dju-dju-wiii’u…”。","habits":"主要栖息于海拔1200-3500米的山地针阔叶混交林和针叶林中，尤其是河流附近的湿润栎树和松树林。宝兴歌鸫通常为留鸟，但在北部繁殖的种群会迁徙至南方越冬。春季迁徙时间为4-5月，秋季为9-10月。主要食物为金龟甲、蝽象、蝗虫、鳞翅目、鞘翅目等昆虫及其幼虫。","breeding":"繁殖期为5-7月。巢建于海拔1500米以上的亚高山针阔叶混交林中，距离地面约2.5米。巢由枯枝、枯草、苔藓和粘土构成，内铺细草茎和纤维。窝卵数4枚，卵呈淡蓝灰绿色，表面散布玫瑰红褐色和灰蓝褐色点斑。卵的大小约为19.5mm×28.9mm，重量约5.5g。","identification":"宝兴歌鸫与欧歌鸫、斑鸫和槲鸫的辨识要点在于：宝兴歌鸫耳羽有黑斑，翼斑醒目，而欧歌鸫耳羽无黑斑；斑鸫耳羽无黑斑，尾上和尾下覆羽棕色；槲鸫耳羽无黑斑，背部有‘虎斑’，头部有细小密集的‘虎斑’。","protection":"IUCN：LC（无危）。宝兴歌鸫在中国特有，种群数量稀少，已列入全球濒危鸟类名录，但尚未被列入中国国家重点保护野生动物名录。","distribution":"分布于中国中部，包括河北、甘肃南部至云南；北部种群可能迁徙至南方过冬。记录有迷鸟出现在韩国南部、台湾、越南北部和印度东北部。"},{"name":"槲鸫","english_name":"Mistle Thrush","scientific_name":"Turdus viscivorus","overview":"槲鸫（英文名：Mistle Thrush，学名：Turdus viscivorus），是雀形目鸫科鸫属的鸟类。体长可达28厘米，以其偏好食用槲寄生果实而得名。广泛分布于欧洲、温带亚洲及北非地区，为候鸟，冬季会由北部和东部地区迁徙至较为温暖的地带。在中国，仅见于新疆等地，数量稀少。","appearance":"槲鸫体型较大，约28厘米，上体呈淡褐色，下体皮黄白色，遍布黑色圆点斑纹。具有一双黄色脚，尾巴较长，末端白色，翼下覆羽亦为白色。雌雄羽毛相似，幼鸟上体颜色较浅，下体黄色，点斑较小。","call":"雄性槲鸫在恶劣天气或夜晚会发出响亮而婉转的鸣叫，叫声为干涩颤音“zerrrrr”及凄郁的下降笛音，类似于乌鸫，但不如欧歌鸫鸣声婉转。","habits":"槲鸫为候鸟，冬天会从北方迁往南方越冬，迁徙时常结成小型鸟群。以多种昆虫、蚯蚓、蜗牛、蛞蝓和浆果为食，尤其喜爱槲寄生的果实。冬季会占据果树，排斥其他鸫科鸟类靠近。","breeding":"槲鸫在树上筑巢，巢由草叶、草根和泥土编织而成，内部铺有干草，通常产卵4-5枚，卵呈白色，带有灰褐或红褐色斑点。","identification":"槲鸫与欧歌鸫相比，体型更大（28厘米），上体褐色更浓，外侧尾羽端部白色，翼下覆羽白色。胸腹颜色较浅，黄或白色，胸侧可能出现块状黑斑。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在欧亚大陆的中部、西部以及非洲北部，非繁殖期则分布于非洲北部和亚洲南部。","other":"槲鸫的学名和中文名均反映了其食槲寄生果实的特性。"},{"name":"大棕鸫","english_name":"Great Thrush","scientific_name":"Turdus fuscater","overview":"大棕鸫（英文名：Great Thrush，学名：Turdus fuscater），是雀形目鸫科鸫属的鸟类。是南美洲最大的鸫科成员，体重可达175克，体型几乎接近喜鹊大小。在海拔2000-4000米的安第斯山脉高地上，常见于开阔地带，包括森林边缘、花园、城镇甚至城市中，胆大且容易观察到。雄鸟具有黄色眼环，与秘鲁鸫相比，体型更大，颜色更深。","appearance":"大棕鸫整体呈暗橄榄棕色，尾部长，体长28-33厘米。雄雌羽色相似，但雄鸟拥有橙色眼环。七个亚种在体型和色彩上有细微差别，但均比其他安第斯山地区的Turdus属鸟类大，雄鸟的黄色眼环尤为显著。","call":"大棕鸫的鸣唱柔和而悦耳，仅在繁殖季节的日出前表演，由快速多变的音乐短语组成，以极高的音符结束。受惊时会发出短暂的'keert'声或一系列'kurt-kurt-kurt-kurt'。","habits":"大棕鸫广泛分布于南美洲的湿润安第斯山环境，尤其在海拔2000米以上的人类活动区域最为常见。它适应性强，栖息地包括开放森林、后院、公园、农田以及城市区域。主要以果实、浆果、昆虫和小型脊椎动物为食。","breeding":"繁殖期随地理位置不同而异，从委内瑞拉的3-4月，哥伦比亚的1-8月，厄瓜多尔的10月，到秘鲁的2月和6月。巢杯状，由小树枝、叶子、草和泥制成，通常位于树或灌木低处。雌鸟产下2枚淡蓝绿色带红斑点的蛋，平均大小约2厘米。","identification":"与秘鲁鸫相比，大棕鸫体型更大，颜色更深，雄鸟有黄色眼环。辉背鸫虽颜色相近，但体型较小，栖息于更湿润的森林内部。","protection":"IUCN：LC（无危）","distribution":"从委内瑞拉西部至玻利维亚西部，贯穿南美洲安第斯山脉。"},{"name":"秘鲁鸫","english_name":"Chiguanco Thrush","scientific_name":"Turdus chiguanco","overview":"秘鲁鸫（英文名：Chiguanco Thrush，学名：Turdus chiguanco），是雀形目鸫科鸫属的鸟类。广泛分布于南美安第斯山脉及西部沙漠丘陵地带。常见于公园、花园、农田及半开放生境，拥有橄榄灰褐色的外观，下部略淡，喉部模糊的黄褐色条纹，喙和腿黄色，虹膜红至栗色。雄雌相似，但在南美东部与南部，雄鸟呈现暗黑灰色，具黄色喙和眼环，雌鸟为深灰蓝黑色，喙黄色。","appearance":"体型中等，体长25至30厘米，体重75至120克。指名亚种为均匀的橄榄灰棕色，下部略显苍白，喉部有模糊的黄褐色条纹，喙、腿及脚均为黄色，虹膜红至栗色。雌雄相似。幼鸟橄榄灰褐色，上部具淡黄褐色中央羽轴纹，头部及翼覆羽有黄褐色斑点，下体具黄褐色斑点及条纹。","call":"歌曲较弱且相对不悦耳，一系列短而简单的旋律片段，以混乱或叽叽喳喳结尾，每段重复2至3次，‘siblisirrilé seblesierrilli...’。叫声包括典型的‘duck-duck’或尖锐的‘tchok-kiek’作为联系声，以及飞行中的快速‘tsi-tsi-tsi’。","habits":"通常单独或成对出现，偏好农业和半开放区域，如散树、灌木丛、园子、公园和轻度灌木林，尤其在干旱区域，但常靠近水源或灌溉区及人类居住地附近。海拔高度从1600米到4000米不等，偶尔可达4650米。","breeding":"筑巢期主要在10月至翌年1月，孵化期约为11至12天，由雌鸟独自承担。巢呈坚固的杯状，由草和细枝构成，内部铺垫柔软纤维。每窝产卵2至3枚，卵呈浅绿色，带红棕色和灰色斑点。","identification":"在智利境内无可比物种，但在玻利维亚和秘鲁需与更大的大棕鸫相区别，后者偏好更湿润的环境。","protection":"IUCN：LC（无危）","distribution":"分布于厄瓜多尔中部向南至秘鲁沿海南部，玻利维亚中部及西部，智利北部（安托法加斯塔、阿塔卡马），以及阿根廷西中部，局部在相邻的智利中部。","other":"在阿根廷，至少在1950年代之前，由于其优美的歌声，曾被用于笼鸟贸易。"},{"name":"乌鸲鸫","english_name":"Sooty Thrush","scientific_name":"Turdus nigrescens","overview":"乌鸲鸫（英文名：Sooty Thrush，学名：Turdus nigrescens），是雀形目鸫科鸫属的鸟类。仅见于哥斯达黎加和巴拿马西部的高地，体长约24-25.5厘米，平均体重96克，全身呈深褐色至黑色，雄鸟特征更为显著，拥有橙色的喙、眼环和腿，以及白色的虹膜。","appearance":"雄性乌鸲鸫呈棕色至黑色，头侧、翅膀和尾巴呈烟灰色，雌鸟较雄鸟更偏棕色，有时喉部有更深的条纹。幼鸟为深棕色，上部有淡黄色条纹，下部有暗棕色斑点，下巴白色，裸露部分浅黄棕色。","call":"其歌声相对较单调，由一系列短小的乐句组成，每句重复3-6次，中间有几秒钟的停顿，包含咕噜声、嗡嗡声或尖锐的类似Vireo的音符。叫声包括独特的低沉摩擦声“grrrek”或“trrrr”，常重复，细长滚动的“prrreee”，和刺耳的“tchweerp, tchweerp”。","habits":"栖息于海拔2200米以上的开阔地带和橡树林边缘，单独或成对活动，主要在地面觅食，翻动草丛和低矮植物垫，以昆虫、蜘蛛和多种浆果为食，尤其喜食杜鹃花科、茄科和梅拉斯特梅斯等植物的果实。","breeding":"繁殖季节通常在3月至5月间，雌鸟在离地2-8米高的树上筑造厚实的草衬杯状巢，产下两枚无斑点的蓝绿色蛋。","identification":"乌鸲鸫与山鸫和黏土色知更鸟外观相似，但山鸫全身均匀棕色，裸露部分颜色较暗，黏土色知更鸟则颜色更淡，喙为黄色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于中美洲的哥斯达黎加和巴拿马西部。"},{"name":"美洲黑鸫","english_name":"Black Thrush","scientific_name":"Turdus infuscatus","overview":"美洲黑鸫（英文名：Black Thrush，学名：Turdus infuscatus），是雀形目鸫科鸫属的鸟类。中型森林鸟类。以黑色或深棕色羽毛为主要特征，常见于中美洲的高海拔常绿林和松树-常绿混交林中，分布于墨西哥至洪都拉斯。","appearance":"成年雄鸟全身黑色，带有鲜艳的黄色喙、眼圈和腿脚，虹膜较暗。雌鸟整体呈深棕色，腹部颜色较浅，喉部有淡色条纹，翼下覆羽呈浅橙色，喙色较暗，眼圈和腿脚黄色。幼鸟上部深棕色，肩部有橙色斑点和条纹，下部橙色，带有模糊的暗棕色斑点，斑点在胸部最密集；一岁雄鸟黑色，羽毛尖端灰褐色，喉部白色带暗色条纹。","call":"鸣唱由一系列丰富而婉转的乐句组成，每句重复2到3次，声音柔和而醇厚，但略显犹豫，有时穿插琐碎和粗糙的声音，甚至模仿其他鸟类的叫声。叫声包括干燥的‘chuh-chuh-chuh-chuh-chuh’，较硬的‘chehk-chehk’声，以及高而细的‘sii’飞行叫声。","habits":"主要栖息在中美洲的高海拔森林，冬季会进行小规模的向下迁移。食物包括昆虫、蠕虫和果实，尤其是小浆果。偶尔会在开阔地带的地面觅食，但主要在树上觅食，常成群出现在结果的树木上。","breeding":"繁殖季节主要集中在2月至6月，如在危地马拉的特克潘山区，仅在这一时期出现，其余时间可能迁移到更低、更温暖的地区。","identification":"与褐背鸫的区别在于后者主要出现在低地，且腿脚呈淡粉色。美洲山鸫具有深色的腿脚，与之不同。","protection":"IUCN：LC（无危）。在奥阿哈卡州较为常见，在墨西哥南部普遍。在洪都拉斯除奥科特佩克省外较为罕见，但在该省则较常见。","distribution":"分布于中美洲，从墨西哥东部和南部至洪都拉斯，可能也分布于尼加拉瓜相邻地区。"},{"name":"辉背鸫","english_name":"Glossy-black Thrush","scientific_name":"Turdus serranus","overview":"辉背鸫（英文名：Glossy-black Thrush，学名：Turdus serranus），是雀形目鸫科鸫属的鸟类。中大型的鸫科鸫属鸟类，广泛分布在南美安第斯山脉的亚热带区域，海拔高度约在1500至2800米之间。该物种以全黑的光泽羽毛、橙色的喙、腿和眼圈为显著特征。在委内瑞拉至阿根廷西北部的自然生境中，辉背鸫常见于湿润的山地森林。","appearance":"雄性辉背鸫全身呈现深邃的光泽黑色，拥有橙色的喙、眼圈和腿。雌鸟则为温暖的中等棕色，喙、腿和眼圈颜色较为暗淡，呈淡黄色。幼鸟上部为深灰褐色，下部较浅且带红色，喙色偏棕色，眼圈和腿黄色。雄鸟幼鸟背部颜色更深，近似烟灰色，雌鸟幼鸟则为暖棕色，两者皆有斑点和条纹覆盖，腹部带有暗色斑点。","call":"辉背鸫的鸣唱独特而快速，由一系列急促音符组成，音调在结尾处上升，形成类似“tii-do-do-iit”或“sriigli sirrieglegi”的声音，尖锐而富有金属质感，通常在黎明前持续约30分钟，间隔短暂，反复吟唱。","habits":"辉背鸫主要栖息于云雾缭绕的山地森林或其边缘地带，偏好在树冠层活动，较少降落地面。它们有时会在黄昏或拂晓时分出现在开阔地带，尤其是在沿路的果树林中觅食。辉背鸫偶尔会加入混合物种的群鸟中。","breeding":"关于辉背鸫的繁殖习性的具体信息有限，但这类物种通常在春季进行繁殖，营巢于树上，产卵数量和孵化期因地区而异。","identification":"辉背鸫与大棕鸫相比，更倾向于隐蔽，而非大胆地在开阔地带跳跃。雄性辉背鸫的光泽黑色羽毛和橙色的喙、腿及眼圈使其容易与其他鸟类区分开来。","protection":"IUCN：LC（无危）","distribution":"辉背鸫的繁殖区域跨越了南美洲的广阔地带，从委内瑞拉一直延伸到阿根廷西北部，包括委内瑞拉的Macarao国家公园、哥伦比亚的Munchique国家公园和阿根廷的Calilegua国家公园等地。","other":"辉背鸫在当地某些地区，如委内瑞拉和厄瓜多尔的Podocarpus国家公园，被视为较为常见的物种。"},{"name":"安第斯灰鸫","english_name":"Andean Slaty Thrush","scientific_name":"Turdus nigriceps","overview":"安第斯灰鸫（英文名：Andean Slaty Thrush，学名：Turdus nigriceps），是雀形目鸫科鸫属的鸟类。分布于南美洲的鸫科鸫属鸟类。在北起厄瓜多尔南部至阿根廷北部的区域可见其踪迹。雄鸟呈中等灰色，头较暗，喉部有淡纹，腹部至臀部白色，雌鸟则整体偏棕色。生活在海拔500至2700米的山地森林。","appearance":"成年雄性安第斯灰鸫上体为板岩灰色，下体略浅，腹部至臀部白色，喉部有黑色细纹，头部颜色更深，眼环、喙和腿黄色。雌鸟上体绿色棕色，下体更淡的绿色棕色，喉部标记不如雄鸟明显。幼鸟类似雌鸟，但上体有橙色斑点和条纹，下体橙色至橙红色，带有深色鳞片状图案。","call":"春季和夏季时，会发出一系列高音混乱的短语，部分音调尖锐、急促而粗糙，之后是长时间的停顿，如“tji tjihe tjie tjihe”或“swidrielipik tillie”。也有“tick tick tick”、“tsok”和悦耳的“pilic”用于联系。同时，有高音“seeee”和特有的尖锐、清脆的“tchee-eh”或“tcheeEElu”。","habits":"栖息于亚热带湿润山地森林的树冠层和边缘地带，次生林，桉树种植园，通常沿着溪流在茂密的灌木丛和林地中活动，偶尔出现在桤木（Alnus）附近。高度从500至2700米，尤其在1000至2100米之间较为常见。","breeding":"繁殖季节在秘鲁西北部为11月至2月（有时从8月初开始出现）；在玻利维亚为12月至2月；在阿根廷西北部为10月至12月（雏鸟出现在1月至2月）。巢置于地面以上3.6米处，蛋数2至4枚，平均2.8枚，蓝色带棕色斑点，平均尺寸26.9毫米×19.6毫米，重量约5.3克。孵化期平均12.5天，雏鸟期平均13天。","identification":"雄鸟与雌鸟的主要区别在于颜色：雄鸟板岩灰色，雌鸟绿色棕色。与黑铁匠鸫的区别在于分布区域和颜色模式。","protection":"IUCN：LC（无危）。局部地区常见，但在秘鲁普遍罕见，在厄瓜多尔被视为近危物种。在厄瓜多尔西南部，由于近年来广泛的森林砍伐，被认为面临一定风险。","distribution":"分布于南美，从厄瓜多尔南部至阿根廷北部，主要在海拔500至2700米的山地森林。","other":"曾被认为是与黑铁匠鸫同一物种的一部分，统称为slaty thrush。"},{"name":"石鸫","english_name":"Blacksmith Thrush","scientific_name":"Turdus subalaris","overview":"石鸫（英文名：Blacksmith Thrush，学名：Turdus subalaris），是雀形目鸫科鸫属的鸟类，分布于南美洲东南部的低地，包括巴西东南部和巴拉圭。雄性石鸫上体灰褐色，下体淡灰色，喉部有明显的白色条纹终止于一片纯白区域；雌鸟整体更偏棕色，缺乏黑色色调。其高音金属质感的鸣唱独特。","appearance":"成年雄性石鸫长约20.5至22.5厘米，重46至55克。上体呈灰色，胸部同样为灰色，喉部白色，中央有黑色条纹并逐渐变为纯白色腹区。腿脚颜色从黄褐色到灰褐色，喙橙黄色至褐色，眼虹膜深褐色，眼环橙黄色至黄绿色或褐色。雌鸟整体颜色较雄鸟更深，可能带有橄榄褐色斑点，尤其是翼覆羽处最为明显。雏鸟上体橄榄褐色，带有橙褐色斑点，喉部和胸部颜色从浅色到中橙黄色，腹部白色，腿脚灰色至红灰色，喙橄榄黑，虹膜棕色。","call":"鸣唱相比其他鸫类，音调更高且带有一种独特的金属质感，通常在春季和夏季听到，偶尔冬季也能听见。","habits":"栖息于森林、林地和公园，主要在阴凉的低至中层树冠活动，也会下地觅食，甚至在草地和牧场边缘觅食。以昆虫和果实为主食，包括蜗牛、甲虫、蚂蚁、苍蝇和多种水果。","breeding":"繁殖范围覆盖阿根廷东北部、巴拉圭东部和巴西南部，部分个体在冬季向北迁徙至巴西中部。","identification":"与安第斯灰鸫区分，石鸫体型较小，缺乏黑色眉纹，腿脚和喙的颜色有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲东南部，包括巴西东南部、巴拉圭东部和阿根廷东北部，也有孤立记录在乌拉圭。"},{"name":"铅背鸫","english_name":"Plumbeous-backed Thrush","scientific_name":"Turdus reevei","overview":"铅背鸫（英文名：Plumbeous-backed Thrush，学名：Turdus reevei），是雀形目鸫科鸫属的鸟类。以其独特的外观和分布著称。在南美洲的干林地带，尤其是厄瓜多尔西部和秘鲁西北部是不可忽视的存在。其上体呈现蓝灰色，下体偏白，两胁带有橙褐色斑纹，喉部洁白，眼周环绕着白色的光环，这些都是其显著的外部特征。","appearance":"成年铅背鸫体型中等，长约23至24厘米，体重在61至66克之间。雄鸟个体的上体呈蓝灰色，眼虹膜白色或带蓝白色，喉部有细小的暗纹终止于白色的新月形标记，胸部淡灰色渐变为腹部的白色，两胁有橙褐色的洗染，腹下部白色；喙和腿均为浅黄色。雌鸟头部略显棕色。幼鸟外观与成鸟相似，但更显棕色，上体和下体有明显的斑点和条纹。","call":"其叫声包括一种急促的哨音'fwee?'以及美妙的鸣唱，通常在繁殖季节短暂期间发出，速度较快，属于典型的鸫科鸣声。此外，它还会发出尖锐的'pseeeu'叫声，通常向下滑降，偶尔也会平调或上升。","habits":"铅背鸫主要栖息于落叶性和半湿润常绿森林，偶尔出现在森林边缘、灌木丛和相邻的空旷地带，海拔高度主要在1600米以下，但在厄瓜多尔曾记录到高达2500米的分布。它们以树栖为主，常在果实丰富的树木上聚集，有时会加入混合物种的鸟群。","breeding":"繁殖期在雨季，大约在1月至3月/4月间。已知的巢穴位于小树上约2米高的位置，由草和其他植物材料构成厚壁的开放杯状巢。另有五个巢穴位于带刺的树上，靠近树干，非常隐蔽，高度在3至5米之间，巢穴为浅杯状，直径约9.5厘米，由树枝、藤蔓、苔藓和干叶制成，使用家畜粪便固定。平均蛋尺寸为27.7毫米×20.9毫米，蓝色带大量棕色斑点。孵化期为9至14天，雏鸟期同样为9至14天。","identification":"铅背鸫的辨识要点在于其蓝灰色的上体、白色的喉部新月标记、橙褐色的两胁以及白色的腹下部。在繁殖季节的鸣叫声也是识别的重要依据。","protection":"IUCN：LC（无危）。铅背鸫在Tumbesian区域EBA有分布，虽然数量不多，但在某些地区如厄瓜多尔的Chongon Hills和秘鲁的Tumbes国家保护区较为常见。","distribution":"主要分布在南美洲的厄瓜多尔西部和秘鲁西北部，繁殖区域与非繁殖区域大致相同，主要栖息地为干林地带。"},{"name":"黑冠鸫","english_name":"Black-hooded Thrush","scientific_name":"Turdus olivater","overview":"黑冠鸫（英文名：Black-hooded Thrush，学名：Turdus olivater），是雀形目鸫科鸫属的鸟类。中等体型的森林鸟类。其显著特征为雄鸟的黑色头冠，与橄榄褐色身躯形成鲜明对比，喙和腿均为黄色。主要分布于南美洲的高海拔森林地带，如哥伦比亚、委内瑞拉和圭亚那南部。在海拔800米以上的环境中是常见的森林鸟类。","appearance":"成年雄性黑冠鸫具有黑色头冠，上体为深橄榄褐色，下体为沙橙色，喙、眼环和腿皆为黄色。雌鸟相似，但头冠较暗淡，脸部和喉部有斑点，腹部颜色更浅，尾部尖端较暗。幼鸟像雌鸟，但翅膀上有双橙色斑点，喉咙和胸部有深色斑纹。亚种caucae的雄鸟缺乏头冠，头部为深色而非黑色，喉部和上胸有模糊的暗纹。其他亚种如sanctaemartae、paraquensis、kemptoni、duidae、roraimae和ptaritepui各有其独特的体色和斑纹差异。","call":"其歌声由一系列响亮、较为缓慢的音乐性短语组成，例如“tee-urr turee tuu-duu tuu-dii churdur turee”和“chur-dii”，有时会插入更高音的“ee’ee”音符。","habits":"黑冠鸫主要栖息于高海拔的森林和次生林，通常在800米以上。它们常在落叶层中觅食，翻找食物，也会出现在果实丰富的树木上，尤其是梅拉斯特莫科斯树，此时可能与其他物种混群。它们有时会跟随行军蚁群觅食。","breeding":"关于其繁殖生态的具体细节未有详细记录。","identification":"雄性黑冠鸫与其他物种区分明显，而雌鸟可能与雌性淡眼鸫混淆，但黑冠鸫体型更大，眼睛更暗，眼环明显，有类似雄鸟的头冠外观。","protection":"IUCN状态未知。","distribution":"黑冠鸫主要分布于南美洲，具体包括哥伦比亚至圭亚那南部的高海拔森林区域。"},{"name":"马谷鸫","english_name":"Maranon Thrush","scientific_name":"Turdus maranonicus","appearance":"马谷鸫体长约21.5厘米。上体为浓郁的棕色，带有模糊的深色鳞状斑纹，下体为暗淡的白色，胸部和侧翼有棕色鳞状斑纹；喙和腿为灰白色。两性相似。幼鸟与成鸟类似，但上体有橙色斑点和条纹，翅膀上有双排橙色斑点的翼带。","call":"其歌声愉快而悠闲，典型的鸫鸣声，比黑嘴鸫的歌声更慢，音符更加模糊。","habits":"它栖息于落叶林木、次生植被、空旷地带、干旱灌木丛和花园，同时也会出现在相对湿润的山地森林和林地边缘；海拔高度主要在200至2000米之间，而在厄瓜多尔则在650至1650米之间。","identification":"没有其他成年鸫鸟具有如此明显的下体标记。其他鸫鸟的幼鸟可能在下体有斑点，但斑点较小，对比度较低，而且不太可能与马谷鸫在同一地区出现。","protection":"IUCN：LC（无危）。这是一种限定范围物种，存在于马拉尼翁山谷EBA。在厄瓜多尔，它在Zumba附近较为常见，北至Valladolid也有少量分布，且在Podocarpus国家公园（厄瓜多尔）内有记录。","distribution":"分布于南美洲的秘鲁北部和厄瓜多尔南部，具体在秘鲁的Cajamarca、La Libertad、Piura等地区以及厄瓜多尔的极端南部。"},{"name":"栗腹鸫","english_name":"Chestnut-bellied Thrush","scientific_name":"Turdus fulviventris","overview":"栗腹鸫（英文名：Chestnut-bellied Thrush，学名：Turdus fulviventris），是雀形目鸫科鸫属的鸟类。主要分布在安第斯山脉东坡。与北美的旅鸫有惊人的相似之处。最显著的外部特征是栗色腹部，这是在它的分布区域内独一无二的。成鸟拥有深色头罩、黄色喙和黄色眼环。这种鸟较为罕见，常在果树上觅食，鲜少落地。","appearance":"栗腹鸫体长23-25厘米，体重69-71克。头部和喉部为黑色，背部呈棕褐石板灰，逐渐过渡至纯灰色胸部，下半身为橙栗色，尾下覆羽为橄榄灰色。喙和眼环为黄橙色，腿为黄褐色。雌雄外观相似，但雌鸟色泽较暗淡。幼鸟缺乏深色头罩，下体有斑驳花纹。","call":"栗腹鸫的鸣唱不常见，由一系列断续的乐句组成，其间穿插刺耳的颤音和嗡嗡声，类似模仿鸟的叫声。其叫声为木质感的“peent”。","habits":"栗腹鸫主要栖息于南美洲的山地森林中，海拔介于1,400至2,600米之间。它们以果实为主食，偶尔在树冠层与其他物种共享果源，有时会在半开阔地带的地面翻动落叶堆觅食昆虫。","identification":"栗腹鸫以其独特的栗色腹部与其它鸫类区分开来。在北部安第斯山脉，它是唯一具有这种特征的鸫科成员。","protection":"IUCN：LC（无危）","distribution":"栗腹鸫的分布范围从委内瑞拉西北部延伸至秘鲁，包括哥伦比亚、厄瓜多尔和秘鲁北部，以及玻利维亚西北部。"},{"name":"棕腹鸫","english_name":"Rufous-bellied Thrush","scientific_name":"Turdus rufiventris","overview":"棕腹鸫（英文名：Rufous-bellied Thrush，学名：Turdus rufiventris），是雀形目鸫科鸫属的鸟类。包括巴西、玻利维亚、巴拉圭、乌拉圭及阿根廷中央地区。以其鲜明的红橙色腹部闻名，体型大，适应性强。在巴西东南部尤为常见，被当地人亲切地称为sabiá-laranjeira。自1966年起，成为圣保罗州的象征，2002年更被选为巴西的国鸟。","appearance":"棕腹鸫身长约25厘米，体重介于59至78克之间，雄鸟平均重68克，雌鸟平均重64克。具橄榄褐色背部和翅膀，褐色条纹的白色喉咙，淡橙色腹部，以及橙黄色眼圈。雌雄相似，但雌鸟较圆润，腿灰暗。幼鸟与成鸟相似，但羽冠至肩部有淡色条纹，翼覆羽橙色尖端，下体橙色带深棕色斑点，腹部至尾根处更显橙色和更干净。","call":"其歌声快速、丰富、连续，通常多变，质量上乘，为南美最佳的鸫科歌手之一。叫声包括低沉的‘pup-pup’、警告声‘tsri’、共鸣的‘juh-jóéit, drew-wip’以及用于非繁殖季节领地防御的下降音调序列。","habits":"栖息于轻林、次生林、半开放森林、灌木丛、草原、干草原、农田、村庄、空地、公园和花园，甚至城市区域，常在近水源地带活动。以昆虫、蜘蛛、蚯蚓、甲虫、苍蝇、蚂蚁和各种野生水果为食，偏好在接近遮蔽的地面觅食，偶尔在开阔水域边缘活动。","breeding":"繁殖期在南美洲各地有所不同，主要集中在8月至11月，但在某些地区可延至次年2月。巢为杯状，由干茎、绿色材料、根须构成，有时镶有牛粪，放置于树干附近的1.3米高处，或高达2.4米的小树分叉处。每窝产卵2至6枚，通常3枚，颜色为绿或蓝色，带有砖红色、栗色或棕色斑点。孵化期13至15天，雏鸟期13至14天，离巢后依赖父母14天。面临紫辉牛鹂寄生风险，影响繁殖成功率。","identification":"与其他鸫属物种的区别在于其明显的红橙色腹部和橄榄褐色背部，以及独特的叫声和鸣唱模式。不同亚种间存在大小和嘴型的差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲东部和中南部，包括巴西、玻利维亚、巴拉圭、乌拉圭及阿根廷中央地区。在巴西东南部尤为普遍，是当地常见的鸟类。","other":"在1920年代，阿根廷曾担忧过度狩猎可能影响其数量，但至今似乎并未受到太大影响，目前仍为分布范围内最常见的鸫类。"},{"name":"南美鸫","english_name":"Austral Thrush","scientific_name":"Turdus falcklandii","overview":"南美鸫（英文名：Austral Thrush，学名：Turdus falcklandii），是雀形目鸫科鸫属的鸟类。广泛分布于南美洲南部，包括智利、阿根廷以及福克兰群岛。其特征包括黄色喙和脚，头部、背部及翅膀呈深棕色，腹部颜色较淡。三个亚种中，Magellan thrush（T. f. magellanicus）体型较小，腹部偏橄榄色，而福克兰亚种（T. f. falcklandii）腹部倾向于赭色，两者喉咙均有条纹。","appearance":"成年南美鸫身长23至26.5厘米，体重95至113克。指名亚种为温暖的棕橄榄色上部，头部至眼下方为黑褐色，下巴和喉咙点缀着淡褐色和黑色斑点，逐渐过渡到赭色的下部。喙、窄眼环和腿橙黄色。性别相似。幼鸟类似成年鸟，但上部有厚重的淡褐色条纹，下部为淡黄褐色带暗褐色斑点。Magellanicus亚种比指名亚种种更小，上部更冷的橄榄棕色，头部更黑，下部更浅，喉咙图案更明显，雌鸟略显苍白。","call":"雄性南美鸫的歌声由一系列以规律节奏重复的哨声和尖叫声组成，通常每句话包含1至4个音符，低音部分响亮而高音部分尖细。歌声富有变化，根据情境的不同，句子中的音节数量差异很大。雄鸟的曲目大小因个体而异，可能与年龄有关，表明物种可能具有开放式学习的条件。","habits":"南美鸫栖息于从浓密的Nothofagus森林的开阔林下到开放森林，人工林，次生林，较轻的开阔林地，森林边缘，河流柳树，灌木丛国家，农业区带有散落树木和树篱，以及花园等环境。在福克兰群岛，它占据多种栖息地，尤其在苔草岛屿和人类定居点，其中灌木、树木和棚屋提供庇护，但也出现在岩石露头和带有蕨类植物和diddee的开阔斜坡上。食物包括蚯蚓、蜗牛、节肢动物（包括昆虫幼虫和蛹，以及福克兰群岛的沙跳蚤）、大量水果，以及在智利奇洛埃岛，它是macho macho（Podocarpus nubigena）种子传播的主要媒介。","breeding":"在智利和阿根廷，繁殖季节为9月至2月；在阿根廷至少10月至11月，也有记录到1月有1枚蛋的巢；在福克兰群岛为8月至12月。筑巢期可达三窝，偶尔在福克兰群岛可达四窝。巢为一个大型深杯状，由干燥的草茎和根纤维构成，有时加入羊毛或线，通常内部用泥或粪便砌墙，衬以草或马毛，位于岩石裂缝、草丛遮蔽的堤岸顶部、大型苔草基座、柏树或金雀花丛中，或羊毛棚梁上。卵数2至3枚，蓝绿色，带有棕色和紫色斑点；尺寸27.0-34.2毫米×19.4-24.0毫米。孵化期14至16天；雏鸟期大约10至11天；从离巢到开始新一窝的时间最短仅为12至14天。","identification":"南美鸫与欧乌鸫相似，但可以通过黄色的喙和脚、更深的头部和背部颜色以及更浅的下部颜色来区分。Magellanicus亚种与指名亚种种相比，体型更小，腹部颜色更偏向橄榄色，喉咙条纹更明显。","protection":"IUCN：LC（无危）","distribution":"在南美洲，南美鸫广泛分布于智利和阿根廷的南部，以及福克兰群岛。在福克兰群岛，其栖息地从苔草岛屿和人类定居点到岩石露头和开阔斜坡，密度最高可达4只雄鸟/公顷，尤其是在成熟的沿海苔草旁。在智利和阿根廷，它们生活在从Nothofagus森林到农业土地甚至花园的各种环境中。","other":"南美鸫在1930年至1960年间在福克兰群岛的分布范围显著扩大，目前总估计有约6000对（估计4000至8000对），最高密度达到4只雄鸟/公顷。然而，由于引入的捕食者，尤其是猫的影响，面临着相当大的捕食压力。"},{"name":"淡胸鸫","english_name":"Pale-breasted Thrush","scientific_name":"Turdus leucomelas","overview":"淡胸鸫（英文名：Pale-breasted Thrush，学名：Turdus leucomelas），是雀形目鸫科鸫属的鸟类。广泛分布于南美洲东部和北部的林地，从巴西至乌拉圭，西部有局部分布。适应人类环境，常见于居民区，甚至在花园和小型树木中筑巢。","appearance":"体型与美国知更鸟相似，但羽毛颜色更为均匀，主要呈橄榄棕色，翼羽和次级飞羽边缘锈色，头部中灰色调，耳羽灰白条纹明显，喉部白色带淡褐色细纹，腹部灰黄至白色，翅膀下橙色。雄雌相似，雌鸟头部可能略显棕色。幼鸟上部斑点和条纹较浅，下部杂色棕色。","call":"歌声由一系列旋律组成，单音节重复变化，如'chirr juep juele chip chirr'，与北美知更鸟相似但更为复杂，常用'hereit, hereit'和'tuwee, tuwee'的乐句。叫声独特，类似粗哑的木头声'quwaak quwaak quwaak'。","habits":"主要以果实为食，辅以昆虫、蠕虫和小蜥蜴。常见于草地、路边觅食，频繁访问结果树和灌木，包括商业种植的树种，如鳄梨、柑橘等。","breeding":"繁殖期广泛，从1月到8月，可能全年繁殖。巢为大型杯状，由苔藓和根须构成，用泥粘合，建于灌木、树上或人造结构上，如屋檐、横梁等。每窝产2-4枚（通常3枚）蓝绿色带红褐色斑点的蛋，孵化期12-13天，雏鸟期16-17天。存在被闪亮牛鹂寄生的情况。","identification":"与奶油腹鸫相比，头部与背部对比明显，无黑色颊纹。","distribution":"主要分布于南美洲北部和中南部，包括巴西、哥伦比亚至乌拉圭，局部存在于西部。"},{"name":"淡腹鸫","english_name":"Creamy-bellied Thrush","scientific_name":"Turdus amaurochalinus","overview":"淡腹鸫（英文名：Creamy-bellied Thrush，学名：Turdus amaurochalinus），是雀形目鸫科鸫属的鸟类。常见于多种生境，包括森林边缘、林地、草原、种植园、城市公园和花园。其显著特征为橄榄褐色背部、黄色喙与黑色眼先形成鲜明对比，腹部呈淡色，喉部有浅色条纹。幼鸟身上可见斑点。","appearance":"体长约22-25厘米，体重52-73克。上身橄榄褐色，头部至眼下方亦为橄榄褐色，除黑色眼先；喉咙呈棕色条纹，胸部和侧翼灰色或灰褐色，下腹部渐变为奶油白色；喙在繁殖季节为黄色，其余时间较暗淡；腿呈暗棕色。性别相似，但雄鸟的翅膀较长，雌鸟平均较重。幼鸟上部深褐色，带有缓冲斑点，下巴和腹部白色，下部缓冲色，有模糊的暗棕色鳞片和斑驳。","call":"鸣唱音乐性但相对单调，干燥且略逊于南美同属物种的活力，由简短的乐句和音符组成，纯净且有颤音，以规律间隔发出，例如“yo-plantáy, nao-nassáyu, aprorasáyú, friiu friiu”或“tüelek jiejie tuele chip…”。叫声包括像瓶塞弹出般的尖锐“pok”声、“psiip”飞行前的叫声，以及警告时的尖锐猫叫声“pchuo”。","habits":"栖息于半湿润到半干旱地区的各种环境，包括开阔的森林、森林边界、较轻的林地、次生林、带刺灌木丛、房屋周围的开阔地带、林地、空地、河岸灌木、庄园、农田、公园、广场及乡村和城市花园。部分迁徙，模式不明，但在南半球冬季，一些个体向北迁移，巴西里约热内卢的大量个体可能来自更南方。","breeding":"在玻利维亚，幼鸟出现于2月至3月；在巴西南部，记录于11月；在阿根廷，于10月至12月，3月见到幼鸟。巢由草、枝条、藤蔓、苔藓、根和空气凤梨构成，用牛粪和泥土粘合，内部铺以细根，置于浓密灌木或树篱中0.6-1.6米高的位置。蛋数通常为3枚，偶尔4枚，蓝绿色带有红色或深棕色斑点；孵化期15天；雏鸟期14-15天。巢穴常被光背拟鹂寄生。","identification":"与其他相似的鸫类（如淡胸鸫）的区别在于其黑色的眼先，这是成年淡腹鸫的显著特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美玻利维亚和巴西南部至阿根廷中部；非繁殖季节分布北部至亚马孙雨林。"},{"name":"美洲山鸫","english_name":"Mountain Thrush","scientific_name":"Turdus plebejus","overview":"美洲山鸫（英文名：Mountain Thrush，学名：Turdus plebejus），是雀形目鸫科鸫属的鸟类。外观较为暗淡的大型鸫科鸟类。雌雄羽毛相似，通体呈深橄榄棕色，翼与尾部颜色较深，喉部略显苍白并带有隐约条纹。常见于中美洲的高海拔森林中，自墨西哥东南部至巴拿马西部。该物种可能被视为单一类型。","appearance":"成年美洲山鸫全身几乎一致的深橄榄棕色，翅膀和尾巴的颜色比身体更深，喉部颜色略浅，呈现模糊的条纹。裸露部分，如喙和腿，呈深色。雌雄外观相似。幼鸟上体斑驳着肉桂色，喉部和下体为肉桂棕色，有深色斑点。","call":"繁殖季节的鸣唱为机械式的单调音调“chip chip cher chip chip cher cher”，叫声为高音的“seee”或“whip”。","habits":"栖息于高海拔的山地森林，偏好有苔藓和附生植物的橡树林，通常在1,800米以上的高度。非繁殖季节会以群体形式活动，觅食时在地上或大枝上跳跃，主要寻找小型果实、昆虫和蜘蛛。","breeding":"筑巢于树上的枝干间，离地面3至12米，巢由草或细根编织，隐藏在附生植物中。繁殖期为3月至6月，每窝产2至3枚绿色蓝调的无斑点蛋。","identification":"与美洲黑鸫雌鸟相似，但后者腿黄色，体色偏棕色，喉部颜色更浅，有明显对比。与褐背鸫的区别在于后者喙黄色，腿肉色，体色更暖的棕色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥东南部到巴拿马西部的高海拔森林。"},{"name":"黑嘴鸫","english_name":"Black-billed Thrush","scientific_name":"Turdus ignobilis","overview":"黑嘴鸫（英文名：Black-billed Thrush，学名：Turdus ignobilis），是雀形目鸫科鸫属的鸟类。在西部亚马逊地区和安第斯山脉北侧广泛分布的鸫科鸟类。常见于开放生境和低地森林，偶尔进入安第斯山麓。其灰褐色的外表并不显眼，拥有淡白色的腹部和独特的黑色喙。常单独或成对出现，十分显眼。","appearance":"成年黑嘴鸫体长约18.5至24厘米，体重48至81克，外观上并无明显特征，橄榄棕色的背部，较淡的下体，面部略深，喉部有棕色条纹，腹部白色至腹股沟。喙和腿为黑色。幼鸟较成鸟颜色更浅，胸部、腹部和胁部有明显的暗色斑点，翼覆羽和三级飞羽有浅色斑点，肩部、背部、臀部和头部有更浅但不太明显的斑点。","call":"其鸣唱是一系列典型的鸫鸣，但相对低调且缺乏激情，与旅鸫的鸣声有相似之处，通常在黎明前和白天都能听到。","habits":"栖息于开阔地带、半开敞区域、草原带树林、轻型次生林、湿润森林边缘、咖啡种植园、受干扰的环境和各种早期演替的生境。也会出现在灌木丛牧场、公园、花园和城镇边缘。一般生活在海拔1600米以下，但在某些地区可高达2800米。","breeding":"繁殖季节在哥伦比亚记录为12月至8月和10月，筑巢高度通常在2.5至3米间，使用苔藓和泥土搭建的粗杯状巢，内部铺有纤维和根须。每次产卵2到3枚，绿蓝色带重褐色斑点。孵化期估计为13至16天，雏鸟期约为14至17天。","identification":"黑嘴鸫可通过其黑色的喙、苍白的下体和缺乏明显的野外观测特征来识别。与白臀鸫、淡胸鸫、罗氏鸫、淡臀鸫和棕榈裸鼻雀相区别。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的西部亚马逊地区和安第斯山脉北侧，包括哥伦比亚、委内瑞拉、圭亚那盾区、巴西、秘鲁、玻利维亚和厄瓜多尔东部。在哥伦比亚较为常见，而在委内瑞拉则相对较少。","other":"在某些地区，如哥伦比亚，黑嘴鸫在人类居住区的行为类似于广泛分布的旅鸫，经常在草坪上觅食。"},{"name":"罗氏鸫","english_name":"Lawrence's Thrush","scientific_name":"Turdus lawrencii","appearance":"成年罗氏鸫体长约21.5至23厘米，体重约73克。雄鸟上身呈橄榄褐色带红褐色调，下身红褐色泛灰，喉部有深色条纹，腹部至臀部白色，喙和眼圈黄色（非繁殖季节颜色较暗淡），腿肉棕色。雌鸟外观相似，但下身颜色较浅，喙色更暗淡。幼鸟上身橙褐色条纹，翼上有双橙色尖端的翼斑，下身布满厚重的棕色斑点。","call":"罗氏鸫的鸣唱复杂多变，从隐秘的高树中发出一系列近似完美的模仿声，包括其他鸟类的歌曲片段和叫声，偶尔夹杂自身特有的几个乐句，其模仿能力惊人，单个个体能掌握超过70种不同的声音。其叫声包括独特的\"ku, kup, kit?\"或\"kup-kip?\"，尖锐的\"peer!\"，哀怨的\"perwheee\"，突然的\"weechee\"和响亮的\"peep peep peep!\"。","habits":"生活在高大的森林中，尤其偏爱溪流周边的环境。它的活动范围广泛，能够长时间连续鸣唱，每天可达数小时，最长间隔不超过15分钟。罗氏鸫的饮食习惯和捕食者信息尚未详细记录。","breeding":"繁殖习性知之甚少，但在秘鲁有记录显示繁殖期可能为1月后期。推测繁殖季节与雨季（11月至3月）重合。已知其巢穴由草和泥制成，通常位于中等大小的光滑树干和凤梨科植物之间，距离水面10至20米。已发现的巢穴中包含两只雏鸟。","identification":"罗氏鸫与淡臀鸫相比颜色较为暗淡，与豪氏鸫相比上身颜色更深，喉部条纹较弱，而黄色的眼圈和喙是区分于其他两种的重要特征。","protection":"IUCN状态未提及。","distribution":"分布于南美洲的亚马孙雨林西部，具体包括委内瑞拉南部、圭亚那西部、哥伦比亚东南部、厄瓜多尔东部、秘鲁东部、巴西西部以及玻利维亚北部。","other":"关于罗氏鸫的更多信息，包括其独特的繁殖行为和生态习性，仍在研究中。"},{"name":"淡臀鸫","english_name":"Cocoa Thrush","scientific_name":"Turdus fumigatus","overview":"淡臀鸫（英文名：Cocoa Thrush，学名：Turdus fumigatus），是雀形目鸫科鸫属的鸟类。常在南美洲东部哥伦比亚至巴西中部和东部以及加勒比海的特立尼达岛和一些小安的列斯群岛发现。其特征为中等体型，上部暗红褐色，下部较浅红褐色。","appearance":"成年淡臀鸫长度约22-24厘米，体重55-83克。上体呈狐狸般的棕色，下体呈淡橙棕色，喉咙有深色条纹，胸部白色带棕色尖端。翅膀下覆羽橙色，喙和腿灰褐色。两性相似，幼鸟下体颜色更淡，类似其他同属幼鸟的斑驳下体。不同亚种在色泽上有细微差异。","call":"其歌声为一系列甜美、上下滑音的哨声。叫声包括快速、略带吱吱声的‘ji-ji-ji-ji-ji’和成对的‘chee-ip, chee-ip’。","habits":"栖息于湿润森林的低层和中层，偏好靠近水源的环境，如溪流旁、沼泽地带和várzea森林。也出现在公园、花园、树木丰富的耕作区、可可和遮阴咖啡种植园。在苏里南限于草原森林和沿海沙丘的暗森林，在法属圭亚那可见于旧红树林和海滨的沼泽森林，以及森林内部的藤本灌木丛。通常在100-1000米海拔高度活动，局部可达1400米，特立尼达岛则高达600米。以蚯蚓、千足虫和浆果为主食，主要在地面觅食。","breeding":"繁殖季节主要在11月至6月间，在小安的列斯群岛；哥伦比亚为8月；特立尼达岛全年均可繁殖，高峰在5月至6月。巢由植物物质和泥构成，覆盖苔藓并以根须衬里，位于地面以上至5米高的树干、树桩、树蕨顶部或河岸凹槽中。每窝产卵2-4枚，蛋色淡绿蓝带淡红褐色斑点。孵化期12.5-13.5天，育雏期13-15天，离巢后依赖父母长达32天。","identification":"与裸眼鸫的区别在于全黑的喙和缺乏显眼的眼环。","protection":"IUCN：LC（无危）","distribution":"南美洲的东部哥伦比亚、亚马逊盆地北部，以及特立尼达岛和小安的列斯群岛南部。在哥伦比亚可达1400米，委内瑞拉北部奥里诺科河以北地区常见，特立尼达岛上普遍，圣文森特和格林纳达岛上数量适中。"},{"name":"白臀鸫","english_name":"Pale-vented Thrush","scientific_name":"Turdus obsoletus","overview":"白臀鸫（英文名：Pale-vented Thrush，学名：Turdus obsoletus），是雀形目鸫科鸫属的鸟类。体型较大的暗褐色鸟类，以白色的臀部和深色的喙为显著特征。广泛分布于中美洲和南美洲，包括哥斯达黎加、厄瓜多尔等地。","appearance":"成鸟体长21.5至23厘米，体重61至82克。上体呈深赤褐色，下体较浅，腹部中央白色，翼下覆羽淡橙色，喙和腿为灰黑色。两性相似。幼鸟与成鸟类似，但上体暗棕色带黄褐色斑点和条纹，翅膀有双橙色斑点，下体橙黄色并带有深棕色斑纹，下巴和腹部白色。","call":"鸣唱快速而旋律优美，通常从树冠隐蔽处发出类似笛声的歌声，有时夹杂着尖锐音符、颤音和急促的‘wiiuwiit’。叫声包括细薄的‘zhwiik’或‘bzeeek’，喉咙发出的‘wuk’声，以及在警戒或归巢时发出的升调‘woeep-woeep-woeep-woeep’。","habits":"栖息于潮湿和湿润的低山、亚热带森林的较低层、亚林冠层和中林冠层，偏好有开阔地带的环境，偶尔出现在森林边缘，非繁殖季节会访问牧场树木和较低的次生林。食性以果实为主，包括棕榈果、月桂科果实、带果皮的种子、浆果和昆虫等，主要在树上觅食，有时也会在地面寻找食物。常加入混合物种群落，非繁殖季节形成10至30只的游荡群。","identification":"与同属其他物种相比，白臀鸫具有独特的白色臀部，叫声和鸣唱也有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，包括哥斯达黎加至厄瓜多尔。在哥斯达黎加较为常见，而在巴拿马、哥伦比亚和厄瓜多尔则相对少见。"},{"name":"豪氏鸫","english_name":"Hauxwell's Thrush","scientific_name":"Turdus hauxwelli","overview":"豪氏鸫（英文名：Hauxwell's Thrush，学名：Turdus hauxwelli），是雀形目鸫科鸫属的鸟类。广泛分布于南美洲亚马逊雨林西部的低地雨林中，包括哥伦比亚东南部、厄瓜多尔东部、秘鲁东部、巴西西部和玻利维亚北部。","appearance":"成鸟整体呈红褐色，上体富丽的赤褐色，臀部略带更强的赤褐色，下体中间偏棕色，喉部有暗色条纹衬托的白色，腹部和臀部白色，边缘处有棕色尖端。翼下覆羽为淡橙色，喙和腿呈灰褐色。性别相似，幼鸟与淡臀鸫幼鸟类似。","call":"鸣唱是一系列悠长、简单的旋律短语，节奏让人联想到南美白颈鸫，部分个体会模仿至少十种当地鸟种的叫声。叫声包括上升的‘drrii’和哀怨的上升‘kwiiiiow’。","habits":"栖息于多种森林生境，尤其偏好成熟的雨林，常在地面边缘和空旷地带觅食，以昆虫和果实为食。有时会在结果的树木附近活动。","breeding":"繁殖季节，巢建在小刺榈树冠中，离地约2.5米，巢由草和泥构成，内部铺有更细的草，蛋壳淡绿蓝色，有不规则的小红褐色斑点，形成大端的环状，类似于欧乌鸫的蛋。已知繁殖记录中，一窝有两个蛋，幼鸟在9月被成鸟喂养。","identification":"豪氏鸫与其他鸫属鸟类的区别在于其红褐色的整体色调和独特的鸣唱。幼鸟与淡臀鸫幼鸟相似，但可通过鸣唱和生活习性的差异来辨识。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊雨林西部，具体包括哥伦比亚东南部、厄瓜多尔东部、秘鲁东部、巴西西部和玻利维亚北部。"},{"name":"纯色鸫","english_name":"Unicolored Thrush","scientific_name":"Turdus haplochrous","overview":"纯色鸫（英文名：Unicolored Thrush，学名：Turdus haplochrous），是雀形目鸫科鸫属的鸟类。仅见于南美洲玻利维亚北部的Mamoré河及其支流周边的泛滥平原森林，尤其是Moxos草地周围的环境。其最显著的外部特征是橄榄褐色的上体，稍淡的下体，暗纹白喉，以及带有黄色眼周皮肤的暗橄榄色喙。","appearance":"纯色鸫体型中等，长约23至24厘米，体重约84克。其羽毛上部为橄榄褐色，下部颜色略浅，喉咙处有白色条纹并带有深色斑点。喙呈淡黄褐色，腿为棕色。雌雄两性的外观相似，而关于幼鸟的描述尚未报道。","call":"其鸣唱为一系列哨音组成的短语，与豪氏鸫相似，但包含颤音和尖叫声。","habits":"生活于亚热带或热带湿润低地森林，偏好难以接近的栖息地，导致其难以被观察到。在干季较为沉默，可能影响对其数量的记录，而湿季时的鸣唱有助于更准确地评估其真实丰度。","breeding":"关于其繁殖行为的信息目前尚不充分。","identification":"与豪氏鸫和黑嘴鸫的区别在于其暗橄榄色的喙、暴露的黄色眼周皮肤以及相对单一的喉部颜色。","protection":"IUCN：NT（近危）；物种分布范围看似很小且分布零散，但其生境广阔且受到的威胁较小。在Beni生物圈保护区和Isiboro Sécure国家公园中存在，但需要加强这些区域的有效管理。","distribution":"分布于南美洲玻利维亚北部，具体包括东南部的Beni省和西部的Santa Cruz省。","other":"关于其确切分布范围的估算存在争议，依据不同的计算方法和记录的可靠性，已知的分布范围可能覆盖192,000平方公里或小至48,860平方公里。"},{"name":"褐背鸫","english_name":"Clay-colored Thrush","scientific_name":"Turdus grayi","overview":"褐背鸫（英文名：Clay-colored Thrush，学名：Turdus grayi），是雀形目鸫科鸫属的鸟类，广泛分布于中美洲至北部哥伦比亚，是哥斯达黎加的国鸟，当地俗称'yigüirro'。其常见于各种灌木林、城镇公园等地，适应力强，常在人类居住区附近活动。","appearance":"整体呈单调的土褐色，腹部略显温暖色调。嘴部淡黄色，喉咙处有模糊的中褐色条纹，逐渐过渡到浅棕色的胸部和胁部，从腹部中部至肛门区域变为更橙黄色。翅膀下覆羽橙色，喙橄榄黄色，腿粉灰色，虹膜棕色。雌雄相似，幼鸟上部斑点状和条纹状暗橙色，脸颊和胸部有大理石般的棕褐色，虹膜棕色。","call":"歌曲是一系列类似模仿鸟的多变音节，低沉而节奏平稳，由许多滑音构成的音乐性短语，通常不规则地重复。叫声为丰富、鼻音的上滑音‘hoouree’、‘reeeur-ee’、‘jerereee’、‘teeweeooip’或‘wee-ee-gwa’。","habits":"常见于开放森林边缘、轻度林地、空地、半开放区域、田边、花园、郊区草坪、牧场、椰子林、芒果果园、咖啡种植园和各类耕作区，喜欢在人类居住区周围活动，主要分布在较为干旱的区域。食性以蚯蚓、蛞蝓、昆虫幼虫和成虫为主，偶尔捕食蜥蜴，也吃多种水果。","breeding":"繁殖期与雨季同步，高度本地化同步，繁殖季节持续约3个月。在墨西哥繁殖期为4月至5月，在伯利兹为5月至7月，在哥斯达黎加和巴拿马为3月至7月（偶尔2月和8月），在哥伦比亚为3月至5月。巢建于树上，高度1至30米，多位于1.5至3.5米间，隐蔽位置。每窝通常产3枚，罕见4枚，孵化期12至13天，巢雏期13天。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至北部哥伦比亚，包括墨西哥、伯利兹、洪都拉斯、哥斯达黎加、巴拿马和哥伦比亚。在南美洲，仅限于低地至约300米海拔；在中美洲，分布于海平面至2100米（哥斯达黎加最高可达2450米，巴拿马1950米），在非繁殖季节会深入更重的森林。","other":"在哥斯达黎加，因其悦耳的歌声深受人们喜爱，被选为国鸟。在人类居住环境的适应性极强，数量随人类活动增加而增长。"},{"name":"裸眼鸫","english_name":"Spectacled Thrush","scientific_name":"Turdus nudigenis","overview":"裸眼鸫（英文名：Spectacled Thrush，学名：Turdus nudigenis），是雀形目鸫科鸫属的鸟类。中等体型的鸫科鸟类，以独特的橙黄色眼环而著称。分布于小安的列斯群岛、南美洲从哥伦比亚至委内瑞拉，东至巴西北部的亚马逊雨林区域。在特立尼达和多巴哥，被当地人称为big-eye grieve。","appearance":"裸眼鸫体长23-24厘米，体重50-75克。上体橄榄棕色，下体较淡，喉部具暗色条纹，白色腹部和臀部边缘带有淡棕色尖端。其最显著特征是宽阔的橙黄色眼环，喙呈黄色，腿橄榄棕色。雌雄相似，幼鸟的眼环较窄，上体有细斑点，翼上有双橙色斑点，下体橙色带暗棕色斑驳，下巴和腹部白色。extimus亚种比指名亚种颜色更深。","call":"其鸣唱是一系列短促、轻柔、单调但悦耳的乐句，比同类物种更富旋律性，但节奏更为停顿。常见叫声为曲折的猫叫声“queeow”。","habits":"裸眼鸫栖息于开放的林地、森林空地和耕作区，主要在树上觅食果实、浆果，也会捕食昆虫如毛虫、甲虫、飞蛾和蚯蚓。它会访问地面，甚至在住宅区的草坪和边缘觅食，偶尔会从鸟桌获取食物。","breeding":"繁殖期在小安的列斯群岛为3月至7月，南美各地有所不同。巢由植物材料和泥构成，内衬根须，通常建在大树枝叉或灌木丛2-8米高处，有时也在地面筑巢。每窝产卵3-4枚，卵深蓝色至淡蓝绿色，带褐色、红色和淡紫色斑点。在特立尼达岛，33%的巢穴成功孵化。","identification":"与类似但地理隔离的厄瓜多尔鸫相比较，裸眼鸫具有更宽的眼环。厄瓜多尔鸫仅在厄瓜多尔西部和秘鲁西北部的森林和林地中发现。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括小安的列斯群岛、南美从哥伦比亚至委内瑞拉，东至巴西北部的亚马逊雨林区域。","other":"在特立尼达和多巴哥，裸眼鸫表现得较为温顺，会接近喂食器和从桌子上取食。"},{"name":"亚马逊裸眼鸫","english_name":"Varzea Thrush","scientific_name":"Turdus sanchezorum","overview":"亚马逊裸眼鸫（英文名：Varzea Thrush，学名：Turdus sanchezorum），是雀形目鸫科鸫属的鸟类。栖息于南美洲西部亚马逊雨林，以季节性洪水森林为主要栖息地，偶尔也在草原和白色沙地森林中发现。其独特的白喉部带有棕色条纹和黄色喙，使其易于识别。","appearance":"体长约22至24厘米，重约58克。头部和上体均匀覆盖着深褐色，上翼覆羽同样色系；飞羽暗淡的棕色，边缘呈温暖的深褐色；尾巴呈灰棕色，基部边缘尤其显深褐色，与上尾覆羽形成鲜明对比。下巴和喉咙为温暖的米白色，中央最白，带有深棕色的条纹，逐渐变为骆驼棕色至两胁和大腿，下胸略淡，腹部中心、肛门和下尾覆羽呈白色，下尾覆羽有棕色条纹；下翼覆羽鲜亮的橙红色，延伸至初级飞羽基部；虹膜棕色，眼环橙色，喙尖端暗黄，基部变黑；腿橄榄灰色。性别相似，幼鸟描述不确定。","call":"具有多样化的鸣声库，最独特的叫声是上升的、哀怨的猫叫般叫声，明显区别于豪氏鸫、黑嘴鸫、淡胸鸫和罗氏鸫。其他叫声包括快速的“cuk”音符系列，以及一些“cuk”音符后跟一到多个悦耳的芦笛音。歌曲由缓慢、柔和的小调组成，包含4至10个音符的短而滑音的短语，频繁插入超过2秒的停顿，比豪氏鸫和Fumigated Thrush的歌曲更短、更慢、更破碎，有更多的丰富滑音短语。","habits":"主要栖息于季节性洪水森林，偶尔也出现在草原和白色沙地森林，通常在较低的层次觅食。亚马逊裸眼鸫在南美洲西部亚马逊流域的较大支流中被记录，包括巴西北部、哥伦比亚东南部极点和秘鲁北部（沿上马约河谷，圣马丁）。","identification":"通过喙和眼环的颜色与非常相似的豪氏鸫和黑嘴鸫相区别；尾部颜色（灰棕色而非红棕色）、初级飞羽下侧的较少红棕色以及喉咙条纹在通常更白的背景下更暗，进一步将其与前者区分开。","protection":"IUCN：LC（无危）。局部常见。","distribution":"南美洲西部亚马逊雨林，包括巴西北部、哥伦比亚东南部极点和秘鲁北部。"},{"name":"厄瓜多尔鸫","english_name":"Ecuadorian Thrush","scientific_name":"Turdus maculirostris","overview":"厄瓜多尔鸫（英文名：Ecuadorian Thrush，学名：Turdus maculirostris），是雀形目鸫科鸫属的鸟类。常见于厄瓜多尔西部森林边缘和开阔地带，其分布亦延伸至秘鲁西北部。成鸟拥有独特的淡褐色羽毛、黄色喙和橙色眼圈，与同类物种相比，具有较窄的黄色眼圈。","appearance":"体长约21.5至23厘米，体重约62至76克。上体橄榄棕色，下体颜色较浅，呈暖棕色，具暗色条纹的白色喉部，腹部中央及臀部白色。眼圈淡黄，喙端深黄色，腿脚橄榄棕。雌雄相似，幼鸟上体斑点状，下体斑驳，喙可能较暗。","call":"能发出悠扬的歌唱，持续时间可达数分钟，同时会发出类似猫叫的‘quee-oww’声。","habits":"主要栖息于林地、森林边缘和开阔地带，海拔可达2000米。以树上的果实、浆果、昆虫和蚯蚓为食，生活习性较为隐蔽，可能偏夜行性，通常单独或成对出现，但在果树附近可能聚集。","breeding":"繁殖期在二月，筑巢于树干低处，巢由泥土和苔藓构成，呈杯状，放置于树桩、枝叉或树枝上，距地面0.5至6米。每窝产卵3枚，蛋壳呈深绿松石色至暗绿色，带有红棕色斑点，平均尺寸27.8×20.9毫米，新鲜重量约为6.5克。孵化成功率约为33.7%。","identification":"与裸眼鸫相似，但眼圈更窄，上体颜色更浅。幼鸟与裸眼鸫幼鸟类似，具有斑点。","protection":"IUCN：LC（无危）","distribution":"分布于南美西部的厄瓜多尔和秘鲁西北部，具体繁殖区域位于厄瓜多尔西部及秘鲁西北部。"},{"name":"白眼鸫","english_name":"White-eyed Thrush","scientific_name":"Turdus jamaicensis","overview":"白眼鸫（英文名：White-eyed Thrush，学名：Turdus jamaicensis），是雀形目鸫科鸫属的鸟类。仅分布于牙买加岛。其最显著的特征是明亮的白色眼睛和独特的断续白色喉环，与深色的羽毛形成鲜明对比。","appearance":"体长23至24厘米，体重约59克。背部至尾部呈灰蓝色，腹部淡灰棕色，头部暗栗色。拥有醒目的白色眼睛，喉咙和下巴白色，胸部条纹为栗棕色，上胸有小白色新月状斑块，下腹白色；喙和腿黑色。雌雄相似，幼鸟与成鸟相似，但胸部条纹更重。","call":"其歌鸣为一系列重复的音乐性短语，包括类似‘hee-haw’的哨声，声音响亮且变化较少，类似于小嘲鸫，但音量更大，变化较小。叫声尖锐刺耳。","habits":"偏好湿润的山地森林，但在大多数有茂密植被的林地都能找到它们的身影。既在树上觅食也在地面活动，以果实、昆虫为食。","breeding":"关于其繁殖习性的详细信息未提供。","identification":"与白颏鸫相比更为羞涩，白颏鸫具有暗色眼睛、橙色喙和腿，且无白色颈环。","protection":"IUCN状态未提供。","distribution":"白眼鸫仅分布于牙买加，包括其繁殖和非繁殖区域。","other":"物种分类上属于单型种，无亚种被认可。"},{"name":"白喉鸫","english_name":"White-throated Thrush","scientific_name":"Turdus assimilis","overview":"白喉鸫（英文名：White-throated Thrush，学名：Turdus assimilis），是雀形目鸫科鸫属的鸟类。在墨西哥至中美洲广泛分布，南至巴拿马中部。有时被误称为\"白喉鸲\"，但这一称呼现今更多用于指代旧大陆的物种。","appearance":"白喉鸫体长约23厘米。其显著特征为黑白条纹相间的喉咙，由一道完整的白色新月形边界环绕。胸部呈淡灰色至灰棕色，背部为深灰色至灰棕色。它还拥有醒目的黄色眼圈、喙和脚。","habits":"白喉鸫栖息于亚热带或热带的干燥森林、湿润低地森林及湿润山地森林。在自然分布区内常见，但在德克萨斯州和亚利桑那州极为罕见，仅记录过三次迷鸟事件（1990年、1998年在德克萨斯州，2019年在亚利桑那州）。","identification":"与\"白喉鸲\"区别明显，后者为旧大陆物种，而白喉鸫为新大陆物种。此外，需与Dagua鸫和白颈鸫相区分，这两者曾被归为其亚种。","protection":"IUCN：LC（无危）","distribution":"中美洲广泛分布，从墨西哥至巴拿马中部，包括东巴拿马和南美洲沿海地区。"},{"name":"达瓜鸫","english_name":"Dagua Thrush","scientific_name":"Turdus daguae","appearance":"达瓜鸫的显著特征在于其深棕色的羽毛，与白喉鸫的其他亚种形成对比。此外，它拥有相对较短且颜色为黑色的嘴部，这些特征有助于识别这一物种。","habits":"达瓜鸫主要分布于中美洲至南美洲西北部，包括巴拿马至厄瓜多尔西北部。它们是杂食性动物，饮食以无脊椎动物为主。","identification":"与白喉鸫的其他亚种相比，达瓜鸫的羽毛颜色更深，嘴部更短且颜色为黑色，这些都是辨识该物种的关键点。","distribution":"达瓜鸫的分布范围涵盖中美洲至南美洲西北部，具体包括巴拿马至厄瓜多尔西北部。"},{"name":"南美白颈鸫","english_name":"White-necked Thrush","scientific_name":"Turdus albicollis","overview":"南美白颈鸫（英文名：White-necked Thrush，学名：Turdus albicollis），是雀形目鸫科鸫属的鸟类。大型的鸫科鸫属鸟类，广泛分布在南美洲的森林和林地中。其显著特征为白颈环，橄榄褐色背部，黄色眼圈，条纹喉部，以及变化多端的腹部颜色（棕色或淡色）和侧翼（橙色存在与否）。分布于哥伦比亚至巴西东部和阿根廷北部。","appearance":"体长20.5-26厘米，体重40-77克。头部前额至脸部呈黑褐色，渐变为暗褐色上体。具黑色条纹的白色喉咙，连接着短而白色的胸部新月斑。胸部中间至上腹部为灰白色，侧翼橙色带有棕色洗色，下腹至肛区白色。两性相似，但幼鸟较暗淡，头部有浅色斑点，翅膀上有模糊的双橙色斑点，下方有棕色条纹。","call":"叫声为独特的'wuk'声，警报声为粗糙的'jjig-wig-wig'。鸣唱较为单调，常发出类似'two-e-o, two-e'的旋律。","habits":"主要栖息于湿润森林和林地，尤其在亚马逊雨林和山地附近的潮湿环境。以地面或近地面的昆虫等无脊椎动物为主食，偶尔食用果实、浆果和种子。常见于跟随军蚁群，但不参与混合物种的群聚。","breeding":"巢为树或灌木低处的衬垫杯状，高度约1-9米。产卵2-3枚，绿蓝色带红斑，仅由雌鸟单独孵化12-13天。社会上为一夫一妻制，但额外配偶交配现象普遍。","identification":"与同属物种相比，白颈鸫的白颈环和侧翼颜色是主要的识别特征。若将南美白颈鸫与T. phaeopygos视为不同物种，则前者被称为'红侧白颈鸫'，后者保留白颈鸫鸫'或改名为'灰侧白颈鸫'。","protection":"IUCN状态未知。","distribution":"分布于南美洲，从哥伦比亚到巴西东部，北至阿根廷北部，包括亚马逊盆地，以及特立尼达和多巴哥群岛。","other":"分类学上，有时将白喉鸫组作为其亚种，此时统称为白喉鸫鸫'；然而，最近的权威倾向于将其视为独立的物种。"},{"name":"棕背鸲鸫","english_name":"Rufous-backed Thrush","scientific_name":"Turdus rufopalliatus","overview":"棕背鸲鸫（英文名：Rufous-backed Thrush，学名：Turdus rufopalliatus），是雀形目鸫科鸫属的鸟类。其主要分布在墨西哥太平洋沿岸，从索诺拉东南部至瓦哈卡东南角的低地热带森林中。成年鸟以其橄榄棕色或锈色的背部与灰色头部形成鲜明对比，腹部白色带有黑色条纹，胸和侧翼为锈色，黄色的喙和眼环为其显著特征。","appearance":"成年棕背鸲鸫体型中等，长度约为21.5至24厘米，平均翼展39.4厘米，体重约74克。雄鸟具有灰色头部、颈部和臀部，上背部为橄榄棕色或锈色，胸部和侧翼也是锈色，腹部和尾下覆羽为白色，喉部白色带有多条黑色条纹。雌鸟色彩较淡，而幼鸟身上有斑点，上部有淡色斑点，下部斑点明显。特例中的三玛丽亚群岛亚种（有时被视为独立物种，即格雷森鸲鸫或格雷森鸫）色彩更为暗淡，几乎无锈色。","call":"其歌声为一系列悠扬的低音颤音短语，例如“weedele loo loo freerlii...”，通常重复2至3次。报警声为长而柔和的下降哨音，如“cheeoo”或“teeeuu”。还有类似美国鸲鸫的其他叫声，飞行叫声较为尖细。","habits":"栖息于干燥的落叶林及其边缘地带，包括人类种植的环境，活动高度从地面到树冠层均有分布。它比美国鸲鸫更为害羞。冬季常形成小群。以果实和无脊椎动物，尤其是昆虫为食。","breeding":"繁殖期为6月至8月，与夏季雨季开始同步。巢通常由植物材料混合泥土制成，位于树上或灌木丛中，可容纳2至3枚蛋。蛋壳呈白色，带有深红褐色的厚重斑点。孵化期大约13天，雏鸟期为14天。巢穴的成功率约为62.5%，平均每个巢产出1.25只雏鸟。","identification":"与美国鸲鸫相比，棕背鸲鸫的上背部更显橄榄棕色或锈色，且体型略小。三玛丽亚群岛亚种色彩更淡，锈色成分较少。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥太平洋沿岸，从索诺拉东南部至瓦哈卡东南角的低地热带森林中。在墨西哥城和瓦哈卡市有孤立的种群，可能源自逃逸的笼养鸟。偶尔会出现在美国墨西哥边境州的河岸树林中。"},{"name":"中美棕颈鸫","english_name":"Rufous-collared Thrush","scientific_name":"Turdus rufitorques","overview":"中美棕颈鸫（英文名：Rufous-collared Thrush，学名：Turdus rufitorques），是雀形目鸫科鸫属的鸟类。大型鸫科鸟类，主要分布于墨西哥南部至洪都拉斯的高山区，常见于松树林、橡树林、农田及村庄周边。与旅鸫关系密切，基于分子数据，两者被认为是近亲。雄鸟个体头部和身体呈黑色，带有醒目的红褐色领圈，喉部白色，下喉及胸部为红褐色，两性及幼鸟颜色较为暗淡。","appearance":"雄性中美棕颈鸫上身黑色，具有宽阔的红褐色领圈，覆盖颈部两侧，连接至红褐色胸部，下巴白色，下喉及胸部红褐色，两翼和尾巴黑色。雌鸟和幼鸟整体颜色较淡，偏棕色，领圈和胸部为肉桂红褐色。黄色喙和腿为其显著特征。成年雄鸟全长约23-25.5厘米，翼展略大，雌鸟稍小。","habits":"中美棕颈鸫栖息于海拔较高的森林地带，偏好有树木的环境，如松林、橡树林。它们会在田野觅食，也会在果实丰富的树丛中寻找食物。常在清晨和傍晚站立于枯死的高树顶端。活动范围广泛，既可见于开阔森林，也可能出现在郊区。","identification":"与美洲山鸫相比，中美棕颈鸫体型更大，颜色更深，具黄喙；与美洲黑鸫幼鸟相比，中美棕颈鸫体型稍大，领圈更为明显，喙色不同。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，自墨西哥南部至洪都拉斯，包括萨尔瓦多和危地马拉。"},{"name":"旅鸫","english_name":"American Robin","scientific_name":"Turdus migratorius","overview":"旅鸫（英文名：American Robin，学名：Turdus migratorius），是雀形目鸫科鸫属的鸟类。从阿拉斯加和加拿大至墨西哥中部，常见于花园、公园、果园和城市绿地。","appearance":"成年旅鸫体长20-28厘米，翼展31-40厘米，平均体重约77克。雄鸟头部深黑，有白色眼圈，眼先有白点；喉咙白色，饰有黑色条纹。背部呈灰褐色，尾羽黑色，飞行时可见尾端白色斑点。下体自胸至腹红橙色，肛周白色。喙黄色，腿脚棕色。雌鸟色彩较淡，白色部位更为突出。幼鸟背部具褐色斑点与浅黄条纹，胸部红橙色更浓郁，翅膀有深色斑点。","call":"拥有复杂且几乎连续的歌声，常被形容为欢快的旋律，由多个可重复的单元组成，间歇短暂。此外，会发出‘cuck’或‘tuk’声用于交流，或发出尖锐的‘yeep’或‘peek’声作为警报。","habits":"栖息于森林、林地、草地、针叶林区，活动区域多样，从苔原到海拔3700米的山地。冬季南迁至美国南部、巴哈马等地。以果实、浆果为主食，兼食昆虫和无脊椎动物，尤其在春季和夏季偏爱软体动物如蚯蚓。","breeding":"繁殖季从4月至8月，雌鸟筑巢，雄鸟辅助收集材料。巢为杯状，由枝条、秸秆构建，内衬软泥和干草。每窝产卵3至6枚，淡蓝或白色，有深褐色斑点，仅由雌鸟孵化11至14天。雏鸟需在巢中停留15至16天才能飞行，每年可育2至3窝。","identification":"与棕背鸲鸫相似，但后者在西部墨西哥常见，有肉桂色下体和灰色头、翅、尾，喉部条纹更多。旅鸫在较高海拔和松树林中更常见。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美阿拉斯加州和加拿大至危地马拉，冬季南迁至美国南部、巴哈马、墨西哥中部。在北美大陆普遍分布，从海平面至高海拔地区均有其踪迹。","other":"作为北美最知名的鸟类之一，旅鸫是Connecticut、Michigan和Wisconsin的州鸟。"},{"name":"红腹鸫","english_name":"La Selle Thrush","scientific_name":"Turdus swalesi","overview":"红腹鸫（英文名：La Selle Thrush，学名：Turdus swalesi），是雀形目鸫科鸫属的鸟类。以其鲜明的黑色上部和橙色腹部在同类中独树一帜。这种鸟极其害羞，但在黎明时分偶尔会在道路边缘露面，使其得以被观察到。其分布范围限于海地和多米尼加共和国的山区。","appearance":"红腹鸫拥有引人注目的黑色头部和上身，与橙色腹部形成鲜明对比。它的下胸至腹部呈白色，向上延伸分割胸部。银白色的耳羽和喉咙点缀着暗色的羽毛。它拥有亮黄色至橙色的眼环和喙，与深色的头部羽毛形成强烈反差。腿为深灰色至黑色。","call":"其歌声由一系列短促的上滑音和下滑音组成，加上长度不一的甜美哨声，缓慢而重复地发出。","habits":"红腹鸫偏好海拔1,300-2,100米的密集云雾森林和湿润的阔叶林环境。它们有时会大胆地在山路上觅食，但大部分时间隐藏于森林底层。栖息地正遭受农业扩张和木炭生产带来的威胁。","identification":"与红腹鸫最为相似的是红腿鸫，但红腿鸫上部颜色较淡，缺乏红色的胸部和侧翼，脚和喙为鲜红色，尾巴有白色斑点。","protection":"IUCN：VU（易危）","distribution":"红腹鸫主要分布在海地和多米尼加共和国的Massif de la Selle山脉、Sierra de Bahoruco山脉、SIerra de Neiba山脉以及Cordillera Central山脉。"},{"name":"白颏鸫","english_name":"White-chinned Thrush","scientific_name":"Turdus aurantius","overview":"白颏鸫（英文名：White-chinned Thrush，学名：Turdus aurantius），是雀形目鸫科鸫属的鸟类。常见于牙买加，具有亮橙色的喙和腿，上体暗灰褐色，下体偏灰，腹部最淡，具白色翼斑、下巴、腹中部和尾下覆羽尖端。其名字来源于不显眼的白色下巴。","appearance":"体长约24-26.5厘米，体重约82克。上体呈光泽的暗棕灰色，向下渐变为中灰色，腹部和胁部颜色最浅，具白色翼斑、下巴、腹中部和尾下覆羽尖端。喙和腿橙色。雌雄相似，幼鸟头部至背部呈红棕色，胸部和胁部红棕色，下巴上的白色可能缺失或减少。","call":"最常见叫声为略带尖锐的上滑音“p’weet”，有时会发出更长的“p’ooo-weeet”。鸣唱为一系列变化的甜美音符，单个或成对出现。","habits":"偏好林地，但也出现在花园和种植园。以蛞蝓、蜗牛、昆虫及其幼虫、蚯蚓、浆果、青蛙、树蟾、小鼠、雏鸟和蜥蜴为食，其中蜥蜴占其饮食的重要部分。在地面的落叶层中觅食，偶尔在牛粪中搜寻。","breeding":"繁殖期主要在5月至7月，第二次繁殖可延长至8月。巢由叶子、纤维根、树枝和竹子、香蕉交织而成，内部铺垫细腻材料，位于灌木、树上（如芒果树）、凤梨科植物或棕榈叶基部。每窝产2-3枚蛋，偶尔4枚，蛋壳呈淡白色至淡绿色，带有红棕色斑点，孵化期16天，第二次繁殖在首次雏鸟离巢11天后开始。","identification":"与白眼鸫相比，后者具白色眼圈和黑色喙及腿，而白颏鸫具有橙色喙和腿，且有白色翼斑。","protection":"IUCN：LC（无危）","distribution":"分布于北美牙买加，为当地特有种。"},{"name":"大开曼鸫","english_name":"Grand Cayman Thrush","scientific_name":"Turdus ravidus","overview":"大开曼鸫（英文名：Grand Cayman Thrush，学名：Turdus ravidus），是雀形目鸫科鸫属的鸟类。曾广泛分布于大开曼岛。其灭绝的原因至今未明，可能与栖息地改变和飓风有关。该鸟暗灰色，腹部白色，尾羽末端带白色，具有醒目的红嘴红腿。","appearance":"成年大开曼鸫全身均匀的蓝灰石板色，下体白色，尾羽具显著的白色端斑，尾部中央两对尾羽无白色，其余尾羽内翈逐渐增多的白色。虹膜棕色或红褐色。雄鸟和雌鸟羽毛相似，但雄鸟平均体型较大。幼鸟整体淡黄色，裸露部位比成鸟更浅。翼展约13.5厘米，尾长11厘米，喙长2.4厘米，脚长3.8厘米。","identification":"与红腿鸫的区别在于喉部颜色与胸部不同，多数亚种具条纹，且下体颜色比大开曼鸫更浅。红腿鸫的翼部图案对比更鲜明。","protection":"IUCN：EX（已灭绝）","distribution":"北美：仅限于大开曼岛。"},{"name":"红腿鸫","english_name":"Red-legged Thrush","scientific_name":"Turdus plumbeus","overview":"红腿鸫（英文名：Western Red-legged Thrush，学名：Turdus plumbeus），是雀形目鸫科鸫属的非迁徙性鸟类。拆分为两个独立成种，本种目前包含“巴哈马型”与“古巴型”。巴哈马型分布于巴哈马北部诸岛；古巴型分布于古巴主岛、青年岛及附近小岛。两者均为留鸟，通体蓝灰，尾具白斑，腿、眼环及喙多呈红色，以果实与无脊椎动物为主食，目前种群稳定，IUCN 评为无危。","appearance":"巴哈马型：上体均匀蓝灰，尾外侧羽具大块白斑；喉部黑色，边缘由白色颏纹及亚须纹勾勒；眼环鲜红，喙呈黑色或仅基部微红，跗跖珊瑚红。古巴型：上体略带橄榄灰，尾白斑略大；喉部黑底上具细密白纹，下胸至腹部中央白色，两侧与尾下覆羽呈鲜明橙红；喙暗红色，端部更深，跗跖橙红。两性相似，雌鸟略小且色稍暗；幼鸟翼覆羽端具淡色斑点或鳞纹，头颈微褐。","call":"雄鸟鸣声缓慢断续，似“cheweap-screet”反复，音色忧郁，偶有模仿；雌鸟不叫。叫声响亮多变，包括成对“chirruit-chirruit”或“pert-squeeer”，告警时连续“wheet-wheet”。黎明前及黄昏为歌唱高峰。","habits":"留鸟，栖息于次生阔叶林、林缘、咖啡种植园及城镇绿地，避开原始密林内部。地栖，行走或疾驰觅食，受惊即迅速飞入灌丛。晨昏最活跃，多单只或成对活动。食物以果实、种子、昆虫、多足类及小型脊椎动物为主，幼鸟获喂大量树蛙与蜥蜴。","breeding":"繁殖季巴哈马型1–9月，古巴型3–11月，均集中在干湿季交替期。一夫一妻制，雌鸟主筑巢，巢为开放式杯状，置于树叉、棕榈或灌丛，高0.5–20米。每窝2–3枚卵（古巴型可达5枚），卵淡绿或白底红褐斑。孵卵期11–13天，仅雌鸟孵卵；雏鸟15–18天离巢，双亲育雏。偶遭辉拟椋鸟寄生但影响小。","identification":"巴哈马型与古巴型最易区别：前者下体无橙色，腹至尾下覆羽纯白；后者侧腹与尾下覆羽呈鲜明橙红。喙色亦有差异，巴哈马型偏黑，古巴型通体暗红。二者尾均具显著白斑，飞行时呈“白边黑尾”，可与其他无此特征的加勒比鸫类区分。","protection":"IUCN: LC（无危）。","distribution":"巴哈马型：繁殖于巴哈马北部——大巴哈马、阿巴科、安德罗斯、新普罗维登斯、伊柳塞拉及卡特岛。古巴型：繁殖于古巴主岛、青年岛及众多离岸小岛。两地均为常年留居，偶有迷鸟至佛罗里达。","other":"东红腿鸫已拆分独立成种。化石记录显示晚更新世已存在于巴哈马，近代因人类活动局部灭绝于部分小岛。"},{"name":"林鸫","english_name":"Forest Thrush","scientific_name":"Turdus lherminieri","overview":"林鸫（英文名：Forest Thrush，学名：Turdus lherminieri），是雀形目鸫科鸫属的鸟类。长度约25至27厘米，体重100至110克。其最显著的特征是上体呈灰褐色，下体有独特的鳞片状斑纹，眼周环绕着宽大的黄色裸皮环。该物种仅见于加勒比海小安的列斯群岛的几个岛屿，包括多米尼加、瓜德罗普、蒙特塞拉特和圣卢西亚，数量稀少。","appearance":"林鸫拥有温暖的棕色上体，头部侧面（脸颊和耳羽）带有细白线条，宽阔的黄色眼圈和后眼斑。下体白色，有暗棕色边缘形成鳞片状图案。虹膜黄色，喙和腿均为黄色。性别相似。幼鸟颜色略淡，上体有模糊的浅色条纹，下体斑点更多。多米尼加亚种喉部羽毛边缘呈红棕色，胸部羽毛中心更长、更尖，白色部分较多；圣卢西亚亚种体型较小，上体颜色较淡，胸部斑点较大，腹部泛黄。","call":"林鸫发出响亮的‘啪’声叫声。其鸣唱包括一系列清脆的音符，旋律悦耳，响亮而远传，类似旅鸫的歌声。叫声还包括尖锐的‘chuk’或‘chuk-chuk’。","habits":"栖息于湿润的山地原始森林和次生林中，偏好成熟湿润、树冠密集的森林，常见于中高海拔。林鸫通常从地面到树冠觅食，以昆虫和浆果为食。过去在秋季大量聚集于圣卢西亚的浆果果树上。","breeding":"繁殖期在4月至7月间。巢为厚实的杯状，由苔藓制成，外部建于灌木、树蕨或树木近地面处。每窝产卵2至3枚，蛋壳呈蓝绿色。无更多信息。","identification":"林鸫因上体的灰褐色与下体明显的鳞片状斑纹而易于识别。多米尼加亚种和圣卢西亚亚种在胸部斑点的大小和颜色上有细微差异。","protection":"IUCN：NT（近危）。该物种受限制分布于小安的列斯群岛，总个体数估计超过10,000只成熟个体，但持续的栖息地丧失和退化对其构成威胁。蒙特塞拉特岛上，由于火山爆发导致栖息地缩减三分之二，但两年内种群恢复了约50%。","distribution":"林鸫分布于小安的列斯群岛的多米尼加、瓜德罗普、蒙特塞拉特和圣卢西亚，数量稀少至罕见。","other":"林鸫曾受到森林损失、与裸眼鸫的竞争、紫辉牛鹂的寄生繁殖以及人类的捕猎影响。"},{"name":"特里斯坦鸫","english_name":"Tristan Thrush","scientific_name":"Turdus eremita","overview":"特里斯坦鸫（英文名：Tristan Thrush，学名：Turdus eremita），是雀形目鸫科鸫属的鸟类。是特里斯坦-达库尼亚群岛特有种，分布于大西洋南部的这一英国海外领土群岛上。其体长约为22厘米，拥有橙色斑点的双翼条纹，下部呈橙黄色，带有深褐色斑驳条纹，腹部中间为淡黄色。该物种仅在特里斯坦群岛的岛屿上发现，以岛屿上的湿草原、苔藓灌木丛和海岸线为栖息地。","appearance":"特里斯坦鸫体长约22至23厘米，重72至110克。成年鸟背部暗褐色，具橙色斑点的双翼条纹；腹部橙黄色，带深褐色斑驳条纹，腹部中间为淡黄色；喙黑色；腿肉色。性别相似。幼鸟上体有浅黄色斑点和条纹。gordoni亚种比指名亚种更大，下方更多斑点而非条纹，面部更苍白，有更多斑点；procax亚种更大，颜色更深，翼下橙色更深。","call":"发出短促的高音'chipping ttslit'声和简单的喘息歌曲。","habits":"特里斯坦鸫占据湿润的草原、蕨类灌木丛、草甸、花园和布满鹅卵石的海岸线。它是一种留鸟，广泛食性，以甲虫、苍蝇和蛆虫、毛虫、蜘蛛、螨虫、鼠妇和蚯蚓为食，尤其喜欢海鸟蛋，能打开小到信天翁的鸟蛋。也会掠夺其他陆地鸟类的巢穴和雏鸟，例如雀鹀和不可达岛秧鸡；甚至会杀死成年的白腹舰海燕。","breeding":"繁殖期为9月至2月。巢由编织的草茎和少量绿叶及苔藓构成的粗糙杯状巢，放置于或略高于地面，位于密集的芦苇丛基部，偶尔在悬崖边缘。产卵数2至3枚，有时4枚（gordoni亚种），蛋壳呈淡青绿色，带有姜棕色斑点和紫色斑块；孵化期未知；离巢期约20天。","identification":"特里斯坦鸫是其范围内唯一的中型鸣禽。与同属的其他物种相比，特里斯坦鸫具有独特的橙色斑点双翼条纹和腹部橙黄色带深褐色条纹的特征。不同亚种之间在大小、颜色和下部斑点密度上存在差异。","protection":"IUCN：NT（近危）","distribution":"特里斯坦鸫分布于特里斯坦-达库尼亚群岛，包括特里斯坦、不可达岛、夜莺岛、中岛和斯托尔滕霍夫岛。在特里斯坦岛上的数量估计为几百只，不可达岛上有850对，全球总数约为6000只。","other":"黑鼠的捕食可能是特里斯坦岛上特里斯坦鸫的威胁之一。"},{"name":"坎皮纳黑嘴鸫","english_name":"Campina Thrush","scientific_name":"Turdus arthuri","overview":"坎皮纳黑嘴鸫（英文名：Campina Thrush，学名：Turdus arthuri），是雀形目鸫科鸫属的鸟类。曾被认为是黑嘴鸫的亚种，现为独立种。主要分布在亚马逊生物圈，包括委内瑞拉东南部、圭亚那、苏里南、哥伦比亚东部和巴西亚马孙雨林中西部。中等体型的黑褐色鸫，具有灰白色的腹部，喉部带有棕色条纹。","appearance":"该物种总长约为202毫米，体重约64克。外观为中等大小的黑褐色，喉部白色并带棕色条纹，腹侧呈淡色，臀部和尾下覆羽白色。两性相似，常单独或成对出现。与近亲泰普黑嘴鸫相比，体型较小，翼部略带橄榄色，整体呈现较为灰暗的外观。","call":"鸣唱通常类似鸫科的音乐性短语系列，但在委内瑞拉东南部，其歌声被描述为更明显的升降起伏模式。叫声尚未详细描述。","habits":"坎皮纳黑嘴鸫偏好光亮的林地、高大的次生林、受干扰的区域，甚至公园和花园。在苏里南，仅限于沙质草原地带，散布着灌木丛和灌木。海拔可达1200米。其饮食习惯与其他鸫属物种相似，以地面觅食为主。","breeding":"繁殖季节未知，但至少从12月至次年3月在苏里南地区可能处于繁殖期。关于筑巢和产卵的明确描述极为缺乏。","identification":"与泰普黑嘴鸫的区别在于灰白的身体、更强的喉部斑纹和不同的栖息环境。在羽色上有细微差异，如翼部的橄榄色洗涤和更为灰暗的整体外观。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲低地，包括委内瑞拉东南部、圭亚那、苏里南、哥伦比亚东部和巴西亚马孙雨林中西部。在巴西的分布范围比原先认为的更广泛。","other":"2019年，基于分子和相对轻微的羽毛差异，与黑嘴鸫的分类地位得到了重新评估，正式确认为独立物种。"},{"name":"泰普黑嘴鸫","english_name":"Pantepui Thrush","scientific_name":"Turdus murinus","overview":"泰普黑嘴鸫（英文名：Pantepui Thrush，学名：Turdus murinus），是雀形目鸫科鸫属的鸟类。主要分布在南美洲委内瑞拉南部、圭亚那东部以及巴西北部的特普伊山脉地区。曾被认为是黑嘴鸫的一个亚种，但遗传学研究显示两者之间并无紧密联系，因而被认定为独立物种。外形上，泰普黑嘴鸫呈现暗橄榄棕色的上体，喉部至腹部为淡白色，带有明显的暗褐色条纹。","appearance":"泰普黑嘴鸫的成年个体长约23至24厘米，两性相似。其头部、侧面、背部、翅膀及尾巴呈深暗橄榄棕色，胸部与两侧体色较浅，环绕着白色的腹部和臀部。喉部白色至米白色，具有显眼的暗褐色条纹。成年泰普黑嘴鸫与黑嘴鸫尤其是debilis亚种，以及坎皮纳黑嘴鸫非常相似，但通过更褐色的身体、较弱的喉部条纹图案和不同的栖息环境可以区分。","call":"泰普黑嘴鸫的鸣叫特征目前知之甚少，但可能类似于黑嘴鸫的典型系列音乐性的短语，包含旅鸫般的鸣唱。此外，还报道了鼻音上升的'queek!'叫声，当受到干扰时，会发出响亮的'Quee-kipper-kipper-kipper'声。","habits":"泰普黑嘴鸫似乎偏好湿润森林边缘（在广阔森林中仅沿大河边缘出现）和早期演替生境。它的迁徙情况未知，但考虑到其分布特点，可能存在季节性海拔分布的变化。饮食方面，虽然缺乏具体数据，但预计以昆虫和果实为主食，食物种类可能会随季节变化。","breeding":"已知在委内瑞拉的Cerro Urutaní，于1977年2月到4月间收集到了一只尾羽短小的雏鸟，同时观察到许多个体正从幼鸟向成鸟换羽。","identification":"泰普黑嘴鸫与黑嘴鸫和坎皮纳黑嘴鸫相似，但可通过更暗的橄榄棕色上体、较淡的下体以及喉部更为模糊的条纹加以区分。在分布区域上，泰普黑嘴鸫局限于特普伊山脉，而其他两种鸫则分布更广泛。","protection":"IUCN：数据缺乏（需更多研究）","distribution":"泰普黑嘴鸫分布于南美洲委内瑞拉南部、圭亚那东部以及巴西北部的特普伊山脉，包括Mount Duida、Mount Roraima、Merumé山脉、Auyán-Tepui、Ptari-Tepui、Sororopán-Tepui、Urutani、Cerro de la Neblina、Cerro Guaiquinima等地。该物种在Parque Nacional Roraima等保护区中有所记录。","other":"泰普黑嘴鸫的系统分类历史复杂，最初由Osbert Salvin于1885年描述，之后被归入黑嘴鸫作为亚种，直到最近的分子系统学研究表明其应独立为种。"},{"name":"白头鸫","english_name":"Taiwan Thrush","scientific_name":"Turdus niveiceps","overview":"白头鸫（英文名：Taiwan Thrush，学名：Turdus niveiceps），是雀形目鸫科鸫属的鸟类。在台湾的山地森林（海拔1000-2500米）中繁殖，雄鸟外观醒目，黑色的身体配以橙色腹部和雪白头部；雌鸟较暗淡，头部呈橄榄褐色斑纹。","appearance":"雄鸟具有白色头部延伸至胸部上部，与全黑或深黑褐色的背部、翅膀和尾巴形成鲜明对比；腹部为赤橙色，腹部中央为白色，带有宽黑纵条纹；眼睛黑色，喙黄色，腿淡黄色。雌鸟头部、侧面橄榄褐色，具明显的淡色眉纹，脸颊带斑点，喉咙下方和喉部淡色，上身暗橄榄褐色，下体为均匀的暗橙褐色。幼鸟类似雌鸟，但更暗更棕色，上体有淡色羽轴纹，下体为更暗的棕色橙色，有黑色尖端。","call":"雄鸟会在树冠处发出一系列高音悦耳的哨声和较低的笛音，开始缓慢，随后加速。","habits":"主要以昆虫和其他小型无脊椎动物为食，包括蜘蛛、蠕虫、小软体动物等，也会吃种子、浆果和小果实。既在树木和灌木丛中觅食，也在地面觅食；通常害羞且难以发现。有时会聚集在结果的树上。一般单独或成对活动，冬季则小群体与其它鸫类一起在地面觅食。","identification":"雄鸟与雌鸟的性二型性明显，与塔岛鸫的亚种相比，台湾鸫展现出更强的性二型性。","protection":"IUCN：LC（无危）。台湾特有种，数量稀少，估计21世纪初其繁殖对数不足10,000对，或成熟个体不到20,000只。由于栖息地破坏和退化，数量疑似在减少。","distribution":"远东：台湾。在台湾中部山区的森林中，海拔1800-2500米，为常驻居民。"},{"name":"埃塞地鸫","english_name":"Ethiopian Thrush","scientific_name":"Turdus simensis","overview":"埃塞地鸫（英文名：Ethiopian Thrush，学名：Turdus simensis），是雀形目鸫科鸫属的鸟类。上部呈棕色，下部有明显的斑点，面部标记鲜明。","appearance":"埃塞地鸫是一种中等体型的鸫，翼宽而尾短，头至尾部为温暖的灰棕色，上部有较暗的中央边缘，形成轻微的斑驳效果。尾部较深的棕色，带有灰色调，最外侧三对尾羽尖端白色。翅膀暗灰色，外缘有大的橙色斑块。脸和下部为淡黄色，有宽阔的黑色眼下的垂直条纹，黑色耳盖条纹，窄的黑色颊纹，以及从胸部到腹部放射状排列的黑色斑点。雌雄相似，但雌鸟通常斑点较少。","call":"其歌声是一系列粗糙的、吐音似的哨声。叫声包括单个或连续的上扬‘wheet’，以及干燥的颤音。","habits":"埃塞地鸫成对或小群体出现在开阔的山区生境中，包括沼泽地、草地和林地，常在重度放牧和烧荒的区域活动。它们在地上长距离奔跑寻找无脊椎动物，停止时直立，抖动翅膀。","breeding":"关于繁殖的信息有限，但已知它们在繁殖季节会求偶、筑巢、交配、产卵、孵化和育雏。","identification":"与近似物种非洲地鸫相比，埃塞地鸫喙更短，尾更长，站立姿势更平，缺乏黑色脸部标记。此外，其叫声和歌声也有显著差异。","protection":"IUCN：LC（无危）","distribution":"埃塞地鸫主要分布在非洲的厄立特里亚和埃塞俄比亚，特别是在Simien山脉周围。","other":"埃塞地鸫的历史分类较为复杂，曾被认为与非洲地鸫同属，但基于形态学、声音和遗传差异，目前被视为独立物种。"},{"name":"蓝大翅鸲","english_name":"Grandala","scientific_name":"Grandala coelicolor","overview":"蓝大翅鸲（英文名：Grandala，学名：Grandala coelicolor），是雀形目鸫科蓝大翅鸲属的鸟类。俗名: 喜玛拉山蓝鸟、蓝丝绒，此鸟以独特的群居生活方式著称，拥有燕子般的轻盈翅膀，栖息于喜玛拉雅山脉的高寒环境，其炫目的蓝色羽毛如同丝绒般光泽夺目。分布于中国南疆诸邻国，自克什米尔至缅甸北部，以及中国境内的甘肃、青海、四川、云南、西藏等地。","appearance":"蓝大翅鸲体长20.5-23厘米，体重38-52克。雄鸟羽毛呈深邃的蓝灰色，尾部和翅膀为黑色。雌鸟及幼鸟羽毛棕色，头部和下体布满白色条纹，翼上有淡淡的白色横纹。臀部为灰蓝色，翼尖和下侧羽毛为白色。","call":"发出‘dew-ee’和‘dewee’的声音。","habits":"蓝大翅鸲栖息于海拔1400-2600米的高山草甸及裸岩山顶地带，偏好湿润的山脊和高地。它们通常结成由同性别组成的群体，飞行姿态和习性类似矶鸫，同时也展现出与紫翅椋鸟相似的集群盘旋行为，冬季则集体栖息于树上。","identification":"雄鸟的深蓝色羽毛与黑色翅膀形成鲜明对比，雌鸟及幼鸟的棕色羽毛和白色条纹有助于与其他鸟类区分。与星椋鸟相比，蓝大翅鸲的长喙和锐利的翅膀轮廓更显独特。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉至中国中部，具体包括印度的喜马拉雅山区从克什米尔至尼泊尔，以及中国境内的甘肃、青海、四川、云南、西藏等地。"},{"name":"东蓝鸲","english_name":"Eastern Bluebird","scientific_name":"Sialia sialis","overview":"东蓝鸲（英文名：Eastern Bluebird，学名：Sialia sialis），是雀形目鸫科蓝鸲属的小型鸟类。雄鸟拥有醒目的皇家蓝色上身，搭配亮丽的橙色喉部和胸部，以及洁白的腹部。雌鸟色调较淡，灰蓝相间，颈侧和胸部带有橙色，腹部纯白。该物种广泛分布于北美洲东部至中部，南至尼加拉瓜，偏好开阔的林地、田野和果园等环境。","appearance":"雄鸟成鸟头部、背部及翅膀呈深邃的蓝色，喉部至胸部为红棕色，腹部雪白。雌鸟成鸟上身淡蓝色，翅膀和尾巴带有蓝灰，颈部和胸部为棕色，头部和背部灰蓝，腹部白色。幼鸟背部和胸部具斑点，翅膀和尾巴可见不同程度的蓝色，白色眼环明显。","call":"东蓝鸲的鸣唱柔和而富有旋律，包括轻柔的jeew或chir-wi声，以及悠扬的chiti WEEW wewidoo歌曲。","habits":"东蓝鸲栖息于开阔地带，如牧场、农田边缘、公园、高尔夫球场等，偏好有树木的开阔环境。它们常在低枝或电线杆上栖息，俯瞰地面寻找昆虫，冬季则在果实树上啄食浆果。","breeding":"春季和夏季进行繁殖，雌鸟通常每年抚育两窝幼鸟。巢建于树洞或人工巢箱中，由雌鸟主导筑巢，历时约十天。每窝产三到七枚淡蓝色或罕见的白色蛋，雌鸟孵化，孵化期13至16天。幼鸟出生后无法自理，由雌鸟照料，约一周后离开巢穴。","identification":"东蓝鸲与西蓝鸲的主要区别在于喉部颜色，东蓝鸲喉部棕色，而西蓝鸲喉部蓝色。","protection":"IUCN：LC（无危）","distribution":"东蓝鸲分布于北美洲东部至中部，南至尼加拉瓜。在繁殖季节，常见于加拿大南部至美国中南部地区；非繁殖季节，部分个体南迁至中美洲。","other":"东蓝鸲在文化中被视为爱情专一的象征，其形象出现在文学作品、歌曲和货币设计中。"},{"name":"西蓝鸲","english_name":"Western Bluebird","scientific_name":"Sialia mexicana","overview":"西蓝鸲（英文名：Western Bluebird，学名：Sialia mexicana），是雀形目鸫科蓝鸲属的鸟类。主要分布在北美的西部地区，南至墨西哥中部。雄鸟拥有亮丽的蓝色头部、背部和翅膀，胸部和两侧呈橙色，有时背部会有棕色斑块；雌鸟色彩较暗淡，蓝灰色调更明显，胸部呈橙色，腹部和下尾覆羽为灰色。西蓝鸲偏好有树木的开阔地带，常以昆虫为食，冬季则转向浆果和水果。","appearance":"西蓝鸲体长约15到18厘米，体型较为结实。雄鸟的头部、背部和翅膀呈现深钴蓝色，胸部和两侧为橙色，腹部和下尾覆羽为灰色，背部可能有棕色斑块。雌鸟的色彩较雄鸟更为暗淡，头部和喉咙为灰色，背部和翅膀为蓝灰色，胸部为橙色，腹部和下尾覆羽为灰色。幼鸟的颜色比成鸟更加暗淡，胸背有斑点。","call":"西蓝鸲的鸣叫声包括‘cheer’、‘chur-chur’和‘chup’等音节，这些声音帮助雄鸟在密集的森林中找到雌鸟，同时也是领土声明的信号。","habits":"西蓝鸲通常群居，非繁殖季节常结成小群体。它们通过从低处的栖木上俯冲地面捕食陆地昆虫，也会在树上觅食浆果。依赖树木作为巢穴和捕食的栖息地，常见于开阔的林地、后院、烧毁的区域和农田。","breeding":"西蓝鸲在树洞或巢箱中筑巢，面临来自树燕、家麻雀和欧洲八哥的竞争。研究显示，约45%的西蓝鸲巢中幼鸟并非雄鸟伴侣的亲生后代。它们通常在早春开始产卵，每窝产卵数为2至8枚，卵呈椭圆形，表面光滑，颜色从浅蓝到蓝白色，孵化期大约19至22天，条件适宜时一年可育两窝。","identification":"西蓝鸲可以通过其蓝色（雄鸟）或灰色（雌鸟）的喉咙与其它蓝鸲属物种区分开来：东蓝鸲的喉咙为橙色，而山蓝鸲全身无橙色部分。","protection":"IUCN：LC（无危）","distribution":"西蓝鸲全年分布于美国加州、落基山脉南部、亚利桑那州和新墨西哥州，南至墨西哥的瓦哈卡州和韦拉克鲁斯州。夏季繁殖区向北延伸至太平洋西北部、不列颠哥伦比亚省和蒙大拿州。北方种群会迁移到南部的繁殖区域，而南方种群通常是留鸟。","other":"西蓝鸲在恢复森林中的繁殖成功率高于未经处理的森林，但在寄生虫感染的风险上更高。"},{"name":"山蓝鸲","english_name":"Mountain Bluebird","scientific_name":"Sialia currucoides","overview":"山蓝鸲（英文名：Mountain Bluebird，学名：Sialia currucoides），是雀形目鸫科蓝鸲属的鸟类。北美鸫科蓝鸲属的一种小型鸟类，以其鲜艳的天蓝色羽毛而闻名，雄鸟全身覆盖着纯粹的天蓝色，雌鸟则呈现蓝绿色。广泛分布于西部北美的高山和中高纬度地区，是美国爱达荷州和内华达州的州鸟。","appearance":"山蓝鸲的体型较小，长约15.5至18厘米，重24至37克。雄鸟拥有明亮的天蓝色上部羽毛，腹部颜色较浅，下腹部几乎全白。雌鸟的头部和背部呈灰褐色，翅膀和尾巴带有淡蓝色，喉咙、胸部和腹部颜色可能从淡灰色到橙色变化不一，下腹部和尾下覆羽为白色。喙、腿和脚均为黑色。","call":"山蓝鸲的叫声为细薄的'few'声，其鸣唱则是高音的颤音'chur chur'。","habits":"山蓝鸲栖息于开阔地带，如草原、灌木草原和高山苔原，偏好有少量树木或可供筑巢的巢箱的环境。它们以昆虫为主食，冬季转而摄食浆果。山蓝鸲能进行远距离迁徙，冬季南迁至墨西哥。","breeding":"山蓝鸲在天然树洞或人为巢箱中筑巢，通常由雌鸟独自建巢，雄鸟负责守卫。每窝产卵4至5枚，孵化期约两周，雏鸟出生后需约21天离巢，直至独立需两个月左右。","identification":"山蓝鸲与东方蓝鸲和西方蓝鸲在外观上有细微差异，最明显的区别在于其缺乏橙色或锈色的羽毛，尤其是胸腹部。雄鸟的蓝色更加纯正，雌鸟的蓝绿色更为显著。","protection":"IUCN：LC（无危）","distribution":"山蓝鸲主要繁殖于西部北美的高山地区，冬季则向南迁移至墨西哥西部。","other":"山蓝鸲受益于19世纪末至20世纪初西部森林的砍伐和牧场的扩张，但随后森林管理的改变导致了其栖息地的减少。近年来，人类建造的巢箱为其提供了额外的繁殖场所，有助于稳定其种群数量。"},{"name":"夏威夷鸫","english_name":"Omao","scientific_name":"Myadestes obscurus","appearance":"夏威夷孤鸫体长18至19.5厘米，重约49至52克。成年鸟呈现灰褐色头部，上体橄榄褐色，下体淡灰色，喙与腿均为黑色。幼鸟上体呈深褐色，带有白色斑点。","call":"夏威夷孤鸫的歌声由一系列响亮、生硬的短句组成，有时在显眼的位置演唱。叫声包括响亮的哨声和一连串上升的笛音般的音符。","habits":"夏威夷孤鸫偏好独自活动，偶尔在冬季形成群体。它们警惕且害羞，遇人即发出警报声。主要在林下灌木丛或树上活动，也会下到地面觅食，食物包括低矮的浆果和陆生无脊椎动物。","breeding":"繁殖期从1月持续到11月，筑巢高峰期在4月至7月。双亲共同照顾幼鸟，实行社会单配制。关于其他相关物种如Käma‘o、Oloma‘o和‘Ämaui的繁殖习性，资料甚少。","identification":"夏威夷孤鸫可通过其灰褐色头部、橄榄褐色上体和淡灰色下体来识别，与其他同属物种如小考岛孤鸫（具有白色眼环和粉色腿）区别明显。","protection":"IUCN：NT（近危）","distribution":"夏威夷孤鸫主要分布在夏威夷岛的东部，居住于海拔3000英尺以上的密集原生森林中，偶尔出现在高山灌木地带。","other":"夏威夷孤鸫面临着栖息地破坏、外来捕食者和疾病的影响，导致其分布范围大幅缩减，保护措施包括栖息地保护、控制捕食者和繁殖计划。"},{"name":"考岛孤鸫","english_name":"Kamao","scientific_name":"Myadestes myadestinus","overview":"考岛孤鸫（英文名：Kamao，学名：Myadestes myadestinus），是雀形目鸫科孤鸫属的鸟类。以灰褐色和橄榄棕色的朴素羽毛著称。这种鸟主要分布于夏威夷可爱岛的山区雨林，曾广泛存在于中湿森林，但现在因生境破坏和外来威胁导致其分布范围大幅缩减。","appearance":"成年考岛孤鸫体长约为18厘米，体重约50克，上部羽毛呈暗灰色至棕色，胸部和两胁颜色较浅。头部前额灰色，无眼环。喙和腿为深色，喙短而宽，基部有刚毛。性别在羽毛颜色上相似。幼鸟上部羽毛更偏棕色，翅膀和尾羽覆羽有明显的鳞片状斑纹，胸羽白色，尖端黑色，覆羽棕色，尖端淡黄色。次年鸟在1月至5月间可通过翼覆羽和三级飞羽上残留的鳞片状斑纹与成鸟区分。","habits":"考岛孤鸫居住在海拔较高的山区雨林，以水果为主食，辅以昆虫等无脊椎动物。它们具有长时间静止不动的习性，但在静止时会频繁地颤动翅膀。由于它们的栖息习性和隐蔽的生活方式，观察者通常通过声音而非视觉发现它们。","breeding":"繁殖活动从1月持续到11月，筑巢高峰期在4月至7月。双亲共同抚育后代，实行社会单配偶制。然而，关于考岛孤鸫具体的繁殖习性的信息非常有限。","identification":"考岛孤鸫与其他夏威夷孤鸫的区别在于腹部和前额更为灰暗。与体型较小的小考岛孤鸫相比，考岛孤鸫有粉色腿脚、更小的体型和较长、更细的喙，以及独特的白眼环和较浅的外尾羽。","protection":"IUCN：EX（绝灭）","distribution":"考岛孤鸫目前仅在夏威夷群岛中的可爱岛（Kaua'i）被发现，主要分布在海拔1000米以上的森林区域。"},{"name":"小考岛鸫","english_name":"Puaiohi","scientific_name":"Myadestes palmeri","appearance":"中等体型（约16.5-17.8厘米长，重37.0-43.0克），橄榄褐色的长腿长身型夏威夷孤鸫。成鸟具有淡色的脸部、灰色胸部和标志性的白色眼环及外侧尾羽。幼鸟胸部呈米白色，有深棕色斑点，背部有明显的淡色斑点。成年后，羽毛转变为统一的橄榄灰棕色。","call":"叫声多样，从简单的颤音到复杂的喘息声，再到尖锐的吱吱声，类似于需要润滑的金属轮子发出的声音。雄鸟全年都会鸣唱，但在繁殖季节来临前会增加频率。","habits":"栖息在海拔1050米以上的森林峡谷，偏好在流溪旁的茂密植被中活动，有时也会出现在附近的山脊。饮食以水果和浆果为主，辅以昆虫和其他无脊椎动物。活动范围受限于Alaka‘i Swamp的偏远地带。","breeding":"繁殖期从3月持续至9月中旬，巢筑于悬崖或树洞中，由雌鸟独自建造，耗时可达一周。每窝产卵通常两枚，蛋壳呈灰绿至蓝绿色，带有红棕色斑点。孵化期大约13-15天。幼鸟离巢后，雄鸟成为主要的食物提供者。","identification":"与考岛孤鸫相比，小考岛孤鸫体型较小，腿部颜色较浅，面部较淡，且拥有明显的白色眼环。幼鸟的胸部斑点比考岛孤鸫更重。与画眉的区别在于后者体型更大，羽毛呈锈褐色，且有黄色喙和腿。","protection":"IUCN：CR（极危）","distribution":"仅分布于太平洋夏威夷群岛中的Kaua‘i岛上，尤其集中于Alaka‘i Wilderness Preserve的中心和南部区域。","other":"1967年被列入美国联邦濒危物种名单，1995年启动了圈养繁殖计划。"},{"name":"拉奈孤鸫","english_name":"Olomao","scientific_name":"Myadestes lanaiensis","overview":"拉奈孤鸫（英文名：Olomao，学名：Myadestes lanaiensis），是雀形目鸫科孤鸫属的鸟类。仅见于毛伊岛、拉奈岛和莫洛凯岛。目前被列为极度濒危物种。","appearance":"这种鸟体长约7英寸，雄鸟和雌鸟外观相似，上部呈深棕色，下部为灰色，腿部黑色。","call":"其鸣声包含复杂旋律，类似长笛音符、流畅的颤音和咕噜声的口哨。叫声则是一种猫样的嘶哑声，另有高音调的哨声，类似警笛。","habits":"它栖息于植被茂密的峡谷中，常在林下层停留，保持蜷缩的姿态。如同其他夏威夷本地鵐类，它以振翅和主要以果实及昆虫为食。","identification":"与夏威夷鵐类的其他物种如小考岛孤鸫、夏威夷孤鸫和可能已灭绝的考岛孤鸫有亲缘关系，但在具体辨识上需进一步研究。","protection":"IUCN：CR (PE)（极危（可能已灭绝））。最后一次确凿的目击记录分别出现在19世纪50年代的瓦胡岛、1933年的拉奈岛以及1980年莫洛凯岛的卡马库保护区。由于土地开垦、城市化发展和由引入的蚊子带来的禽疟疾，以及外来动物如野猪的干扰，导致其数量急剧下降。","distribution":"分布于太平洋的夏威夷群岛，包括毛伊岛、拉奈岛和莫洛凯岛。"},{"name":"坦氏孤鸫","english_name":"Townsend's Solitaire","scientific_name":"Myadestes townsendi","overview":"坦氏孤鸫（英文名：Townsend's Solitaire，学名：Myadestes townsendi），是雀形目鸫科孤鸫属的鸟类。中等体型的鸫科孤鸫属鸟类，广泛分布在北美西部，夏季偏好高海拔山区，冬季则会降至低地，特别偏爱杜松树丛。成鸟羽毛呈均匀的中灰色，具有白色的环眼带和翼上的淡褐色斑块。其鸣声复杂，被誉为最美妙的鸟鸣之一。","appearance":"坦氏孤鸫长约20-22厘米，体重约30-35克，体态修长，喙短而宽，尾较长。成鸟头部、背部、胸部和腹部均为灰色，上身略深于下身，具白色眼环。翼上有暗灰色的主羽，基部带有宽阔的淡褐色条纹；三级飞羽边缘明显为白色。最外侧尾羽的外缘和内缘远端一半为白色，内侧尾羽尖端有变化的白色部分。幼鸟的轮廓羽毛有黑色、淡褐色和白色的重斑点，上身和下身均有，翼和尾与成鸟相似。","call":"坦氏孤鸫的鸣唱复杂，由响亮、旋律优美的笛音组成，包含上升和下降的乐句，间杂低沉、沙哑的音符，但没有明显的模式，带有一种略显机械的质感。叫声为尖锐的'eeek'声或清晰柔和的哨声'heeh'。","habits":"坦氏孤鸫夏季栖息于各种高山针叶林，秋季迁至较低海拔，冬季在杜松树丛或提供丰富果实的其他生境中度过。它们通常仅作短距离的垂直迁移，北部种群会向南迁徙更远的距离。以杜松果为主食，也捕食昆虫。","breeding":"繁殖季节，雄鸟会在树冠顶端显著地歌唱，然后进入森林下层与伴侣安静地觅食。筑巢于地面岩石、倒木或其他遮蔽物下，巢穴位于暴露的泥土斜坡沿路边，便于发现。繁殖期早期开始，能多次重新筑巢。巢穴易受捕食者的威胁，是影响繁殖成功率的主要因素。","identification":"坦氏孤鸫在墨西哥与褐背孤鸫区别在于上体和飞羽为灰色，无棕色或红褐色色调。","protection":"IUCN：LC（无危）","distribution":"繁殖区域：从加拿大西部至美国西部直至墨西哥中部。非繁殖区域：扩展至大平原，墨西哥内陆北部，甚至沙漠绿洲。","other":"坦氏孤鸫在迁徙期间的行为研究不足。"},{"name":"褐背孤鸫","english_name":"Brown-backed Solitaire","scientific_name":"Myadestes occidentalis","overview":"褐背孤鸫（英文名：Brown-backed Solitaire，学名：Myadestes occidentalis），是雀形目鸫科孤鸫属的中型鸟类。长约21厘米（8英寸）。以其独特的褐色背部和灰白色的眼圈而著称，常见于墨西哥西北部至洪都拉斯的山地森林。","appearance":"褐背孤鸫体长20.5-21.5厘米，体重38-44克。头部呈暗灰色，逐渐过渡到橄榄红褐色的臀部和尾羽基部，肩部和翼缘呈现更丰富的锈棕色。尾羽外侧具白色尖端，胸部为暗淡的灰色，向下渐变为较浅的灰色。嘴黑色，腿灰粉色。雌雄相似，幼鸟体羽边缘呈棕白色，形成斑点或鳞片状效果。不同亚种间存在轻微的颜色差异。","call":"褐背孤鸫的鸣唱是一个加速下降的音符高潮，常被形容为笛子或钟声般的甜美声音。此外，它还发出刺耳的金属声叫声和鼻音的嘶哑警报声。","habits":"栖息于墨西哥和中美洲北部的半落叶山林，包括混合松栎树林，通常靠近溪流。以水果为食，也捕食昆虫。其生活习性与其它同类物种相似，包括栖息、迁徙和飞行特点。","breeding":"繁殖季节从2月持续到7月，可能延伸至9月。巢为杯状，由苔藓或松针构成，内部衬以松针或树苔，位于地面附近或斜坡上的凹处，隐藏在暴露的树根后或森林中的树苗或巨石底部。每窝产2-3枚蛋，蛋壳呈褐色至奶油色，带有深红褐色条纹和斑点。孵化期未知，雏鸟期约17天。","identification":"与其他孤鸫属鸟类相比，褐背孤鸫具有明显的褐色背部和白色眼圈，以及特有的鸣唱。不同亚种之间在背部和喉部的颜色上有所差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥西北部至洪都拉斯的繁殖区域。在美国鸟类观察协会区域，仅有一例记录在亚利桑那州东南部的Huachuca山脉。"},{"name":"古巴孤鸫","english_name":"Cuban Solitaire","scientific_name":"Myadestes elisabeth","overview":"古巴孤鸫（英文名：Cuban Solitaire，学名：Myadestes elisabeth），是雀形目鸫科孤鸫属的鸟类。又被称为古巴夜莺，是鸫科孤鸫属的一种特有鸟类，仅分布于古巴。以独特的外观著称，拥有柔和的灰色下体与棕色上体，以及鲜明的眼环和黑色颊须，白色尾羽外缘显著。","appearance":"古巴孤鸫体长19至20.5厘米，体重21.5至33克。头部和背部橄榄棕色，三级飞羽呈温暖的棕色，次级飞羽基部和初级飞羽边缘亦为棕色。下体从下巴到腹部为淡灰白色，胸部略显灰色。嘴上颚黑色，下颚角质色，尖端暗色；腿为黄褐色。雌雄相似，幼鸟上部斑驳有纹，胸侧有棕色斑点。","call":"其鸣声嘹亮、清脆、笛声般悦耳且富有旋律感，声音回荡且传播远，类似湿润手指摩擦精致瓷器杯边的声音，与棕喉孤鸫的鸣声相似。叫声为短促的哨音。","habits":"栖息于湿润的山地森林，主要在树冠层活动，似乎依赖石灰岩峭壁筑巢。常见于海拔较高的湿润林地和松树林。","breeding":"具体繁殖信息未详述，但其分布局限，仅在特定山脉发现，暗示繁殖习性可能与特定环境条件紧密相关。","identification":"与其他鸟类的区别在于独特的面部图案和白色尾羽外缘，尤其是与捕蝇鸟的区分，尽管它们有静坐捕食昆虫的行为，但没有任何捕蝇鸟具有类似的特征。","protection":"IUCN：NT（近危）。受限制范围物种，分布于古巴EBA。在西古巴仅限于Sierra de los Órganos、Sierra del Rosario和Sierra de la Güira山区，在东古巴则分布在Sierra Maestra、Sierra del Magüey、Sierra de Moa、Toa和Baracoa。敏感于栖息地改变，面临持续的栖地丧失威胁。","distribution":"仅分布于古巴，包括西古巴的Sierra de los Órganos、Sierra del Rosario和Sierra de la Güira，以及东古巴的Sierra Maestra、Sierra del Magüey、Sierra de Moa、Toa和Baracoa。"},{"name":"棕喉孤鸫","english_name":"Rufous-throated Solitaire","scientific_name":"Myadestes genibarbis","overview":"棕喉孤鸫（英文名：Rufous-throated Solitaire，学名：Myadestes genibarbis），是雀形目鸫科孤鸫属的鸟类。独特的中型鸟类，以砖红色喉咙和下腹部，以及铅灰色羽毛著称。常居住在湿润的山区森林，分布于牙买加、海地岛，以及多米尼加、马提尼克、圣卢西亚和圣文森特等小安的列斯群岛。","appearance":"棕喉孤鸫体长约19至20.5厘米，体重24至30克。成鸟具有一条白色新月状斑纹位于眼下方，橙色点缀的脸部，白色的下巴和白色基部的髭纹。上体呈板岩灰色，黑色初级飞羽盖羽和次级飞羽基部，内侧初级飞羽有小白点，形成小型白翼斑。尾部外侧羽毛为白色，胸部为栗色，腹部及两胁为赭黄色。喙黑色，腿黄色。雄雌相似。幼鸟上体暗色，有明显的橙色斑点和条纹，下体橙色和板岩色交错，臀部和尾下覆羽为纯橙色。","call":"鸣唱为一系列拉长的、单调的笛声，音调各异，有时会发出‘twuit, toi, tu-tu-tu-tu’的声音。叫声包括类似远处汽车喇叭的单长‘toot’。","habits":"主要栖息于亚热带或热带湿润低地森林及山地森林。严格树栖，食物包括果实和昆虫，如美洲毒莓和苦木果。喂食时常在空中突袭，摘取果实，捕捉昆虫。","identification":"与其他孤鸫属物种相比，棕喉孤鸫具有独特的砖红色喉咙和下腹部，以及其特有的鸣叫声。","protection":"IUCN：LC（无危）","distribution":"分布于牙买加和海地岛，以及多米尼加、马提尼克、圣卢西亚和圣文森特等小安的列斯群岛。"},{"name":"黑脸孤鸫","english_name":"Black-faced Solitaire","scientific_name":"Myadestes melanops","overview":"黑脸孤鸫（英文名：Black-faced Solitaire，学名：Myadestes melanops），是雀形目鸫科孤鸫属的鸟类。以其美丽的歌喉著称。其最显著的外部特征是灰蓝色的身体与黑色面部形成鲜明对比，橙色的喙和腿为其增添了几分独特魅力。分布于中美洲的哥斯达黎加和巴拿马高海拔森林地带。","appearance":"黑脸孤鸫拥有流线型的中等体型，成鸟全身呈现灰蓝色，脸部与下巴为深黑色，翅膀与尾巴边缘呈灰色，翼下覆羽银白色，飞行时尤为明显。橙色的腿和喙使其在外形上更加突出。幼鸟头部与背部有淡褐色条纹，下体有淡褐色与棕色斑点。平均长度16-18.5厘米，体重约33克。","call":"其鸣唱如同长笛般清澈飘渺，常在傍晚时分从阴暗的树冠中发出，声音美妙而空灵。","habits":"栖息于潮湿的山地森林中，高度范围750至3000米。在雨季，会下降到400米左右的低地，此时可能形成松散的群落。以浆果和昆虫为主要食物来源，觅食活动通常在植被较低的位置进行。","breeding":"繁殖期在4月至6月间，雌鸟在树洞、苔藓覆盖的裂缝或树叉间的隐蔽处筑杯状巢，由苔藓和肝叶构成。每次产卵2至3枚，卵壳呈白色或粉红色，带有红褐色斑点。孵化期大约15至16天。","identification":"在哥斯达黎加和巴拿马西部范围内，黑脸孤鸫是唯一一种具有黑色面部和橙色喙的Myadestes属鸟类，与之相似的多色孤鸫和安第斯孤鸫分布区不同，且后两者背部和翅膀颜色不同，易于区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于哥斯达黎加和巴拿马的山地森林，海拔750至3000米。雨季时，会迁移到海拔最低可达100米的低地。","other":"在受保护和难以触及的区域，黑脸孤鸫数量稳定，但在其他地区，由于笼鸟贸易和森林砍伐，其数量受到严重影响。"},{"name":"多色孤鸫","english_name":"Varied Solitaire","scientific_name":"Myadestes coloratus","overview":"多色孤鸫（英文名：Varied Solitaire，学名：Myadestes coloratus），是雀形目鸫科孤鸫属的鸟类。中型的鸫类。其分布区域极为有限，仅见于巴拿马与哥伦比亚边境的云雾森林。","appearance":"这种鸟拥有独特的灰头灰下体，面部黑色，背部棕色，橙色的喙和腿脚。雌雄外观相似，没有显著的性别差异。","call":"它更常被听到而非看到，其鸣唱如同长笛般清脆，由不同音高的响亮音符组成。","habits":"栖息于海拔约900至1500米的云雾森林，最可能在挂满果实的树旁被发现。偏好湿润的亚热带或热带山地森林。","identification":"在所处的地理范围内，其独特的外观使其难以与其他物种混淆。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲的巴拿马南部（从Serranía de Majé开始）和相邻的哥伦比亚西北部。"},{"name":"安第斯孤鸫","english_name":"Andean Solitaire","scientific_name":"Myadestes ralloides","overview":"安第斯孤鸫（英文名：Andean Solitaire，学名：Myadestes ralloides），是雀形目鸫科孤鸫属的鸟类。广泛分布于南美洲，从委内瑞拉北部至玻利维亚西部，栖息于安第斯山脉的云雾森林中，海拔高度介于1,000至2,500米之间。","appearance":"这是一种体型较小的鸫科鸟类，外观较为普通，上部羽毛呈红褐色，下部羽毛为灰色，缺乏醒目的特征标记。雄鸟和雌鸟的外观相似，很难通过羽毛颜色或大小来区分。它们通常会在一个位置长时间停留不动。","call":"尽管外表不起眼，安第斯孤鸫却拥有美妙的歌声。其鸣唱由一系列悠长、轻松的笛音组成，声音空灵，犹如天籁之音，往往在长时间的悠闲序列中展现出来。","habits":"安第斯孤鸫在声音上通常相当常见，但在视觉上却难以观察到，它们偏好隐蔽的生活方式，常常长时间停留在同一个位置。它们最常被发现于果实丰富的树木附近，可能在此处觅食。","identification":"在同属物种中，安第斯孤鸫的辨识主要依赖于其独特的叫声以及所处的特定生境——安第斯山脉的云雾森林。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，范围覆盖委内瑞拉北部至玻利维亚西部，包括哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。"},{"name":"灰孤鸫","english_name":"Slate-colored Solitaire","scientific_name":"Myadestes unicolor","overview":"灰孤鸫（英文名：Slate-colored Solitaire，学名：Myadestes unicolor），是雀形目鸫科孤鸫属的鸟类。以其幽灵般的笛音鸣唱闻名。广泛分布于中美洲，从墨西哥南部直至尼加拉瓜，尤其活跃在云雾缭绕的山地森林中，是当地生态环境的重要组成部分。在墨西哥，灰孤鸫在某些天主教仪式中扮演着特殊角色。","appearance":"灰孤鸫体长约19至20.5厘米，体重介于30至44克之间。全身羽毛呈深灰色，上体颜色略深，下体稍浅。初级飞羽覆盖羽呈现黑色，而飞羽边缘泛着淡褐色，尾羽外侧为灰白色。眼睛周围有一圈断续的白色眼环。喙部颜色较深，腿脚呈黄绿色。雌雄两性的外观相似，而幼鸟则具有暗色斑点，上体边缘黑色，下体羽毛中央呈淡白色，形成鳞状外观。","call":"灰孤鸫的鸣唱空灵而迷人，是其栖息地云雾森林中的标志性声音。它的歌声通常以几个犹豫的音符开始，随后发展成一系列清晰或颤动的笛音，精心演绎，旋律优美，常常包含或以松散的颤音结束。","habits":"灰孤鸫偏好独自活动，常安静地站立于低至高处的森林枝头，姿态较为挺拔。它们偶尔会与其他物种一同聚集在结果树旁。主要栖息于亚热带或热带湿润的山地森林。","identification":"灰孤鸫与褐背孤鸫相比，其白色眼环更为明显，后者更多见于松树和橡树林。此外，灰孤鸫的羽毛色泽更接近深灰色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，范围自墨西哥东南部（包括圣路易斯波托西和伊达尔戈州）南至危地马拉、伯利兹西部、洪都拉斯、萨尔瓦多北部及尼加拉瓜西北部。"},{"name":"棕褐孤鸫","english_name":"Rufous-brown Solitaire","scientific_name":"Cichlopsis leucogenys","overview":"棕褐孤鸫（英文名：Rufous-brown Solitaire，学名：Cichlopsis leucogenys），是雀形目鸫科棕褐孤鸫属的特色孤鸫，分布于南美的广泛分散地点，包括巴西、哥伦比亚、厄瓜多尔、圭亚那、秘鲁、苏里南和委内瑞拉。其羽毛呈现温暖的棕色，腹部颜色较浅。","appearance":"成鸟上身呈锈褐色，头部至背部色泽更浓郁，臀部转为栗色，下巴和喉咙为扩散的丰富栗色，胸部上方为橄榄锈色，下方为橄榄色，腹部温暖的锈色，肛门区为狐狸般的淡橙色，翅膀下覆羽橙色至淡黄色。喙和腿为暗黄褐色，眼圈窄而淡黄。雄鸟和雌鸟相似，幼鸟上部有淡黄色条纹，翼覆羽有淡黄色斑点。","call":"发出一系列沙哑和颤音的音符，高低音交替，如“t’l’deuu … tl’dii … tl’deuueee … tliwoodii, tsss-tsss … tliiidii-i …”。歌声复杂且旋律性强，与安第斯孤鸫相比，音调更少笛声。","habits":"主要以果实为食，偶尔可能摄入一些无脊椎动物。它在静止栖息后会积极觅食于果木和灌木，特别是在森林边缘的Melastomataceae植物，尤其当有混种群时更为明显。","identification":"通过其温暖的棕色羽毛、黄色的眼圈和下喙部分的黄色，以及可能在头部、翅膀和喉咙上的淡黄色或肉桂色调来识别。与安第斯孤鸫和其他同属物种相比，其歌声和外观有所不同。","protection":"IUCN：NT（近危）","distribution":"分布于南美洲西部、北部和东南部的云雾森林，包括巴西、哥伦比亚、厄瓜多尔、圭亚那、秘鲁、苏里南和委内瑞拉的特定区域。"},{"name":"黑嘴夜鸫","english_name":"Black-billed Nightingale-Thrush","scientific_name":"Catharus gracilirostris","overview":"黑嘴夜鸫（英文名：Black-billed Nightingale-Thrush，学名：Catharus gracilirostris），是雀形目鸫科夜鸫属的小型鸟类。其最显著的外部特征是全灰色的身体，背部略带棕色，黑色的喙和腿。分布于中美洲高海拔地区，常见于哥斯达黎加中部至巴拿马西部的湿山地森林。","appearance":"体型紧凑，短而圆的翅膀，长瘦的腿。上部包括翅膀和尾羽上表面呈橄榄棕色，脸和前额为石板灰，胸部和腹部主要为灰色，喉部白色，腹部中央有灰白色区域。胸带橄榄色，中心较淡。幼鸟颜色较暗，头部和下体更暗淡。","call":"鸣唱由简单的笛声组成，常重复播放。","habits":"栖息于低矮植被或森林地面，偏好湿山地森林和人类干扰环境。以昆虫、蜘蛛和小果实为食，以典型的鸫类方式翻动落叶寻找食物。","breeding":"巢建于灌木或小树1至5米高的位置，通常产2枚绿蓝色带褐色斑点的蛋。","identification":"与红顶夜鸫相比，黑嘴夜鸫体型较小，颜色更深，具有完全黑色的喙，脸部和头顶为深灰色，下体有橄榄色胸带。","protection":"IUCN状态未提供。","distribution":"繁殖于中美洲，具体为哥斯达黎加中部至巴拿马西部的湿山地森林和高海拔地区。"},{"name":"橙腹夜鸫","english_name":"Orange-billed Nightingale-Thrush","scientific_name":"Catharus aurantiirostris","overview":"橙腹夜鸫（英文名：Orange-billed Nightingale-Thrush，学名：Catharus aurantiirostris），是雀形目鸫科夜鸫属的中型鸟类。主要分布于中美洲和南美洲，从墨西哥西北部至哥伦比亚北部和委内瑞拉中部。其最显著的特征是拥有明亮的橙色喙、眼环和腿脚。","appearance":"体长约14厘米，北方种群背部和头顶呈褐色，胸腹部白色，南方种群则具有灰色的头冠和较暗的胸部及两侧。幼鸟上体棕色，具模糊的斑点，颈部、胸部和两侧有斑驳的花纹，喉部和腹部白色。性别相似，但存在亚种间的颜色差异。","call":"鸣声全年可闻，由隐蔽处发出一系列短促、杂乱且尖锐的音节，包含吱吱声、颤音和颤鸣，每组音节重复多次，声音略显生硬和刺耳，不同于同类的音乐性叫声。","habits":"栖息于多种森林类型，包括干旱的荆棘林、次生林、森林边缘、轻型林地、路边植被、灌木斜坡和峡谷、种植园、安静的灌木花园和湿润松栎林的溪流旁。以昆虫、蜘蛛、蠕虫和其他无脊椎动物为食，也吃水果和种子，常在地面或附近觅食，有时会进入小空地或攀至中层树冠摘食浆果。","breeding":"繁殖季节从4月末到9月在墨西哥，3月至8月在哥斯达黎加，3月至7月及11月在哥伦比亚，5月在特立尼达岛。巢为厚壁杯状，由绿色苔藓、根须和干草构成，内部衬有细嫩的藤蔓、根须、草茎或花序，置于灌木、密丛、咖啡树、玉米植株、果树或树篱中，距地面0.1至3米高。每窝产卵2至3枚，卵壳颜色多样，孵化期13至15天，雏鸟期13至17天。","identification":"通过其独特的橙色喙、眼环和腿脚以及较暗的叫声来区分于其他近似物种。","protection":"IUCN：LC（无危）","distribution":"广泛分布于中美洲和南美洲，包括墨西哥、哥斯达黎加、哥伦比亚、委内瑞拉等地，从西北墨西哥至北哥伦比亚和中委内瑞拉。"},{"name":"灰背夜鸫","english_name":"Slaty-backed Nightingale-Thrush","scientific_name":"Catharus fuscater","overview":"灰背夜鸫（英文名：Slaty-backed Nightingale-Thrush，学名：Catharus fuscater），是雀形目鸫科夜鸫属的鸟类。小型、隐秘的鸫科夜鸫属鸟类，分布于中美洲至南美洲中部，包括哥斯达黎加至玻利维亚北部。其显著特征为深灰色的背部与头部，腹部为较浅的灰色，而明亮的橙色腿、喙和眼环则形成鲜明对比。虹膜呈淡色，这在同类中较为独特。","appearance":"灰背夜鸫的体型约为17厘米，整体外观为暗灰色，背部颜色最深，额头部分尤甚。喉部和腹部呈中灰色，腹部中央可能带有少许白色，有时会略带黄色调。雌雄外观相似，但有关两性背部色彩强度差异的报道存在，具体差异可能因种群而异，需进一步研究确认。幼鸟的颜色则更为丰富，冠羽为灰黑色，颈后为天然棕色，背部、臀部、肩羽和翼覆羽介于天然棕色和骨棕色之间，翅膀和尾巴为灰黑色。","call":"灰背夜鸫的鸣唱由简单的笛音组成，往往重复播放。","habits":"灰背夜鸫栖息于海拔较高的湿润森林中，偏好靠近地面活动，常沿小径现身但通常十分害羞。它们更常被听到而非见到，倾向于在浓密的林下灌木丛中活动。","identification":"在中美洲，灰背夜鸫的特征明显，不太可能与其他物种混淆。在南美洲，它可能与淡眼鸫、斑夜鸫和黑头夜鸫混淆，但可通过下体的斑点、暗褐色背部以及虹膜颜色加以区分。","protection":"IUCN：LC(无危)","distribution":"灰背夜鸫的分布区域覆盖了中美洲的哥斯达黎加至南美洲的北部玻利维亚，包括哥伦比亚、厄瓜多尔、巴拿马、秘鲁和委内瑞拉。","other":"关于灰背夜鸫的羽毛更换、裸露部位颜色以及测量数据等方面的详细信息，请参阅原始文献。"},{"name":"茶色夜鸫","english_name":"Russet Nightingale-Thrush","scientific_name":"Catharus occidentalis","overview":"茶色夜鸫（英文名：Russet Nightingale-Thrush，学名：Catharus occidentalis），是雀形目鸫科夜鸫属的鸟类。上体呈温暖的赤褐色，下体为淡灰色，带有模糊的斑点。该物种在高海拔的松林和橡树林中活动，特别是在早晨和傍晚，沿安静的道路和小径跳跃。与橙喙夜鸫和红帽夜鸫相似，但可通过其独特的叫声和翼下的黄色条纹加以区分。","appearance":"茶色夜鸫体型较小，上体颜色多为红褐色或橄榄褐色，具体取决于亚种。下体为淡灰色，喉部颜色较淡，胸部有隐约的斑点或条纹。翅膀展开时可见基部为浅黄色的飞羽，形成鲜明的翼下条纹。喙上部为暗褐色，下部为肉色，尖端深色。","call":"其叫声独特，由一系列薄而清脆的重复短语组成。","habits":"栖息于半干旱的松-橡树森林，通常在较为开阔的林下层活动。活动范围在海拔1500至3500米之间，主要在地面觅食，偶尔访问开阔地带，尤其是在黎明和黄昏。","breeding":"关于繁殖期、求偶、营巢、交配、产卵、孵化和育雏的信息未提及。","identification":"与红帽夜鸫和橙喙夜鸫极为相似，但红帽夜鸫的下喙无深色尖端，下体颜色更暗，无翼下黄色条纹；橙喙夜鸫具有明亮的橙色喙和眼圈，以及黄色的跗蹠和脚趾。","protection":"IUCN：LC (无危)","distribution":"主要分布在中美洲的墨西哥，包括繁殖区域和非繁殖区域，常见于海拔1500至3500米的半干旱松-橡树森林。","other":"之前曾被认为与红顶夜鸫同种，但现在认为它们在重叠分布区并无杂交现象。"},{"name":"红顶夜鸫","english_name":"Ruddy-capped Nightingale-Thrush","scientific_name":"Catharus frantzii","overview":"红顶夜鸫（英文名：Ruddy-capped Nightingale-Thrush，学名：Catharus frantzii），是雀形目鸫科夜鸫属的小型鸟类。广泛分布于中美洲高山森林，包括墨西哥南部至巴拿马西部的太平洋和加勒比海两侧。其栖息地主要在海拔1500至3500米的常绿和针叶林下层。红顶夜鸫以棕色上身和灰白色下身为显著特征，冠部呈深红褐色，是最为醒目的羽毛部分。观察最佳时机是在清晨或傍晚，通过播放鸣叫或在森林小径缓慢安静行走。","appearance":"红顶夜鸫体型小巧，具典型的鸫科鸟类结构。上体为中等棕色，下体灰至近白色，冠部呈温暖的红褐色。成鸟两性相似，腹部可能更白。幼鸟与成鸟相似，但嘴下端呈暗色，头部和背部颜色较暗，面部较成鸟更暗，胸腹部位带有暗色斑点。","call":"红顶夜鸫的鸣唱是一系列优美丰富而变化多端的哨音，其叫声为高而细的‘seet’或‘whooeet’。","habits":"红顶夜鸫主要在地面觅食，也会在结果的灌木和树木中寻找食物。它们栖息在湿润的山地橡树和针叶林下层，活动范围广泛，常单独或成对出现，翻动落叶寻找昆虫和蜘蛛，也食用小果实。","breeding":"红顶夜鸫的巢建于密集的下层植被或灌丛中，高度在1至4米之间，通常靠近水源。每窝产两枚带有褐色斑点的灰绿色或蓝绿色蛋，仅由雌鸟孵化约15至16天，孵化后双亲共同喂养幼鸟约14至16天至离巢。","identification":"红顶夜鸫与非常相似的茶色夜鸫相比，整体颜色略深，下喙全为浅橙色，胸部更平滑。其歌声也更富韵律，比茶色夜鸫更为丰富。此外，需与橙腹夜鸫相区别，后者具有鲜橙色的喙和眼环。","protection":"IUCN：LC（无危）","distribution":"红顶夜鸫的分布范围涵盖了中美洲的高山地带，从墨西哥南部直至巴拿马西部，跨越太平洋和加勒比海两侧。主要栖息于海拔1350至3500米的湿润山地森林中。"},{"name":"黑头夜鸫","english_name":"Black-headed Nightingale-Thrush","scientific_name":"Catharus mexicanus","overview":"黑头夜鸫（英文名：Black-headed Nightingale-Thrush，学名：Catharus mexicanus），是雀形目鸫科夜鸫属的鸟类。从墨西哥中东部至巴拿马的热带和亚热带常绿森林中。","appearance":"这种体型较小的夜鸫具有朴素的胸部羽毛，头顶呈黑色，上体暗淡，与橙色的眼环和喙形成鲜明对比，使其外观独特。地面觅食为主，偶尔在结果的灌木和树木中活动。","call":"其鸣唱略带沙哑，不甚悠扬，具有辨识度。","habits":"栖息于山地和丘陵地带的常绿森林，偏好湿润环境。通常较为隐秘，听到其声音远比见到它更为常见。活动范围广泛，从低层到中层树冠均有其身影。","breeding":"具体繁殖细节尚需更多研究，但已知会在适宜的季节进行繁殖，可能在地面或低矮植被中筑巢。","identification":"在昏暗的林下环境中，可能会与橙嘴夜鸫混淆，后者上体呈锈褐色。通过观察上体颜色和听其独特的鸣声可进行区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括中美洲，自墨西哥中东部至巴拿马，覆盖了广泛的山地和丘陵地带。","other":"当与红帽夜鸫相遇时，黑头夜鸫表现出较强的领地意识。"},{"name":"斑夜鸫","english_name":"Yellow-throated Nightingale-Thrush","scientific_name":"Catharus dryas","overview":"斑夜鸫（英文名：Yellow-throated Nightingale-Thrush，学名：Catharus dryas），是雀形目鸫科夜鸫属的鸟类。以及带有暗色斑点的黄色下体，使其成为夜鸫属中显著的成员。分布在中美洲，从墨西哥南部至尼加拉瓜西北部。","appearance":"体长约17-19厘米，体重36-44克。雄鸟具鲜明的黑头，橄榄灰色背部，下喉至腹部为橄榄斑点的杏黄色，翼侧灰白，腹下至尾部白色；雌鸟相似，但头部较灰，背部更绿，嘴顶较暗。不同亚种在背部颜色和下体斑纹上有所差异。","call":"鸣唱独特，一系列短促、变化多端的乐句，每句包含2-3个丰富、清澈（偶尔粗犷）的音符，速度略快，音调低沉。常伴有响亮的喙击声。","habits":"常见于地面觅食，偶尔在森林小径上黄昏时分活动。有时会跟随行军蚁群。栖息于热带和亚热带湿润山地森林。","breeding":"寿命约4.2年，非迁徙物种。雌鸟用苔藓、青苔和树叶筑巢，以树根和草固定，形成深而坚固的巢。","identification":"与斯克氏夜鸫相似，但分布范围不重叠。不同亚种间在颜色和斑纹上有细微差别。","protection":"IUCN：LC（无危）。在某些地区较为罕见。","distribution":"分布于中美洲，从墨西哥南部至尼加拉瓜西北部，零星分布于委内瑞拉，哥伦比亚的Cueva de los Guácharos国家公园有记录，厄瓜多尔西部安第斯山脉比东部更为普遍。","other":"历史上，Sclater's夜鸫曾被归为的亚种，后研究确认其为独立物种Spotted Nightingale-Thrush。"},{"name":"斯克氏夜鸫","english_name":"Speckled Nightingale-Thrush","scientific_name":"Catharus maculatus","overview":"斯克氏夜鸫（英文名：Speckled Nightingale-Thrush，学名：Catharus maculatus），是雀形目鸫科夜鸫属的鸟类。特征鲜明，拥有黑色头部、橙色眼环、喙和腿，以及带有暗斑的黄色下体。分布于南美洲，从哥伦比亚东部至阿根廷北部。","appearance":"体长17至19厘米，体重36至44克。雄鸟具有黑色头部，橄榄灰上体，下巴和喉部为淡黄色，从喉咙下方到腹部为橄榄斑点的杏黄色，灰色侧腹，白色下腹至肛门。眼环、喙和腿为橙色。雌鸟相似，但头部黑色偏灰，背部更绿，喙顶较暗。不同亚种在背部颜色、翅膀灰色程度和下体斑点上有差异。","call":"鸣唱独特，一系列短而多变的乐句，每句由2至3个丰富、清澈的音符组成，有时类似‘tru-lii? chii-lolíí trolowi chii-trelelíí trolowii’，比灰背夜鸫的鸣唱略快、低沉和粗糙，常让人联想到棕林鸫的鸣声；经常发出响亮的喙击声。","habits":"常见于地面叶堆中觅食，偶尔在黄昏时分出现在森林小径上。有时会跟随军队蚁群觅食。栖息于热带和亚热带常绿山地森林。","breeding":"关于繁殖的信息未提供。","identification":"与斑夜鸫相似，但二者分布范围无重叠。","protection":"IUCN：LC（无危）。","distribution":"分布于南美安第斯山脉两侧，从委内瑞拉西部到阿根廷北部，包括哥伦比亚东部至阿根廷北部。在厄瓜多尔，西坡的分布比东坡更为广泛。","other":"2017年，基于线粒体DNA分析、形态测量和声音数据，以及生态位建模，确定斯克氏夜鸫应视为独立物种，而非Spotted Nightingale-Thrush的亚种。"},{"name":"棕夜鸫","english_name":"Veery","scientific_name":"Catharus fuscescens","overview":"棕夜鸫（英文名：Veery，学名：Catharus fuscescens），是雀形目鸫科夜鸫属的鸟类。以其优美、螺旋下降的笛音般的歌声闻名。羽毛呈温暖的红褐色，胸部淡黄色，腹部白色，斑点模糊且集中于上胸。该物种广泛分布于北美，偏好湿润的林地生境，冬季迁徙至南美和中美洲。","appearance":"棕夜鸫长约17-18厘米，体重约30克。背部、尾巴和翅膀均匀红褐色，喉部和胸部淡黄色，胸部仅有隐约可见的红褐色斑点。腹部白色，两胁浅灰色。眼圈淡色，脚趾和胫骨后部颜色苍白。性别外观一致，但可通过翼展和尾长在同龄群体中区分。","call":"拥有独特的向下螺旋式笛音歌曲，通常在黄昏和黎明时分吟唱。常见的叫声为粗糙的下行‘veerr’声。","habits":"栖息于北美的湿润落叶林中，偏好靠近水源的浓密植被。以昆虫为主食，晚夏和秋季则以水果和浆果为食。迁徙时会经过墨西哥湾和加勒比海。","breeding":"在早熟的湿润森林中筑巢，靠近溪流或沼泽。巢由三层结构组成，外层为树叶和支撑枝条，内层编织材料，内衬柔软物质。每窝产3-5枚绿色蓝底可能带棕色斑点的蛋，孵化期10-14天。雏鸟孵化后10-12天即可离巢。","identification":"与同属的灰颊夜鸫、比氏夜鸫、斯氏夜鸫和隐夜鸫相比，东部个体上体更呈肉桂色，西部个体上体橄榄棕色更深，喉侧条纹较暗。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大南部和美国北部的湿润落叶林。非繁殖季节迁徙至中美和南美，包括亚马逊盆地。","other":"已记录到被褐头牛鹂寄生的案例，以及棕林鸫为棕夜鸫雏鸟提供亲代照顾的情况。"},{"name":"灰颊夜鸫","english_name":"Grey-cheeked Thrush","scientific_name":"Catharus minimus","appearance":"灰颊夜鸫体型中等，长约15-17厘米，重约26-30克，比其他Catharus属的鸫略大。上体呈灰褐色，下面色偏灰，尤其在两胁处颜色更深。脸部灰色，眼周有淡色环，但不如其他种类明显。喙基部下方有一亮黄色区域，尤其是纽芬兰亚种(C. m. minimus)更为显著。两种亚种之间存在细微差异，北方亚种(C. m. aliciae)背部和两胁更显橄榄灰，而纽芬兰亚种则颜色更偏向橄榄棕。","call":"灰颊夜鸫的鸣唱复杂，由模糊的笛音组成，通常在结束时向下弯曲，与棕夜鸫的螺旋下降式鸣声类似，但音调更高、更细，带鼻音和结巴停顿。其飞行叫声高亢、尖锐、鼻音十足，发出\"queer\"的声音。","habits":"灰颊夜鸫是长距离迁徙鸟类，平均迁徙距离可达300公里，冬季在亚马逊盆地度过。它们在春季穿越加勒比海和墨西哥湾。繁殖季节从五月持续到八月，栖息于北美的北部针叶林和阔叶灌木丛，范围从纽芬兰至阿拉斯加，以及西伯利亚东部。偏好低矮的针叶林、再生森林、开阔的老树冠下生长密集的灌木和小针叶树，以及风蚀地带和树线附近的矮小云杉和冷杉。","breeding":"灰颊夜鸫的繁殖行为相对隐秘，巢通常建于地面或低矮的灌木中，高度一般不超过2米。雌鸟用干草和泥土混合搭建巢穴。每年仅繁殖一次，每窝产卵平均4枚，孵化期为13至14天，由雌鸟承担。若巢早期失败，则可能再次筑巢。雏鸟在孵化后11至13天离巢，由双亲共同照顾。个体一年后开始繁殖，预计为一夫一妻制。","identification":"灰颊夜鸫与比氏夜鸫几乎无法通过外观区分，主要依据大小、歌声和分布区域。比氏夜鸫的羽毛可能略带红色，而灰颊夜鸫的羽毛更显灰色。此外，比氏夜鸫的喙基部黄色区域较小。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美北部和西伯利亚东北部，包括纽芬兰至阿拉斯加和西伯利亚东部。非繁殖期迁徙至中美洲和南美洲。","other":"灰颊夜鸫的两个亚种——北方亚种(C. m. aliciae)和纽芬兰亚种(C. m. minimus)，在外观上有细微差别，特别是在背部颜色和喙基部黄色区域的大小上。"},{"name":"比氏夜鸫","english_name":"Bicknell's Thrush","scientific_name":"Catharus bicknelli","overview":"比氏夜鸫（英文名：Bicknell's Thrush，学名：Catharus bicknelli），是雀形目鸫科夜鸫属的鸟类。其繁殖地局限于北美东北部偏远地区的山顶云杉林。体型中等，约17.5厘米长，重约28克，主要分布于加拿大东南部和美国东北部的特定山区。以独特的声音著称，被形容为精致、悠长且略带忧郁。比氏夜鸫的命名来源于美国业余鸟类学家尤金·比克内尔，他在19世纪晚期于纽约州卡茨基尔山脉的斯莱德山首次科学发现了这一物种。","appearance":"比氏夜鸫的平均长度约为17厘米，体重在26至30克之间，雄鸟和雌鸟的外观相似。成鸟的背部颜色为橄榄棕色到棕褐色，与带有栗色色调的尾巴形成对比。胸部为偏白色，带淡黄色调，上面散布着暗色斑点，这些斑点在侧面和下胸部逐渐变得模糊。腿呈淡紫色至紫罗兰色，眼环微弱，脸颊灰色。下颌骨的三分之二为黄色，尖端和上颌骨为黑色。与非常相似的灰颊夜鸫相比，比氏夜鸫平均体型稍小。","call":"比氏夜鸫的鸣唱是一系列混乱的笛声，以较高的音符结束。叫声包括下降的哨声（被称为‘啤酒叫声’），报警情况下的‘咕噜声’以及飞行中的‘尖叫声’。","habits":"比氏夜鸫偏好海拔高且受强风和重冰影响的高山针叶林，通常在915米以上的高度筑巢。它们在迁徙期间更为常见于开阔地带，而繁殖季节则显得极为隐秘。它们主要以昆虫为食，夏季晚期开始摄取野果，迁徙和冬季继续食用。在冬季，它们生活在大安的列斯群岛的阔叶林中，偏好较高海拔。","breeding":"比氏夜鸫的繁殖期涉及复杂的求偶行为，雌鸟可能与多个雄鸟交配，这是一种称为多雄制的繁殖策略。巢由雌鸟单独建造，位于针叶树干附近，靠近水平树枝，离地面约2米。每窝产卵三到四枚，孵化期大约两周，雏鸟在父母双方的喂养下迅速成长，从出生到羽翼丰满只需12天。","identification":"比氏夜鸫与灰颊夜鸫极为相似，但可以通过以下几点辨别：比氏夜鸫的尾巴和翅膀带有栗色色调，上体颜色更暖，下颌骨基部更亮黄，腿色为淡紫至紫罗兰色。叫声和歌曲虽相似，但比氏夜鸫的歌曲结尾音调常保持不变或上升。","protection":"IUCN：VU（易危）","distribution":"繁殖区主要位于加拿大东南部和美国东北部，包括魁北克省东南部、新斯科舍省、新英格兰北部天空岛屿、纽约州的阿迪朗达克山脉和卡茨基尔山脉。非繁殖区集中在大安的列斯群岛，尤其是多米尼加共和国和海地的高地森林。","other":"比氏夜鸫面临的主要威胁包括气候变化导致的栖息地丧失和退化，以及冬季度假地的破坏。"},{"name":"斯氏夜鸫","english_name":"Swainson's Thrush","scientific_name":"Catharus ustulatus","overview":"斯氏夜鸫（英文名：Swainson's Thrush，学名：Catharus ustulatus），是雀形目鸫科夜鸫属的鸟类。中型的鸫科鸟类。以威廉·斯温森的名字命名，他是英国的一位著名鸟类学家。属于Catharus属，以其低调的色彩和美妙的、上升的笛音般的歌声而著称。分布于北美的北部地区，包括加拿大、阿拉斯加和美国北部，以及太平洋沿岸的落叶木林。","appearance":"斯氏夜鸫长约16至20厘米，翼展平均30厘米，翼长8.7至10.5厘米，喙长1.5至1.9厘米，跗跖长2.5至3.1厘米，体重介于23至45克之间。其上体呈棕色，下体白色，两胁带棕色，胸部淡棕色且带有深色斑点。腿粉色，眼圈浅棕色。东部个体上体橄榄棕色，西部个体更偏向红棕色。其翼下有白色-暗色-白色的典型Catharus属模式。","call":"斯氏夜鸫的鸣唱是一系列急促的笛音，音调螺旋式上升。","habits":"栖息于北美北部的针叶林中，偏爱茂密的下层植被。在太平洋沿岸，它们居住在落叶木林中。它们会迁徙到南墨西哥至阿根廷过冬。沿海亚种沿太平洋海岸迁徙，冬季分布在墨西哥至哥斯达黎加，而大陆种群则先向东迁徙再向南，经由佛罗里达到达巴拿马至玻利维亚越冬。","breeding":"它们在森林地面觅食，偶尔也会在树上。主要食物是昆虫、果实和浆果。斯氏夜鸫会在水平树枝上筑杯状巢。","identification":"与隐夜鸫相比，斯氏夜鸫有更明显的黄色眼环和面颊，且上体颜色更为橄榄棕色或红棕色，而非灰棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布于北美，非繁殖期则迁徙至中美和南美。","other":"可能因隐夜鸫的栖息地适应性更强而受到排挤。冬季，斯氏夜鸫倾向于避开人类活动区域。"},{"name":"隐夜鸫","english_name":"Hermit Thrush","scientific_name":"Catharus guttatus","overview":"隐夜鸫（英文名：Hermit Thrush，学名：Catharus guttatus），是雀形目鸫科夜鸫属的鸟类。中等体型的北美鸫科鸟类，以其斑点胸部和红褐色尾巴著称。广泛分布在北美的森林中，从加拿大到墨西哥北部，冬季迁徙至美国南部、墨西哥和危地马拉等地过冬。隐夜鸫是北美最广布的森林繁殖候鸟之一，其种群在过去20年间保持稳定甚至有所增长。","appearance":"隐夜鸫体长15-18厘米，翼展25-30厘米，体重介于18-37克之间。头部和背部主要呈棕色，尾巴具有鲜明的红褐色。腹部白色，胸部带有深色斑点，两胁呈灰色或棕色。腿粉红色，眼周有一圈白色环。东部个体上体更橄榄棕，而西部个体偏灰棕色。","call":"隐夜鸫的歌声被赞誉为自然界中最美妙的声音之一，其歌曲开始于一个长音，随后是几个以小调旋律下降的乐句，重复在不同的音高上，通常从高处的开阔位置发出。","habits":"隐夜鸫在加拿大、阿拉斯加南部和美国东北部及西部的针叶林或混交林中繁殖，筑巢于地面或低树上。冬季迁徙至美国南部、墨西哥和危地马拉。它们在森林地面觅食，主要以昆虫和浆果为食。","breeding":"隐夜鸫在春季繁殖，通常在森林地面或低矮的树上建造杯状巢，以昆虫和浆果为主要食物。","identification":"隐夜鸫与北美其他Catharus属鸟类相比，体形更为紧凑和粗壮，翅膀相对较长，上体颜色和尾巴颜色形成鲜明对比。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美广泛区域，冬季迁徙至美国南部、墨西哥和危地马拉。","other":"隐夜鸫是佛蒙特州的州鸟，文化中常被视为美国声音的象征。"},{"name":"棕林鸫","english_name":"Wood Thrush","scientific_name":"Hylocichla mustelina","overview":"棕林鸫（英文名：Wood Thrush，学名：Hylocichla mustelina），是雀形目鸫科棕林鸫属的唯一物种鸟类。北美特有种。广泛分布在北美洲，冬季迁徙至中美洲和墨西哥南部。以其标志性的斑驳外观和被誉为北美最悦耳的鸣声而闻名。分布区自加拿大东南部至美国中部和东部，近年来数量显著下降。","appearance":"中等体型，长18-21.5厘米，翼展30-40厘米，体重48-72克。上体红褐色，具黑色斑点；下体白色，胸前有明显的黑斑。眼圈白色，腿脚粉红色。幼鸟背部、颈部和翼覆羽有额外的赭色条纹和斑点。雄雌相似，但雄鸟翅膀和尾巴稍长。","call":"拥有被赞誉为北美最美丽的鸣声之一，歌曲由三个部分组成，首部低沉不可闻，中部响亮，尾部似颤音，同时发出两音，赋予其笛声般的空灵质感。","habits":"栖息于东部落叶林和混合森林，偏好有流水、湿润土壤和高下层植被覆盖的环境。夜间迁徙，利用星象和地球磁场定位。以昆虫和果实为食，夏季偏爱连续摄食昆虫以满足代谢需求。","breeding":"春季开始繁殖，一般尝试养育两窝，每窝产2-4枚淡蓝色卵，仅雌鸟孵卵，孵化期11-14天。雏鸟晚成性，双亲共同喂养，幼鸟离巢后仍受父母照料至独立。","identification":"与Catharus属的其他北美鸫相比，体型更大，斑点更醒目。幼鸟背部有额外的斑纹。雄鸟翅膀和尾巴比雌鸟略长。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括美国中部和东部，加拿大东南部。冬季迁徙至中美洲，主要在墨西哥南部至巴拿马的低地热带森林。","other":"因森林破坏和碎片化导致的巢穴掠食和寄生现象增加，影响了繁殖成功率。"},{"name":"黑孤鸫","english_name":"Black Solitaire","scientific_name":"Entomodestes coracinus","overview":"黑孤鸫（英文名：Black Solitaire，学名：Entomodestes coracinus），是雀形目鸫科黑孤鸫属的鸟类。几乎全身漆黑的鸟类，仅头部侧面有一块醒目的白色斑纹。分布于南美洲哥伦比亚和厄瓜多尔的特定地区，栖息于湿润的苔藓山地森林。","appearance":"黑孤鸫体型约23厘米，以独特的直立姿态站立。全身主要呈黑色，但在头部侧面、肩胛部下方和尾羽外缘可见白色。成年鸟具光泽的黑色羽毛，最显眼的是银白色的脸颊，翼下覆羽和腋羽的白色部分在飞行中可见，尾羽外侧下半部分也是白色。虹膜红色，喙上颌深色，下颌橙黄色，跗跖呈暗灰褐色。幼鸟颜色较淡，主要为棕色，缺乏成鸟的腋下白色。","call":"黑孤鸫的叫声为均匀的哨音，带有轻微粗糙的音质，间隔时间较长，简单而有节奏。","habits":"黑孤鸫常单独出现在森林的中上层，偏好非常湿润、苔藓覆盖的云雾林环境。其活动与食物可获得性相关，具体迁徙模式尚不清楚。主要以果实和浆果为食。","breeding":"关于黑孤鸫的繁殖信息知之甚少，由于其栖息地难以接近，许多生活史细节有待进一步研究。","identification":"黑孤鸫在其分布范围内独一无二，与安第斯山地区的其他Solitaire种类如棕褐孤鸫和安第斯孤鸫以及某些Turdus属鸫鸟在外观上有相似之处，但可通过其黑色羽毛和白色特征加以区分。","protection":"IUCN：LC（无危）","distribution":"黑孤鸫主要分布于南美洲的哥伦比亚和厄瓜多尔的湿热山地森林。","other":"尽管分布范围有限，但黑孤鸫的种群被认为相对稳定，目前尚未被列入受威胁物种名单。"},{"name":"白耳孤鸫","english_name":"White-eared Solitaire","scientific_name":"Entomodestes leucotis","overview":"白耳孤鸫（英文名：White-eared Solitaire，学名：Entomodestes leucotis），是雀形目鸫科黑孤鸫属的鸟类，美丽且具有鲜明图案的山地森林鸟。其显著特征为红棕色背部、黑色腹部、黑色头部、宽大的白色髭纹以及珊瑚红色喙。分布于南美洲的秘鲁和玻利维亚的山地森林。","appearance":"体长约22至24厘米，体重约58克。雄鸟具大块白色面颊斑，位于髭纹至耳羽之间，将头部黑色与腹部黑色区分开来；颈背至上尾覆羽和上翼覆羽呈丰富的栗色，翼弯处带白色；飞羽深黑色，尾部深黑色，外侧尾羽末端白色；下翼有宽阔的白色条纹；虹膜颜色可变，从红色到棕色；喙黑色，下颚黄色；腿黑色。雌鸟与雄鸟相似，但头顶较棕，下体带褐色。幼鸟非常相似，但冠部和颈背有淡褐色条纹，腿黄色。","call":"从隐蔽的栖息处发出奇异的、极高音调的、类似鼻音的‘wreeeeeeenh’声，虽弱却传播远，每隔约7至8秒重复一次。","habits":"栖息于湿润的山地森林及其边缘的树冠层。以浆果、其他水果、种子和昆虫为食。有时会形成松散的群体，也会加入混合鸟群。","identification":"白耳孤鸫的识别要点在于其独特的黑白配色和宽大的白色髭纹，以及珊瑚红色喙。","distribution":"分布于南美洲安第斯山脉东坡，从北秘鲁至中央玻利维亚（圣克鲁斯）。"},{"name":"紫宽嘴鸫","english_name":"Purple Cochoa","scientific_name":"Cochoa purpurea","overview":"紫宽嘴鸫（英文名：Purple Cochoa，学名：Cochoa purpurea），是雀形目鸫科宽嘴鸫属的鸟类。俗名: 紫鸫，极为羞怯、行动迟缓的林栖鸟类，羽色独特，不同于典型鸫类。雄鸟通体呈粉灰紫，头顶银蓝，雌鸟则为栗褐色，主要分布于喜马拉雅山脉至越南北部的湿润山地森林，海拔1000–3000米。","appearance":"体长25–28厘米，体重100–106克。雄鸟整体为深灰紫色，头顶银蓝色，面部黑色，飞羽具银灰色双斑与黑色间隔，翼尖黑色，尾羽淡紫灰色，末端具黑色带。雌鸟羽色模式与雄鸟相似，但上体为红褐色，下体橙褐色。幼鸟羽色类似雌鸟，但体羽为巧克力褐色，上体具浅红褐色斑点，下体具深褐色鳞状斑纹。","call":"鸣声为低沉、清晰、悠长的哨音“fwhiiiiiiiiit”，起始略上扬且柔和，随后音调平稳，骤然结束，比绿宽嘴鸫更深更纯。叫声包括低哑的“nyerr”、细薄的“sit”或“srii”，以及轻柔高亢的“pink-pink trrrrrew”。","habits":"栖息于湿润的山地及亚高山森林，偏好沟壑、溪谷等阴湿环境，常见于林下层及中上层。行动迟缓，极少离枝，偶尔参与混合种群活动。主要以浆果、昆虫及软体动物为食，也取食多种植物果实，如Beilschmiedia assamica、Alseodaphne petiolaris、Machilus duthiei及Prunus ceylanica等。","breeding":"繁殖期为5月至7月。巢为浅杯状，筑于距地面2–6米的小树分叉处。每窝产卵2–4枚，卵呈淡海绿色，具亮红褐色斑块，覆于淡紫灰色底斑之上。其余繁殖行为尚缺乏详细记录。","identification":"紫宽嘴鸫羽色独特，雄鸟紫灰、雌鸟栗褐，均具银蓝头顶与黑色面部，极易与其他鸫类区分。与同属的绿宽嘴鸫相比，羽色更偏紫，鸣声更低沉。幼鸟羽色近似雌鸟，但具明显斑点与鳞纹，可据此识别。","protection":"IUCN: LC（无危）","distribution":"繁殖区域包括印度北部（北阿坎德邦）向东至印度东北部、阿萨姆丘陵、缅甸北部、中国中南部（四川南部、云南）、泰国西北部、老挝北部及越南北部（北圻）。非繁殖期部分个体可能迁徙至孟加拉国等地，冬季分布尚不明确。","other":"该种为单型种，无亚种分化。由于其隐蔽性强，实际种群数量可能被低估。在老挝曾有9只个体在当地市场出售，提示其可能面临局部捕捉压力。"},{"name":"绿宽嘴鸫","english_name":"Green Cochoa","scientific_name":"Cochoa viridis","overview":"绿宽嘴鸫（英文名：Green Cochoa，学名：Cochoa viridis），是雀形目鸫科宽嘴鸫属的鸟类。俗名: 绿鸫。鲜艳的绿色羽毛和神秘的行踪使其成为森林中的隐士。分布于中国南疆周边国家以及云南、福建等地，偏好常绿阔叶林环境，尤其是有小溪流经的阴凉山谷。","appearance":"成年绿宽嘴鸫体长约25-28厘米，雄鸟体重88-99克，雌鸟117-122克。雄鸟主要呈苔绿色，头顶和颈背闪耀着中蓝色光泽，脸面略深，腹部偏蓝，喉部和腹部尤为明显。翼上的银蓝色斑块与黑色条纹形成鲜明对比，尾羽银蓝，末端具黑色横带。雌鸟相似，但体色更偏青铜绿，翅膀斑块染有青铜绿色。幼鸟头部黑色羽毛带有白色条纹，全身布满红棕色斑点，翅羽基部边缘呈淡蓝色。","call":"绿宽嘴鸫的歌声为一连串高而细的纯音哨声，持续约两秒，略显衰减，通常自树冠层发出，声音清澈悠长。此外，还会发出尖锐的叫声和非常高的短促‘pok’声。","habits":"绿宽嘴鸫栖息于海拔较低的常绿阔叶林和山地森林，偶尔会降至地面觅食。它们主要以浆果、昆虫和软体动物为食，甚至会利用石头敲开蜗牛壳。通常成对或小群体活动，有时也会独自觅食，甚至从树梢空中捕捉昆虫。","breeding":"繁殖期集中在5月至7月，筑巢于小树分叉处，离地1.5至6米，靠近水源。巢呈浅杯状，主要由苔藓和草根构成。每窝产卵2-4枚，卵色灰绿，表面散布红色斑点。雌雄亲鸟轮流孵卵，共同育雏。","identification":"绿宽嘴鸫与同属其他种类相比，其独特的苔绿色体羽和翼上的银蓝与黑色斑块组合是显著的辨识特征。雄鸟的蓝色头部和眼纹，以及浅蓝尾羽，也是识别的关键。","protection":"IUCN：LC（无危）国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"分布于喜马拉雅山脉至越南，具体包括柬埔寨、中国（云南、福建）、印度、老挝、缅甸、尼泊尔、泰国、越南和可能的不丹。在中国大陆，主要分布于云南、福建等地。","other":"绿宽嘴鸫的迁徙模式尚不清楚，它们在印度的冬季分布情况仍待研究。"},{"name":"苏门答腊宽嘴鸫","english_name":"Sumatran Cochoa","scientific_name":"Cochoa beccarii","overview":"苏门答腊宽嘴鸫（英文名：Sumatran Cochoa，学名：Cochoa beccarii），是雀形目鸫科宽嘴鸫属的特有鸟类，分布于印尼苏门答腊岛的高海拔森林地带。其外观介于大型鸫鸟与小型乌鸦之间，两性皆呈现油亮黑色，拥有电蓝色的尾羽、翼部和头顶。雄鸟面部深邃，而雌鸟面部呈浅黄褐色。","appearance":"成年雄鸟宽嘴鸫的羽毛如天鹅绒般，略带光泽，全身黑色，额头、头顶和尾羽中央呈暗淡的粉蓝色，翅膀上有一块由蓝灰色构成的显著白色斑块。雌鸟整体暗棕色，喉部和脸部呈姜黄色，下颚有小片白色区域，翅膀上的蓝色斑块稍淡，腿色较浅。幼鸟特征未详述。","call":"其鸣唱是一系列令人忧郁的哨声，回荡在森林中。","habits":"栖息于苏门答腊山脉的茂密森林中，活动范围广泛，可能在地面寻找昆虫或落果，也参与混群觅食活动。偏好在离地5至10米的灌木丛中采食小型果实。","breeding":"关于繁殖习性的具体细节尚未充分记录。","identification":"雄鸟与雌鸟在外表上有明显差异，雄鸟黑色面部，雌鸟则为浅黄褐色面部，通过颜色和体型可以有效辨别。","protection":"IUCN：LC（无危）","distribution":"仅分布于印尼苏门答腊岛的山区，包括Kerinci-Seblat国家公园等关键地点。","other":"由于其栖息地的持续丧失，全球估计数量在2500至10,000只成熟个体之间，且数量正在减少。"},{"name":"马来宽嘴鸫","english_name":"Javan Cochoa","scientific_name":"Cochoa azurea","overview":"马来宽嘴鸫（英文名：Javan Cochoa，学名：Cochoa azurea），是雀形目鸫科宽嘴鸫属的特有种。体型厚实，行动迟缓，极难发现，仅栖息于爪哇岛的山地和丘陵森林。","appearance":"雄鸟全身呈现深蓝色，头部和翅膀上带有淡色斑点。雌鸟主要为暗褐色，翅膀、尾巴和头部显露出蓝色。整体大小、形状和行为模式帮助区分其与其它暗蓝森林鸟类。","call":"发出高音、细薄的哨声和尖锐的叽叽喳喳声。","habits":"生活在亚热带或热带湿润的山地森林中，因颜色和行为在阴暗森林中难以察觉。","identification":"通过体型、色彩和行为特征与巽他啸鸫及Sunda Robin的Javan亚种相区分。","protection":"IUCN：VU（易危）。全球估计成熟个体数量在2500至10000之间，因生境丧失（农业侵占和局部开发）而持续下降。仅在Gunung Gede-Pangrango和Gunung Halimun国家公园有所记录，可能也在Gunung Tangkuban Prahu自然保护区出现过。小规模出现在鸟类贸易中，需监控。","distribution":"分布于远东地区的爪哇岛西部和中部山区。"},{"name":"食果鸫","english_name":"Fruithunter","scientific_name":"Chlamydochaera jefferyi","overview":"食果鸫（英文名：Fruithunter，学名：Chlamydochaera jefferyi），是雀形目鸫科食果鸫属的鸟类。独特而神秘的鸟种，仅见于东南亚的婆罗洲岛上的森林中，具有明显的黑领和黑色翼尖，是岛上的一道独特风景。","appearance":"雄性食果鸫全身灰白，而雌鸟则带有锈褐色调。两性皆有显著的黑色颈圈，细长的黑色面罩环绕至头部后方，翼尖同样漆黑。其独特的外观使它在同类中脱颖而出。","call":"通常保持安静，偶尔会发出高亢而细长的‘tsiiiii’叫声。","habits":"这种鸟在婆罗洲的高地森林中游牧般地寻找结果树，偏好在森林的中下层活动，常以成对或小群体的形式出现。","breeding":"繁殖生态最近才被揭示，雌鸟负责孵卵和照料，雄鸟则参与喂养雏鸟。","identification":"食果鸫的黑领和面罩是识别它的关键特征，同时它与Corvoidea类如颤鸟（Lalage）或真 Oriolus 的相似性使其在分类上显得独特。","protection":"IUCN：LC（无危）","distribution":"分布于婆罗洲北部、西部和中部的山脉，范围从基纳巴卢山南至Pueh山和Schwaner山脉。近期也在东南部的Meratus山脉被发现。","other":"历史上曾被误归入Campephagidae科，称为黑胸颤鸟。"},{"name":"暗色石䳭","english_name":"Boulder Chat","scientific_name":"Pinarornis plumosus","overview":"暗色石䳭（英文名：Boulder Chat，学名：Pinarornis plumosus），是雀形目鸫科暗色石䳭属的鸟类。为南方非洲特有种，主要分布在干树林和灌木草原地带。体羽呈深灰褐色，腹部转为黑色，喉部有细小的白色尖端，尾羽外缘白色，仅中央两对尾羽除外，翼部在飞行时可见白色斑点。成鸟相似，幼鸟上体有淡色条纹，胸部有斑点。","appearance":"体长约25厘米，重约66克，体色上部为暗棕色至灰色，下部逐渐变为黑色，下巴和喉咙有细小的白色尖端，臀部有微弱的白色鳞状纹。尾羽除中央两对外，其余均有白色尖端，初级飞羽上有白色斑块，主要在飞行时可见。喙和腿均为黑色。雌雄相似，幼鸟上体有轻微的淡色横纹，胸部有斑点。","call":"发出一系列高音调、甜美而清脆的鸣唱，类似欧亚鸲的声音。另有独特的叫声，为高音的‘twiiwiip tiiiip tiiwiiiiiiit’或‘tsuui tsu tsu p’loo’，像连续3到4次的吱嘎声，每音持续0.5秒，后有0.5秒停顿，连续重复数分钟。","habits":"偏好有树荫覆盖的花岗岩山丘，常出现在有大石块和散落树木的较低斜坡，以及陡峭干燥的岩石河床。栖息地可能小于0.5公顷，被森林或灌木草原包围，通常为米奥诺木林，但在博茨瓦纳东部也有科洛福斯佩尔姆林。主要在树冠下的巨石间活动，避开开阔的岩石区或植被密集的地方。","breeding":"繁殖季节从9月至翌年1月，高峰在10月至11月。繁殖后，家庭群体保持在一起直至下一繁殖季。","identification":"其独特的体色和尾羽特征使其易于识别。在飞行中，白色的翼斑和尾羽尖端尤为明显。幼鸟与成鸟相比，上体有轻微的淡色条纹，胸部有斑点。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲南部，包括博茨瓦纳东部、津巴布韦南部、赞比亚东部和马拉维。存在三个显著的种群：博茨瓦纳西部和津巴布韦南部；津巴布韦东北部，延伸至莫桑比克西部；赞比亚东部沿卢安瓜河谷至马拉维。","other":"暗色石䳭属为单型属，没有近亲物种，被认为是在南非的花岗岩盾上进化而来，其分布范围几乎与这一地质结构相吻合。"}];
